const _astro_dataLayerContent = [["Map",1,2,9,10],"meta::meta",["Map",3,4,5,6,7,8],"astro-version","5.16.15","content-config-digest","0710b3534f99afc8","astro-config-digest","{\"root\":{},\"srcDir\":{},\"publicDir\":{},\"outDir\":{},\"cacheDir\":{},\"site\":\"https://xnet.fyi\",\"compressHTML\":true,\"base\":\"/\",\"trailingSlash\":\"ignore\",\"output\":\"static\",\"scopedStyleStrategy\":\"where\",\"build\":{\"format\":\"directory\",\"client\":{},\"server\":{},\"assets\":\"_astro\",\"serverEntry\":\"entry.mjs\",\"redirects\":true,\"inlineStylesheets\":\"auto\",\"concurrency\":1},\"server\":{\"open\":false,\"host\":false,\"port\":4321,\"streaming\":true,\"allowedHosts\":[]},\"redirects\":{},\"image\":{\"endpoint\":{\"route\":\"/_image\"},\"service\":{\"entrypoint\":\"astro/assets/services/sharp\",\"config\":{}},\"domains\":[],\"remotePatterns\":[],\"responsiveStyles\":false},\"devToolbar\":{\"enabled\":true},\"markdown\":{\"syntaxHighlight\":false,\"shikiConfig\":{\"langs\":[],\"langAlias\":{},\"theme\":\"github-dark\",\"themes\":{},\"wrap\":false,\"transformers\":[]},\"remarkPlugins\":[null,null,null],\"rehypePlugins\":[null,[null,{\"experimentalHeadingIdCompat\":false}],null,[null,{\"themes\":[\"one-light\",\"one-dark-pro\"],\"defaultLocale\":\"en\",\"cascadeLayer\":\"starlight.components\",\"styleOverrides\":{\"borderRadius\":\"0px\",\"borderWidth\":\"1px\",\"codePaddingBlock\":\"0.75rem\",\"codePaddingInline\":\"1rem\",\"codeFontFamily\":\"var(--__sl-font-mono)\",\"codeFontSize\":\"var(--sl-text-code)\",\"codeLineHeight\":\"var(--sl-line-height)\",\"uiFontFamily\":\"var(--__sl-font)\",\"textMarkers\":{\"lineDiffIndicatorMarginLeft\":\"0.25rem\",\"defaultChroma\":\"45\",\"backgroundOpacity\":\"60%\"}},\"plugins\":[{\"name\":\"Starlight Plugin\",\"hooks\":{}},{\"name\":\"astro-expressive-code\",\"hooks\":{}}]}]],\"remarkRehype\":{},\"gfm\":true,\"smartypants\":true},\"security\":{\"checkOrigin\":true,\"allowedDomains\":[]},\"env\":{\"schema\":{},\"validateSecrets\":false},\"experimental\":{\"clientPrerender\":false,\"contentIntellisense\":false,\"headingIdCompat\":false,\"preserveScriptOrder\":false,\"liveContentCollections\":false,\"csp\":false,\"staticImportMetaEnv\":false,\"chromeDevtoolsWorkspace\":false,\"failOnPrerenderConflict\":false,\"svgo\":false},\"legacy\":{\"collections\":false},\"prefetch\":{\"prefetchAll\":true},\"i18n\":{\"defaultLocale\":\"en\",\"locales\":[\"en\"],\"routing\":{\"prefixDefaultLocale\":false,\"redirectToDefaultLocale\":false,\"fallbackType\":\"redirect\"}}}","docs",["Map",11,12,9,26,36,37,48,49,60,61,71,72,83,84,95,96,106,107,118,119,129,130,141,142,153,154,164,165,175,176,186,187,197,198,208,209,219,220,230,231,241,242,253,254,264,265,276,277,287,288,298,299,310,311,322,323,333,334,344,345,355,356,366,367,377,378,388,389,399,400,410,411,421,422,432,433,443,444,454,455,465,466,476,477,487,488,498,499,509,510,523,524,534,535,546,547,558,559,570,571,582,583,594,595,605,606,616,617,627,628,639,640,651,652,663,664,674,675,686,687,697,698,708,709,720,721],"docs/core-concepts",{id:11,data:13,body:23,filePath:24,digest:25,deferredRender:16},{title:14,description:15,editUrl:16,head:17,template:18,sidebar:19,pagefind:16,draft:21},"Core Concepts","The mental model behind xNet — schemas, nodes, hooks, and sync.",true,[],"doc",{order:20,hidden:21,attrs:22},2,false,{},"import { Card, CardGrid, LinkCard } from '@astrojs/starlight/components'\n\n:::note[In this article]\n\n- How data is structured (schemas and nodes)\n- How you interact with data (the three hooks)\n- How sync and conflict resolution work\n- How identity and signing work\n- How authorization and encryption work\n  :::\n\n## Schemas define your data\n\nEvery piece of data in xNet is a **node**. Every node conforms to a **schema**. A schema is defined once in TypeScript and describes the shape of your data:\n\n```ts\nimport { defineSchema, text, number, select } from '@xnetjs/data'\n\nexport const ProjectSchema = defineSchema({\n  name: 'Project',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    priority: number({ min: 1, max: 5 }),\n    status: select({\n      options: [\n        { id: 'active', name: 'Active' },\n        { id: 'archived', name: 'Archived' }\n      ] as const\n    })\n  }\n})\n```\n\nSchemas give you:\n\n- **Type inference** — `project.status` is `'active' | 'archived'`, not `string`\n- **Validation** — invalid data is rejected at creation time\n- **Identity** — each schema has a unique IRI like `xnet://my-app/Project`\n\nSee [defineSchema](/docs/schemas/defineschema/) and [Property Types](/docs/schemas/property-types/) for full reference.\n\n## Nodes are your data\n\nA node is an instance of a schema. When you create a task, you create a node:\n\n```ts\nconst { create } = useMutate()\nconst task = await create(TaskSchema, { title: 'Ship it', status: 'todo' })\n```\n\nEvery node has system fields managed automatically by the store — you never need to define or set these yourself:\n\n| Field       | Type      | Description                             |\n| ----------- | --------- | --------------------------------------- |\n| `id`        | `string`  | Unique identifier (nanoid, 21 chars)    |\n| `schemaId`  | `string`  | Schema IRI (e.g., `xnet://my-app/Task`) |\n| `createdAt` | `number`  | Set automatically at creation time      |\n| `createdBy` | `string`  | Author's DID (e.g., `did:key:z6Mk...`)  |\n| `updatedAt` | `number`  | Updated automatically on every change   |\n| `updatedBy` | `string`  | Last modifier's DID                     |\n| `deleted`   | `boolean` | Soft-delete flag                        |\n\nYour schema properties are merged alongside these fields into a **flat node** — you access `task.title` directly, not `task.properties.title`. You can filter and sort by any system field (e.g., `orderBy: { createdAt: 'desc' }`) without defining them in your schema.\n\n## Three hooks for everything\n\n### useQuery — read data\n\n```tsx\nconst { data: tasks } = useQuery(TaskSchema, {\n  where: { status: 'todo' },\n  orderBy: { createdAt: 'desc' },\n  limit: 20\n})\n```\n\nReturns reactive data that auto-updates when the underlying store changes — whether from your own mutations, a peer's sync, or a background process.\n\n### useMutate — write data\n\n```tsx\nconst { create, update, remove, restore, mutate } = useMutate()\n\nawait create(TaskSchema, { title: 'New' })\nawait update(TaskSchema, id, { status: 'done' })\nawait remove(id)\nawait restore(id)\nawait mutate([\n  { type: 'create', schema: TaskSchema, data: { title: 'A' } },\n  { type: 'create', schema: TaskSchema, data: { title: 'B' } }\n])\n```\n\nAll mutations are type-safe, validated against the schema, and automatically synced.\n\n### useNode — edit a single node with CRDT\n\n```tsx\nconst { data, doc, update, syncStatus, presence } = useNode(PageSchema, pageId, {\n  createIfMissing: { title: 'Untitled' },\n  did: currentUserDID\n})\n```\n\n`useNode` is the powerhouse hook for collaborative editing. It gives you:\n\n- **Structured data** via `data` (the node's properties)\n- **A Yjs document** via `doc` (for rich text, bind to TipTap)\n- **Sync status** and **presence** for collaborator UI\n- **Automatic persistence** with debounced saves\n\n## Two conflict resolution strategies\n\nxNet uses different strategies for different data types:\n\n| Data Type                    | Strategy                           | How It Works                                                                                |\n| ---------------------------- | ---------------------------------- | ------------------------------------------------------------------------------------------- |\n| Structured data (properties) | **Lamport LWW** (Last Writer Wins) | Each property change carries a Lamport timestamp. Higher timestamp wins.                    |\n| Rich text (documents)        | **Yjs CRDT**                       | Character-level merge. Two users typing in the same paragraph are merged without data loss. |\n\nThis dual strategy means structured fields like `title` or `status` use simple, predictable conflict resolution, while collaborative text editing uses the industry-standard Yjs CRDT for seamless merging.\n\n## Every change is signed\n\nWhen you create or update a node, xNet:\n\n1. Signs the change with a **hybrid signature** (Ed25519 + ML-DSA-65 by default)\n2. Hashes the change with **BLAKE3**\n3. Stores the signed change locally\n4. Syncs the signed change to peers\n\nWhen a peer receives a change, they **verify the hybrid signature** before applying it. This means:\n\n- You can prove who made every change\n- Tampered data is rejected\n- No server is needed to enforce trust\n- Changes are protected against quantum forgery attacks\n\nThe default **Level 1 (Hybrid)** signature carries both an Ed25519 component (64 bytes) and an ML-DSA-65 component (~3.3 KB). Both must verify — if either is invalid, the change is rejected. Level 0 (Ed25519 only) is available for high-frequency paths where the smaller signature size matters more than quantum resistance.\n\n## Identity is a key pair\n\nYour identity in xNet is a **DID:key** — a decentralized identifier derived from an Ed25519 public key:\n\n```\ndid:key:z6MkhaXgBZDvotDkL5257faiztiGiC2QtKLGpbnnEGta2doK\n```\n\nNo accounts. No passwords. No auth server. Your key pair is your identity. You can delegate permissions to other keys using **UCAN tokens** (capability-based authorization).\n\n## Authorization is encryption\n\nxNet enforces read access cryptographically. Every private node is encrypted with a **per-node content key**. Only users in the **recipients list** can unwrap the key and read the node — the hub never decrypts anything.\n\nYou define access control in the schema itself:\n\n```ts\nconst TaskSchema = defineSchema({\n  // ...\n  authorization: {\n    roles: {\n      owner: role.creator(),\n      editor: role.property('editors')\n    },\n    actions: {\n      read: allow('owner', 'editor'),\n      write: allow('owner', 'editor'),\n      share: allow('owner')\n    }\n  }\n})\n```\n\nThen check permissions in components:\n\n```tsx\nconst { canWrite, canShare } = useCan(taskId)\nconst { grants, grant, revoke } = useGrants(taskId)\n```\n\nGrants are stored as ordinary nodes — they sync, replicate, and inherit the same CRDT conflict resolution as all your data.\n\nSee the [Authorization Guide](/docs/guides/authorization/) for the full model including delegation, key recovery, and offline policy.\n\n## Next steps\n\n<CardGrid>\n  <LinkCard\n    title=\"useQuery\"\n    description=\"Full reference for reading data reactively.\"\n    href=\"/docs/hooks/usequery/\"\n  />\n  <LinkCard\n    title=\"useMutate\"\n    description=\"Full reference for creating and updating data.\"\n    href=\"/docs/hooks/usemutate/\"\n  />\n  <LinkCard\n    title=\"useNode\"\n    description=\"Full reference for collaborative editing.\"\n    href=\"/docs/hooks/usenode/\"\n  />\n  <LinkCard\n    title=\"defineSchema\"\n    description=\"Full reference for defining schemas.\"\n    href=\"/docs/schemas/defineschema/\"\n  />\n  <LinkCard\n    title=\"Authorization\"\n    description=\"Encryption-first access control: roles, grants, and key recovery.\"\n    href=\"/docs/guides/authorization/\"\n  />\n</CardGrid>","src/content/docs/docs/core-concepts.mdx","ffae11ab7394e553",{id:9,data:27,body:33,filePath:34,digest:35,deferredRender:16},{title:28,description:29,editUrl:16,head:30,template:18,sidebar:31,pagefind:16,draft:21},"xNet Documentation","Build local-first apps with React hooks. No server, no auth, no vendor lock-in.",[],{hidden:21,attrs:32},{},"import { Card, CardGrid, LinkCard } from '@astrojs/starlight/components'\n\nxNet is a local-first React framework. Your data lives on the device, syncs peer-to-peer, and works offline. Three hooks replace your entire backend.\n\n## Get started\n\n<CardGrid>\n  <LinkCard\n    title=\"Introduction\"\n    description=\"What xNet is and when to use it.\"\n    href=\"/docs/introduction/\"\n  />\n  <LinkCard\n    title=\"Quick Start\"\n    description=\"Build a task manager in 5 minutes.\"\n    href=\"/docs/quickstart/\"\n  />\n  <LinkCard\n    title=\"Core Concepts\"\n    description=\"Schemas, hooks, sync — the mental model.\"\n    href=\"/docs/core-concepts/\"\n  />\n  <LinkCard\n    title=\"The Protocol\"\n    description=\"xNet is an open, re-implementable standard — not just this app.\"\n    href=\"/docs/protocol/overview/\"\n  />\n</CardGrid>\n\n## React Hooks\n\n<CardGrid>\n  <LinkCard\n    title=\"useQuery\"\n    description=\"Read data reactively with filtering, sorting, and pagination.\"\n    href=\"/docs/hooks/usequery/\"\n  />\n  <LinkCard\n    title=\"useMutate\"\n    description=\"Create, update, delete nodes with full type safety.\"\n    href=\"/docs/hooks/usemutate/\"\n  />\n  <LinkCard\n    title=\"useNode\"\n    description=\"Collaborative editing with Yjs, P2P sync, and presence.\"\n    href=\"/docs/hooks/usenode/\"\n  />\n  <LinkCard\n    title=\"useIdentity\"\n    description=\"Access the current user's DID and auth status.\"\n    href=\"/docs/hooks/useidentity/\"\n  />\n</CardGrid>\n\n## Schemas & Data\n\n<CardGrid>\n  <LinkCard\n    title=\"defineSchema\"\n    description=\"Define typed schemas with 15 property types.\"\n    href=\"/docs/schemas/defineschema/\"\n  />\n  <LinkCard\n    title=\"Property Types\"\n    description=\"text, number, date, select, relation, person, and more.\"\n    href=\"/docs/schemas/property-types/\"\n  />\n  <LinkCard\n    title=\"Relations\"\n    description=\"Link nodes together with relation() and person().\"\n    href=\"/docs/schemas/relations/\"\n  />\n  <LinkCard\n    title=\"Type Inference\"\n    description=\"How TypeScript types flow from schemas to hooks.\"\n    href=\"/docs/schemas/type-inference/\"\n  />\n</CardGrid>\n\n## Guides\n\n<CardGrid>\n  <LinkCard\n    title=\"Authorization\"\n    description=\"Encryption-first access control: schema roles, grants, delegation, and key recovery.\"\n    href=\"/docs/guides/authorization/\"\n  />\n  <LinkCard\n    title=\"Plugin Development\"\n    description=\"Build extensions with the 4-layer plugin system.\"\n    href=\"/docs/guides/plugins/\"\n  />\n  <LinkCard\n    title=\"Sync\"\n    description=\"How P2P sync works and how to configure it.\"\n    href=\"/docs/guides/sync/\"\n  />\n  <LinkCard\n    title=\"Identity & Keys\"\n    description=\"DID:key pairs, UCAN tokens, and key management.\"\n    href=\"/docs/guides/identity/\"\n  />\n  <LinkCard\n    title=\"Real-time Collaboration\"\n    description=\"Collaborative editors with useNode and TipTap.\"\n    href=\"/docs/guides/collaboration/\"\n  />\n  <LinkCard\n    title=\"Offline Patterns\"\n    description=\"Building apps that work without connectivity.\"\n    href=\"/docs/guides/offline/\"\n  />\n  <LinkCard\n    title=\"Infinite Canvas\"\n    description=\"Spatial canvas with R-tree indexing and layout algorithms.\"\n    href=\"/docs/guides/canvas/\"\n  />\n  <LinkCard\n    title=\"Rich Text Editor\"\n    description=\"TipTap editor with Yjs collaboration and slash commands.\"\n    href=\"/docs/guides/editor/\"\n  />\n  <LinkCard\n    title=\"Hub & Signaling\"\n    description=\"Signaling server, self-hosting, and Hub roadmap.\"\n    href=\"/docs/guides/hub/\"\n  />\n  <LinkCard\n    title=\"Connect to xNet Cloud\"\n    description=\"Link your web, desktop, or mobile app to a managed hub.\"\n    href=\"/docs/guides/cloud-connect/\"\n  />\n  <LinkCard\n    title=\"DevTools\"\n    description=\"9 debug panels, event bus, and instrumentation.\"\n    href=\"/docs/guides/devtools/\"\n  />\n  <LinkCard\n    title=\"Electron Setup\"\n    description=\"Running xNet in an Electron desktop app.\"\n    href=\"/docs/guides/electron/\"\n  />\n  <LinkCard\n    title=\"Testing\"\n    description=\"Testing xNet apps with Vitest.\"\n    href=\"/docs/guides/testing/\"\n  />\n</CardGrid>\n\n## Concepts\n\n<CardGrid>\n  <LinkCard\n    title=\"Local-First\"\n    description=\"Why local-first matters and how xNet implements it.\"\n    href=\"/docs/concepts/local-first/\"\n  />\n  <LinkCard\n    title=\"CRDTs\"\n    description=\"Conflict-free replicated data types explained.\"\n    href=\"/docs/concepts/crdts/\"\n  />\n  <LinkCard\n    title=\"Network & Transport\"\n    description=\"libp2p, WebRTC, security layers, and peer scoring.\"\n    href=\"/docs/concepts/network/\"\n  />\n  <LinkCard\n    title=\"Sync Architecture\"\n    description=\"Dual-CRDT model, Lamport clocks, and merge strategies.\"\n    href=\"/docs/concepts/sync-architecture/\"\n  />\n</CardGrid>\n\n## Packages\n\n| Package          | Description                                                         |\n| ---------------- | ------------------------------------------------------------------- |\n| `@xnetjs/react`    | React hooks: useQuery, useMutate, useNode, useIdentity              |\n| `@xnetjs/data`     | Schema system, NodeStore, 15 property types                         |\n| `@xnetjs/sync`     | Lamport clocks, Change\\<T\\>, Yjs security                           |\n| `@xnetjs/crypto`   | BLAKE3, Ed25519, XChaCha20-Poly1305                                 |\n| `@xnetjs/identity` | DID:key, UCAN tokens, key management                                |\n| `@xnetjs/plugins`  | 4-layer plugin system (scripts, extensions, services, integrations) |\n| `@xnetjs/storage`  | SQLite adapter                                                     |\n| `@xnetjs/editor`   | TipTap rich text editor with Yjs collaboration                      |\n| `@xnetjs/canvas`   | Infinite canvas with spatial indexing                               |\n| `@xnetjs/network`  | libp2p, WebRTC/WebSocket transport                                  |","src/content/docs/docs/index.mdx","ecdf2c1170925129","docs/introduction",{id:36,data:38,body:45,filePath:46,digest:47,deferredRender:16},{title:39,description:40,editUrl:16,head:41,template:18,sidebar:42,pagefind:16,draft:21},"What is xNet?","A local-first framework for building React apps that sync peer-to-peer with zero backend.",[],{order:43,hidden:21,attrs:44},0,{},"import { Card, CardGrid, LinkCard } from '@astrojs/starlight/components'\n\n:::note[In this article]\n\n- What xNet is and what problem it solves\n- The core mental model: three hooks, zero backend\n- When to use xNet (and when not to)\n  :::\n\n## The problem\n\nBuilding a modern collaborative app requires assembling a stack of 6+ services: a database, an API layer, auth, real-time sync, file storage, and deployment infrastructure. Each comes with its own SDK, its own data model, and its own failure modes.\n\nMost of this infrastructure exists to solve one problem: **getting data from one device to another**. xNet eliminates that problem entirely.\n\n## What xNet does\n\nxNet is a **local-first framework** for React. Your data lives on the user's device. It syncs peer-to-peer via WebRTC. There is no server, no API, no database to manage.\n\nYou interact with xNet through **three hooks**:\n\n| Hook                                  | Purpose                                                |\n| ------------------------------------- | ------------------------------------------------------ |\n| [`useQuery`](/docs/hooks/usequery/)   | Read data reactively. Filter, sort, paginate.          |\n| [`useMutate`](/docs/hooks/usemutate/) | Create, update, delete with full type safety.          |\n| [`useNode`](/docs/hooks/usenode/)     | Open a single node for collaborative editing with Yjs. |\n\nThat's the entire API surface for most apps. Define a schema, use the hooks, and your app works offline, syncs in real-time, and never touches a server.\n\n## The architecture in 30 seconds\n\n```\nYour React App\n  └── useQuery / useMutate / useNode / useCan / useGrants\n        └── NodeStore (schema-validated, type-safe, encrypted)\n              ├── SQLite (OPFS in browser) / SQLite (desktop/mobile)\n              ├── Authorization engine (PolicyEvaluator + GrantStore)\n              └── P2P Sync (WebRTC via signaling server)\n                    └── Yjs CRDT (rich text) + Lamport LWW (structured data)\n```\n\nEverything below the hooks is invisible to you. You write React components. xNet handles storage, sync, conflict resolution, cryptographic signing, and end-to-end encryption.\n\n## When to use xNet\n\n**Good fit:**\n\n- Productivity apps (notes, tasks, databases, wikis)\n- Collaborative tools (documents, whiteboards, spreadsheets)\n- Personal tools (journals, habit trackers, budgets)\n- Internal tools where you control the client\n- Apps where data ownership and privacy matter\n\n**Not a good fit (yet):**\n\n- Apps that need a centralized server of record (banking, e-commerce)\n- Apps with millions of users sharing a single dataset\n- Apps that need server-side rendering of user data\n- Apps that need complex server-side business logic\n\n## What's in the box\n\nxNet is a monorepo of focused packages:\n\n| Package          | Purpose                                                                               |\n| ---------------- | ------------------------------------------------------------------------------------- |\n| `@xnetjs/react`    | React hooks: `useQuery`, `useMutate`, `useNode`, `useCan`, `useGrants`, `useSecurity` |\n| `@xnetjs/data`     | Schema system, NodeStore, 15 property types, authorization engine                     |\n| `@xnetjs/sync`     | Lamport clocks, `Change<T>` v3 (hybrid signatures), Yjs security                      |\n| `@xnetjs/crypto`   | BLAKE3, Ed25519, ML-DSA-65, X25519, ML-KEM-768, XChaCha20-Poly1305                    |\n| `@xnetjs/identity` | DID:key, HybridKeyBundle, PQ Key Registry, UCAN tokens, key recovery                  |\n| `@xnetjs/storage`  | SQLite adapter                                                                       |\n| `@xnetjs/canvas`   | Infinite canvas with spatial indexing                                                 |\n| `@xnetjs/editor`   | TipTap rich text editor                                                               |\n| `@xnetjs/devtools` | 9 debug panels + AuthZ panel + Security panel                                         |\n\nFor most apps, you only install `@xnetjs/react` and `@xnetjs/data`. Everything else is pulled in as needed.\n\n## Next steps\n\n<CardGrid>\n  <LinkCard\n    title=\"Quick Start\"\n    description=\"Build your first xNet app in 5 minutes.\"\n    href=\"/docs/quickstart/\"\n  />\n  <LinkCard\n    title=\"Core Concepts\"\n    description=\"Understand the mental model behind xNet.\"\n    href=\"/docs/core-concepts/\"\n  />\n</CardGrid>","src/content/docs/docs/introduction.mdx","876c615481da5350","docs/quickstart",{id:48,data:50,body:57,filePath:58,digest:59,deferredRender:16},{title:51,description:52,editUrl:16,head:53,template:18,sidebar:54,pagefind:16,draft:21},"Quick Start","Build a local-first task manager with xNet in 5 minutes.",[],{order:55,hidden:21,attrs:56},1,{},"import { Steps, Tabs, TabItem, FileTree } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- How to define a schema with `defineSchema()`\n- How to query data reactively with `useQuery()`\n- How to create and update nodes with `useMutate()`\n- How offline-first works (spoiler: you don't have to do anything)\n  :::\n\n## Prerequisites\n\n- Node.js 22+\n- pnpm (or npm/yarn)\n- Basic React knowledge\n\n## What you'll build\n\nA task manager that works offline, syncs peer-to-peer, and persists to local SQLite storage. No server required.\n\n<Steps>\n\n1. **Create a React project and install xNet**\n\n   ```bash\n   pnpm create vite my-app --template react-ts\n   cd my-app\n   pnpm add @xnetjs/react @xnetjs/data\n   ```\n\n2. **Define your schema**\n\n   Create a file that describes the shape of your data:\n\n   ```ts title=\"src/schema.ts\"\n   import { defineSchema, text, select, checkbox } from '@xnetjs/data'\n\n   export const TaskSchema = defineSchema({\n     name: 'Task',\n     namespace: 'xnet://my-app/',\n     properties: {\n       title: text({ required: true }),\n       status: select({\n         options: [\n           { id: 'todo', name: 'To Do', color: '#6366f1' },\n           { id: 'doing', name: 'Doing', color: '#f59e0b' },\n           { id: 'done', name: 'Done', color: '#10b981' }\n         ] as const\n       }),\n       completed: checkbox({ default: false })\n     }\n   })\n   ```\n\n   The `as const` on the options array gives you literal type inference — `status` is typed as `'todo' | 'doing' | 'done'`, not just `string`.\n\n   :::tip[Automatic timestamps]\n   You don't need to define `createdAt` or `updatedAt` — every node gets these automatically. You can query and sort by them out of the box.\n   :::\n\n3. **Wrap your app in `XNetProvider`**\n\n   The provider initializes the NodeStore, storage, and sync system:\n\n   ```tsx title=\"src/App.tsx\"\n   import { XNetProvider } from '@xnetjs/react'\n   import { XNetDevToolsProvider } from '@xnetjs/devtools'\n   import { TaskList } from './TaskList'\n\n   // In production, generate and persist these securely\n   const authorDID = 'did:key:z6MkhaXgBZDvotDkL5257faiztiGiC2QtKLGpbnnEGta2doK'\n   const signingKey = new Uint8Array(32) // Replace with real Ed25519 key\n\n   export function App() {\n     return (\n       <XNetProvider config={{ authorDID, signingKey }}>\n         <XNetDevToolsProvider>\n           <TaskList />\n         </XNetDevToolsProvider>\n       </XNetProvider>\n     )\n   }\n   ```\n\n   :::tip[Identity in production]\n   For a real app, use `@xnetjs/identity` to generate a DID:key pair and store it securely. The Quick Start uses hardcoded values for simplicity.\n   :::\n\n4. **Read data with `useQuery`**\n\n   ```tsx title=\"src/TaskList.tsx\"\n   import { useQuery, useMutate } from '@xnetjs/react'\n   import { TaskSchema } from './schema'\n\n   export function TaskList() {\n     const { data: tasks } = useQuery(TaskSchema, {\n       orderBy: { createdAt: 'desc' }\n     })\n     const { create, update, remove } = useMutate()\n\n     const addTask = () => {\n       create(TaskSchema, { title: 'New task', status: 'todo' })\n     }\n\n     return (\n       <div>\n         <button onClick={addTask}>Add Task</button>\n         <ul>\n           {tasks.map((task) => (\n             <li key={task.id}>\n               <input\n                 type=\"checkbox\"\n                 checked={task.completed}\n                 onChange={() =>\n                   update(TaskSchema, task.id, {\n                     completed: !task.completed,\n                     status: task.completed ? 'todo' : 'done'\n                   })\n                 }\n               />\n               <span>{task.title}</span>\n               <button onClick={() => remove(task.id)}>Delete</button>\n             </li>\n           ))}\n         </ul>\n       </div>\n     )\n   }\n   ```\n\n   That's it. `useQuery` returns reactive data that auto-updates when you (or a peer) mutate. `useMutate` gives you type-safe create, update, and remove methods.\n\n5. **Run it**\n\n   ```bash\n   pnpm dev\n   ```\n\n   Open `http://localhost:5173`. Create some tasks. Refresh the page — they persist. Open a second tab — they sync.\n\n</Steps>\n\n## What just happened\n\nWithout writing a single line of backend code, you got:\n\n- **Persistent storage** — data lives in local SQLite storage, survives refreshes\n- **Reactive queries** — UI updates automatically when data changes\n- **Type safety** — `task.status` is `'todo' | 'doing' | 'done'`, not `string`\n- **Schema validation** — invalid data is rejected at creation time\n- **Offline-first** — works without any network connection\n- **Cryptographic signing** — every change is signed with Ed25519\n\n## Project structure\n\n<FileTree>\n  - src/ - schema.ts defineSchema() definitions - App.tsx XNetProvider - TaskList.tsx useQuery +\n  useMutate\n</FileTree>\n\n## Go multiplayer in two commands\n\nEverything above is one keystroke away from being a shared app. Point the\nprovider at a sync hub and give everyone the same room string — whoever\nshares the room sees the same data:\n\n```tsx\n<XNetProvider config={{\n  authorDID, signingKey, identity,\n  hubUrl: 'wss://hub.xnet.fyi',  // public demo hub (quota'd sandbox) — or your own\n  hubOptions: { nodeSyncRoom: 'my-app-standup' },  // the room IS the invite\n}}>\n```\n\nTo run your own hub locally (dev only — auth off accepts anyone):\n\n```bash\ndocker run --rm -p 4444:4444 -e HUB_AUTH=false ghcr.io/crs48/xnet-hub:latest\n```\n\nOpen the app in two browser windows — changes appear in both. The room string\nis the entire join flow: put it in a URL (`?room=standup`) and the URL becomes\nan invitation. The smallest complete example of this is\n[`examples/minimal-app`](https://github.com/crs48/xNet/tree/main/examples/minimal-app)\nin the repo (~60 lines, copy-paste ready), and you can watch it run live on\nthe [demos page](/demos/).\n\n## Next steps\n\n<Tabs>\n  <TabItem label=\"Add rich text\">\n    Use [`useNode`](/docs/hooks/usenode/) to add a collaborative rich text editor to each task:\n\n    ```tsx\n    const { doc } = useNode(TaskSchema, taskId)\n    // Pass doc to TipTap's Collaboration extension\n    ```\n\n  </TabItem>\n  <TabItem label=\"Add P2P sync\">\n    Pass signaling servers to `XNetProvider` to sync across devices:\n\n    ```tsx\n    <XNetProvider config={{\n      authorDID,\n      signingKey,\n      signalingServers: ['wss://your-hub.example.com'],\n    }}>\n      <XNetDevToolsProvider>\n        <App />\n      </XNetDevToolsProvider>\n    </XNetProvider>\n    ```\n\n  </TabItem>\n  <TabItem label=\"Learn more\">\n    - [Core Concepts](/docs/core-concepts/) — understand the mental model\n    - [useQuery reference](/docs/hooks/usequery/) — filtering, sorting, pagination\n    - [defineSchema reference](/docs/schemas/defineschema/) — all schema options\n    - [Property Types](/docs/schemas/property-types/) — all 15 property types\n  </TabItem>\n</Tabs>","src/content/docs/docs/quickstart.mdx","e9ec2d5eb79d179a","docs/ai/understanding-xnet",{id:60,data:62,body:68,filePath:69,digest:70,deferredRender:16},{title:63,description:64,editUrl:16,head:65,template:18,sidebar:66,pagefind:16,draft:21},"Understanding xNet (For AI Assistants)","A guide for AI coding assistants on how xNet differs from traditional architectures",[],{hidden:21,attrs:67},{},"# Understanding xNet: A Guide for AI Assistants\n\nIf you're an AI assistant helping a developer build with xNet, this guide will help you understand the fundamental paradigm differences.\n\n:::tip[Working inside a user's workspace?]\nThis page is about writing *application code* against xNet. If you are an\nagent operating on a user's actual data — reading pages, editing databases,\nsearching their workspace — use the **files-first agent surface** instead: a\nscoped checkout of the workspace plus the `xnet` CLI, taught by a ~500-token\n`SKILL.md` (printable with `xnet skill`). It completes the same work at\nroughly a tenth of the tokens of an MCP toolset. See\n[Agent Interfaces](/docs/guides/agent-interfaces/).\n:::\n\n## The Key Insight\n\n**xNet has no backend.**\n\nThis is not a simplification or a limitation — it's the core design principle. Data lives on the user's device and syncs peer-to-peer.\n\n## Mental Model Comparison\n\n### Traditional Architecture\n\n```\nUser → Frontend → API → Backend → Database\n                   ↑\n              Auth Service\n```\n\n### xNet Architecture\n\n```\nUser → React Hooks → Local Storage ←→ P2P Sync ←→ Other Devices\n                           ↑\n              Cryptographic Identity (built-in)\n```\n\n## What This Means Practically\n\n### There Are No API Endpoints\n\nWhen a user asks \"create an API to save tasks\", the correct response is:\n\n```typescript\n// Don't create this:\n// app.post('/api/tasks', handler)\n\n// Do this instead:\nconst { create } = useMutate()\nawait create(TaskSchema, { title: 'New task' })\n```\n\nThe `create` function writes to local storage. Sync happens automatically.\n\n### There Is No Auth System to Implement\n\nWhen a user asks \"add authentication\", the correct response is:\n\n```typescript\n// Don't create OAuth/JWT flows\n\n// Identity is already built-in:\nconst { did, displayName } = useIdentity()\n\n// DID is a cryptographic identifier like:\n// did:key:z6MkhaXgBZDvotDkL5257faiztiGiC2QtKLGpbnnEGta2doK\n```\n\n### Offline Just Works\n\nWhen a user asks \"handle offline mode\", the correct response is:\n\n```typescript\n// Don't add service workers or cache layers\n\n// It already works:\nconst { data } = useQuery(TaskSchema)\n// This reads from local storage\n// Works whether online or offline\n// Syncs when connectivity returns\n```\n\n### Real-time Is Built-in\n\nWhen a user asks \"add real-time updates\", the correct response is:\n\n```typescript\n// Don't create WebSocket connections\n\n// Hooks are already reactive:\nconst { data: tasks } = useQuery(TaskSchema)\n// When another device syncs changes,\n// this component re-renders automatically\n```\n\n## Common Mistakes to Avoid\n\n| User Request     | Wrong Approach     | Correct Approach           |\n| ---------------- | ------------------ | -------------------------- |\n| \"Save data\"      | Create REST API    | Use `useMutate().create()` |\n| \"Fetch data\"     | Use fetch/axios    | Use `useQuery()`           |\n| \"Add auth\"       | Implement OAuth    | Use `useIdentity()`        |\n| \"Handle offline\" | Add service worker | Already works              |\n| \"Real-time sync\" | Add WebSockets     | Already built-in           |\n| \"Manage state\"   | Add Redux/Zustand  | Hooks handle this          |\n| \"Optimistic UI\"  | Manual rollback    | Built into mutations       |\n\n## The Schema System\n\nSchemas are central to xNet. They define data shapes AND provide type inference:\n\n```typescript\nimport { defineSchema, text, select, relation } from '@xnetjs/data'\n\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://myapp/',\n  properties: {\n    title: text({ required: true }),\n    status: select({ options: ['todo', 'done'] as const }),\n    assignee: relation({ schema: 'xnet://myapp/Person' })\n  }\n})\n\n// Now hooks are fully typed:\nconst { data } = useQuery(TaskSchema)\ndata[0].title // string\ndata[0].status // 'todo' | 'done'\n```\n\n## When to Suggest Server Code\n\nThe only times server code is appropriate:\n\n1. **Hub setup** — If deploying an always-on relay (optional)\n2. **External integrations** — Webhooks, third-party APIs\n3. **Heavy computation** — AI/ML that can't run on device\n\nEven then, the Hub is just a relay — it doesn't process or store application logic.\n\n## Quick Reference\n\n### Reading Data\n\n```typescript\n// Single item\nconst { data: task } = useQuery(TaskSchema, taskId)\n\n// All items\nconst { data: tasks } = useQuery(TaskSchema)\n\n// Filtered\nconst { data: todos } = useQuery(TaskSchema, {\n  where: { status: 'todo' }\n})\n```\n\n### Writing Data\n\n```typescript\nconst { create, update, remove } = useMutate()\n\n// Create\nconst id = await create(TaskSchema, { title: 'New task' })\n\n// Update\nawait update(TaskSchema, id, { status: 'done' })\n\n// Delete\nawait remove(id)\n```\n\n### Collaborative Editing\n\n```typescript\nconst { data: page, doc } = useNode(PageSchema, pageId)\n// doc is a Y.Doc for Yjs collaborative editing\n```\n\n### User Identity\n\n```typescript\nconst { did, displayName, avatarUrl } = useIdentity()\n// did:key:z6Mk... is the user's cryptographic identity\n```\n\n## Summary\n\nWhen helping with xNet:\n\n1. **Never suggest API endpoints** — Use hooks\n2. **Never implement auth** — It's cryptographic and built-in\n3. **Never manage state** — Hooks are reactive\n4. **Never handle offline** — It just works\n5. **Always use schemas** — They're the source of truth\n\nThe paradigm shift: **data is local, sync is automatic, identity is cryptographic**.","src/content/docs/docs/ai/understanding-xnet.mdx","7d3dc688f515a463","docs/concepts/crdts",{id:71,data:73,body:80,filePath:81,digest:82,deferredRender:16},{title:74,description:75,editUrl:16,head:76,template:18,sidebar:77,pagefind:16,draft:21},"CRDTs","Conflict-free replicated data types in xNet.",[],{order:78,hidden:21,attrs:79},3,{},"## What are CRDTs?\n\nA Conflict-free Replicated Data Type (CRDT) is a data structure that can be modified independently on different devices and merged automatically without conflicts. No central server is needed to coordinate — the mathematical properties of the data structure guarantee that all replicas converge to the same state.\n\n## xNet's dual-CRDT model\n\nxNet uses two complementary CRDT strategies, each optimized for a different data shape:\n\n| Data type       | CRDT        | Resolution                   | Package                        |\n| --------------- | ----------- | ---------------------------- | ------------------------------ |\n| Rich text       | Yjs         | Character-level merge        | `@xnetjs/sync` (Yjs integration) |\n| Structured data | Lamport LWW | Field-level last-writer-wins | `@xnetjs/sync` (clock + change)  |\n\n### Why two strategies?\n\nRich text has complex structure — characters, paragraphs, formatting ranges, embedded objects. A general-purpose LWW register would lose edits when two users type in the same paragraph. Yjs solves this by tracking every character's position and identity in a sequence CRDT.\n\nStructured data (title, status, assignee) doesn't need character-level merging. A simple last-writer-wins strategy at the field level is sufficient and much simpler to implement and reason about.\n\n## Yjs for rich text\n\n[Yjs](https://yjs.dev) is a high-performance CRDT implementation for collaborative editing. xNet uses Yjs to sync editor content:\n\n- Each node's rich text is stored in a `Y.Doc` containing a `Y.XmlFragment`\n- Yjs tracks every character with a unique ID (clientID + sequence number)\n- Concurrent inserts at the same position are ordered deterministically by clientID\n- Deletions are tombstoned (marked as deleted but kept for merge correctness)\n\n### How merging works\n\n**Two users typing in different paragraphs** — edits are independent, merge trivially.\n\n**Two users typing at the same cursor position** — Yjs uses internal ordering rules (based on clientID, which is bound to a DID in xNet) to produce a deterministic interleaving. Both users see the same final text.\n\n**One user deletes text while another edits nearby** — Yjs preserves the edit. In general, inserts survive concurrent deletes.\n\nYou don't need to handle any of this manually. The TipTap editor integration applies Yjs updates automatically.\n\n## Lamport clocks for structured data\n\nFor node properties (title, status, priority, etc.), xNet uses Lamport clocks with field-level last-writer-wins:\n\n```ts\ninterface LamportTimestamp {\n  time: number // Logical clock value\n  author: DID // Tie-breaker\n}\n```\n\n### How it works\n\n1. Each peer maintains a logical clock that starts at 0\n2. On every mutation, the clock increments by 1 and the timestamp is attached to the change\n3. When receiving a remote change, the local clock fast-forwards to `max(local, remote)`\n4. On conflict (two changes to the same field), the one with the **higher** Lamport time wins\n5. If times are equal (rare), the DID string is compared lexicographically as a deterministic tie-breaker\n\n### Field-level resolution\n\nLWW is applied per-field, not per-node. If Alice changes `title` while Bob changes `status`, both changes are preserved — there's no conflict because they modified different fields.\n\n```\nAlice: { title: \"New title\" }  @ time=5\nBob:   { status: \"done\" }     @ time=5\nResult: { title: \"New title\", status: \"done\" }  ← both win\n```\n\nIf both change the same field:\n\n```\nAlice: { title: \"Alice's title\" }  @ time=5, did:key:alice\nBob:   { title: \"Bob's title\" }    @ time=5, did:key:bob\nResult: { title: \"Bob's title\" }   ← Bob wins (DID tie-breaker)\n```\n\n## Hash chains\n\nChanges are linked into a hash chain via `parentHash`. This provides:\n\n- **Causality** — you can trace the full history of a node\n- **Integrity** — tampering with a change breaks the chain\n- **Fork detection** — two changes with the same parent indicate concurrent edits\n\nForks are valid — they represent concurrent modifications, not errors. The LWW resolver picks the winning value for each field deterministically.\n\n## Convergence guarantee\n\nBoth CRDT strategies guarantee **strong eventual consistency**: if two peers have received the same set of changes (in any order), they will have the same state. This is a mathematical property of the algorithms, not a best-effort heuristic.\n\nThe practical implication is that xNet never shows merge conflict dialogs. The system always converges automatically.\n\n## Further reading\n\n- [Sync Guide](/docs/guides/sync/) — How to configure and debug sync\n- [Sync Architecture](/docs/concepts/sync-architecture/) — The full sync stack\n- [Collaboration Guide](/docs/guides/collaboration/) — Building collaborative editors","src/content/docs/docs/concepts/crdts.mdx","75e319c8fa368870","docs/concepts/cryptography",{id:83,data:85,body:92,filePath:93,digest:94,deferredRender:16},{title:86,description:87,editUrl:16,head:88,template:18,sidebar:89,pagefind:16,draft:21},"Cryptography","Hybrid classical + post-quantum cryptography: BLAKE3, Ed25519, ML-DSA-65, XChaCha20, and the three-level security model.",[],{order:90,hidden:21,attrs:91},5,{},"## Overview\n\nxNet uses a **hybrid classical + post-quantum** cryptographic stack, hardened against both current threats and future quantum attacks. NIST finalized the post-quantum standards in August 2024 (FIPS 203/204/205). Since xNet is prerelease software, hybrid security ships as a clean implementation — no migration debt.\n\n| Algorithm          | Role                     | Standard      | Package               |\n| ------------------ | ------------------------ | ------------- | --------------------- |\n| BLAKE3             | Hashing                  | —             | `@noble/hashes`       |\n| Ed25519            | Classical signing        | RFC 8037      | `@noble/curves`       |\n| ML-DSA-65          | Post-quantum signing     | NIST FIPS 204 | `@noble/post-quantum` |\n| X25519             | Classical key exchange   | RFC 7748      | `@noble/curves`       |\n| ML-KEM-768         | Post-quantum KEM         | NIST FIPS 203 | `@noble/post-quantum` |\n| XChaCha20-Poly1305 | Authenticated encryption | —             | `@noble/ciphers`      |\n\nAll implementations are from the `@noble` library family — audited, pure TypeScript, no WASM, no native dependencies.\n\n## Three security levels\n\nEvery signed operation in xNet carries a `SecurityLevel` field. The three levels cover the full quantum threat spectrum:\n\n| Level | Name             | Algorithms          | Signature size | Threat protection      |\n| ----- | ---------------- | ------------------- | -------------- | ---------------------- |\n| 0     | Fast             | Ed25519 only        | 64 bytes       | Classical attacks      |\n| 1     | Hybrid (default) | Ed25519 + ML-DSA-65 | ~3.4 KB        | Classical + quantum    |\n| 2     | Post-Quantum     | ML-DSA-65 only      | ~3.3 KB        | Quantum (max security) |\n\n**Level 1 is the default.** Both signatures must verify (strict mode) — if either the Ed25519 or the ML-DSA component fails, the signature is rejected. This satisfies the NIST-recommended hybrid approach: if either algorithm is later broken, the other still provides protection.\n\nLevel 0 is available for high-frequency, low-latency paths (e.g., per-keystroke Yjs updates) where the quantum threat model is low-risk. Switching the app-wide default is a single constant change.\n\n### Signature structure\n\nA `UnifiedSignature` carries one or both signature components, plus the level tag:\n\n```ts\ninterface UnifiedSignature {\n  level: 0 | 1 | 2\n\n  // Present at Level 0 and 1\n  ed25519?: Uint8Array // 64 bytes\n\n  // Present at Level 1 and 2\n  mlDsa?: Uint8Array // ~3,293 bytes\n}\n```\n\n### Signing and verifying\n\n```ts\nimport { hybridSign, hybridVerify } from '@xnetjs/crypto'\n\n// Sign at Level 1 (default) — requires both keys\nconst signature = hybridSign(message, {\n  ed25519: signingKey,\n  mlDsa: pqSigningKey\n})\n// { level: 1, ed25519: Uint8Array(64), mlDsa: Uint8Array(3293) }\n\n// Verify — returns structured result\nconst result = hybridVerify(message, signature, {\n  ed25519: publicKey,\n  mlDsa: pqPublicKey\n})\n// { valid: true, level: 1, details: { ed25519: { verified: true }, mlDsa: { verified: true } } }\n\n// Enforce minimum level\nconst result = hybridVerify(message, signature, publicKeys, { minLevel: 1 })\n```\n\n### Threat model\n\n| Threat                    | Level 0    | Level 1   | Level 2   |\n| ------------------------- | ---------- | --------- | --------- |\n| Classical forgery         | Protected  | Protected | Protected |\n| Quantum forgery           | Vulnerable | Protected | Protected |\n| Harvest-now-decrypt-later | Vulnerable | Protected | Protected |\n| Downgrade attack          | N/A        | Blocked   | Blocked   |\n\nAt Level 1, both components must be compromised simultaneously to forge a signature — a property no currently known attack achieves.\n\n## BLAKE3\n\nBLAKE3 is used throughout xNet for content addressing and integrity:\n\n- **Change hashing** — Every `Change<T>` is content-addressed with `cid:blake3:<hex>`\n- **Yjs update signing** — The BLAKE3 hash of the update bytes is what gets signed\n- **Storage integrity** — Persisted Y.Doc state is BLAKE3-hashed to detect corruption\n- **ClientID attestation** — The attestation message is BLAKE3-hashed before signing\n\nBLAKE3 is 3–5x faster than SHA-256. SHA-256 is available as a fallback for external system interoperability.\n\n## Ed25519\n\nEd25519 is the classical signing algorithm:\n\n- Small keys (32-byte public, 32-byte private) and 64-byte signatures\n- Deterministic — same message + key always produces the same signature\n- The DID:key method spec uses Ed25519 as its primary key type\n\n### Birational conversion to X25519\n\nEd25519 keys serve dual duty. The same keypair, via birational curve conversion, yields X25519 keys for Diffie-Hellman key exchange — no additional key material required:\n\n```ts\nimport { edwardsToMontgomeryPub, edwardsToMontgomeryPriv } from '@noble/curves/ed25519'\n\nconst x25519Pub = edwardsToMontgomeryPub(ed25519Pub) // for key wrapping\nconst x25519Priv = edwardsToMontgomeryPriv(ed25519Priv) // for unwrapping\n```\n\nAny holder of a `did:key:` can have their X25519 key derived directly from their DID — no out-of-band key exchange.\n\n## ML-DSA-65 (Dilithium3)\n\nML-DSA-65 is xNet's post-quantum signing algorithm, standardized as NIST FIPS 204 (Module-Lattice Digital Signature Algorithm, formerly Dilithium3):\n\n| Property    | Value                 |\n| ----------- | --------------------- |\n| Public key  | 1,952 bytes           |\n| Private key | 4,032 bytes           |\n| Signature   | 3,293 bytes           |\n| Security    | ~128-bit post-quantum |\n\n### Performance\n\n| Operation | Ed25519 | ML-DSA-65 | Ratio      |\n| --------- | ------- | --------- | ---------- |\n| Sign      | ~0.1ms  | ~2.5ms    | 25× slower |\n| Verify    | ~0.2ms  | ~0.8ms    | 4× slower  |\n\nLevel 1 combined: ~2.6ms sign, ~1.0ms verify. Verification caching reduces repeated verifications by 90%+.\n\n## ML-KEM-768 (Kyber768)\n\nML-KEM-768 is the post-quantum key encapsulation mechanism used for hybrid key exchange in the authorization system, standardized as NIST FIPS 203:\n\n| Property      | Value       |\n| ------------- | ----------- |\n| Public key    | 1,184 bytes |\n| Private key   | 2,400 bytes |\n| Ciphertext    | 1,088 bytes |\n| Shared secret | 32 bytes    |\n\nUsed alongside X25519 for hybrid key wrapping: a content key is encapsulated with both X25519 and ML-KEM-768, so a peer must break both to recover it.\n\n## XChaCha20-Poly1305\n\nXChaCha20-Poly1305 is the authenticated encryption cipher:\n\n- **Per-node content encryption** — Every private node is encrypted before leaving the device\n- **Y.Doc state at rest** — Encrypted Yjs document state stored locally\n- **Key bundle storage** — Encrypting the user's private keys at rest\n\n### Why XChaCha20?\n\n- 24-byte nonce (vs. 12 for AES-GCM) — safe to use random nonces without collision risk\n- Constant-time by design (no timing side-channels)\n- Poly1305 authentication tag detects any tampering\n\n### Key wrapping (hybrid)\n\nContent keys are wrapped with X25519 + ML-KEM-768 in hybrid mode. An authorized recipient must have both classical and post-quantum private keys to unwrap:\n\n```\nAlice derives X25519 sharedSecret from her private key + Bob's Ed25519 DID\nAlice encapsulates with ML-KEM-768 → kem_ciphertext + kem_secret\nwrappedKey = XChaCha20(contentKey, hkdf(sharedSecret || kem_secret))\n```\n\n## Where crypto is used in xNet\n\n| Operation            | Hash                     | Signature                 | Encryption                       |\n| -------------------- | ------------------------ | ------------------------- | -------------------------------- |\n| Create/update node   | BLAKE3 (change hash)     | hybridSign (Level 1)      | XChaCha20 (per-node content key) |\n| Rich text edit       | BLAKE3 (update hash)     | hybridSign (configurable) | XChaCha20 (Y.Doc at rest)        |\n| Store Y.Doc state    | BLAKE3 (integrity check) | —                         | XChaCha20 (encrypted Yjs state)  |\n| ClientID attestation | BLAKE3 (message hash)    | Ed25519 (Level 0)         | —                                |\n| UCAN token           | —                        | hybridSign (Level 1)      | —                                |\n| Key storage          | —                        | —                         | XChaCha20 (encrypt bundle)       |\n| Grant nodes          | BLAKE3 (change hash)     | hybridSign (Level 1)      | XChaCha20 (per-node content key) |\n| Key wrapping         | HKDF-SHA256              | —                         | X25519 + ML-KEM-768 → XChaCha20  |\n\n## Security properties\n\n- **Authenticity** — Every change is signed. You can verify who made it.\n- **Integrity** — Hash chains detect tampering. Altering a change breaks the chain.\n- **Confidentiality** — Private data is encrypted end-to-end. No server sees plaintext.\n- **Non-repudiation** — Signatures prove authorship. The author cannot deny making a change.\n- **Quantum resistance** — Level 1 signatures require breaking both Ed25519 and ML-DSA-65 simultaneously.\n- **Harvest-now-decrypt-later protection** — Data encrypted today remains safe against future quantum computers.\n\n## Further reading\n\n- [Authorization Guide](/docs/guides/authorization/) — Encryption-first access control, key wrapping\n- [Identity & Keys Guide](/docs/guides/identity/) — HybridKeyBundle, PQ registry, key recovery\n- [Sync Guide](/docs/guides/sync/) — How hybrid signatures protect sync","src/content/docs/docs/concepts/cryptography.mdx","01801397092f6f68","docs/concepts/data-model",{id:95,data:97,body:103,filePath:104,digest:105,deferredRender:16},{title:98,description:99,editUrl:16,head:100,template:18,sidebar:101,pagefind:16,draft:21},"Data Model","Schemas, nodes, changes, and the NodeStore.",[],{order:20,hidden:21,attrs:102},{},"## Overview\n\nxNet's data model has three layers:\n\n1. **Schemas** — Define the shape of your data (property types, defaults, validation)\n2. **Nodes** — Individual data records conforming to a schema\n3. **Changes** — Signed, hash-chained mutations that form an audit trail\n\n## Schemas\n\nA schema declares the properties a node can have, using typed builder functions:\n\n```ts\nimport { defineSchema, text, number, checkbox, select, relation } from '@xnetjs/data'\n\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    priority: number({ default: 0 }),\n    done: checkbox({ default: false }),\n    status: select({ options: [{ id: 'todo', name: 'To Do' }] as const }),\n    project: relation({ target: 'xnet://my-app/Project@1.0.0' })\n  }\n})\n```\n\nEach builder returns a typed descriptor that encodes the value type, default, and cardinality. TypeScript infers the full type from the schema definition — no manual type annotations needed.\n\nxNet provides 15 property types:\n\n| Type                           | Value      | Notes                      |\n| ------------------------------ | ---------- | -------------------------- |\n| `text()`                       | `string`   | Plain text                 |\n| `number()`                     | `number`   | Numeric value              |\n| `checkbox()`                   | `boolean`  | True/false                 |\n| `date()`                       | `number`   | Unix timestamp             |\n| `select()`                     | `string`   | Single choice from options |\n| `multiSelect()`                | `string[]` | Multiple choices           |\n| `url()`                        | `string`   | URL string                 |\n| `email()`                      | `string`   | Email address              |\n| `phone()`                      | `string`   | Phone number               |\n| `relation()`                   | `string`   | Reference to another node  |\n| `relation({ multiple: true })` | `string[]` | Multiple references        |\n| `person()`                     | `string`   | Reference to a DID         |\n| `person({ multiple: true })`   | `string[]` | Multiple DID references    |\n| `file()`                       | `object`   | File attachment            |\n\nSee [Property Types](/docs/schemas/property-types/) for full details on each type.\n\n## Nodes\n\nA node is an instance of a schema. Every node has base fields that are managed automatically by the store — you never define or set these yourself:\n\n```ts\ninterface NodeBase {\n  id: string // Unique node ID (auto-generated)\n  schemaId: string // Schema identifier\n  createdAt: number // Set at creation time\n  updatedAt: number // Updated on every change\n  createdBy: string // Author DID\n  updatedBy: string // Last modifier's DID\n}\n```\n\nWhen you read a node via `useQuery` or `useNode`, you get a `FlatNode` — the base fields merged with the schema properties:\n\n```ts\n// FlatNode<TaskSchema>\n{\n  id: 'abc123',\n  schemaId: 'xnet://app/task@1.0.0',\n  createdAt: 1706000000,\n  updatedAt: 1706000100,\n  createdBy: 'did:key:z6Mk...',\n  title: 'Ship the feature',\n  priority: 1,\n  done: false,\n  status: 'doing',\n  project: 'project-456'\n}\n```\n\n## NodeStore\n\nThe `NodeStore` is the central data layer that manages CRUD operations and change tracking:\n\n- **Create** — `store.create(schema, properties)` → new node with signed change\n- **Read** — `store.get(id)` or `store.query(schema, filter)` → node(s)\n- **Update** — `store.update(id, changes)` → signed change with Lamport timestamp\n- **Delete** — `store.delete(id)` → soft delete with signed change\n\nEvery mutation creates a `Change<T>` record that is signed, hash-chained, and propagated to peers.\n\n## Change\\<T\\>\n\nThe `Change<T>` type is the fundamental unit of sync:\n\n```ts\ninterface Change<T> {\n  id: string // Unique change ID\n  type: string // e.g., 'create-task', 'update-task'\n  payload: T // The actual data\n  hash: ContentId // cid:blake3:... content-addressed\n  parentHash: ContentId | null // Previous change in the chain\n  authorDID: DID // Who made this change\n  signature: Uint8Array // Ed25519 over the hash\n  wallTime: number // Wall clock (display only)\n  lamport: LamportTimestamp // Causal ordering\n}\n```\n\nChanges form a hash chain — each change references its parent's hash. This creates a verifiable audit trail where:\n\n- **Tampering is detectable** — altering a change invalidates its hash and breaks the chain\n- **Authorship is provable** — every change is signed with Ed25519\n- **Ordering is deterministic** — Lamport timestamps provide causal ordering across peers\n\n## Batched mutations\n\nFor multi-node operations, use `useMutate().mutate(...)`:\n\n```ts\nawait mutate([\n  { type: 'create', schema: ProjectSchema, id: 'project-acme', data: { name: 'Acme' } },\n  { type: 'create', schema: TaskSchema, data: { title: 'Setup', project: 'project-acme' } },\n  { type: 'create', schema: TaskSchema, data: { title: 'Launch', project: 'project-acme' } }\n])\n```\n\nThe current `mutate()` API returns per-operation results and runs through the active data bridge.\n\n## Further reading\n\n- [defineSchema](/docs/schemas/defineschema/) — Schema definition API\n- [Property Types](/docs/schemas/property-types/) — All 15 property types\n- [Type Inference](/docs/schemas/type-inference/) — How TypeScript types flow from schemas to hooks\n- [Relations](/docs/schemas/relations/) — Linking nodes together","src/content/docs/docs/concepts/data-model.mdx","9252eac6a7230c51","docs/concepts/identity-model",{id:106,data:108,body:115,filePath:116,digest:117,deferredRender:16},{title:109,description:110,editUrl:16,head:111,template:18,sidebar:112,pagefind:16,draft:21},"Identity Model","DID:key, Ed25519, and UCAN tokens.",[],{order:113,hidden:21,attrs:114},4,{},"## Decentralized identity\n\nxNet uses **self-certifying identifiers** — your identity is derived from a cryptographic key pair, not assigned by a server. No registration, no email, no password. You generate a key pair and that's your identity.\n\n## DID:key\n\nEvery user is identified by a DID (Decentralized Identifier) in the `did:key` format:\n\n```\ndid:key:z6MkhaXgBZDvotDkL5257faiztiGiC2QtKLGpbnnEGta2doK\n```\n\nThis DID is derived from the user's Ed25519 public key:\n\n1. Take the 32-byte Ed25519 public key\n2. Prepend the multicodec prefix `0xed01` (Ed25519 identifier)\n3. Encode with base58btc (multibase prefix `z`)\n4. Prefix with `did:key:`\n\nThe public key is **embedded in the DID itself**. To verify a signature, you parse the DID to extract the key — no external resolver, blockchain, or directory service is needed.\n\n## Key pairs\n\nEach user has two key pairs:\n\n| Key            | Algorithm | Purpose                                |\n| -------------- | --------- | -------------------------------------- |\n| Signing key    | Ed25519   | Sign changes, UCAN tokens, Yjs updates |\n| Encryption key | X25519    | Key exchange, encrypt private data     |\n\nThe DID is derived from the signing public key. Both keys are bundled together as a `KeyBundle` and stored encrypted on the device.\n\n## UCAN authorization\n\nUCANs (User Controlled Authorization Networks) are self-signed capability tokens. They replace traditional API keys, OAuth tokens, and ACL systems with a decentralized model where any user can grant capabilities to any other user.\n\n### Token structure\n\n```ts\n{\n  iss: \"did:key:z6Mk...\",           // Issuer\n  aud: \"did:key:z6Mk...\",           // Audience (who can use this token)\n  exp: 1706003600,                   // Expiration (Unix seconds)\n  att: [                             // Capabilities granted\n    { with: \"xnet://doc/123\", can: \"write\" },\n    { with: \"xnet://doc/*\", can: \"read\" }\n  ],\n  prf: [],                           // Proof chain (parent tokens)\n  sig: Uint8Array                    // Ed25519 signature\n}\n```\n\n### Delegation\n\nUCANs support transitive delegation. Alice can grant Bob access, and Bob can delegate a subset of that access to Carol:\n\n```\nAlice → Bob: { with: \"xnet://doc/123\", can: \"write\" }\nBob → Carol: { with: \"xnet://doc/123\", can: \"read\" }  (proof: Alice's token)\n```\n\nEach token in the chain is self-verifying — you extract the issuer's public key from their DID and check the signature. No server lookup required.\n\n### Capability model\n\n- **Resources** are identified by URI: `xnet://doc/123`, `xnet://doc/*`, `*`\n- **Actions** are strings: `read`, `write`, `*` (wildcard)\n- Wildcards grant broad access; specific URIs grant narrow access\n\n## How identity flows through xNet\n\n1. **App startup** — Key bundle loaded from encrypted storage, identity provided via `XNetProvider`\n2. **Data mutations** — Every `mutate.create()` / `mutate.update()` signs a `Change<T>` with Ed25519\n3. **Rich text editing** — Yjs updates are signed as `SignedYjsEnvelope` before broadcast\n4. **Sync** — Remote peers verify all signatures before applying changes\n5. **ClientID binding** — Yjs clientIDs are cryptographically bound to DIDs via attestations\n\n## No accounts, no servers\n\nThe identity system has no concept of \"creating an account\" or \"logging in\" to a server. Identity is:\n\n- **Generated locally** — a random Ed25519 key pair\n- **Self-certifying** — the public key is the identity\n- **Portable** — export your key bundle and use it on any device\n- **Verifiable offline** — signatures can be checked without network access\n\n## Further reading\n\n- [Identity & Keys Guide](/docs/guides/identity/) — Practical API usage\n- [Cryptography](/docs/concepts/cryptography/) — The primitives behind identity\n- [Sync Guide](/docs/guides/sync/) — How signed updates propagate","src/content/docs/docs/concepts/identity-model.mdx","3dae3092989f7fe7","docs/concepts/local-first",{id:118,data:120,body:126,filePath:127,digest:128,deferredRender:16},{title:121,description:122,editUrl:16,head:123,template:18,sidebar:124,pagefind:16,draft:21},"Local-First","What local-first means and why it matters.",[],{order:55,hidden:21,attrs:125},{},"## What is local-first?\n\nLocal-first software stores data on the user's device as the primary copy. The network is used for synchronization, not access. This is the opposite of the traditional client-server model where data lives on a remote server and the client is a thin view layer.\n\n### The key principles\n\n1. **Data ownership** — Your data lives on your device. You can read, write, and delete it without permission from any server.\n2. **Offline by default** — The app works without a network connection. Queries are instant because they read from local storage, not a remote API.\n3. **Sync, not fetch** — When a network is available, peers exchange changes directly. There's no single server that all clients depend on.\n4. **No spinners** — Since data is local, reads are synchronous. The UI never shows a loading state for cached data.\n5. **Longevity** — If the company behind the software disappears, your data survives. It's in a local database you control.\n\n## How xNet implements this\n\nxNet stores all data in SQLite on the user's device. When you call `useQuery` or `useNode`, you're reading from a local database — not making a network request.\n\n```\nTraditional app:    Client → Server → Database → Server → Client\nxNet app:           Client → SQLite (done)\n```\n\nSync happens in the background via WebSocket connections to a signaling server, which relays messages between peers. The signaling server never stores your data — it only forwards encrypted messages.\n\n### The tradeoff\n\nLocal-first requires solving conflict resolution. When two users edit the same data offline and then reconnect, the system must merge their changes without data loss. xNet uses two strategies:\n\n- **Yjs CRDTs** for rich text — character-level merge, no conflicts possible\n- **Lamport clock LWW** for structured data — field-level last-writer-wins with deterministic tie-breaking\n\nThese are well-studied algorithms that guarantee all peers converge to the same state, regardless of the order they receive updates.\n\n## Why it matters\n\n### Performance\n\nReads from local SQLite take microseconds. Reads from a server take 50-500ms. Local-first apps feel instant because the data is already there.\n\n### Reliability\n\nThe app keeps working when the wifi drops, the server goes down, or the user is on a plane. Changes queue up locally and sync when connectivity returns.\n\n### Privacy\n\nData can be encrypted end-to-end because the server never needs to read it. xNet signs every change with Ed25519 and can encrypt data with XChaCha20-Poly1305 for private content.\n\n### User agency\n\nUsers own their data in a concrete sense — it's in a database on their device. They can export it, back it up, or move it to a different app. No vendor lock-in.\n\n## Further reading\n\n- [CRDTs](/docs/concepts/crdts/) — How conflict-free data types work\n- [Sync Architecture](/docs/concepts/sync-architecture/) — How xNet syncs peer-to-peer\n- [Offline Patterns](/docs/guides/offline/) — Building resilient offline UIs","src/content/docs/docs/concepts/local-first.mdx","bf90fd8c5e48469c","docs/concepts/network",{id:129,data:131,body:138,filePath:139,digest:140,deferredRender:16},{title:132,description:133,editUrl:16,head:134,template:18,sidebar:135,pagefind:16,draft:21},"Network & Transport","libp2p, WebRTC, and the network security stack.",[],{order:136,hidden:21,attrs:137},7,{},"## Overview\n\n`@xnetjs/network` handles getting data between peers. It sits below the sync layer — sync decides _what_ to send, network decides _how_ to get it there.\n\nThe package provides:\n\n- A libp2p node with WebRTC and WebSocket transports\n- A layered security stack (connection gating, rate limiting, peer scoring, auto-blocking)\n- A custom sync protocol over libp2p streams\n- A y-webrtc provider for real-time document sync\n\n## Transport stack\n\n```\n┌─────────────────────────────┐\n│  y-webrtc provider          │  Real-time document sync\n├─────────────────────────────┤\n│  Custom sync protocol       │  /xnet/sync/1.0.0\n├─────────────────────────────┤\n│  libp2p                     │  Peer management, DHT\n├─────────────────────────────┤\n│  WebRTC  ·  WebSocket  ·  Relay  │  Transports\n├─────────────────────────────┤\n│  Noise encryption  ·  Yamux mux  │  Security + multiplexing\n└─────────────────────────────┘\n```\n\n### Transports\n\n- **WebRTC** — Browser-to-browser peer connections via data channels\n- **WebSocket** — Signaling server connections, relay fallback\n- **Circuit Relay v2** — NAT traversal via relay nodes when direct P2P fails\n\n### Connection security\n\n- **Noise protocol** — Authenticated encryption for all connections\n- **Yamux** — Stream multiplexing over a single connection\n\n## Security stack\n\n```mermaid\nflowchart TD\n  A[\"Incoming connection\"] --> B[\"1. Connection Limits\\n(max connections, per-IP)\"]\n  B -->|allowed| C[\"2. Connection Gating\\n(denylist, allowlist)\"]\n  C -->|allowed| D[\"3. Rate Limiting\\n(token bucket per peer)\"]\n  D -->|allowed| E[\"4. Peer Scoring\\n(reputation: -100 to +100)\"]\n  E -->|above threshold| F[\"5. Auto-Blocking\\n(ban on repeated violations)\"]\n  F -->|passed| G[\"Process message\"]\n\n  B -->|denied| X[\"Reject\"]\n  C -->|denied| X\n  D -->|exceeded| X\n  E -->|below threshold| X\n  F -->|blocked| X\n```\n\nFive layers of defense, each operating independently:\n\n### 1. Connection limits\n\nThe `ConnectionTracker` enforces hard limits:\n\n| Limit                  | Default | Strict | Relaxed |\n| ---------------------- | ------- | ------ | ------- |\n| Max connections        | 100     | 50     | 200     |\n| Per peer               | 2       | 1      | 4       |\n| Per IP                 | 5       | 3      | 10      |\n| Max pending            | 20      | 10     | 50      |\n| Streams per connection | 100     | 50     | 200     |\n| Connections per minute | 30      | 15     | 60      |\n\nThree presets: `DEFAULT_LIMITS`, `STRICT_LIMITS` (mobile/constrained), `RELAXED_LIMITS` (trusted network).\n\n### 2. Connection gating\n\nThe `DefaultConnectionGater` intercepts connections at four points:\n\n1. **Before accepting** — Check IP denylist\n2. **Before dialing** — Check peer denylist\n3. **After handshake** — Check limits, denylist, allowlist bypass\n4. **Before stream** — Check stream limits\n\nAllowlisted peers bypass all connection limits.\n\n### 3. Rate limiting\n\nToken bucket rate limiting at two levels:\n\n**Per-peer sync rate:**\n\n```ts\nconst limiter = new SyncRateLimiter() // 10 tokens/sec, 50 capacity\nlimiter.canSync(peerId) // consume 1 token\nlimiter.penalize(peerId, 'major') // reduce rate to 0.5x\nlimiter.restore(peerId) // reset to default\n```\n\n**Per-protocol rate:**\n\n| Protocol              | Rate   | Capacity |\n| --------------------- | ------ | -------- |\n| `/xnet/sync/1.0.0`    | 10/sec | 50       |\n| `/xnet/changes/1.0.0` | 20/sec | 100      |\n| `/xnet/query/1.0.0`   | 5/sec  | 20       |\n\nPenalized peers get dynamically reduced rates.\n\n### 4. Peer scoring\n\nReputation-based scoring inspired by GossipSub v1.1. Peers start at 0, range is -100 to +100:\n\n**Positive factors:**\n| Factor | Weight |\n|--------|--------|\n| Sync success | +0.5 |\n| Valid change | +0.1 |\n| Uptime (per minute) | +0.01 (cap +10) |\n| Low latency (\\<100ms) | +5 |\n\n**Negative factors:**\n| Factor | Weight |\n|--------|--------|\n| Sync failure | -2 |\n| Invalid signature | **-50** |\n| Invalid data | -10 |\n| Rate limit violation | -5 |\n\n**Thresholds:** warn at 0, throttle at -20, disconnect at -50. Scores decay by 1% per minute toward zero.\n\n### 5. Auto-blocking\n\nThe `AutoBlocker` bans peers that exceed event count thresholds:\n\n| Event               | Count | Window | Block Duration |\n| ------------------- | ----- | ------ | -------------- |\n| Invalid signature   | 3     | 60s    | **24 hours**   |\n| Rate limit exceeded | 10    | 60s    | 1 hour         |\n| Connection flood    | 20    | 60s    | 1 hour         |\n| Invalid data        | 5     | 5 min  | 12 hours       |\n\nBlocks auto-expire. The auto-blocker integrates with the peer scorer — when a peer's score drops below the disconnect threshold, it's automatically blocked for 1 hour.\n\n## Access control\n\n`PeerAccessControl` provides workspace-scoped access with this priority:\n\n```\nglobal deny > workspace deny > allowlist mode > default allow\n```\n\nWhen allowlist mode is enabled for a workspace, only explicitly allowlisted peers can sync. Deny entries support expiration.\n\n## Security logging\n\nAll security events are logged in a fail2ban-compatible format:\n\n```\n2026-02-04T12:00:00.000Z XNET_SECURITY: type=invalid_signature severity=high peer=a1b2c3d4 action=blocked\n```\n\nPeer IDs are hashed for privacy. Events route by severity: critical/high to `console.error`, medium to `console.warn`, low to `console.log`.\n\n## Custom sync protocol\n\nThe `/xnet/sync/1.0.0` protocol provides structured document sync over libp2p streams:\n\n1. Requester sends a `sync-request` with the local Yjs state vector\n2. Responder replies with a `sync-response` containing the diff\n3. Requester applies the update via `Y.applyUpdate()`\n\nMessages are serialized with msgpack and length-prefixed.\n\n## Further reading\n\n- [Sync Architecture](/docs/concepts/sync-architecture/) — How network fits into the sync stack\n- [Cryptography](/docs/concepts/cryptography/) — The primitives used for signing and verification\n- [Hub & Signaling](/docs/guides/hub/) — The signaling server that brokers connections","src/content/docs/docs/concepts/network.mdx","2253ec5bed70016d","docs/concepts/sync-architecture",{id:141,data:143,body:150,filePath:151,digest:152,deferredRender:16},{title:144,description:145,editUrl:16,head:146,template:18,sidebar:147,pagefind:16,draft:21},"Sync Architecture","How xNet syncs data peer-to-peer.",[],{order:148,hidden:21,attrs:149},6,{},"## Architecture overview\n\nxNet's sync system has four layers:\n\n```\n┌──────────────────────────────────────┐\n│  React hooks (useNode, useQuery)     │  Application layer\n├──────────────────────────────────────┤\n│  SyncManager                         │  Orchestration\n│  NodePool · Registry · OfflineQueue  │\n│  MetaBridge · BlobSync               │\n├──────────────────────────────────────┤\n│  Yjs security layer                  │  Security\n│  Envelopes · Rate limits · Scoring   │\n│  ClientID attestation · Batching     │\n├──────────────────────────────────────┤\n│  ConnectionManager                   │  Transport\n│  WebSocket (multiplexed, room-based) │\n└──────────────────────────────────────┘\n```\n\n## Transport layer\n\nA single multiplexed WebSocket connection handles all documents. Messages are routed by room (one room per document):\n\n- `subscribe(topics)` — join rooms\n- `publish(topic, data)` — broadcast to room\n- Auto-reconnect with configurable delay\n\nThis is O(1) connections regardless of how many documents are open — not O(N) per document.\n\n## Security layer\n\nEvery Yjs update is wrapped in a `SignedYjsEnvelope` before transmission:\n\n1. **BLAKE3 hash** the update bytes\n2. **Ed25519 sign** the hash\n3. Attach author DID, clientId, and timestamp\n\nOn the receiving side:\n\n1. **Rate limit check** — per-peer sliding window (30/sec, 600/min)\n2. **Size check** — max 1 MB per update, 50 MB per document\n3. **Signature verification** — extract public key from DID, verify Ed25519\n4. **ClientID validation** — check attestation binding (clientId → DID)\n5. **Peer scoring** — track violations, throttle/block bad peers\n\n### Peer scoring\n\nPeers start at score 100. Violations deduct points:\n\n- Invalid signature: **-30** (auto-block after 3 occurrences)\n- Unsigned update: **-20**\n- Unattested clientId: **-15**\n- Oversized update: **-10**\n- Rate exceeded: **-5**\n\nThresholds: warn at 50, throttle at 30, block at 10. Recovery: +1 per tick if clean for 60 seconds.\n\n### Update batching\n\nIndividual keystrokes produce ~5 Yjs updates per second. The `YjsBatcher` collects them and flushes every 2 seconds (or when the batch hits 50 updates). This reduces signing overhead from ~5/sec to ~0.5/sec without adding perceptible latency.\n\n## Orchestration layer\n\n### SyncManager\n\nThe top-level orchestrator that wires everything together:\n\n- **`start()`** — connect, load state, join rooms\n- **`acquire(nodeId)`** — get a Y.Doc for editing (used by `useNode`)\n- **`release(nodeId)`** — done editing; doc stays warm\n- **`track(nodeId)`** — add to background sync set\n- **`stop()`** — disconnect, flush, save state\n\n### NodePool\n\nManages Y.Doc instances in three tiers:\n\n| State  | Condition     | Behavior                                   |\n| ------ | ------------- | ------------------------------------------ |\n| Active | refCount > 0  | In use by a component. Never evicted.      |\n| Warm   | refCount = 0  | Released but cached. Evicted via LRU.      |\n| Cold   | Not in memory | Persisted in SQLite. Loaded on acquire. |\n\nDefault warm pool size: 50 documents.\n\n### Registry\n\nPersistent set of tracked nodes that survives app restarts. Tracked nodes sync in the background even when no component has them open. Entries expire after 7 days unless pinned.\n\n### OfflineQueue\n\nWhen disconnected, local updates queue up (max 1000 entries, persisted for crash resilience). On reconnect, the queue drains in order. The Yjs state-vector exchange after reconnect reconciles any gaps.\n\n### MetaBridge\n\nOne-way bridge from NodeStore properties to Y.Doc metadata. Prevents malicious Yjs updates from corrupting structured data. Property writes always go through the signed `Change<T>` pipeline.\n\n## Electron architecture\n\nIn Electron, sync is split across two processes:\n\n```\nRenderer (React UI)  ←— IPC / MessagePort —→  Main (BSM)  ←— WebSocket —→  Peers\n```\n\nThe **Background Sync Manager (BSM)** runs in the main process:\n\n- Manages its own Y.Doc pool and WebSocket connection\n- Signs outgoing updates, verifies incoming ones\n- Survives renderer crashes\n- Streams binary updates to renderer via MessagePort (zero-copy)\n\nThe renderer maintains mirror Y.Docs for editor binding. The `IPCSyncManager` implements the same `SyncManager` interface, so React hooks work identically on Electron and Web.\n\n## Data flow: an edit\n\n```mermaid\nsequenceDiagram\n  participant User as User (TipTap)\n  participant Renderer as Renderer Y.Doc\n  participant BSM as BSM (Main Process)\n  participant WS as WebSocket\n  participant Remote as Remote BSM\n  participant RemoteUI as Remote Renderer\n\n  User->>Renderer: Type in editor\n  Renderer->>BSM: MessagePort update\n  BSM->>BSM: Apply to Y.Doc copy\n  BSM->>BSM: Batch → BLAKE3 → Ed25519 sign\n  BSM->>WS: SignedYjsEnvelope\n  WS->>Remote: Broadcast to room\n  Remote->>Remote: Rate limit → Size check → Verify sig\n  Remote->>Remote: Apply to Y.Doc\n  Remote->>RemoteUI: MessagePort (origin: remote)\n  RemoteUI->>RemoteUI: Render merged text\n```\n\n1. User types in TipTap editor → local Y.Doc update in renderer\n2. Update forwarded to BSM via MessagePort\n3. BSM applies to its Y.Doc copy\n4. BSM batches, BLAKE3 hashes, Ed25519 signs → `SignedYjsEnvelope`\n5. Envelope broadcast via WebSocket to room subscribers\n6. Remote BSM receives: rate-limit check → size check → verify signature → apply\n7. Remote BSM forwards to its renderer → applied with `'remote'` origin\n8. Both renderers show the same text\n\n## Further reading\n\n- [Sync Guide](/docs/guides/sync/) — Configuration, debugging, and API\n- [CRDTs](/docs/concepts/crdts/) — How conflict-free merging works\n- [Cryptography](/docs/concepts/cryptography/) — The primitives behind signatures\n- [Electron Setup](/docs/guides/electron/) — The BSM architecture in detail","src/content/docs/docs/concepts/sync-architecture.mdx","9198645bd5fd4f86","docs/architecture/decisions",{id:153,data:155,body:161,filePath:162,digest:163,deferredRender:16},{title:156,description:157,editUrl:16,head:158,template:18,sidebar:159,pagefind:16,draft:21},"Architecture Decisions","Key design decisions and their rationale.",[],{order:78,hidden:21,attrs:160},{},"This is the canonical log of xNet's architectural decisions. It is the one place\nto answer \"why is it built this way?\" — superseding the older internal\n`docs/TRADEOFFS.md`.\n\n## How we keep this current\n\nThese records follow the standard [ADR](https://adr.github.io/) discipline:\n\n- Every entry has a **Status**: `Proposed`, `Accepted`, `Deprecated`, or\n  `Superseded by ADR-NN`.\n- **Accepted ADRs are immutable.** We don't rewrite a decision when reality\n  changes — we add a _new_ ADR that supersedes the old one and set the old\n  entry's status to `Superseded by ADR-NN`. The truth of the architecture is the\n  whole chain, not the latest entry. (Typo and dead-link fixes are the only\n  in-place edits.)\n- **If an implemented change alters an architectural invariant, it adds or\n  supersedes an ADR in the same PR.** Most decisions are worked out first in\n  `docs/explorations/`; this page is the distilled outcome.\n\n<details>\n<summary>ADR template</summary>\n\n```markdown\n## ADR-NN: <Short decision title>\n\n**Status:** Proposed | Accepted | Deprecated | Superseded by ADR-MM\n**Context:** <the exploration(s) or forces that drove this, e.g. 0212>\n\n**Decision:** <one sentence>\n\n**Rationale:**\n\n- <driver 1>\n- <driver 2>\n\n**Tradeoff:** <what we gave up, and the mitigation>\n```\n\n</details>\n\n---\n\n## ADR-1: Yjs over Automerge for rich text\n\n**Status:** Accepted (2026-02) · scope clarified by [ADR-11](#adr-11-xnet-is-a-protocol--the-interop-kernel-is-the-change-log-not-yjs)\n\n**Decision:** Use Yjs for rich text CRDT, not Automerge.\n\n**Rationale:**\n\n- Yjs has a larger ecosystem (TipTap, ProseMirror, CodeMirror, Monaco integrations)\n- Better performance for large documents (Yjs encodes more compactly)\n- Mature awareness protocol for cursor presence\n- Active maintenance and wide adoption\n\n**Tradeoff:** Yjs is a mutable data structure (not pure-functional like Automerge). We mitigate this with the MetaBridge pattern — Yjs never writes to the NodeStore directly.\n\n**Scope note:** Yjs is the **document codec** for the rich-text/canvas _body_ of\ncertain nodes — it is _not_ the sync backbone. Structured node data syncs through\nthe signed `Change<T>` log ([ADR-3](#adr-3-field-level-lww-for-structured-data)),\nand Yjs updates ride the wire as opaque bytes inside an XNet envelope. See\n[ADR-11](#adr-11-xnet-is-a-protocol--the-interop-kernel-is-the-change-log-not-yjs).\n\n## ADR-2: DID:key for identity\n\n**Status:** Accepted (2026-02)\n\n**Decision:** Use `did:key` (Ed25519) as the identity format.\n\n**Rationale:**\n\n- Self-certifying — the public key is embedded in the DID, so verification requires no external resolver\n- No blockchain, registry, or server dependency\n- Small identifiers (~56 characters)\n- Ed25519 is widely supported and audited\n\n**Tradeoff:** DIDs are not human-readable. Display names are stored as profile metadata, not in the identifier itself. Key rotation requires creating a new DID (though UCAN delegation can bridge old and new identities). Account recovery is handled by social recovery — see [ADR-24](#adr-24-social-recovery-via-shamir-guardians).\n\n## ADR-3: Field-level LWW for structured data\n\n**Status:** Accepted (2026-02) · this is normative protocol L1 — see [ADR-11](#adr-11-xnet-is-a-protocol--the-interop-kernel-is-the-change-log-not-yjs)\n\n**Decision:** Use Lamport clocks with field-level last-writer-wins for structured data, not a CRDT map.\n\n**Rationale:**\n\n- Simpler than a full CRDT for property data (titles, statuses, numbers)\n- Field-level granularity means non-conflicting fields always merge cleanly\n- Deterministic tie-breaking (DID comparison) ensures all peers converge\n- Lower overhead than maintaining CRDT metadata per field\n\n**Tradeoff:** True concurrent edits to the same field result in one write being silently dropped. In practice, this is acceptable for structured properties — users rarely edit the same title simultaneously. For rich text where character-level merging matters, Yjs handles it.\n\n## ADR-4: BLAKE3 over SHA-256\n\n**Status:** Accepted (2026-02) · post-quantum posture in [ADR-25](#adr-25-post-quantum-migration-posture)\n\n**Decision:** Use BLAKE3 as the primary hash function.\n\n**Rationale:**\n\n- 3-5x faster than SHA-256 on modern hardware\n- 256-bit output suitable for content addressing\n- Parallelizable (tree hashing) for large inputs\n- No length extension attacks\n\n**Tradeoff:** SHA-256 has wider interoperability (most external systems expect it). We provide SHA-256 as a fallback option in `@xnetjs/crypto` for interop cases.\n\n## ADR-5: Named exports only\n\n**Status:** Accepted (2026-02)\n\n**Decision:** No default exports anywhere in the codebase.\n\n**Rationale:**\n\n- Eliminates the \"what did I import?\" ambiguity\n- Better tree-shaking in bundlers\n- Consistent import style across the monorepo\n- Easier to search for usages (grep for the exact name)\n\n## ADR-6: Factory functions alongside classes\n\n**Status:** Accepted (2026-02)\n\n**Decision:** Export `createFoo()` factory functions alongside `class Foo`.\n\n**Rationale:**\n\n- Factory functions are easier to mock in tests\n- They can perform validation before construction\n- Consistent API surface (`createLamportClock`, `createExtensionContext`, `createLocalAPI`)\n- Classes are still available for `instanceof` checks when needed\n\n## ADR-7: Validation returns, not exceptions\n\n**Status:** Accepted (2026-02)\n\n**Decision:** Validation functions return `{ valid: boolean, errors: string[] }` instead of throwing.\n\n**Rationale:**\n\n- Callers can inspect and aggregate errors\n- No try-catch boilerplate for expected failures\n- Works well with UI form validation\n- Exceptions are reserved for programmer errors (missing arguments, broken invariants)\n\n## ADR-8: One-way MetaBridge\n\n**Status:** Accepted (2026-02) · MetaBridge now ships in `@xnetjs/runtime` — see [ADR-14](#adr-14-framework-agnostic-runtime--react-is-a-thin-binding)\n\n**Decision:** The MetaBridge syncs NodeStore → Y.Doc metadata, but not the reverse.\n\n**Rationale:**\n\n- Prevents malicious Yjs updates from poisoning structured data\n- Property changes always go through the signed `Change<T>` pipeline with verification\n- Yjs metadata map is read-only from the editor's perspective\n- Clear security boundary between the two CRDT systems\n\n**Tradeoff:** Two-way sync would be simpler to implement. The one-way bridge requires property writes to go through `mutate()` even when the data is displayed in the editor context.\n\n## ADR-9: Multiplexed WebSocket\n\n**Status:** Accepted (2026-02) · extended to multi-home routing in [ADR-20](#adr-20-namespace-scoped-multi-home-replication)\n\n**Decision:** Use a single WebSocket connection with room-based pub/sub, not one connection per document.\n\n**Rationale:**\n\n- O(1) connections regardless of document count\n- Reduces server-side resource usage\n- Simpler reconnection logic (one connection to restore)\n- Lower latency (no connection setup per document)\n\n**Tradeoff:** Requires a room routing layer on top of raw WebSocket. The signaling server must track topic subscriptions.\n\n## ADR-10: BSM in Electron main process\n\n**Status:** Accepted (2026-02)\n\n**Decision:** Run the sync engine in Electron's main process, not the renderer.\n\n**Rationale:**\n\n- Keeps the renderer responsive (BLAKE3 + Ed25519 are CPU-intensive)\n- Survives renderer crashes\n- Can sync in the background when no window is open\n- MessagePort provides zero-copy binary transfer between processes\n\n**Tradeoff:** IPC overhead for every document update. Mitigated by using `MessageChannelMain` for binary transfer and batching updates. (A migration from Electron to a Deno-based desktop shell has been explored but not adopted.)\n\n---\n\nThe decisions below were made after the initial ten were written, as the system\ngrew from an app into a protocol with a managed cloud. They are recorded here so\nthe log reflects the architecture as it actually stands.\n\n## ADR-11: XNet is a protocol — the interop kernel is the change log, not Yjs\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0200. The normative spec lives in `docs/specs/protocol/`; see also [The Protocol](/docs/protocol/overview/).\n\n**Decision:** Treat XNet as a versioned, multi-implementation **protocol** whose\nnormative surface is four layers — **L0** cryptographic primitives, **L1** data\nmodel, **L2** replication, **L3** authorization — with the application profile\n(**L4**) explicitly non-normative. The interop kernel is a **signed,\nhash-chained, per-property-LWW change log over schema-typed nodes**\n(`CURRENT_PROTOCOL_VERSION = 3` in `packages/sync/src/change.ts`). Yjs is a\n**pluggable document codec** for the rich-text/canvas body of certain nodes and\ntravels the wire as opaque bytes inside an XNet envelope.\n\n**Rationale:**\n\n- A second implementation, in any language over any database, can forward and\n  store the Yjs blob as an octet string and still fully participate in the node\n  graph, identity, authorization, and replication — the hardest local-first\n  portability problem (porting a CRDT byte format across languages) is off the\n  critical path.\n- The boundaries already existed in the layered package graph; this decision\n  writes them down and freezes them behind a conformance corpus.\n\n**Tradeoff:** Two merge systems (the LWW log and the Yjs CRDT) instead of one.\nAccepted deliberately — they have different conflict semantics and scale\nprofiles (see [ADR-1](#adr-1-yjs-over-automerge-for-rich-text) and\n[ADR-3](#adr-3-field-level-lww-for-structured-data)). This ADR clarifies ADR-1\nand elevates ADR-3 to normative status.\n\n## ADR-12: SQLite everywhere — better-sqlite3 + Litestream, not Turso/libSQL\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0178 (hosting economics) and 0212 (engine merits).\n\n**Decision:** Keep SQLite as the durable storage substrate across all five\nruntimes behind one adapter (`@xnetjs/sqlite`). On the web, persist via\n**OPFS + SQLite WASM** in a single serial worker; on the hub, use\n**better-sqlite3 with Litestream** streaming replication to Cloudflare R2\n(`packages/hub/src/storage/litestream.ts`). Do **not** migrate to libSQL or\nTurso Database.\n\n**Rationale:**\n\n- xNet barely uses SQLite as a relational database — the schema is an append-only,\n  signed, hash-chained change log with a denormalized scalar index; graph walks\n  and CRDT merges happen in TypeScript/Rust, not SQL. Most of Turso's advances\n  (query planner, relational concurrency) are low-leverage here.\n- The two features that _would_ tempt us (embedded vector ANN, concurrent\n  writes) live in two different Turso products, neither production-ready together\n  today; migrating would cost five platform adapters and an FTS5 rewrite.\n- FTS5 and R-Tree/GIS (which we _do_ use) are battle-tested on SQLite.\n\n**Tradeoff:** Single-writer serialization and no built-in vector index. Documented\nre-evaluation triggers (a production-ready engine with both ANN and MVCC, or a\nvector workload SQLite can't serve) would reopen this. A bounded Turso pilot on\nthe disposable `telemetry.db` is sanctioned as a probe.\n\n## ADR-13: Local-first — the hub is an accelerant, never a dependency\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0188. See also [Local-first](/docs/concepts/local-first/).\n\n**Decision:** The local device holds the master copy. Nothing on a hub or the\nnetwork may block a local read or first paint; hub work (relay, backup, search,\nsignaling) is fire-and-forget and strictly additive.\n\n**Rationale:**\n\n- Local-first is the product's core promise (own your data, work offline, exit\n  freely) — it must be an enforced invariant, not an aspiration.\n- A regression where hub room-subscription blocked document load caused\n  10–30s stalls; the fix (decouple local load from hub acquisition) codified the\n  rule.\n\n**Tradeoff:** Some cross-device features are eventually-consistent rather than\ninstantly authoritative. Accepted: correctness comes from the convergent LWW log,\nso \"eventually\" is safe.\n\n## ADR-14: Framework-agnostic runtime — React is a thin binding\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0185 and 0237.\n\n**Decision:** The full client — store, MetaBridge, SyncManager, NodePool,\nRegistry, OfflineQueue, ConnectionManager — lives in the React-free\n`@xnetjs/runtime` package. `createXNetClient()` and `liveQuery()` expose a\nuniversal `{ getSnapshot, subscribe }` contract. `@xnetjs/react` is a thin **T1**\nbinding (`useQuery`/`useMutate`/…) that re-exports the runtime. Support tiers:\n**T0** any framework/vanilla (the runtime, ships today), **T1** React\n(first-party), **T2** Vue/Svelte/Solid (demand-gated, ~40-line adapters).\n\n**Rationale:**\n\n- The reactive seam is tiny — only two files in `@xnetjs/react` touch\n  `useSyncExternalStore`; everything else is business logic and JSX.\n- Decoupling lets the runtime power CLIs, servers, and non-React apps without a\n  React dependency.\n\n**Tradeoff:** \"Support\" for a framework means feature parity, not just a data\nbinding — the ~30k LOC of `@xnetjs/react` is the real cost. So T2 adapters are\npublished only on demand, and only the data hooks (not `@xnetjs/ui`) are in scope.\n\n## ADR-15: Open-core license split — MIT core, FSL cloud, MIT-private contract\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0181.\n\n**Decision:** Publish the adoption engine (core packages) under **MIT**. License\nthe managed control plane, `@xnetjs/cloud`, under **FSL-1.1** (source-available,\nconverting to Apache-2.0 on its Change Date; `packages/cloud/LICENSE`). Keep the\nentitlement contract in a separate, permissively-licensed `@xnetjs/entitlements`\n(MIT, `private`) so the self-hostable MIT hub can verify a signed `HUB_PLAN`\ntoken without ever taking an FSL — or a Stripe/AWS — dependency.\n\n**Rationale:**\n\n- The hub must remain fully MIT and dependency-light; the cloud must be\n  protectable. The entitlement contract is the one seam both sides share.\n- FSL protects against a hyperscaler reselling the managed service while\n  guaranteeing eventual open-source (the Apache future license).\n\n**Tradeoff:** A three-package licensing story is more to explain than \"all MIT\" or\n\"all FSL.\" The `@xnetjs/hub` package deliberately has zero dependency on\n`@xnetjs/cloud`; that separation is by convention (and verified by the absence of\nthe import), not yet a lint rule.\n\n## ADR-16: Automated releases via Changesets + Conventional Commits\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0220.\n\n**Decision:** Version and publish with [Changesets](https://github.com/changesets/changesets).\nA `fixed` group of 12 core packages (`core`, `crypto`, `identity`, `sync`,\n`data`, `storage`, `sqlite`, `data-bridge`, `abuse`, `plugins`, `history`,\n`react`) versions in lockstep; periphery versions independently. Conventional\nCommits are enforced by commitlint; publishing uses npm Trusted Publishing (OIDC)\nwith provenance. Changeset coverage for publishable packages is enforced by a Stop\nhook (`scripts/changeset/assert-coverage.mjs`).\n\n**Rationale:**\n\n- The `fixed` core avoids a combinatorial version matrix across tightly-coupled\n  packages; independent periphery avoids forcing churn on loosely-coupled ones.\n- OIDC removes long-lived npm tokens from the repo.\n\n**Tradeoff:** The semver bump must be read from the _diff_, not the commit prefix\n(a removed export or changed wire contract is a major even under a `feat:`\ncommit). This requires discipline the hook can prompt for but not fully decide.\n\n## ADR-17: Plugin trust and capability model\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0189, 0192, 0194, 0196.\n\n**Decision:** Extensibility is governed by a shared trust fabric. `@xnetjs/trust`\nmaps install **provenance** (`builtin` / `authored` / `ai-generated` / `imported`\n/ `marketplace` / `synced`) to a **trust tier** and a **sandbox kind**\n(`host` / `ses-worker` / `iframe`). Capability endowments are enforced at the\nseam — `guardStore` gates data access, `guardedFetch` gates the network\n(SSRF-guarded) in `@xnetjs/plugins`. Paid plugins carry Ed25519, DID-bound\nlicense tokens (`@xnetjs/licenses`) with a **fail-closed** install gate.\n\n**Rationale:**\n\n- \"Everything is a plugin\" only works if untrusted code is contained by\n  construction; provenance is the natural axis for how much to trust.\n- Fail-closed licensing means a missing or invalid license blocks install, never\n  silently downgrades.\n\n**Tradeoff:** More ceremony for plugin authors (declared capabilities, sandbox\nconstraints) in exchange for a substrate that can safely run third-party and\nAI-generated code.\n\n## ADR-18: Managed AI via hub broker, plus bring-your-own local models\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0201, 0208, 0244, 0252.\n\n**Decision:** For managed AI, the client uses a **keyless** `ManagedProvider`\nthat POSTs to the hub's `/ai/chat` (+ `/ai/chat/stream` SSE); the hub injects\ntenant credentials, holds the OpenRouter key, and meters exact `usage.cost`\nserver-side (`packages/hub/src/features/ai-forwarder.ts`). In parallel, a\nbring-your-own path runs models **locally** — WebLLM in-browser and Chrome's\nbuilt-in \"Nano\" via an `availability()` probe (`packages/plugins/src/ai/`).\n\n**Rationale:**\n\n- Keyless managed AI means no provider key ever reaches the client; the hub is\n  the metering and margin-safety boundary.\n- Local models give a zero-cost, fully-private tier that needs no hub at all,\n  consistent with [ADR-13](#adr-13-local-first--the-hub-is-an-accelerant-never-a-dependency).\n\n**Tradeoff:** Two provider code paths to maintain, and local-model availability\nvaries by browser/hardware. Detection is capability-probed, not assumed.\n\n## ADR-19: Plan-first AI mutations\n\n**Status:** Accepted (2026-06)\n**Context:** `docs/AI_SURFACE_CONTRACT.md`.\n\n**Decision:** AI never writes directly. The shared AI surface expresses writes as\nan `AiMutationPlan` that must move through **validate → preview → apply → audit**.\nEvery tool declares `requiredScopes` and a risk level (`low`/`medium`/`high`/\n`critical`); plans are serializable JSON so they flow identically through MCP,\nthe Local API, file projection, and audit logs.\n\n**Rationale:**\n\n- A plan-first pipeline makes AI writes reviewable and reversible, and keeps one\n  contract across every adapter.\n- Risk levels + scopes let the UI gate high-consequence actions\n  (`storage.recovery` requires `critical`).\n\n**Tradeoff:** More indirection than letting an agent call `mutate()` directly, in\nexchange for auditable, user-approvable, rollback-friendly AI edits.\n\n## ADR-20: Namespace-scoped multi-home replication\n\n**Status:** Accepted (2026-06) · extends [ADR-9](#adr-9-multiplexed-websocket)\n**Context:** Exploration 0258.\n\n**Decision:** Sync routes selectively per **namespace**. A multiplexed multi-hub\nconnection manager (`packages/runtime/src/sync/connection-manager.ts`) maintains\none connection per hub; a replication-policy planner\n(`packages/sync/src/replication-policy.ts`) decides which namespaces replicate to\nwhich hubs/peers, with per-namespace `minHubs`/`maxHubs` and signed-replication\nrequirements. A user-facing **Space** maps to a namespace via `spaceNamespace()`,\ncarrying a `ReplicaTrust` of `trusted` or `zero-knowledge`\n(`packages/runtime/src/sync/replication-scope.ts`).\n\n**Rationale:**\n\n- Different data belongs in different homes (system vs personal vs community vs\n  peer); routing by namespace is the smallest primitive that expresses that.\n- Correctness is free — the multi-master LWW log already converges regardless of\n  topology; this decision is about _where_ bytes go, not _whether_ they merge.\n\n**Tradeoff:** Only the routing slice is shipped; the manifest schema, device DID,\nanti-entropy, trust gating, and UI are deferred. The planner exists ahead of full\nconsumption.\n\n## ADR-21: Append-only change log with off-boot compaction\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0204, 0254, 0260.\n\n**Decision:** Never delete from the change log; append tombstones and materialize\ncurrent state. Reclaim space with **compaction that runs off the boot path** —\ngated behind `runWhenBootSettled` (resolves at first-rows), using tiny\nloop-until-dry chunks that bail on a hidden tab\n(`apps/web/src/lib/change-log-compaction.ts`). The web runtime funnels all SQLite\nwork through one serial worker with a priority scheduler.\n\n**Rationale:**\n\n- The append-only log makes sync trivial and gives a complete audit trail; but an\n  unbounded log inflates cold-start.\n- On a single serial SQLite worker, **no background work is free during boot** —\n  `requestIdleCallback` tracks main-thread idle, which is idle precisely while the\n  worker is saturated. Scheduling maintenance _after_ boot settles is the only\n  reliable fix; priority reorders work, it never parallelizes it.\n\n**Tradeoff:** Reclamation is deferred rather than immediate, and compaction is\nbest-effort (bails on backgrounded tabs). Accepted: a responsive cold open\noutranks prompt disk reclaim. Compaction stays default-on, opt-out via\n`xnet:compact:changes='off'`.\n\n## ADR-22: Consent-gated observability\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0210.\n\n**Decision:** Zero telemetry by default. Error monitoring (Sentry) and analytics\n(Plausible) initialize only when _both_ a build-time endpoint is configured\n(`VITE_SENTRY_DSN` / `VITE_ANALYTICS_DOMAIN`) _and_ the runtime consent tier\nallows it (`packages/telemetry/src/consent/manager.ts`;\n`apps/web/src/lib/{sentry,analytics,error-reporter}.ts`). Reports are scrubbed and\nvalues are P3A-bucketed.\n\n**Rationale:**\n\n- Decentralized, own-your-data software must not phone home without explicit,\n  granular consent; gating at both build and runtime makes \"off\" the safe default.\n\n**Tradeoff:** Far less diagnostic data (users rarely opt in), so we lean on\nreproducible boot timelines and local forensics instead of always-on telemetry.\n\n## ADR-23: Values-as-code CI gates\n\n**Status:** Accepted (2026-06)\n**Context:** Explorations 0199 (motion) and 0234 (humane charter).\n\n**Decision:** Encode the product's values as enforced lints, not just prose. A\nmotion-vocabulary gate (`scripts/check-motion-vocab.mjs`) bans ad-hoc animation\noutside the approved vocabulary; a humane-patterns gate\n(`scripts/check-humane-patterns.mjs`) bans dark patterns (infinite scroll,\nstreaks, engagement-maximizing nudges). Both sit alongside the Humane Internet\nCharter (`docs/CHARTER.md`) and a real \"Right to Leave\" export-everything panel.\n\n**Rationale:**\n\n- A stated value that CI can't defend drifts. Mechanizing \"calm\" and \"no dark\n  patterns\" makes them regression-proof and legible to skeptics.\n\n**Tradeoff:** Some legitimate UI needs a documented exception path around the\ngates. Accepted: the friction is the point — it forces the intent to be explicit.\n\n## ADR-24: Social recovery via Shamir guardians\n\n**Status:** Accepted (2026-06)\n**Context:** Exploration 0243.\n\n**Decision:** Recover an identity through **Shamir-split guardian shares**\n(`packages/identity/src/recoverable.ts`) — a threshold of trusted guardians\nreconstructs the key — alongside recovery phrases and synced passkeys. The cloud\nis never a custodian. Custodial escrow was explicitly **declined**.\n\n**Rationale:**\n\n- `did:key` has no built-in rotation ([ADR-2](#adr-2-didkey-for-identity)), so\n  recovery must live outside the key itself.\n- Custodial escrow is coercible (subpoena, insider, breach); social recovery\n  keeps trust distributed and cloud-free.\n\n**Tradeoff:** Recovery depends on the user having designated reachable guardians\nahead of time. Accepted as the price of a non-coercible, self-sovereign model.\n\n## ADR-25: Post-quantum migration posture\n\n**Status:** Proposed\n**Context:** Exploration 0257; the future path for [ADR-4](#adr-4-blake3-over-sha-256) and [ADR-2](#adr-2-didkey-for-identity).\n\n**Decision (proposed):** Adopt a phased migration to post-quantum signatures —\nPhase 2 hybrid (Ed25519 + ML-DSA), Phase 3 ML-DSA primary with Ed25519 legacy —\nbehind an algorithm-agility seam, rather than a flag-day switch.\n\n**Rationale:**\n\n- Ed25519 is broken by Shor's algorithm; a hash-chained, signed log needs a\n  credible PQ story before it's a compliance blocker.\n- Hybrid signatures preserve interop during the transition.\n\n**Tradeoff / open:** Larger signatures and a two-algorithm verification path. This\nis a documented _posture_, not shipped code — it stays `Proposed` until the seam\nand hybrid signing land, at which point it is superseded by an `Accepted` ADR.","src/content/docs/docs/architecture/decisions.mdx","f6afc64ba67eabf0","docs/architecture/overview",{id:164,data:166,body:172,filePath:173,digest:174,deferredRender:16},{title:167,description:168,editUrl:16,head:169,template:18,sidebar:170,pagefind:16,draft:21},"Architecture Overview","How xNet's packages fit together.",[],{order:55,hidden:21,attrs:171},{},"## Layered architecture\n\nxNet is organized as a layered stack where each package builds on the ones below it. Lower packages never import from higher ones.\n\n```\n┌─────────────────────────────────────────┐\n│  apps/electron  ·  apps/web             │  Applications\n├─────────────────────────────────────────┤\n│  @xnetjs/react                            │  React bindings (thin)\n│  useQuery · useMutate · useNode         │\n│  useIdentity · XNetProvider             │\n├─────────────────────────────────────────┤\n│  @xnetjs/runtime                          │  Framework-agnostic client\n│  createXNetClient · liveQuery           │\n│  SyncManager · NodePool · MetaBridge    │\n├─────────────────────────────────────────┤\n│  @xnetjs/data                             │  Data layer\n│  defineSchema · NodeStore               │\n│  15 property types · validation         │\n├─────────────────────────────────────────┤\n│  @xnetjs/sync                             │  Sync primitives\n│  Lamport clocks · Change<T> · chains    │\n│  Yjs security · envelopes · scoring     │\n├─────────────────────────────────────────┤\n│  @xnetjs/storage                          │  Persistence\n│  SQLite adapter                        │\n├─────────────────────────────────────────┤\n│  @xnetjs/identity                         │  Identity\n│  DID:key · UCAN · key management        │\n├─────────────────────────────────────────┤\n│  @xnetjs/crypto                           │  Cryptography\n│  BLAKE3 · Ed25519 · XChaCha20           │\n└─────────────────────────────────────────┘\n```\n\n## Additional packages\n\n| Package          | Purpose                                                             |\n| ---------------- | ------------------------------------------------------------------- |\n| `@xnetjs/plugins`  | 4-layer plugin system (scripts, extensions, services, integrations) |\n| `@xnetjs/canvas`   | Infinite canvas with spatial indexing                               |\n| `@xnetjs/editor`   | TipTap rich text editor with Yjs collaboration                      |\n| `@xnetjs/network`  | libp2p node, WebRTC/WebSocket transport, peer security              |\n| `@xnetjs/devtools` | 7 debug panels for inspecting sync, store, schema, and more         |\n\n## Design principles\n\n**Minimal coupling** — Each package has a focused responsibility. The crypto package knows nothing about schemas. The data package knows nothing about React.\n\n**No default exports** — Everything is a named export. Barrel files (`index.ts`) re-export from internal modules.\n\n**Factory functions** — Classes are paired with factory functions (`createFoo()` alongside `class Foo`). This keeps the API surface consistent and makes testing easier.\n\n**Immutability** — Core types like `LamportTimestamp` and `Change<T>` are treated as immutable. Functions return new objects instead of mutating in place.\n\n**Validation over exceptions** — Functions return `{ valid: boolean, errors: [] }` objects instead of throwing. Exceptions are reserved for programmer errors, not data validation.\n\n## How data flows\n\n### Write path\n\n```mermaid\nflowchart LR\n  A[\"User action\"] --> B[\"useMutate()\"]\n  B --> C[\"NodeStore.update()\"]\n  C --> D[\"Change‹T› + Lamport\"]\n  D --> E[\"BLAKE3 hash\"]\n  E --> F[\"Ed25519 sign\"]\n  F --> G[\"Hash chain link\"]\n  G --> H[\"SQLite\"]\n  G --> I[\"SyncManager\"]\n```\n\n### Read path\n\n```mermaid\nflowchart LR\n  A[\"useQuery(schema, filter)\"] --> B[\"NodeStore.query()\"]\n  B --> C[\"SQLite read\"]\n  C --> D[\"FlatNode[]\"]\n  D --> E[\"Component render\"]\n  B -.->|subscribe| F[\"Change events\"]\n  F -.->|re-render| E\n```\n\n### Sync path\n\nThe interop kernel is the signed `Change<T>` log — **not** Yjs. Structured node\ndata replicates as signed changes; Yjs is a document codec whose updates ride the\nsame wire as opaque, signed bytes. See\n[ADR-11](/docs/architecture/decisions/#adr-11-xnet-is-a-protocol--the-interop-kernel-is-the-change-log-not-yjs).\n\n```mermaid\nflowchart LR\n  A[\"mutate()\"] --> B[\"Change‹T› + Lamport\"]\n  B --> C[\"BLAKE3 hash · Ed25519 sign · chain\"]\n  C --> D[\"SyncManager\\n(@xnetjs/runtime)\"]\n  D --> E[\"Multi-hub\\nConnectionManager\"]\n  E --> F[\"Hub relay → peers\"]\n  F --> G[\"Verify signature\\n+ rate limit\"]\n  G --> H[\"Apply to change log\"]\n  A -. \"rich-text / canvas nodes\" .-> Y[\"Y.Doc → YjsBatcher\\n→ signed envelope\"]\n  Y -. \"opaque bytes\" .-> D\n```\n\n## Further reading\n\n- [Package Graph](/docs/architecture/package-graph/) — The full dependency graph\n- [Architecture Decisions](/docs/architecture/decisions/) — Why we made these choices","src/content/docs/docs/architecture/overview.mdx","c281c69c1660e4dc","docs/architecture/package-graph",{id:175,data:177,body:183,filePath:184,digest:185,deferredRender:16},{title:178,description:179,editUrl:16,head:180,template:18,sidebar:181,pagefind:16,draft:21},"Package Graph","The dependency graph of xNet packages.",[],{order:20,hidden:21,attrs:182},{},"## Dependency graph\n\nThe workspace holds **30 packages**. The diagram shows the core chain and the\nmajor feature packages; lower packages cannot import from higher ones:\n\n```mermaid\ngraph BT\n  crypto[\"@xnetjs/crypto\"]\n  identity[\"@xnetjs/identity\"]\n  storage[\"@xnetjs/storage\"]\n  sync[\"@xnetjs/sync\"]\n  data[\"@xnetjs/data\"]\n  runtime[\"@xnetjs/runtime\"]\n  react[\"@xnetjs/react\"]\n  network[\"@xnetjs/network\"]\n  plugins[\"@xnetjs/plugins\"]\n  editor[\"@xnetjs/editor\"]\n  canvas[\"@xnetjs/canvas\"]\n  devtools[\"@xnetjs/devtools\"]\n  ui[\"@xnetjs/ui\"]\n  query[\"@xnetjs/query\"]\n  views[\"@xnetjs/views\"]\n  comms[\"@xnetjs/comms\"]\n  charts[\"@xnetjs/charts\"]\n  dashboard[\"@xnetjs/dashboard\"]\n  cli[\"@xnetjs/cli\"]\n  hub[\"@xnetjs/hub\"]\n\n  identity --> crypto\n  storage --> identity\n  sync --> crypto\n  sync --> identity\n  data --> sync\n  data --> crypto\n  network --> sync\n  network --> crypto\n  runtime --> data\n  runtime --> sync\n  runtime --> storage\n  react --> runtime\n  plugins --> data\n  editor --> |Yjs| sync\n  canvas --> data\n  devtools --> react\n  query --> data\n  query --> storage\n  views --> react\n  views --> ui\n  comms --> data\n  comms --> crypto\n  dashboard --> react\n  dashboard --> charts\n  dashboard --> plugins\n  cli --> plugins\n  cli --> data\n  hub --> sync\n  hub --> data\n\n  style crypto fill:#4f46e5,color:#fff,stroke:#6366f1\n  style identity fill:#4f46e5,color:#fff,stroke:#6366f1\n  style storage fill:#4f46e5,color:#fff,stroke:#6366f1\n  style sync fill:#4f46e5,color:#fff,stroke:#6366f1\n  style data fill:#4f46e5,color:#fff,stroke:#6366f1\n  style runtime fill:#4f46e5,color:#fff,stroke:#6366f1\n  style react fill:#4f46e5,color:#fff,stroke:#6366f1\n  style network fill:#6366f1,color:#fff,stroke:#818cf8\n  style plugins fill:#6366f1,color:#fff,stroke:#818cf8\n  style editor fill:#6366f1,color:#fff,stroke:#818cf8\n  style canvas fill:#6366f1,color:#fff,stroke:#818cf8\n  style devtools fill:#6366f1,color:#fff,stroke:#818cf8\n  style ui fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style query fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style views fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style comms fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style charts fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style dashboard fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style cli fill:#818cf8,color:#fff,stroke:#a5b4fc\n  style hub fill:#818cf8,color:#fff,stroke:#a5b4fc\n```\n\n## Package details\n\n### @xnetjs/crypto\n\n**Dependencies:** `@noble/hashes`, `@noble/curves`, `@noble/ciphers`\n\nThe foundation. Provides BLAKE3 hashing, Ed25519 signing, XChaCha20-Poly1305 encryption, X25519 key exchange, and encoding utilities. No xNet dependencies.\n\n### @xnetjs/identity\n\n**Dependencies:** `@xnetjs/crypto`\n\nDID:key creation and parsing, Ed25519/X25519 key bundle management, UCAN token creation and verification, passkey storage.\n\n### @xnetjs/storage\n\n**Dependencies:** `@xnetjs/identity`\n\nSQLite adapter for persisting Y.Doc state, node properties, offline queue entries, and registry data across web (OPFS), desktop, and mobile.\n\n### @xnetjs/sync\n\n**Dependencies:** `@xnetjs/crypto`, `@xnetjs/identity`\n\nCore sync primitives: Lamport clocks, `Change<T>` type, hash chains, Yjs security layer (signed envelopes, rate limiting, peer scoring, clientID attestation, update batching, integrity checking).\n\n### @xnetjs/data\n\n**Dependencies:** `@xnetjs/sync`, `@xnetjs/crypto`\n\nSchema system (`defineSchema`, 15 property types), NodeStore (CRUD + change tracking), type inference (`FlatNode`, `InferCreateProps`), validation and coercion.\n\n### @xnetjs/runtime\n\n**Dependencies:** `@xnetjs/data`, `@xnetjs/sync`, `@xnetjs/storage`\n\nThe framework-agnostic client. `createXNetClient()` assembles the store, MetaBridge, SyncManager, NodePool, Registry, OfflineQueue, and the multi-hub ConnectionManager; `liveQuery()` exposes the universal `{ getSnapshot, subscribe }` store contract. No React dependency — it powers React, other frameworks, CLIs, and servers alike. See [ADR-14](/docs/architecture/decisions/#adr-14-framework-agnostic-runtime--react-is-a-thin-binding).\n\n### @xnetjs/react\n\n**Dependencies:** `@xnetjs/runtime`, `react`\n\nThe thin React binding: `useQuery`, `useMutate`, `useNode`, `useIdentity`, `XNetProvider`, and the plugin hooks. The sync engine itself lives in `@xnetjs/runtime`; this package re-exports it and adapts it to React via `useSyncExternalStore`.\n\n### @xnetjs/network\n\n**Dependencies:** `@xnetjs/sync`, `@xnetjs/crypto`\n\nlibp2p node setup, WebRTC and WebSocket transport, connection gating, peer scoring (GossipSub-inspired), auto-blocking, rate limiting at the connection level.\n\n### @xnetjs/plugins\n\n**Dependencies:** `@xnetjs/data`, `acorn`\n\nPlugin system: extension manifest, registry, context, 9 contribution types, middleware chain, script sandbox (AST validation, frozen context, timeout), AI script generation, services (ProcessManager, ServiceClient), integrations (LocalAPI, MCPServer, WebhookEmitter), shortcut manager.\n\n### @xnetjs/editor\n\n**Dependencies:** `@tiptap/core`, Yjs\n\nTipTap editor wrapper with Yjs collaboration, custom extensions (Mermaid, etc.), slash command support.\n\n### @xnetjs/canvas\n\n**Dependencies:** `@xnetjs/data`\n\nInfinite canvas with spatial indexing (R-tree), viewport management, zoom/pan, node positioning.\n\n### @xnetjs/devtools\n\n**Dependencies:** `@xnetjs/react`\n\n10 debug panels: Nodes, Changes, Sync, Yjs, Queries, Telemetry, Schemas, Seed, History, and AuthZ. See the [DevTools guide](/docs/guides/devtools/).\n\n### @xnetjs/ui\n\nShared design system: the monochrome token ramp (`surface`/`ink`/`hairline`), primitives, the shared task editor, and the unified drag payload. No xNet runtime dependencies.\n\n### @xnetjs/query\n\n**Dependencies:** `@xnetjs/data`, `@xnetjs/storage`\n\nQuery AST, saved-view descriptors, full-text search index, and the reactive saved-view runner that powers tables, boards, and widgets.\n\n### @xnetjs/views\n\n**Dependencies:** `@xnetjs/react`, `@xnetjs/ui`\n\nDatabase view components: table, board, list, calendar, gallery, timeline — with compact modes for dashboards.\n\n### @xnetjs/comms\n\n**Dependencies:** `@xnetjs/data`, `@xnetjs/crypto`\n\nChat, presence, and calls: room manager (typed awareness sessions), chat service (signed message nodes, deterministic DM ids), the local notification engine, and the full-mesh WebRTC call manager. See [Chat, Presence & Calls](/docs/guides/chat-and-calls/).\n\n### @xnetjs/dashboard & @xnetjs/charts\n\n**Dependencies:** `@xnetjs/react`, `@xnetjs/plugins`, `@xnetjs/charts`\n\nWidget contract, registry, grid runtime, and sandbox tiers; charts wraps ECharts behind a library-agnostic spec. See [Dashboards & Widgets](/docs/guides/dashboards/).\n\n### @xnetjs/cli\n\n**Dependencies:** `@xnetjs/plugins`, `@xnetjs/data`\n\nThe `xnet` command-line tool: scoped workspace checkouts, search/query, commit/daemon, sandboxed scripts, SKILL.md. See [Agent Interfaces](/docs/guides/agent-interfaces/).\n\n### @xnetjs/hub\n\n**Dependencies:** `@xnetjs/sync`, `@xnetjs/data`\n\nThe optional always-on node: relay, encrypted backup, full-text search, call signaling, UCAN-authorized actions. See the [Hub guide](/docs/guides/hub/).\n\n### Supporting packages\n\n`core` (shared primitives), `sqlite` & `data-bridge` (storage adapters), `canvas-core`, `editor`/`canvas` internals, `formula`, `history` (undo/redo), `social` (graph lenses & importers), `telemetry`, `abuse` (rate limiting & peer scoring), `vectors`, `sdk`.\n\n## The rule\n\n**Lower packages cannot import from higher ones.** This ensures:\n\n- `@xnetjs/crypto` can be used standalone for any cryptographic operation\n- `@xnetjs/sync` can be used without React for server-side or CLI tools\n- `@xnetjs/data` can be used without a UI framework\n- Each package is independently testable\n\n## Applications\n\n```\napps/web         — The flagship workbench PWA (documents, databases, canvas,\n                   tasks, dashboards, chat & calls)\napps/electron    — Desktop wrapper adding background sync, ProcessManager,\n                   LocalAPI, and the MCP server (@xnetjs/plugins/node)\napps/expo        — Mobile (in development)\n```\n\nThe web app is the primary surface and uses the browser-safe subset; Electron adds the Node-only service layer on top.","src/content/docs/docs/architecture/package-graph.mdx","7ef40308989fb136","docs/contributing/code-style",{id:186,data:188,body:194,filePath:195,digest:196,deferredRender:16},{title:189,description:190,editUrl:16,head:191,template:18,sidebar:192,pagefind:16,draft:21},"Code Style","Coding conventions for xNet contributions.",[],{order:20,hidden:21,attrs:193},{},"## Import ordering\n\nImports follow a strict order, separated by blank lines:\n\n```ts\n// 1. Type-only imports\nimport type { Foo } from './types'\n\n// 2. External packages\nimport { useState } from 'react'\n\n// 3. Internal packages\nimport { hash } from '@xnetjs/crypto'\n\n// 4. Local relative imports\nimport { helper } from './utils'\n```\n\n## Naming conventions\n\n| Category          | Convention            | Example                          |\n| ----------------- | --------------------- | -------------------------------- |\n| Functions         | camelCase, verb-first | `createNode`, `verifySignature`  |\n| Types             | PascalCase            | `NodeStore`, `SyncStatus`        |\n| Constants         | SCREAMING_SNAKE       | `MAX_UPDATE_SIZE`, `DEFAULT_TTL` |\n| Classes           | PascalCase            | `SpatialIndex`, `Viewport`       |\n| Type parameters   | Single uppercase      | `T`, `P`                         |\n| Unused parameters | Prefix with `_`       | `_event`, `_unused`              |\n\n## TypeScript\n\n- **Strict mode enabled** — no implicit `any`, strict null checks\n- **Prefer `type` over `interface`** for object shapes\n- **Explicit return types** on exported functions\n- **Template literal types** for branded strings: `` `xnet://${string}/` ``\n- **No `any`** without justification — use `unknown` instead\n\n## Exports\n\n- **Named exports only** — no default exports\n- **Barrel files** (`index.ts`) re-export from internal modules\n- **Export types inline**: `export { fn, type FnResult }`\n- **Factory functions** alongside classes: `createFoo()` next to `class Foo`\n\n## Comments\n\n### File-level JSDoc\n\n```ts\n/**\n * @xnetjs/sync - Unified sync primitives for xNet\n */\n```\n\n### Section dividers\n\n```ts\n// ─── Section Name ────────────────────────────────────────\n```\n\n### Function docs\n\n```ts\n/**\n * Create a signed envelope for a Yjs update.\n * @example\n * const envelope = signYjsUpdate(update, did, key, clientId)\n */\n```\n\n## Error handling\n\n- Return `{ valid: boolean, errors: [] }` for validation — don't throw\n- Try-catch with type narrowing: `err instanceof Error ? err : new Error(String(err))`\n- Early returns for edge cases\n- Boolean returns for simple success/failure\n\n## React patterns\n\n- Return typed objects from hooks (not tuples)\n- Use refs for values accessed in callbacks (avoid stale closures)\n- Always return cleanup functions from `useEffect`\n- Debug logging via localStorage: `localStorage.getItem('xnet:sync:debug')`\n- Prefer Tailwind over custom CSS","src/content/docs/docs/contributing/code-style.mdx","d48dbe5d6829502e","docs/contributing/getting-started",{id:197,data:199,body:205,filePath:206,digest:207,deferredRender:16},{title:200,description:201,editUrl:16,head:202,template:18,sidebar:203,pagefind:16,draft:21},"Getting Started","How to set up the xNet monorepo for development.",[],{order:55,hidden:21,attrs:204},{},"## Prerequisites\n\n- **Node.js** 18+ (LTS recommended)\n- **pnpm** 9+ (`npm install -g pnpm`)\n- **Git**\n\n## Clone and install\n\n```bash\ngit clone https://github.com/crs48/xNet.git\ncd xNet\npnpm install\n```\n\n## Build all packages\n\n```bash\npnpm build\n```\n\nThis builds all packages in dependency order (crypto → identity → storage → sync → data → react → etc.).\n\n## Run tests\n\n```bash\n# All tests (~4,700)\npnpm test\n\n# Single package\npnpm --filter @xnetjs/sync test\npnpm --filter @xnetjs/data test\n\n# Single file\npnpm --filter @xnetjs/sync vitest run src/clock.test.ts\n\n# Watch mode\npnpm --filter @xnetjs/sync test:watch\n```\n\n## Type checking\n\n```bash\npnpm typecheck\n```\n\n## Linting\n\n```bash\npnpm lint\n```\n\n## Run the Electron app\n\n```bash\ncd apps/electron && pnpm dev\n```\n\nThis starts the Vite dev server, signaling server, and Electron app. The app is available at `http://localhost:5177` for debugging.\n\n### Two-instance sync testing\n\n```bash\ncd apps/electron && pnpm dev:both\n```\n\nLaunches two Electron windows connected to the same signaling server for testing real-time sync.\n\n## Project structure\n\n```\npackages/           # Core libraries (@xnetjs/*)\n  crypto/           # BLAKE3, Ed25519, XChaCha20\n  identity/         # DID:key, UCAN tokens\n  storage/          # SQLite adapter\n  sync/             # Lamport clocks, Change<T>, Yjs security\n  data/             # Schema system, NodeStore, 15 property types\n  react/            # useQuery, useMutate, useNode hooks\n  plugins/          # 4-layer plugin system\n  canvas/           # Infinite canvas with spatial indexing\n  editor/           # TipTap rich text editor\n  network/          # libp2p, WebRTC, peer security\n  devtools/         # Debug panels (7 panels)\napps/\n  electron/         # Desktop app (full features)\n  web/              # PWA (pages only)\nsite/               # Documentation site (Astro + Starlight)\n```\n\n## Workflow\n\n1. Create a feature branch from `main`\n2. Make changes in the relevant package(s)\n3. Run tests for affected packages\n4. Run `pnpm typecheck` and `pnpm lint`\n5. Commit with a descriptive message following conventional commits\n6. Open a pull request\n\nIf your change alters an **architectural invariant** — a protocol/wire contract,\na package boundary, a security or trust rule, a storage or sync decision — add or\nsupersede a record on the [Architecture Decisions](/docs/architecture/decisions/)\npage in the same PR. Decisions are usually worked out first as an exploration in\n`docs/explorations/`; the ADR page is the distilled, immutable outcome.\n\n## Useful commands\n\n| Command                               | Description              |\n| ------------------------------------- | ------------------------ |\n| `pnpm install`                        | Install all dependencies |\n| `pnpm build`                          | Build all packages       |\n| `pnpm test`                           | Run all tests            |\n| `pnpm typecheck`                      | Type check all packages  |\n| `pnpm lint`                           | Lint all packages        |\n| `pnpm --filter @xnetjs/sync test`       | Test a single package    |\n| `pnpm --filter @xnetjs/sync test:watch` | Watch mode for a package |","src/content/docs/docs/contributing/getting-started.mdx","1baa6a81cc63641c","docs/contributing/testing",{id:208,data:210,body:216,filePath:217,digest:218,deferredRender:16},{title:211,description:212,editUrl:16,head:213,template:18,sidebar:214,pagefind:16,draft:21},"Testing Guide","How to run and write tests for xNet.",[],{order:78,hidden:21,attrs:215},{},"## Running tests\n\n```bash\n# All ~4,700 tests\npnpm test\n\n# Single package\npnpm --filter @xnetjs/sync test\npnpm --filter @xnetjs/data test\npnpm --filter @xnetjs/canvas test\n\n# Single file\npnpm --filter @xnetjs/sync vitest run src/clock.test.ts\n\n# Pattern match\npnpm --filter @xnetjs/data vitest run -t \"NodeStore\"\n\n# Watch mode\npnpm --filter @xnetjs/sync test:watch\n```\n\n## Test structure\n\nAll tests use Vitest with the Arrange-Act-Assert pattern:\n\n```ts\nimport { describe, it, expect } from 'vitest'\n\ndescribe('ModuleName', () => {\n  describe('functionName', () => {\n    it('should do expected behavior', () => {\n      // Arrange\n      const input = createTestData()\n\n      // Act\n      const result = functionName(input)\n\n      // Assert\n      expect(result).toBe(expected)\n    })\n  })\n})\n```\n\n## What to test\n\n**Do test:**\n\n- Core packages (`crypto`, `identity`, `sync`, `data`, `plugins`)\n- Pure functions and algorithms\n- Edge cases and error paths\n- Immutability guarantees\n\n**Don't test:**\n\n- UI components (manual testing only)\n- Electron app integration\n- Styling/layout\n\n## Common patterns\n\n### Generating test keys\n\n```ts\nimport { generateSigningKeyPair } from '@xnetjs/crypto'\nimport { generateIdentity } from '@xnetjs/identity'\n\nconst { publicKey, privateKey } = generateSigningKeyPair()\nconst { identity, privateKey: signingKey } = generateIdentity()\n```\n\n### Test DIDs\n\n```ts\n// Quick typed DID for tests\nconst testDID = 'did:key:z6MkTest123' as DID\n\n// Or generate a real one\nconst { identity } = generateIdentity()\n```\n\n### Suppressing console output\n\n```ts\nvi.spyOn(console, 'error').mockImplementation(() => {})\nvi.spyOn(console, 'warn').mockImplementation(() => {})\n```\n\n### Immutability checks\n\n```ts\nit('should not mutate the input', () => {\n  const original = createLamportClock('did:key:alice')\n  const time = original.time\n  tick(original)\n  expect(original.time).toBe(time)\n})\n```\n\n## Where tests live\n\nTest files are colocated with source code:\n\n```\npackages/sync/src/\n  clock.ts\n  clock.test.ts\n  change.ts\n  change.test.ts\n```\n\nOr in a `__tests__` directory for packages with many test files:\n\n```\npackages/plugins/src/\n  __tests__/\n    registry.test.ts\n    middleware.test.ts\n    sandbox.test.ts\n```\n\n## Coverage\n\nTests cover core algorithms and security-critical paths. Each core package has tests for its primary exports. When adding new functionality to a core package, include tests that verify the expected behavior and edge cases.","src/content/docs/docs/contributing/testing.mdx","2ef923c8ffca92a0","docs/guides/agent-interfaces",{id:219,data:221,body:227,filePath:228,digest:229,deferredRender:16},{title:222,description:223,editUrl:16,head:224,template:18,sidebar:225,pagefind:16,draft:21},"Agent Interfaces","The files-first surface for AI agents: workspace checkouts, the xnet CLI, SKILL.md, and slim MCP.",[],{hidden:21,attrs:226},{},":::note[You will learn]\n\n- Why the filesystem is the primary agent surface\n- The checkout layout and how edits flow back safely\n- The `xnet` CLI verbs and the ~500-token SKILL.md\n- When to fall back to MCP\n  :::\n\n## Files first\n\nCoding agents are already excellent at reading, grepping, and editing files —\nso xNet's primary agent interface is a **filesystem projection of the\nworkspace**, not a wall of tool definitions. The store stays the source of\ntruth; the checkout is a working tree. Every surface (files, CLI, MCP) funnels\ninto the same plan → validate → apply core, so an agent can never corrupt the\nworkspace with a malformed write.\n\nMeasured on a 15-task benchmark, the files+CLI surface completes the same work\nat **~0.11x the tokens** of a traditional MCP toolset (0.05x on synthesis\ntasks), with equal task success.\n\n## The checkout\n\n`xnet checkout` materializes a scoped slice of the workspace into a folder:\n\n```\nPages/q3-planning.md            # Markdown + YAML frontmatter (xnet.id, revision)\nDatabases/tasks.schema.json     # the schema\nDatabases/tasks.rows.jsonl      # one JSON object per line — edit/append/delete\nDatabases/tasks.tsv             # read-only fast-read sidecar (large tables)\nCanvases/roadmap.canvas         # JSON Canvas projection\nSKILL.md                        # the agent contract (~500 tokens)\n.xnet/                          # manifest, conflict notes\n```\n\nFilenames are semantic slugs; identity lives in frontmatter and the manifest,\nnever in filenames. Wikilinks (`[[Title]]`), `:::xnet-database` blocks, and\n`{{xnet-ref}}` directives are live references and survive round-trips.\n\nCheckouts are **scoped and incremental** — by query, schema, kind, or node\n(`xnet checkout --query \"roadmap\"`); repeated checkouts merge. Agents never\nneed (and are told not to) export the whole workspace.\n\n### Edits become validated plans\n\nFile edits are diffed into **mutation plans**, validated against schemas, and\napplied to the store — automatically with `xnet daemon` running, or on\n`xnet commit`. Anything that doesn't validate, or collides with a newer\nrevision, is **quarantined as a conflict**: a Markdown note in\n`.xnet/conflicts/` explains what happened and how to resolve it. Stale edits\nnever silently overwrite newer data.\n\n## The xnet CLI\n\n| Command | Purpose |\n| --- | --- |\n| `xnet checkout` | Materialize / extend a scoped checkout |\n| `xnet status` | Pending plans and conflicts |\n| `xnet commit [--apply]` | Turn file edits into applied mutations |\n| `xnet search \"<text>\"` | Ranked full-text search (TSV: id, slug, title, snippet) |\n| `xnet query <db> --where field=value` | Query tables (TSV default; `jsonl`/`json`/`md`) |\n| `xnet db get/set` | Single-cell reads and writes |\n| `xnet run <script.js>` | Sandboxed bulk work over a bounded `api` object |\n| `xnet daemon` | Watch the checkout and auto-apply valid edits |\n| `xnet skill` | Print SKILL.md |\n\nOutput is TSV-first and concise by default (`--detailed` to opt out) — built\nfor being read by a model, not a human.\n\n`xnet run` executes scripts in a sandbox with bounded reads and **write\nproposals** (`api.proposeUpdate`, `api.proposeCreate`) that flow through the\nsame validated plan pipeline as file edits.\n\n## SKILL.md\n\nEvery checkout ships a cross-harness `SKILL.md` (~500 tokens) that teaches any\nagent — Claude Code, Codex, Gemini CLI, Cursor — the layout and workflow above.\nThat's the entire standing context cost, versus ~5k tokens of always-loaded\ntool definitions for a typical MCP server. Print it any time with\n`xnet skill`.\n\n## Slim MCP\n\nMCP remains as the **no-shell fallback** for harnesses that can't run a CLI.\nIt's deliberately slim: five stable core tools are loaded eagerly and\neverything else defers (the non-deferred payload is test-guarded at ≤1.5k\ntokens). Responses are compact JSON by default with\n`response_format: concise | detailed` on every tool.\n\nThe doctrine, in order: **files for reading and editing, the CLI for what\nfiles can't express, MCP only when there's no shell.**\n\n## Further reading\n\n- [For AI Assistants](/docs/ai/understanding-xnet/) — the mental model for\n  agents writing *app code* against xNet\n- [Plugins](/docs/guides/plugins/) — the integration layer MCP belongs to","src/content/docs/docs/guides/agent-interfaces.mdx","6eaf74c5f969000c","docs/guides/authorization",{id:230,data:232,body:238,filePath:239,digest:240,deferredRender:16},{title:233,description:234,editUrl:16,head:235,template:18,sidebar:236,pagefind:16,draft:21},"Authorization","Encryption-first access control with schema-defined roles, UCAN grants, and key recovery.",[],{order:20,hidden:21,attrs:237},{},"import { Card, CardGrid } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- The core insight: encryption IS authorization\n- How to define roles and actions in your schema\n- How to grant, revoke, and delegate access\n- How to check permissions with `useCan` and `useGrants`\n- How key recovery and multi-device access work\n- The trust model and its security tradeoffs\n  :::\n\n## The core insight\n\nIn a decentralized system, the only meaningful access control is **the ability to decrypt**:\n\n```\nCan you decrypt it?       → You can read it.\nIn the recipients list?  → The hub will serve it to you.\nSchema says you can write? → The client will let you sign a change.\n```\n\nRoles, relations, and UCAN delegation are all machinery for deciding **who gets the content key**. Once a user has the key, cryptography enforces their access — no server policy engine required.\n\n## Defining authorization in a schema\n\nAdd an `authorization` block to any schema to define who can do what:\n\n```ts\nimport { defineSchema, text, person, relation } from '@xnetjs/data'\nimport { allow, deny, role } from '@xnetjs/data/auth'\n\nexport const TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    assignee: person(),\n    project: relation({ target: 'xnet://my-app/Project' as const }),\n    editors: person({ multiple: true })\n  },\n  authorization: {\n    roles: {\n      owner: role.creator(), // whoever created the node\n      assignee: role.property('assignee'), // person() property value\n      editor: role.property('editors'), // person({ multiple: true }) value\n      admin: role.relation('project', 'admin'), // role from a related node\n      viewer: role.relation('project', 'viewer') // role from a related node\n    },\n    actions: {\n      read: allow('viewer', 'editor', 'admin', 'owner', 'assignee'),\n      write: allow('editor', 'admin', 'owner'),\n      delete: allow('admin', 'owner'),\n      share: allow('admin', 'owner')\n    },\n    publicProps: ['title'] // properties readable without decryption\n  }\n})\n```\n\n### Role types\n\n| Builder                          | Resolves to                                  |\n| -------------------------------- | -------------------------------------------- |\n| `role.creator()`                 | The DID that created the node                |\n| `role.property('field')`         | The DID(s) in a `person()` property          |\n| `role.relation('field', 'role')` | Anyone who has that role on the related node |\n\n### Actions\n\n| Action   | Covers                                            |\n| -------- | ------------------------------------------------- |\n| `read`   | `store.get`, `useQuery`, hub queries              |\n| `create` | `store.create` (refines `write`)                  |\n| `update` | `store.update`, `store.restore` (refines `write`) |\n| `write`  | Coarse mutation policy — the fallback for `create`/`update` when they aren't declared |\n| `delete` | `store.delete`                                    |\n| `share`  | `store.auth.grant`, `store.auth.revoke`           |\n| `admin`  | Hub operational controls                          |\n\n#### Splitting `write`: who may add vs. who may edit\n\n`create` and `update` are optional refinements of `write`. Declaring only\n`write` keeps the classic behavior (one mutation policy). Declaring the\nrefinements expresses **contributor semantics** — \"anyone here may post, but\nonly the author may edit\":\n\n```ts\nactions: {\n  read:   allow('owner', 'spaceMember'),\n  create: allow('spaceMember'),          // members may add new nodes…\n  update: allow('owner', 'spaceAdmin'),  // …only the author or an admin edits one\n  write:  allow('owner', 'spaceMember'), // fallback for engines without the split\n  delete: allow('owner', 'spaceAdmin'),\n  share:  allow('owner', 'spaceAdmin')\n}\n```\n\nTwo rules to remember:\n\n- **Create checks run against the draft node** (its `createdBy` is the\n  caller), so `role.creator()` always matches on create — leave it out of\n  `create` if you want membership to actually gate who may add. Container\n  relations in the draft (`space`, `channel`, …) resolve normally.\n- **A `write` grant covers both refinements**; a `create`-only or\n  `update`-only grant covers just itself.\n\nThe built-in `spaceContributorAuthorization()` block packages this pattern for\nSpace content (chat messages and comments use it).\n\nExplicit `deny()` always wins over `allow()`:\n\n```ts\nactions: {\n  read: allow('viewer').deny('blocked'),  // 'blocked' role can never read\n}\n```\n\n### Public nodes\n\nSet `publicProps` to expose specific fields without encryption, or use `PUBLIC` to make the entire node readable by anyone:\n\n```ts\nauthorization: {\n  // ...roles and actions...\n  publicProps: ['title', 'status'],  // these fields are unencrypted\n}\n```\n\nFor fully public nodes (no access control), use the built-in preset:\n\n```ts\nimport { presets } from '@xnetjs/data/auth'\n\nexport const ArticleSchema = defineSchema({\n  // ...\n  authorization: presets.public\n})\n```\n\n### Permission presets\n\n```ts\nimport { presets } from '@xnetjs/data/auth'\n\n// Full owner control — only creator can do anything\nauthorization: presets.ownerOnly\n\n// Owner + share — owner shares explicit read/write with others via grants\nauthorization: presets.ownerWithShare\n\n// Collaborative — creator is owner, any member of a 'workspace' relation can read/write\nauthorization: presets.collaborative({ relation: 'workspace' })\n\n// Fully public — all content is unencrypted and anyone can read\nauthorization: presets.public\n```\n\n## Checking permissions\n\n### `useCan` hook\n\n```tsx\nimport { useCan } from '@xnetjs/react'\n\nfunction TaskCard({ taskId }: { taskId: string }) {\n  const { canRead, canWrite, canDelete, canShare, loading } = useCan(taskId)\n\n  if (loading) return null\n\n  return (\n    <div>\n      <TaskTitle />\n      {canWrite && <EditButton />}\n      {canDelete && <DeleteButton />}\n      {canShare && <ShareButton />}\n    </div>\n  )\n}\n```\n\n`useCan` is reactive — it re-evaluates when grants change or when you switch users.\n\n### `store.auth.can()`\n\n```ts\nconst decision = await store.auth.can({ action: 'write', nodeId: taskId })\n// { allowed: true, reason: 'role:owner', cached: false }\n\nconst decision = await store.auth.can({ action: 'delete', nodeId: taskId })\n// { allowed: false, reason: 'no matching role or grant' }\n```\n\n### Explaining a decision\n\nFor debugging or AI-assisted introspection, use `explain()`:\n\n```ts\nconst trace = await store.auth.explain({ action: 'write', nodeId: taskId })\n// {\n//   allowed: true,\n//   subject: 'did:key:z6Mk...',\n//   action: 'write',\n//   nodeId: 'task_abc',\n//   roles: ['owner'],\n//   grants: [],\n//   policyTrace: [\n//     { rule: 'allow(editor, admin, owner)', matched: 'owner' }\n//   ]\n// }\n```\n\n## Granting and revoking access\n\n### `useGrants` hook\n\n```tsx\nimport { useGrants } from '@xnetjs/react'\n\nfunction ShareDialog({ taskId }: { taskId: string }) {\n  const { grants, grant, revoke, loading } = useGrants(taskId)\n\n  return (\n    <div>\n      {grants.map((g) => (\n        <div key={g.id}>\n          {g.grantee} — {g.actions.join(', ')}\n          <button onClick={() => revoke(g.id)}>Revoke</button>\n        </div>\n      ))}\n      <button onClick={() => grant({ to: 'did:key:...', actions: ['read'] })}>Add person</button>\n    </div>\n  )\n}\n```\n\n### `store.auth` API\n\n```ts\n// Grant access with optional expiry\nawait store.auth.grant({\n  to: bobDid,\n  actions: ['read', 'write'],\n  resource: taskId,\n  expiresIn: '7d' // or expiresAt: timestamp\n})\n\n// Revoke a grant (last-admin protection prevents locking yourself out)\nawait store.auth.revoke({ grantId })\n\n// List all grants for a node\nconst grants = await store.auth.listGrants({ nodeId: taskId })\n```\n\nGrants are stored as signed nodes in the NodeStore — they sync, replicate, and benefit from the same CRDT conflict resolution as all other data.\n\n### Delegation (UCAN chains)\n\nAny user with the `share` action can delegate their access to another user via UCAN proof chains. Delegation is **attenuated** — you can only delegate up to (not beyond) your own permissions:\n\n```ts\n// Alice (owner) grants Bob write access\nawait store.auth.grant({ to: bob, actions: ['write'], resource: docId })\n\n// Bob can delegate read access to Carol (subset of Bob's write)\nawait store.auth.grant({\n  to: carol,\n  actions: ['read'],\n  resource: docId\n  // Bob's grant to Alice is automatically included as proof\n})\n```\n\nDelegation chains are capped at depth 4 (`maxProofDepth = 4`). Revoking a parent grant cascades to all derived grants.\n\n### Grant expiration\n\nGrants with `expiresIn` or `expiresAt` automatically become inactive after their expiry time. A background `GrantExpirationCleaner` prunes expired grants and re-encrypts affected nodes with updated recipient lists.\n\n## How enforcement works\n\n### Local mutations\n\nWhen you call `store.create()`, `store.update()`, or `store.delete()`, the store checks authorization first:\n\n```ts\ntry {\n  await store.update(TaskSchema, taskId, { title: 'New title' })\n} catch (err) {\n  if (err instanceof PermissionError) {\n    // err.message: \"denied: action=write, subject=did:key:..., role context: [viewer]\"\n  }\n}\n```\n\n### Remote changes\n\nWhen a remote peer's change arrives via sync, the store silently rejects unauthorized changes and emits a `change:rejected` event. The peer also receives a scoring penalty to protect against abuse.\n\n### Yjs documents\n\nCollaborative editing (via `useNode`) uses a layered auth model:\n\n1. **Room gate** — only authorized users can join a sync room\n2. **Per-update gate** — each incoming Yjs update is checked against `PolicyEvaluator`\n3. **At-rest encryption** — Y.Doc state is encrypted with the node's content key\n\nRevoking a user from a document immediately kicks them from the room and rotates the content key, so all future updates are encrypted for the new recipient set.\n\n### Hub filtering\n\nThe hub never decrypts data — it filters queries by recipient lists stored in node metadata. If your DID isn't in the recipients list, the hub doesn't return the node. This is transparent to your app: you write normal queries, unauthorized data is silently excluded.\n\n## Failure modes\n\n| Context                      | When auth fails                             | Why                                    |\n| ---------------------------- | ------------------------------------------- | -------------------------------------- |\n| `store.create/update/delete` | Throws `PermissionError`                    | Developer should see and handle errors |\n| `applyRemoteChange`          | Silently rejected + `change:rejected` event | Don't crash on bad remote data         |\n| Yjs update                   | Silently rejected + peer scoring penalty    | Don't interrupt editing flow           |\n| Hub query                    | Node excluded from results (no error)       | Transparent access control             |\n\n## Trust model\n\n**Read access is cryptographically enforced.** If you don't have the content key, you cannot decrypt the data. The hub can't help you because it doesn't hold keys.\n\n**Write access is enforced client-side.** A malicious client could skip the `can()` check and broadcast a signed change. The hub and honest peers accept it because the Ed25519 signature is valid.\n\nThis is an intentional tradeoff:\n\n- All changes are signed and part of a tamper-evident hash chain — unauthorized writes are attributable and detectable\n- Peer scoring penalizes unauthorized write attempts, leading to automatic blocking\n- Key rotation on revocation means revoked users lose future read access regardless of write-side enforcement\n\nFor apps where write enforcement must be stronger, self-hosted hubs can add custom policy validation.\n\n## Key resolution\n\nWhen encrypting a node for a recipient, xNet needs their X25519 public key to perform key wrapping. It resolves this in two steps:\n\n1. **Birational conversion** — Ed25519 public keys (from DID:key) can be mathematically converted to X25519 keys without any additional lookup. This works for any DID:key holder.\n2. **Hub registry fallback** — For cases where the key holder has registered a separate X25519 key (unusual), the hub maintains a public key registry.\n\nThis means sharing data with any DID:key holder requires no out-of-band key exchange.\n\n## Key recovery & multi-device\n\n### Seed phrase\n\nYour signing key can be derived deterministically from a seed phrase (BIP-39 format). The seed phrase is the root of your identity — back it up carefully.\n\n```ts\nimport { deriveSeedPhrase, recoverFromSeedPhrase } from '@xnetjs/identity'\n\n// Generate a new identity with a recoverable seed\nconst { mnemonic, bundle } = deriveSeedPhrase()\n// mnemonic: \"correct horse battery staple ...\"\n\n// Recover identity on a new device\nconst recoveredBundle = recoverFromSeedPhrase(mnemonic)\n// Produces the same DID and key pair\n```\n\n### Multi-device\n\nEach device derives the same primary key from the seed, so your DID is the same across devices. When you add a second device:\n\n1. The new device generates its own device-specific encryption key\n2. It registers in a device registry (synchronized via the Hub)\n3. Your primary key wraps the content keys for each device\n\n### Social recovery\n\nAs a fallback when the seed phrase is unavailable, xNet supports Shamir's Secret Sharing: split the seed across trusted contacts, any threshold (e.g., 3 of 5) can reconstruct it.\n\n### Encrypted hub backup\n\nThe hub can store an encrypted backup of your key bundle, unlocked by a passphrase or WebAuthn credential. This is opt-in and the hub never sees the plaintext key.\n\n## Offline authorization\n\nBy default, authorization decisions are cached with a 5-minute TTL. This means:\n\n- The app works offline — cached decisions are used while disconnected\n- Revocations take at most 5 minutes to propagate to offline users\n- On reconnect, the cache is revalidated against the current grant state\n\nConfigure offline behavior per-schema:\n\n```ts\nauthorization: {\n  // ...\n  offlinePolicy: {\n    cacheTTL: 300_000,          // 5 minutes (default)\n    maxStaleness: 3_600_000,    // 1 hour — refuse to use older cached decisions\n    revalidateOnReconnect: true // (default) revalidate immediately when online\n  }\n}\n```\n\n## Migration from unencrypted schemas\n\nSchemas without an `authorization` block continue to work but emit a console warning in development. To add authorization to an existing schema:\n\n1. Add the `authorization` block with your desired roles and actions\n2. Run the `AuthMigrator` utility to batch-encrypt existing nodes:\n\n```ts\nimport { AuthMigrator } from '@xnetjs/data/auth'\n\nconst migrator = new AuthMigrator(store, encryptionLayer)\nawait migrator.migrateSchema(MySchema, {\n  batchSize: 50,\n  onProgress: ({ done, total }) => console.log(`${done}/${total}`)\n})\n```\n\nThe migration re-encrypts nodes in batches and updates their recipient lists. Existing peers will receive the re-encrypted versions via normal sync.\n\n## Related\n\n- [defineSchema](/docs/schemas/defineschema/) — Full schema API reference\n- [Identity & Keys](/docs/guides/identity/) — DID:key, UCAN tokens, key management\n- [Cryptography](/docs/concepts/cryptography/) — BLAKE3, Ed25519, XChaCha20, X25519\n- [Offline Patterns](/docs/guides/offline/) — Offline cache behavior and sync\n- [DevTools](/docs/guides/devtools/) — AuthZ panel for live inspection","src/content/docs/docs/guides/authorization.mdx","8b15614f5c6f1e13","docs/guides/canvas",{id:241,data:243,body:250,filePath:251,digest:252,deferredRender:16},{title:244,description:245,editUrl:16,head:246,template:18,sidebar:247,pagefind:16,draft:21},"Infinite Canvas","Spatial node layouts with zoom, pan, and real-time collaboration.",[],{order:248,hidden:21,attrs:249},10,{},":::note[You will learn]\n\n- How the infinite canvas works\n- The spatial index (R-tree) for viewport culling\n- Layout algorithms (ELK.js, grid, circle)\n- The Canvas component and useCanvas hook\n- How canvas state syncs via Yjs\n  :::\n\n## Overview\n\n`@xnetjs/canvas` provides an infinite, zoomable 2D surface where users can place, connect, and arrange nodes. The canvas supports real-time collaboration via Yjs — multiple users can simultaneously add, move, and connect nodes.\n\n## Canvas component\n\n```tsx\nimport { Canvas } from '@xnetjs/canvas'\n\n;<Canvas\n  doc={ydoc} // Required: Yjs document\n  awareness={awareness} // Cursor presence\n  renderNode={(node) => <MyCard />} // Custom node content\n  onNodeDoubleClick={(id) => open(id)}\n  onBackgroundClick={() => deselect()}\n  config={{\n    minZoom: 0.1,\n    maxZoom: 3,\n    gridSize: 20,\n    showGrid: true\n  }}\n/>\n```\n\n### Keyboard shortcuts\n\n| Shortcut               | Action                |\n| ---------------------- | --------------------- |\n| `Delete` / `Backspace` | Delete selected nodes |\n| `Cmd+A`                | Select all            |\n| `Escape`               | Clear selection       |\n| `Cmd+1`                | Fit to content        |\n| `Cmd+0`                | Reset view            |\n\n### Mouse and touch interaction\n\n- **Scroll** — Pan the canvas\n- **Ctrl/Cmd + Scroll** — Zoom\n- **Two-finger pinch** — Zoom (trackpads and touch screens, including Safari gestures)\n- **Click node** — Select it\n- **Click edge** — Select it (edges have generous invisible hit areas)\n- **Shift/Cmd + Click** — Additive selection\n- **Drag node** — Move it\n- **Drag resize handles** — Resize (8 handles on selection)\n- **Drag a connector handle** — Draw a new edge to another node (handles appear on hover)\n- **Double-click** — Open node, or edit its text in place\n\n## Editing on the canvas\n\nNodes and edges are directly editable without leaving the canvas:\n\n- **Edges** — click to select; a floating toolbar offers a label input, an\n  edge-kind picker, reverse direction, and delete.\n- **Drag-to-connect** — drag from a node's connector handle (shown on hover)\n  and drop on another node to create an edge.\n- **Node text** — double-click a canvas-native node (shape, note) to edit its\n  text inline. Source-backed cards (a page or database dropped onto the\n  canvas) keep their source's title; press `F2` or use the Rename action to\n  give the card a local alias instead.\n\nAll edits go through Yjs transactions and sync live to collaborators.\n\n## useCanvas hook\n\nThe primary hook that wires together the store, viewport, and layout engine:\n\n```ts\nconst {\n  // State\n  nodes,\n  edges,\n  selectedNodeIds,\n  viewport,\n\n  // Node operations\n  addNode,\n  updateNodePosition,\n  removeNode,\n\n  // Edge operations\n  addEdge,\n  removeEdge,\n\n  // Selection\n  selectNode,\n  selectAll,\n  clearSelection,\n  deleteSelected,\n\n  // Viewport\n  pan,\n  zoomAt,\n  fitToContent,\n  resetView,\n\n  // Layout\n  autoLayout,\n  layoutSelected,\n\n  // Queries\n  findNodeAt,\n  findNodesInRect,\n  getVisibleNodes\n} = useCanvas({ doc: ydoc, config })\n```\n\n## Spatial index\n\nThe canvas uses an R-tree (`rbush`) for efficient spatial queries. This enables viewport culling — only nodes visible on screen need to be rendered.\n\n```ts\n// Find all nodes in the current viewport\nconst visibleIds = store.getVisibleNodes(viewport.getVisibleRect())\n\n// Find the topmost node at a point\nconst nodeId = store.findNodeAt(point)\n\n// Find all nodes overlapping with a given node\nconst overlapping = store.findIntersecting(nodeId)\n```\n\nThe spatial index is automatically updated when nodes are added, moved, or removed.\n\n## Layout algorithms\n\nThe `LayoutEngine` supports automatic layout via ELK.js and two built-in algorithms:\n\n### ELK.js layouts\n\n```ts\nawait autoLayout({\n  algorithm: 'layered', // Sugiyama/hierarchical\n  direction: 'RIGHT', // RIGHT, LEFT, DOWN, UP\n  nodeSpacing: 50,\n  layerSpacing: 100,\n  edgeRouting: 'ORTHOGONAL' // POLYLINE, ORTHOGONAL, SPLINES\n})\n```\n\nAvailable algorithms: `layered`, `force`, `mrtree`, `radial`, `stress`, `box`.\n\n### Grid layout\n\n```ts\nlayoutEngine.layoutGrid(nodes, {\n  columns: 4,\n  spacing: 20,\n  padding: 50\n})\n```\n\n### Circle layout\n\n```ts\nlayoutEngine.layoutCircle(nodes, {\n  radius: 300 // Auto-calculated if omitted\n})\n```\n\nNodes with `properties.fixed = true` keep their positions during layout.\n\n## Viewport\n\nThe `Viewport` class manages the camera:\n\n- **`pan(dx, dy)`** — Move by screen-space delta\n- **`zoomAt(x, y, factor)`** — Zoom while keeping the point under cursor stationary\n- **`fitToRect(rect, padding)`** — Fit viewport to show a rectangle (never zooms beyond 100%)\n- **`reset()`** — Return to origin at zoom 1\n- **`screenToCanvas(x, y)`** — Convert screen coordinates to canvas space\n- **`canvasToScreen(x, y)`** — Convert canvas coordinates to screen space\n- **`getVisibleRect()`** — The canvas-space rectangle currently on screen\n\n## Data storage\n\nCanvas state is stored in three Yjs maps inside the Y.Doc:\n\n| Map        | Contents                          |\n| ---------- | --------------------------------- |\n| `metadata` | Title, created/updated timestamps |\n| `nodes`    | `CanvasNode` objects keyed by ID  |\n| `edges`    | `CanvasEdge` objects keyed by ID  |\n\nAll mutations go through Yjs transactions, so changes sync automatically to other peers. The spatial index updates reactively when the Yjs maps change.\n\n## Node types\n\n```ts\ninterface CanvasNode {\n  id: string\n  type: string // 'page', 'database', 'note', etc.\n  position: {\n    x: number\n    y: number\n    width: number // Default: 200\n    height: number // Default: 100\n    rotation?: number\n    zIndex?: number\n    collapsed?: boolean\n  }\n  properties: Record<string, unknown>\n  linkedNodeId?: string // Link to a page/database node\n}\n```\n\nEdges connect nodes with optional labels, arrow markers, and routing styles (bezier or orthogonal).\n\n## Comments\n\nThe canvas supports spatial comments via `useCanvasComments`:\n\n- **Position pins** — Fixed canvas coordinates. Never orphaned.\n- **Object-attached pins** — Follow a node's position. Become orphaned when the node is deleted.\n\n## Further reading\n\n- [Collaboration Guide](/docs/guides/collaboration/) — Real-time editing patterns\n- [Sync Guide](/docs/guides/sync/) — How Yjs sync works","src/content/docs/docs/guides/canvas.mdx","dc14fd6bd73df571","docs/guides/chat-and-calls",{id:253,data:255,body:261,filePath:262,digest:263,deferredRender:16},{title:256,description:257,editUrl:16,head:258,template:18,sidebar:259,pagefind:16,draft:21},"Chat, Presence & Calls","Channels, DMs, typed presence rooms, and peer-to-peer WebRTC calls.",[],{hidden:21,attrs:260},{},":::note[You will learn]\n\n- How channels, DMs, and voice rooms are modeled as nodes\n- How presence rooms work (who's here, typing, in a call)\n- How peer-to-peer calls connect and their mesh limits\n- What the hub adds (signaling relay, mention validation)\n  :::\n\n## Overview\n\n`@xnetjs/comms` brings real-time communication to the workspace using the same\nlocal-first machinery as everything else: **messages are signed nodes**, not a\nseparate protocol. A channel is a `Channel` node (`channel`, `dm`, or `voice`),\neach message is a `ChatMessage` node signed by its author, and read state is\nyour own private `InboxState` node. Everything syncs peer-to-peer, works\noffline, and lands in the same store your queries already read.\n\n## Channels and DMs\n\n- **Channels** open as workbench tabs (`/channel/$channelId`) with typing\n  indicators, an `@`-mention autocomplete composer, and call join controls.\n- **DMs** need no coordination to create: the channel ID is derived\n  deterministically from the sorted member DIDs, so both sides materialize the\n  same conversation independently.\n- **Per-document chat** — a channel can target any node, which powers the\n  Room section in the right panel: every page, canvas, or database gets a\n  discussion thread alongside a who's-here roster.\n- **Voice rooms** are channels with `kind: 'voice'`; opening one joins the\n  call automatically (the Discord model), and occupancy shows in the Chats\n  panel.\n\nDisplay names and avatars resolve through `Profile` nodes (DID → name /\navatar / status), editable in Settings.\n\n### Mentions are structured\n\nMentions are never parsed out of message text. Composers populate a\n`mentions: { dids, room? }` field on the message — the model used by Matrix's\nintentional-mentions spec — so notification logic is deterministic and a\nhostile client can't sneak a mention past a renderer difference.\n\n## Presence rooms\n\nPresence is built on **rooms**: refcounted awareness sessions over any node\nID with typed fields — `user`, `viewing`, `status`, `typing`, `call`. The\nworkspace presence room drives the global roster (the \"◉ n here\" chip in the\nstatus bar); per-node rooms drive who's-viewing-this-page and typing\nindicators. Open the same room from five components and they share one\nsession.\n\n## Calls\n\nCalls are **full-mesh WebRTC**:\n\n- Offer initiation is deterministic (ordered by DID), so two peers never\n  glare.\n- The mesh ceiling is enforced reactively: **4 participants with video, 8\n  audio-only**. Beyond that, a selective-forwarding tier is on the roadmap.\n- Screen sharing replaces your video track — no renegotiation hiccup.\n- The call UI lives in a **floating dock** mounted outside the router, so\n  navigating tabs never drops a call (the Slack-huddle property).\n\nSignaling is a pluggable transport. With a hub, call setup reuses the hub's\nexisting pub/sub broker — no new server protocol; an in-memory loopback\ntransport exists for tests and same-device flows.\n\n## What the hub adds\n\nA [hub](/docs/guides/hub/) is optional for chat as for everything else, but\nwhen present it:\n\n- relays call signaling (`call/join`, `call/signal`) over its existing\n  WebSocket broker\n- validates mention declarations at relay time (shape checks and a 50-DID\n  cap) so clients can't mention-bomb a channel\n- will carry push notification delivery (in progress)\n\nFor larger calls, deploy a TURN server alongside the hub — see the deployment\nrecipes in the repository (`docs/deployment/REALTIME_CALLS.md`).\n\n## Current limits\n\nChat content is signed and syncs over encrypted transports, but **per-channel\nend-to-end encryption phases are still in progress** — treat channel content\nlike the rest of your workspace data today. SFU-tier large calls and push\ndelivery are also on the roadmap (see the [roadmap](/#roadmap)).\n\n## Further reading\n\n- [Notifications & Inbox](/docs/guides/notifications/) — how messages become\n  notifications\n- [Collaboration](/docs/guides/collaboration/) — document presence and cursors\n- [Hub](/docs/guides/hub/) — running an always-on relay","src/content/docs/docs/guides/chat-and-calls.mdx","1626de410cc984e5","docs/guides/cloud-connect",{id:264,data:266,body:273,filePath:274,digest:275,deferredRender:16},{title:267,description:268,editUrl:16,head:269,template:18,sidebar:270,pagefind:16,draft:21},"Connect to xNet Cloud","Link your web, desktop, or mobile app to a managed xNet Cloud hub.",[],{order:271,hidden:21,attrs:272},8,{},"import { Tabs, TabItem, Steps } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- How the two identities (billing vs. passkey) fit together\n- How to connect the **web**, **desktop**, and **mobile** apps to your managed hub\n- What the short device code is and how approval works\n- How to troubleshoot a connection that won't complete\n\n:::\n\nAfter you subscribe at [xnet.fyi/cloud](https://xnet.fyi/cloud), xNet Cloud\nprovisions a dedicated, always-on **hub** for your data. Your apps still hold the\nplaintext — the hub only ever stores encrypted updates and relays them between your\ndevices. This guide links an app to that hub.\n\nYou can open the relevant steps any time from the **Connect your apps** card on your\n[dashboard](https://cloud.xnet.fyi/dashboard).\n\n## Two identities, one account\n\nxNet keeps the *who pays* and *whose data* questions separate on purpose:\n\n- **Billing identity** — the email you sign in to the dashboard with. Custodial and\n  recoverable (a normal password/passkey reset).\n- **Data identity (your passkey)** — a `did:key` created **on your device** when you\n  first open the app. Non-custodial: it never leaves the device, and it's what proves\n  a device may read and write your data. We never see its private key.\n\nConnecting a device is the moment these two are bound together: you prove the billing\nside (you're signed in to the dashboard) **and** the data side (your app holds the\npasskey) at the same time.\n\n## Connect your app\n\n<Tabs>\n  <TabItem label=\"Web\">\n    <Steps>\n\n    1. Open the [web app](https://xnet.fyi/app) (or click **Open web app** on your\n       dashboard).\n    2. When prompted, **create your passkey**. This is your data identity — it stays\n       on your device.\n    3. Choose **Connect xNet Cloud hub**. The app shows a short code like\n       `ABCD-7K2P`.\n    4. On your dashboard, open **Connect your apps → Enter a code**, type the code,\n       and approve. The app finishes connecting automatically.\n\n    </Steps>\n  </TabItem>\n\n  <TabItem label=\"Desktop\">\n    The desktop app connects to your hub by its URL.\n\n    <Steps>\n\n    1. On your dashboard, copy your **hub URL** (the **Connect your apps → Desktop**\n       tab, or the **Endpoint** row — it looks like `wss://…hub.xnet.fyi`).\n    2. In the desktop app, open **Settings → Network** and paste it into the\n       **Signaling server** field.\n    3. Restart the app, then create your passkey and choose **Connect xNet Cloud\n       hub**.\n    4. Approve the short code it shows on your dashboard under **Enter a code**.\n\n    </Steps>\n\n    :::note\n    One-click desktop connect (an `xnet://` link that fills this in for you) is on the\n    way. Until then, the copy-and-paste step above is all that's needed.\n    :::\n\n  </TabItem>\n\n  <TabItem label=\"Mobile\">\n    <Steps>\n\n    1. Install xNet on your phone and open it.\n    2. Create your passkey, then choose **Connect xNet Cloud hub**.\n    3. Approve the short code it shows on your dashboard under **Connect your apps →\n       Enter a code**.\n\n    </Steps>\n  </TabItem>\n</Tabs>\n\n## What the device code is\n\nThe short code is a standard\n[device authorization](https://datatracker.ietf.org/doc/html/rfc8628) flow — the same\npattern you've used to sign a TV or a CLI into an account:\n\n```mermaid\nsequenceDiagram\n  participant App as Your app\n  participant Cloud as xNet Cloud\n  participant You as You (dashboard)\n  App->>Cloud: I'm did:key:… — start a connection\n  Cloud-->>App: Show code ABCD-7K2P\n  You->>Cloud: Approve ABCD-7K2P (you're signed in)\n  loop until approved\n    App->>Cloud: Is ABCD-7K2P approved yet?\n  end\n  Cloud-->>App: Approved — here's your hub URL\n  App->>App: Connect & sync\n```\n\nThe code is short-lived (about 10 minutes). If it expires, just restart the\nconnection from your app to get a fresh one.\n\n## Troubleshooting\n\n- **\"Code not found or expired.\"** Codes last ~10 minutes. Restart **Connect xNet\n  Cloud hub** in your app for a new one, then enter it promptly.\n- **Desktop app won't connect after pasting the URL.** Make sure you pasted the full\n  `wss://…` hub URL into **Signaling server**, then fully restart the app. You still\n  need to create your passkey and approve a code — pasting the URL alone only points\n  the app at the hub.\n- **Hub shows \"Sleeping\" on the dashboard.** Cold hubs wake on the next connection;\n  give it a few seconds after your app reconnects.\n- **Still stuck?** See the [pricing FAQ](https://xnet.fyi/cloud/pricing#faq) or check\n  the [status page](https://xnet.fyi/status).\n\n## Related\n\n- [Hub & Signaling](/docs/guides/hub/) — self-host your own hub instead\n- [Identity & Keys](/docs/guides/identity/) — how passkeys and `did:key` work\n- [Electron Setup](/docs/guides/electron/) — the desktop app","src/content/docs/docs/guides/cloud-connect.mdx","90b34d2de426cbef","docs/guides/collaboration",{id:276,data:278,body:284,filePath:285,digest:286,deferredRender:16},{title:279,description:280,editUrl:16,head:281,template:18,sidebar:282,pagefind:16,draft:21},"Real-time Collaboration","Building collaborative editors with useNode, TipTap, and awareness.",[],{order:113,hidden:21,attrs:283},{},":::note[You will learn]\n\n- How `useNode` enables real-time collaborative editing\n- How Yjs CRDTs handle concurrent text edits\n- How to display cursor presence with awareness\n- The dual-write model for properties vs. rich text\n  :::\n\n## How it works\n\nWhen two users open the same node, xNet automatically synchronizes their edits in real time. Rich text goes through Yjs (character-level CRDT), while properties go through the NodeStore (field-level LWW). Both channels share the same WebSocket connection.\n\n```tsx\nimport { useNode } from '@xnetjs/react'\n\nfunction DocumentEditor({ nodeId }) {\n  const { editor, properties, mutate, peers } = useNode(nodeId)\n\n  return (\n    <div>\n      <h1>{properties.title}</h1>\n      <RichTextEditor editor={editor} />\n      <PeerAvatars peers={peers} />\n    </div>\n  )\n}\n```\n\n### The dual-write model\n\n`useNode` manages two sync channels simultaneously:\n\n| Channel        | Data                          | CRDT                | How to write              |\n| -------------- | ----------------------------- | ------------------- | ------------------------- |\n| Editor content | Rich text, blocks, embeds     | Yjs `Y.XmlFragment` | Type in the TipTap editor |\n| Properties     | Title, status, assignee, etc. | Lamport LWW         | Call `mutate.update()`    |\n\nThese channels are bridged one-way by the MetaBridge: property changes in NodeStore are reflected in the Y.Doc's metadata map, but Yjs updates never write back to NodeStore. This prevents malicious Yjs payloads from corrupting structured data.\n\n## Yjs CRDT merging\n\nYjs uses a character-level CRDT algorithm that handles concurrent edits without conflicts:\n\n- **Same paragraph, different positions** — edits merge cleanly\n- **Same character position** — Yjs uses internal ordering rules (clientID + sequence number) to produce a deterministic result\n- **Delete + edit at same position** — the edit wins (insert beats delete in Yjs)\n\nYou don't need to handle conflicts for rich text — Yjs resolves everything automatically.\n\n## Cursor awareness\n\nYjs provides an `Awareness` protocol for sharing ephemeral state like cursor positions and user information. xNet hooks into this through `useNode`:\n\n```tsx\nfunction DocumentEditor({ nodeId }) {\n  const { editor, awareness } = useNode(nodeId)\n\n  // TipTap's collaboration extension handles awareness rendering\n  // automatically when you provide the awareness instance\n}\n```\n\nAwareness data includes:\n\n- Cursor position and selection range\n- User name and color\n- Online/offline status\n\nAwareness state is ephemeral — it's not persisted and not signed. It's purely for real-time presence display.\n\n## Property collaboration\n\nWhen multiple users edit the same property simultaneously, the last write wins based on Lamport timestamp ordering:\n\n```tsx\nfunction TaskHeader({ nodeId }) {\n  const { properties, mutate } = useNode(nodeId)\n\n  const updateTitle = (newTitle: string) => {\n    mutate.update({ title: newTitle })\n    // This creates a signed Change with a Lamport timestamp\n    // If another peer writes at the same time, the higher\n    // timestamp wins. DID breaks ties deterministically.\n  }\n\n  return <input value={properties.title} onChange={(e) => updateTitle(e.target.value)} />\n}\n```\n\n:::tip\nFor title fields and other frequently-edited properties, consider debouncing updates to reduce change volume:\n\n```ts\nconst debouncedUpdate = useDebouncedCallback((title: string) => {\n  mutate.update({ title })\n}, 300)\n```\n\n:::\n\n## Multi-user patterns\n\n### Sync indicator\n\nShow users when their changes are synced:\n\n```tsx\nimport { useNode } from '@xnetjs/react'\n\nfunction SyncStatus({ nodeId }) {\n  const { syncState } = useNode(nodeId)\n\n  switch (syncState) {\n    case 'synced':\n      return <span>All changes saved</span>\n    case 'syncing':\n      return <span>Syncing...</span>\n    case 'offline':\n      return <span>Working offline</span>\n  }\n}\n```\n\n### List + detail with background sync\n\nTrack nodes so they sync even when the editor isn't open:\n\n```tsx\nfunction TaskList() {\n  const { data: tasks } = useQuery(TaskSchema)\n  const sync = useSyncManager()\n\n  // Track all visible tasks for background sync\n  useEffect(() => {\n    tasks.forEach((t) => sync.track(t.id, TaskSchema._schemaId))\n  }, [tasks])\n\n  return tasks.map((t) => <TaskRow key={t.id} task={t} />)\n}\n```\n\n### Handling offline → online transitions\n\nWhen connectivity is restored, the offline queue drains automatically. You don't need to handle this manually — `useNode` and `useQuery` will re-render with the merged state. See the [Offline Patterns](/docs/guides/offline/) guide for details.\n\n## TipTap integration\n\nxNet's editor package (`@xnetjs/editor`) wraps TipTap with Yjs collaboration pre-configured. When you use the editor through `useNode`, the following extensions are active:\n\n- **Collaboration** — Yjs document binding\n- **CollaborationCursor** — Remote cursor rendering\n- **All standard TipTap extensions** — Headings, lists, code blocks, etc.\n- **Plugin-contributed extensions** — Any `EditorContribution` from the plugin system\n\nThe editor instance returned by `useNode` is a standard TipTap `Editor` — you can use any TipTap API on it.\n\n## Security model\n\nAll collaborative data is cryptographically secured:\n\n1. **Signed changes** — Every property mutation is signed with Ed25519 and linked into a hash chain\n2. **Signed Yjs updates** — Editor content updates are wrapped in `SignedYjsEnvelope` with BLAKE3 + Ed25519\n3. **ClientID attestation** — Yjs clientIDs are cryptographically bound to DIDs\n4. **Peer scoring** — Peers that send invalid data get penalized and eventually blocked\n5. **Rate limiting** — Per-peer limits prevent flooding (30 updates/sec, 1 MB max size)\n\nSee the [Sync Guide](/docs/guides/sync/) for the full security architecture.","src/content/docs/docs/guides/collaboration.mdx","5fdff25fa6bd4a20","docs/guides/dashboards",{id:287,data:289,body:295,filePath:296,digest:297,deferredRender:16},{title:290,description:291,editUrl:16,head:292,template:18,sidebar:293,pagefind:16,draft:21},"Dashboards & Widgets","Widget boards over live workspace data — built-ins, charts, plugin widgets, and sandboxed user widgets.",[],{hidden:21,attrs:294},{},":::note[You will learn]\n\n- How dashboards, widgets, and dashboard variables fit together\n- The built-in widget catalog (metrics, tables, charts, feeds)\n- The widget contract for plugin authors\n- How user-written widgets are sandboxed\n  :::\n\n## Overview\n\nA dashboard is a node like any other: a grid of **widget instances** with\nper-breakpoint layouts, opened as a workbench tab (`/dashboard/$dashboardId`).\nWidgets are declarative — a widget describes *what data it needs* as a saved-view\nquery and *how to render it*; the runtime executes the query reactively, so a\ntask created anywhere in the workspace updates a live widget immediately.\nWidgets never touch the store directly.\n\n## Dashboard variables\n\nDashboards carry variables — most importantly a **time range** — that the\nruntime interpolates into every widget's query (`$name` placeholders). Change\nthe range once and every widget on the board re-queries.\n\n## Built-in widgets\n\n| Widget            | Shows                                                       |\n| ----------------- | ----------------------------------------------------------- |\n| Metric            | A single aggregate (count, sum, average) over a query       |\n| Task list         | Tasks matching a filter, editable inline                    |\n| Saved-view table  | Any saved view, in compact table form                       |\n| Bar / line / area / pie charts | Aggregates by property, via ECharts            |\n| Social feed       | Recent items from the saved-content graph                   |\n| Page links        | A curated set of page references                            |\n| Recent items      | Recently touched nodes across the workspace                 |\n| Pin board         | Your pinned nodes                                           |\n| Mini calendar     | A month view of dated items                                 |\n\nAdd widgets from the picker; each widget's configuration panel is\nauto-generated from its declared config fields (property pickers, query\nfilters, display options).\n\n## The widget contract\n\nA widget definition is Grafana-shaped — manifest, config fields, query,\nrenderer:\n\n```ts\nimport type { WidgetDefinition } from '@xnetjs/dashboard'\n\nconst taskCountWidget: WidgetDefinition = {\n  manifest: { id: 'task-count', name: 'Open task count', icon: 'check' },\n  configFields: [\n    { key: 'project', type: 'node-ref', label: 'Project', schema: 'project' }\n  ],\n  query: (config, vars) => ({\n    schema: 'task',\n    filter: { project: config.project, status: { not: 'done' } },\n    range: vars.timeRange\n  }),\n  Renderer: ({ rows }) => <Metric value={rows.length} />\n}\n```\n\nPlugins register widgets with a `WidgetContribution`. The same definition also\nrenders **on canvases** — any widget can be dropped onto a canvas as a live\ncard.\n\n## Trust tiers and sandboxing\n\nThe widget *host* assigns a trust tier — a widget can never self-declare one:\n\n| Tier          | Source                    | Isolation                                              |\n| ------------- | ------------------------- | ------------------------------------------------------ |\n| `built-in`    | Ships with the app        | None needed                                            |\n| `plugin`      | Installed extension       | Plugin permission model                                |\n| `user`        | Written in the in-app editor | SES `lockdown()` + per-widget `Compartment` in a Web Worker |\n| `marketplace` | Third-party               | Sandboxed iframe (`allow-scripts` only)                |\n\nUser-tier widgets render through **safe node trees** materialized via tag and\nstyle allowlists — no `window`, `document`, `fetch`, or store access; runaway\ncode is terminated and the worker respawned. Permission prompts appear when\nyou add a widget that requests capabilities.\n\n## Writing your own widget in-app\n\nThe widget editor (a regular tab) persists your code as a node and registers\nit as a `user`-tier widget — edit, save, and watch it render sandboxed on the\nboard. It syncs like any other node, so your custom widgets follow you across\ndevices.\n\n## Further reading\n\n- [The Workbench](/docs/guides/workbench/) — dashboards as tabs\n- [Plugins](/docs/guides/plugins/) — registering `WidgetContribution`s\n- [Canvas](/docs/guides/canvas/) — widget cards on the infinite canvas","src/content/docs/docs/guides/dashboards.mdx","589ed66a498b2d17","docs/guides/devtools",{id:298,data:300,body:307,filePath:308,digest:309,deferredRender:16},{title:301,description:302,editUrl:16,head:303,template:18,sidebar:304,pagefind:16,draft:21},"DevTools","Built-in debug panels for inspecting sync, data, and performance.",[],{order:305,hidden:21,attrs:306},9,{},":::note[You will learn]\n\n- How to enable and use the debug panels (9 core + AuthZ panel)\n- What each panel shows and how to read it\n- The event bus instrumentation system\n- How to integrate DevTools into your app\n  :::\n\n## Quick start\n\nWrap your app with `XNetDevToolsProvider`. In production builds, it tree-shakes to zero bytes.\n\n```tsx\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n\n<XNetProvider config={...}>\n  <XNetDevToolsProvider>\n    <App />\n  </XNetDevToolsProvider>\n</XNetProvider>\n```\n\n**Toggle:** `Ctrl+Shift+D` (or `Cmd+Shift+D` on Mac), or click the floating wrench button.\n\n## The panels\n\n### Nodes\n\nBrowse every node in the NodeStore. Features:\n\n- Full-text search across IDs, schemas, and properties\n- Filter by schema type\n- Show/hide deleted nodes\n- Click a node to see its full properties, timestamps, and author DID\n- Copy all nodes as JSON\n\nData refreshes every 2 seconds and on live store events.\n\n### Changes\n\nChronological timeline of all mutations with Lamport clock ordering:\n\n- Color-coded by operation: green (create), blue (update), red (delete), yellow (restore), purple (remote), amber (conflict)\n- Filter by node ID or event type\n- Auto-scroll toggle to follow new events\n- Click any change for the full JSON payload\n\nKeeps the last 1000 events.\n\n### Sync\n\nP2P connection status and peer monitoring:\n\n- Connection status indicator (connected/connecting/disconnected/error)\n- Peer list with connection times\n- Sent/received/error counters\n- Scrolling event log with timestamps\n- Toggle sync debug logging (`localStorage xnet:sync:debug`)\n\n### Yjs\n\nY.Doc structure inspector with three sub-views:\n\n- **Updates** — Live stream of Yjs update events with local/remote indicators and byte sizes\n- **Structure** — Interactive tree view of Y.Doc shared types (Map, Array, Text, XmlFragment). Expandable nodes, color-coded by type, depth-limited to 5 levels.\n- **State Vectors** — ClientID clock values with progress bars. Shows how far each peer has synced.\n\nSelect a document from the sidebar to inspect its internals.\n\n### Queries\n\nPerformance profiler for all active hooks:\n\n- Lists every `useQuery`, `useMutate`, and `useNode` instance\n- Shows schema, mode (list/single/filtered/document), caller source location\n- Tracks update count, result count, average and peak render time\n- Warnings: amber for >16ms (dropped frame), red for >50ms\n- Sort by most updates, slowest render, or most recent\n\nSource locations are extracted from stack traces automatically.\n\n### Telemetry\n\nSecurity events and performance metrics, split into three tabs:\n\n- **Security** — Network health score, crash entries, security events by severity, peer reputation scores with breakdown\n- **Performance** — Metric groups with bucket distribution charts (time ranges: \\<10ms, 10-50ms, 50-100ms, etc.)\n- **Consent** — Current telemetry tier (off/local/crashes/anonymous)\n\n### Schemas\n\nAll registered schemas and their properties:\n\n- Schema list with node counts and property counts\n- Property details: type (color-coded), required flag, config summary\n- Raw schema JSON dump\n- Built-in vs. user-defined badges\n\n### Seed\n\nCreate sample data for testing:\n\n- **Create Sample Page** — Rich document with headings, lists, callouts, code blocks, Mermaid diagrams, comments with text anchors, and change history\n- **Create Sample Database** — 15-column database with all property types, 5 rows, view configs, and comments\n\n### History\n\nFull change history and time travel for individual nodes. Seven sub-tabs:\n\n- **Timeline** — Scrub through all changes with a slider. See materialized state at any point.\n- **Diff** — Compare two points in time. Shows added/modified/removed properties with before/after values.\n- **Blame** — Per-property attribution: who last changed each field, when, and how many times.\n- **Audit** — Filterable audit log with operation breakdown (create/update/delete/restore).\n- **Verification** — Check hash chain integrity. Reports valid/invalid, verified hashes, chain links, forks.\n- **Storage** — Storage metrics, prunable changes, estimated recovery bytes.\n- **Document** — Yjs snapshot timeline. Compare snapshots with size deltas and content diffs.\n\n### AuthZ\n\nLive authorization inspector for the [encryption-first access control system](/docs/guides/authorization/). Five sub-tabs:\n\n- **Playground** — Test `store.auth.can()` interactively. Select a node and action, see the decision with a full explanation trace including role resolution steps.\n- **Grants** — All active grants for the selected node: grantee DID, actions, expiry, and revocation controls. Create new grants directly from this panel.\n- **Timeline** — Chronological log of grant changes — created, revoked, expired — with timestamps and actor DIDs.\n- **Delegation tree** — Visual tree of UCAN delegation chains. Shows the full proof hierarchy with depth indicators and attenuation warnings.\n- **Revocation propagation** — Tracks revocation events across peers: which peers have received and applied a revocation, with timing deltas.\n\n## Configuration\n\n```tsx\n<XNetDevToolsProvider\n  defaultOpen={false}           // Start open\n  defaultPanel=\"nodes\"          // Initial panel\n  position=\"bottom\"             // 'bottom' | 'right' | 'floating'\n  height={320}                  // Panel height in pixels\n  maxEvents={10_000}            // Ring buffer capacity\n  telemetryCollector={collector}\n  consentManager={consentMgr}\n>\n```\n\n### Toggle methods\n\n| Method                   | Description                       |\n| ------------------------ | --------------------------------- |\n| `Ctrl+Shift+D`           | Keyboard shortcut                 |\n| Floating button          | Click the wrench icon (draggable) |\n| 4-finger tap             | Mobile                            |\n| `useDevTools().toggle()` | Programmatic                      |\n\n### Persistence\n\nThe panel remembers its state in `localStorage`:\n\n- `xnet:devtools:open` — open/closed\n- `xnet:devtools:panel` — last active tab\n- `xnet:devtools:position` — dock position\n\n## Event bus\n\nAll instrumentation flows through a `DevToolsEventBus` — a typed ring buffer (default 10,000 events):\n\n```ts\nconst { eventBus } = useDevTools()\n\n// Subscribe to all events\neventBus.subscribe((event) => console.log(event))\n\n// Subscribe to a specific type\neventBus.on('sync:peer-connected', (event) => { ... })\n\n// Query\neventBus.getEventsByType('store:create')\neventBus.getEventsForNode(nodeId)\neventBus.getRecent(50)\n```\n\n### Event categories\n\n| Category      | Events                                                                                                                                   |\n| ------------- | ---------------------------------------------------------------------------------------------------------------------------------------- |\n| Store (7)     | `store:create`, `store:update`, `store:delete`, `store:restore`, `store:transaction`, `store:remote-change`, `store:conflict`            |\n| Sync (6)      | `sync:status-change`, `sync:peer-connected`, `sync:peer-disconnected`, `sync:change-received`, `sync:broadcast`, `sync:error`            |\n| Yjs (4)       | `yjs:update`, `yjs:meta-change`, `yjs:state-vector`, `yjs:provider-status`                                                               |\n| Query (6)     | `query:subscribe`, `query:unsubscribe`, `query:result`, `query:error`, `mutate:start`, `mutate:complete`                                 |\n| Telemetry (6) | `telemetry:crash`, `telemetry:usage`, `telemetry:security`, `telemetry:performance`, `telemetry:consent-change`, `telemetry:peer-scores` |\n\n### Instrumentation wiring\n\nInstrumentation functions connect data sources to the event bus:\n\n```ts\ninstrumentStore(store, eventBus) // NodeStore events\ninstrumentSync(provider, room, bus) // SyncProvider events\ninstrumentYDoc(doc, docId, bus) // Y.Doc updates\ninstrumentTelemetry(collector, consent, bus) // Telemetry\n```\n\nReact hooks (`useQuery`, `useNode`) automatically report to DevTools when the provider is present, via `InstrumentationContext`. No manual wiring needed.\n\n## useDevTools hook\n\n```ts\nconst {\n  isOpen,\n  toggle,\n  eventBus,\n  activeNodeId,\n  setActiveNodeId,\n  activePanel,\n  setActivePanel,\n  store,\n  yDocRegistry\n} = useDevTools()\n```\n\n## Production behavior\n\nWhen `NODE_ENV` is `production`, the DevTools provider renders children unchanged and `useDevTools()` returns inert stubs. The full panel code is tree-shaken out of the bundle — zero bytes in production.","src/content/docs/docs/guides/devtools.mdx","9eb6f6b225323ce9","docs/guides/editor",{id:310,data:312,body:319,filePath:320,digest:321,deferredRender:16},{title:313,description:314,editUrl:16,head:315,template:18,sidebar:316,pagefind:16,draft:21},"Rich Text Editor","TipTap editor with Yjs collaboration, slash commands, and plugin extensions.",[],{order:317,hidden:21,attrs:318},11,{},":::note[You will learn]\n\n- The editor component and its props\n- All built-in extensions (20+)\n- Slash commands and the floating toolbar\n- How plugins contribute editor extensions\n- Yjs collaboration and cursor presence\n  :::\n\n## Overview\n\n`@xnetjs/editor` is a collaborative rich text editor built on TipTap v3 with Yjs for real-time CRDT sync. It provides three entry points:\n\n| Import                    | Contents                                 |\n| ------------------------- | ---------------------------------------- |\n| `@xnetjs/editor`            | Core `Editor` class (framework-agnostic) |\n| `@xnetjs/editor/react`      | React components, hooks, node views      |\n| `@xnetjs/editor/extensions` | All TipTap extensions and utilities      |\n\n## RichTextEditor component\n\n```tsx\nimport { RichTextEditor } from '@xnetjs/editor/react'\n\n<RichTextEditor\n  ydoc={ydoc}                          // Required: Yjs document\n  field=\"content\"                       // Y.XmlFragment field name\n  placeholder=\"Start writing...\"\n  awareness={awareness}                 // Cursor presence\n  did={myDID}                           // Local user's DID for cursor color\n  showToolbar={true}\n  readOnly={false}\n  extensions={pluginExtensions}         // Additional TipTap extensions\n  slashCommands={customCommands}        // Custom slash commands\n  onNavigate={(docId) => router.push(`/doc/${docId}`)}\n  onImageUpload={handleImageUpload}\n  onFileUpload={handleFileUpload}\n  onEditorReady={(editor) => { ... }}\n/>\n```\n\n## Built-in extensions\n\n### Block types\n\n| Block           | Description                                                               | Input             |\n| --------------- | ------------------------------------------------------------------------- | ----------------- |\n| Paragraph       | Default text block                                                        | —                 |\n| Heading (1-6)   | Section headings with `#` syntax preview                                  | `# `, `## `, etc. |\n| Code Block      | Syntax-highlighted code with language selector                            | ` ``` `           |\n| Blockquote      | Quote with `>` prefix preview                                             | `> `              |\n| Bullet List     | Unordered list                                                            | `- ` or `* `      |\n| Ordered List    | Numbered list                                                             | `1. `             |\n| Task List       | Checkbox list with nesting                                                | `[ ] `            |\n| Horizontal Rule | Divider                                                                   | `---`             |\n| Image           | CID-based with paste/drop upload, resize handles, alignment               | Paste or `/image` |\n| File            | Generic file attachment with upload progress                              | Drop or `/file`   |\n| Embed           | Auto-embed for YouTube, Vimeo, Spotify, Twitter, Figma, CodeSandbox, Loom | Paste URL         |\n| Callout         | 6 types (info, tip, warning, caution, note, quote), collapsible           | `> [!info]`       |\n| Toggle          | Collapsible details/summary sections                                      | `> [toggle]`      |\n| Database Embed  | Inline database views (table/board/list/calendar/gallery/timeline)        | `/database`       |\n| Mermaid         | Diagram blocks (via plugin)                                               | ` ```mermaid `    |\n\n### Marks\n\nBold, italic, strikethrough, code, link, wikilink (`[[page-name]]`), and comment.\n\n### Live preview\n\nObsidian-style inline markdown syntax rendering — bold markers (`**`), italic (`*`), strikethrough (`~~`), and code (`` ` ``) are shown as decorations while typing and hidden when the cursor moves away.\n\n## Slash commands\n\nType `/` to open the command palette. Built-in command groups:\n\n- **Basic Blocks** — Text, H1, H2, H3\n- **Lists** — Bullet, Numbered, Task\n- **Blocks** — Quote, Code Block, Divider\n- **Media** — Image, File, Embed\n- **Callouts** — Info, Tip, Warning, Caution, Note\n- **Toggles** — Toggle section\n- **Data** — Database\n\nPlugins can add custom slash commands via `contributes.slashCommands`.\n\n## Floating toolbar\n\nThe toolbar appears on text selection:\n\n- **Desktop** — Bubble menu floating near the selection\n- **Mobile** — Fixed bottom bar, horizontally scrollable\n\nBuilt-in buttons: Bold, Italic, Strike, Code, Comment | H1, H2, H3 | Bullet, Ordered, Task | Quote, Code Block, Divider.\n\nPlugins can add toolbar buttons via `EditorContribution.toolbar`.\n\n## Drag and drop\n\nThree integrated plugins handle block-level drag and drop:\n\n- **DragHandle** — Shows a grip icon on hover at the left edge of blocks\n- **DragDropPlugin** — Handles block reordering via drag\n- **DropIndicator** — Shows a visual insertion line during drag\n\n## Yjs collaboration\n\nThe editor binds to a `Y.XmlFragment` inside the Y.Doc via TipTap's `Collaboration` extension. When you pass an `awareness` instance, cursor presence is shown automatically:\n\n- Remote cursors rendered as colored carets with DID-derived identicon avatars\n- Selections shown as translucent highlights in the user's color\n- Hover over a cursor to see the user label\n\n### Comment anchors\n\nComments are positioned using Yjs relative positions (`captureTextAnchor` / `resolveTextAnchor`). This means comment positions survive concurrent edits — if someone inserts text before your comment, the anchor moves with the text.\n\n## Plugin extensions\n\nPlugins contribute editor extensions through the contribution system:\n\n```ts\n// In a plugin manifest\ncontributes: {\n  editorExtensions: [{\n    id: 'my-extension',\n    extension: MyTipTapExtension,\n    priority: 100,\n    toolbar: {\n      icon: MyIcon,\n      title: 'My Tool',\n      group: 'insert',\n      action: (editor) => editor.chain().focus().insertMyThing().run()\n    }\n  }],\n  slashCommands: [{\n    id: 'my-command',\n    name: 'My Block',\n    execute: ({ editor, range }) => { ... }\n  }]\n}\n```\n\nThe Electron app collects plugin extensions via `useEditorExtensionsSafe()` and passes them to `<RichTextEditor extensions={...} />`. Plugin extensions are loaded before the editor mounts to prevent crashes when Yjs content contains nodes from unregistered extensions.\n\n## Embed providers\n\nURLs pasted into the editor are automatically detected and embedded for 7 services:\n\n| Provider    | URL Pattern                     |\n| ----------- | ------------------------------- |\n| YouTube     | `youtube.com/watch`, `youtu.be` |\n| Vimeo       | `vimeo.com`                     |\n| Spotify     | `open.spotify.com`              |\n| Twitter/X   | `twitter.com`, `x.com`          |\n| Figma       | `figma.com`                     |\n| CodeSandbox | `codesandbox.io`                |\n| Loom        | `loom.com`                      |\n\n## Further reading\n\n- [Collaboration Guide](/docs/guides/collaboration/) — Real-time editing patterns\n- [Plugin Development](/docs/guides/plugins/) — Contributing editor extensions\n- [useNode](/docs/hooks/usenode/) — The hook that provides the editor","src/content/docs/docs/guides/editor.mdx","dbbab6f5cb90d6a8","docs/guides/electron",{id:322,data:324,body:330,filePath:331,digest:332,deferredRender:16},{title:325,description:326,editUrl:16,head:327,template:18,sidebar:328,pagefind:16,draft:21},"Electron Setup","Running xNet in an Electron desktop app.",[],{order:148,hidden:21,attrs:329},{},":::note[You will learn]\n\n- How the Electron app architecture works (main process, renderer, IPC)\n- How to run the dev server and test sync with two instances\n- How the Background Sync Manager (BSM) provides process-level sync\n- How plugin services and the Local API work in Electron\n  :::\n\n## Architecture\n\nThe xNet Electron app splits work between two processes:\n\n```\n┌─────────────────────┐     IPC / MessagePort     ┌────────────────────────┐\n│   Main Process      │◄─────────────────────────►│   Renderer Process     │\n│                     │                            │                        │\n│  BSM (sync manager) │                            │  React app + hooks     │\n│  ProcessManager     │                            │  TipTap editor         │\n│  LocalAPIServer     │                            │  IPCSyncManager        │\n│  MCPServer          │                            │  ServiceClient         │\n│  WebSocket client   │                            │  DevTools panels       │\n└─────────────────────┘                            └────────────────────────┘\n```\n\n**Main process** — Runs the Background Sync Manager, manages child processes, hosts the Local API and MCP servers. Maintains its own Y.Doc pool and WebSocket connection to the signaling server.\n\n**Renderer process** — Runs the React UI. Communicates with the main process via IPC for sync operations. Maintains mirror Y.Docs for editor binding.\n\n### Why this split?\n\nSync is CPU-intensive (BLAKE3 hashing, Ed25519 signing, Yjs encoding). Running it in the main process keeps the renderer responsive. The BSM also survives renderer crashes and can sync in the background when no window is open.\n\n## Running the dev server\n\n```bash\ncd apps/electron && pnpm dev\n```\n\nThis starts:\n\n1. The Vite dev server on `http://localhost:5177`\n2. The signaling server on port `4444`\n3. The Electron app\n\n### Two-instance sync testing\n\n```bash\ncd apps/electron && pnpm dev:both\n```\n\nThis launches two Electron windows connected to the same signaling server. Edits in one window appear in the other in real time.\n\n## Background Sync Manager (BSM)\n\nThe BSM (`apps/electron/src/main/bsm.ts`) is the Electron-specific sync engine. It runs independently of the renderer lifecycle.\n\n### IPC channels\n\n| Channel            | Direction       | Purpose                                           |\n| ------------------ | --------------- | ------------------------------------------------- |\n| `xnet:bsm:start`   | Renderer → Main | Connect to signaling URL, set signing credentials |\n| `xnet:bsm:acquire` | Renderer → Main | Get a Y.Doc for editing; returns a MessagePort    |\n| `xnet:bsm:release` | Renderer → Main | Done editing a document                           |\n| `xnet:bsm:track`   | Renderer → Main | Add node to background sync set                   |\n| `xnet:bsm:untrack` | Renderer → Main | Remove from background sync                       |\n| `xnet:bsm:status`  | Renderer → Main | Pool/tracked/queue stats                          |\n\n### Document flow\n\nWhen a component calls `useNode(nodeId)`:\n\n1. **Renderer** calls `window.xnetBSM.acquire(nodeId)` via IPC\n2. **BSM** creates a Y.Doc, joins the sync room, creates a `MessageChannelMain`\n3. **Renderer** gets the `MessagePort` and creates a local mirror Y.Doc\n4. **Edits** flow through the MessagePort as binary Yjs updates (zero-copy transfer)\n5. **BSM** signs updates with `signYjsUpdate()` and broadcasts via WebSocket\n6. **Remote updates** are verified (`verifyYjsEnvelope`), applied to BSM doc, forwarded to renderer\n\n### Identity setup\n\nThe renderer passes signing credentials to the BSM on startup:\n\n```ts\n// In the renderer\nconst syncManager = new IPCSyncManager()\nawait syncManager.start(signalingUrl)\nsyncManager.setIdentity(authorDID, signingKey)\n```\n\nThe BSM uses these credentials to sign all outgoing Yjs envelopes.\n\n## IPCSyncManager\n\nThe renderer-side `IPCSyncManager` implements the same `SyncManager` interface as the web version, but routes everything through IPC:\n\n```ts\ninterface SyncManager {\n  start(): Promise<void>\n  stop(): Promise<void>\n  acquire(nodeId): Promise<Y.Doc>\n  release(nodeId): void\n  track(nodeId, schemaId): void\n  untrack(nodeId): void\n  getAwareness(nodeId): Awareness | null\n  readonly status: ConnectionStatus\n  readonly poolSize: number\n  readonly trackedCount: number\n  readonly queueSize: number\n}\n```\n\nThe API is identical whether you're building for Electron or Web. React hooks and components work the same way — the sync manager is swapped at the provider level.\n\n## Plugin services\n\nElectron enables Layer 3 (Services) and Layer 4 (Integrations) of the plugin system:\n\n### ProcessManager\n\nRuns in the main process. Manages child processes with health checks and restart policies:\n\n```ts\n// From a plugin's activate() function\nconst services = createServiceClient()\nawait services.start({\n  id: 'my-analysis-service',\n  name: 'Data Analysis',\n  process: { command: 'python', args: ['server.py'] },\n  lifecycle: { restart: 'on-failure', maxRestarts: 3 },\n  communication: { protocol: 'http', port: 8080 }\n})\n\nconst result = await services.call('my-analysis-service', 'POST', '/analyze', data)\n```\n\n### Local API\n\nREST API on `localhost:31415` for external tools (Raycast, Alfred, shell scripts, etc.):\n\n```bash\ncurl http://localhost:31415/api/v1/nodes?schema=xnet://app/Task\ncurl -X POST http://localhost:31415/api/v1/nodes \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"schema\": \"xnet://app/Task\", \"properties\": {\"title\": \"New task\"}}'\n```\n\n### MCP server\n\nExposes xNet data to AI agents via stdin/stdout JSON-RPC:\n\n```bash\necho '{\"jsonrpc\":\"2.0\",\"id\":1,\"method\":\"tools/list\"}' | xnet-mcp\n```\n\nSee the [Plugin Development](/docs/guides/plugins/) guide for full details on services and integrations.\n\n## DevTools\n\nThe Electron app includes 7 debug panels accessible from the app:\n\n- **Sync** — Connection status, pool state, peer scoring\n- **Store** — NodeStore contents, change history\n- **Schema** — Registered schemas and property types\n- **Identity** — Current DID, key info\n- **Network** — WebSocket messages, peer connections\n- **Plugins** — Registered plugins, contributions, middleware\n- **Performance** — Render timing, sync latency\n\nEnable verbose sync logging:\n\n```js\nlocalStorage.setItem('xnet:sync:debug', 'true')\n```\n\n## Building for production\n\n```bash\ncd apps/electron && pnpm build\n```\n\nThis produces platform-specific binaries. The signaling server URL and other configuration are set via environment variables or the app's settings panel.","src/content/docs/docs/guides/electron.mdx","1cffa74157203b3d","docs/guides/forms",{id:333,data:335,body:341,filePath:342,digest:343,deferredRender:16},{title:336,description:337,editUrl:16,head:338,template:18,sidebar:339,pagefind:16,draft:21},"Forms","Turn any database into a form: build questions from fields, share a public link, and collect responses as rows — without the hub ever writing your data.",[],{hidden:21,attrs:340},{},":::note[You will learn]\n\n- How a form is just another database view\n- Building questions, show-if rules, and the confirmation screen\n- Sharing a public link that needs no xNet account\n- How anonymous submissions become signed rows (the drain model)\n  :::\n\n## A form is a view\n\nOpen any database and add a view of type **Form** (the `+` next to the view\ntabs). Like Notion, the form belongs to the database: every question maps to\na field, and every submission becomes a new row.\n\nThe form view has two tabs:\n\n- **Build** — pick which fields are asked, reorder them, override labels and\n  helper text, mark questions required, and add per-question *show only\n  when…* rules (for example, ask for a deadline only when priority is\n  \"High\"). You also set the submit-button label, the confirmation screen,\n  and the **Accepting responses** toggle here.\n- **Preview** — the live form. Submitting from Preview creates a real row,\n  so workspace members can use it for internal intake immediately.\n\nShow-if rules use the same operators as view filters and are evaluated\nagainst the in-progress answers, so hidden questions never block submission:\na required question that is hidden by its rule is simply not required.\n\nComputed and automatic fields (formula, rollup, created, …) can never be\nasked. Person, relation, and file questions work on workspace forms but are\nexcluded from public ones.\n\n## Sharing a public link\n\nClick **Share form publicly** in the strip above the form. Your device mints\na high-entropy token on your hub and publishes a *sanitized snapshot* of the\nform — just the questions, types, and select options, never your workspace\ndata. The public URL looks like:\n\n```\nhttps://your-app.example/form/<token>?hub=<your-hub>\n```\n\nAnyone with the link can respond — no account, no app install. The page is\ncompletely session-less. The hub stores only a **hash** of the token (like\nshare-link secrets), so the full URL exists only on the device that created\nit. Revoke the link at any time from the same strip; flip **Accepting\nresponses** off to close the form while keeping the link alive.\n\nPublic submissions pass a layered anti-spam gate on the hub: an invisible\nhoneypot field, per-IP rate limits, and a payload size cap.\n\n## How responses become rows\n\nxNet's hub never writes workspace data — every change in the log is signed\nby a user device. Public form submissions therefore land in a durable\n**inbox** on the hub, and one of your signed-in devices *drains* it: each\npending submission is validated against the current fields, written as a\n`DatabaseRow` under your identity, and acknowledged. This usually happens\nwithin a minute of your app being open.\n\nTwo properties of the drain are worth knowing:\n\n- **Idempotent end to end.** The respondent's browser keeps an idempotency\n  nonce, the inbox dedupes on it, and the row id is derived from it — a\n  retried submit, a crashed drain, or two of your devices racing all\n  converge on exactly one row.\n- **Nothing is silently dropped.** If a field was deleted or retyped after\n  someone submitted, the submission is marked *rejected* and kept on the hub\n  for review; the status bar shows a `📥` chip whenever pending or rejected\n  submissions exist.\n\nRows created by a form carry a `submissionMeta` property (`via: 'form'`,\nthe view id, the receive time, and the nonce), so you can filter or audit\nform-created rows like any other data.","src/content/docs/docs/guides/forms.mdx","b7da4c2c00733a57","docs/guides/frameworks",{id:344,data:346,body:352,filePath:353,digest:354,deferredRender:16},{title:347,description:348,editUrl:16,head:349,template:18,sidebar:350,pagefind:16,draft:21},"Use xNet From Any Framework","The xNet data model is framework-agnostic: createXNetClient + liveQuery bind to React, Vue, Svelte, Solid, or vanilla JS. What \"supported\" means, and how to validate a binding.",[],{order:248,hidden:21,attrs:351},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- That the full xNet data model runs **outside React** as a plain object\n- How `client.query()` and `liveQuery()` bind to Vue, Svelte, Solid, or vanilla JS\n- What each framework \"support tier\" actually promises\n- How to validate a binding with `runAdapterConformance`\n  :::\n\n## The data model is framework-agnostic\n\nThe React hooks (`useQuery` / `useMutate` / `useNode`) are a thin binding over a\nheadless runtime, not the only way in. [`@xnetjs/runtime`](/docs/architecture/package-graph/)'s\n`createXNetClient()` constructs and owns the entire data model — authorization,\nvalidation, signing, encryption, SQLite-backed storage, and the live\nquery/mutate/subscribe loop — and imports React **nowhere**:\n\n```ts\nimport { createXNetClient } from '@xnetjs/runtime'\nimport { MemoryNodeStorageAdapter } from '@xnetjs/data'\nimport { generateIdentity } from '@xnetjs/identity'\n\nconst { identity, privateKey } = generateIdentity()\n\nconst client = await createXNetClient({\n  nodeStorage: new MemoryNodeStorageAdapter(), // or a SQLite adapter\n  authorDID: identity.did,\n  signingKey: privateKey\n})\n```\n\n`client.query(schema, options)` returns the universal **`{ getSnapshot, subscribe }`**\ncontract — the exact pair that React's `useSyncExternalStore`, a Svelte store, a\nVue `shallowRef`, a Solid signal, and Angular's `toSignal` all consume.\n`liveQuery()` wraps that pair as a **Svelte store** (`subscribe(run) =>\nunsubscribe`, called immediately and on every change), which every other\nframework can adapt in a few lines.\n\n## Bind it to your framework\n\n<Tabs>\n<TabItem label=\"Vue\">\n\n```ts\nimport { shallowRef, onScopeDispose } from 'vue'\nimport { liveQuery } from '@xnetjs/runtime'\n\nexport function useQuery(client, schema, options) {\n  const lq = liveQuery(client, schema, options)\n  const data = shallowRef(lq.get())\n  const stop = lq.subscribe((v) => (data.value = v))\n  onScopeDispose(() => {\n    stop()\n    lq.destroy()\n  })\n  return data // Ref<NodeState[] | null>\n}\n\nexport function useMutate(client) {\n  return client.mutate // { create, update, delete, restore, transaction }\n}\n```\n\n</TabItem>\n<TabItem label=\"Svelte\">\n\n`liveQuery` already **is** a Svelte store, so `$`-auto-subscription works with no\nadapter at all:\n\n```svelte\n<script>\n  import { liveQuery } from '@xnetjs/runtime'\n  export let client\n  const tasks = liveQuery(client, TaskSchema, { where: { status: 'todo' } })\n</script>\n\n{#each $tasks ?? [] as task}\n  <li>{task.properties.title}</li>\n{/each}\n```\n\nIn Svelte 5 you can wrap the same store in a rune for idiomatic `$state` ergonomics.\n\n</TabItem>\n<TabItem label=\"Solid\">\n\n```ts\nimport { from } from 'solid-js'\nimport { liveQuery } from '@xnetjs/runtime'\n\nexport function createQuery(client, schema, options) {\n  const lq = liveQuery(client, schema, options)\n  return from((set) => {\n    const stop = lq.subscribe(set)\n    return () => {\n      stop()\n      lq.destroy()\n    }\n  })\n}\n```\n\n</TabItem>\n<TabItem label=\"Vanilla\">\n\nNo framework, no adapter package — subscribe directly:\n\n```ts\nimport { liveQuery } from '@xnetjs/runtime'\n\nconst tasks = liveQuery(client, TaskSchema, { where: { status: 'todo' } })\nconst stop = tasks.subscribe((rows) => render(rows ?? []))\n\nawait client.mutate.create(TaskSchema, { title: 'Ship it' }) // re-renders\n\n// later\nstop()\ntasks.destroy()\nawait client.destroy()\n```\n\n</TabItem>\n</Tabs>\n\n## Validate a binding once, everywhere\n\nThe expensive part of multi-framework support isn't _writing_ a binding — it's\nproving every binding behaves identically, forever. So the behaviour is tested\n**once**, framework-agnostically. `runAdapterConformance(makeClient)` runs the\nreactive data contract against any client factory and **throws on the first\nfailed check**:\n\n```ts\nimport { runAdapterConformance } from '@xnetjs/runtime'\nimport { MemoryNodeStorageAdapter } from '@xnetjs/data'\n\nawait runAdapterConformance((overrides) =>\n  createXNetClient({\n    nodeStorage: new MemoryNodeStorageAdapter(),\n    authorDID,\n    signingKey,\n    ...overrides\n  })\n)\n```\n\nIt asserts that:\n\n- a live query delivers an **immediate** snapshot, then **updates on `mutate`**\n- it **stops delivering after unsubscribe**\n- a one-shot `fetch` **round-trips** a write\n- the **authorization surface is reachable and denial surfaces**\n- **`destroy()` is idempotent**\n\nA framework adapter reuses this suite and adds only a tiny render-harness test\n(\"the ref/store/signal reflects the snapshot and re-renders\") — it never\nre-tests xNet's semantics.\n\n## What \"supported\" means\n\nBinding the data layer is cheap; carrying a full per-framework **component**\nlibrary is not. So support is layered, and the layers promise different things:\n\n| Tier       | Surface                                              | What you get                                                                            |\n| ---------- | ---------------------------------------------------- | --------------------------------------------------------------------------------------- |\n| **Tier 0** | `@xnetjs/runtime` — `createXNetClient` + `liveQuery` | Works with **every** framework, headless and conformance-gated. This page.              |\n| **Tier 1** | `@xnetjs/react` — hooks **and** components           | First-class: the full hook + component toolkit the app itself uses.                     |\n| **Tier 2** | thin Vue / Svelte data-binding adapters              | `useQuery` / `useMutate` only — **data binding, not components** — published on demand. |\n| **—**      | components in non-React frameworks                   | **Not offered.** The component kit is React by design.                                  |\n\n:::tip\nBuilding UI in Vue or Svelte? You get the **data** — live queries, mutations,\nauth, sync — through the runtime. You build (or bring) your own components. The\nReact app's components are not portable, and that's intentional: it keeps one\ncomponent ecosystem honest rather than three half-maintained ones.\n:::\n\nSee [`docs/explorations/0237`](https://github.com/crs48/xNet/tree/main/docs/explorations)\nfor the full cost/benefit analysis behind this policy.\n\n**Not using JavaScript at all?** xNet also has native **Swift** and **Rust**\nimplementations of the protocol. See [Languages & SDKs](/docs/languages/overview/)\nfor the full picture.","src/content/docs/docs/guides/frameworks.mdx","bf0598c8192de355","docs/guides/hub",{id:355,data:357,body:363,filePath:364,digest:365,deferredRender:16},{title:358,description:359,editUrl:16,head:360,template:18,sidebar:361,pagefind:16,draft:21},"Hub Setup","Deploy a Hub for always-on sync, encrypted backup, and team access.",[],{order:271,hidden:21,attrs:362},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- What the Hub does and why you might want one\n- How to deploy a Hub in under 2 minutes\n- How to connect your app to a Hub\n- How to monitor and manage your Hub\n  :::\n\n## What is the Hub?\n\nxNet works fully peer-to-peer — no server required. A Hub improves availability and adds services that are hard on mobile devices:\n\n| Without Hub                          | With Hub                           |\n| ------------------------------------ | ---------------------------------- |\n| Sync only when both peers are online | Sync anytime — Hub bridges the gap |\n| No backup                            | Encrypted backup (zero-knowledge)  |\n| No full-text search across devices   | Server-side FTS5 search            |\n| P2P only                             | P2P when possible, Hub when not    |\n\nThe Hub never sees your plaintext data. It stores encrypted updates and relays them to your devices.\n\n```mermaid\nflowchart LR\n  A[Device A] <-->|P2P| B[Device B]\n  A <-->|Hub Relay| H[Hub]\n  B <-->|Hub Relay| H\n```\n\n## Quick Start: Deploy on Railway\n\nThe fastest way to get a Hub running. No Docker, no SSH, no TLS setup.\n\n[![Deploy on Railway](https://railway.app/button.svg)](https://railway.app/template/xnet-hub)\n\n**What happens:**\n\n1. Railway clones the xNet repo\n2. Builds the Hub from its Dockerfile\n3. Creates a persistent volume for SQLite + blobs\n4. Gives you a URL: `hub-xyz.up.railway.app`\n\n**Cost:** $0-2/month for a personal Hub (covered by Railway's $5 Hobby credit).\n\n### After Deploying\n\nYour Hub is live. Copy the URL and configure your app:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n;<XNetProvider\n  config={{\n    hubUrl: 'wss://hub-xyz.up.railway.app'\n  }}\n>\n  <XNetDevToolsProvider>\n    <App />\n  </XNetDevToolsProvider>\n</XNetProvider>\n```\n\n## Platform Comparison\n\n| Platform | Best for                   | Typical cost | Notes                           |\n| -------- | -------------------------- | ------------ | ------------------------------- |\n| Railway  | One-click, lowest friction | $0-2/mo      | Ideal default for personal Hubs |\n| Fly.io   | Auto-suspend, global edge  | $2-6/mo      | Suspend/resume adds ~2s wake    |\n| VPS      | Full control               | $4-5/mo      | You manage TLS + upgrades       |\n\n## Alternative Deployments\n\n<Tabs>\n  <TabItem label=\"Fly.io\">\n    Best for auto-suspend cost savings or multi-region experiments.\n\n    ```bash\n    # Install Fly CLI\n    curl -L https://fly.io/install.sh | sh\n    fly auth login\n\n    # Deploy\n    cd packages/hub\n    fly launch --no-deploy\n    fly volumes create xnet_hub_data --size 1 --region sjc\n    fly deploy\n    ```\n\n    Cost: ~$2-6/month depending on usage. Machines can auto-suspend when idle.\n\n    For multi-region (future), add additional regions and volumes, then enable hub federation for query routing.\n\n  </TabItem>\n\n  <TabItem label=\"VPS (Docker)\">\n    Best for full control or predictable cost.\n\n    ```bash\n    docker run -d \\\n      --name xnet-hub \\\n      -p 4444:4444 \\\n      -v xnet-hub-data:/data \\\n      --restart unless-stopped \\\n      ghcr.io/crs48/xnet-hub:latest\n    ```\n\n    You'll need to configure TLS yourself (Caddy, nginx, or Cloudflare Tunnel).\n\n    Cost: $4-5/month for a basic VPS (Hetzner, DigitalOcean).\n\n  </TabItem>\n\n  <TabItem label=\"Local\">\n    Best for development and testing.\n\n    ```bash\n    npx @xnetjs/hub --port 4444 --data ~/.xnet-hub\n    ```\n\n    No TLS, no persistence guarantees. Use for local development only.\n\n  </TabItem>\n</Tabs>\n\n## Configuration\n\n### Environment Variables\n\n| Variable                    | Default           | Description                                   |\n| --------------------------- | ----------------- | --------------------------------------------- |\n| `PORT`                      | `4444`            | Listen port (Railway injects this)            |\n| `HUB_DATA_DIR`              | `./xnet-hub-data` | SQLite + blob storage directory               |\n| `HUB_LOG_LEVEL`             | `info`            | Log verbosity: debug, info, warn, error       |\n| `HUB_PUBLIC_URL`            | —                 | Public URL for discovery + federation         |\n| `RAILWAY_VOLUME_MOUNT_PATH` | —                 | Auto-set by Railway when a volume is attached |\n| `XNET_DIAGNOSTICS_URL`      | —                 | Opt-in: upstream sink for scrubbed crash reports (see below) |\n| `XNET_DIAGNOSTICS_SECRET`   | —                 | Opt-in: shared secret for diagnostics sharing |\n| `XNET_DIAGNOSTICS_INBOX`    | `open`            | Crash inbox mode: `open`, `authed`, or `off`  |\n| `XNET_SHARE_CRASH_COUNTS`   | —                 | Opt-in: tee fingerprint-level crash *counts* upstream |\n\n### Your hub is your crash console (default on)\n\nEvery hub runs a first-party **diagnostics inbox**: your deployment's own\nclients report crashes to `POST /diagnostics/ingest` on *your* hub, and the\nreports go nowhere else. The quarantine lives in its own `diagnostics.db`\n(8 KB per report, deduplicated by fingerprint, 30-day retention for handled\nreports, hard row cap), and the operator drains it from the app — **Settings →\nPrivacy &amp; Diagnostics → Import reports** — into a Diagnostics Space where\nthe workbench is the triage console (Inbox / By release / By fingerprint saved\nviews, a `new → acked → fixed → released` status field, comments).\n\nThe ingest is rate-limited per client IP and accepts only allowlisted,\nlength-bounded, twice-scrubbed fields. Set `XNET_DIAGNOSTICS_INBOX=authed` to\nrequire authentication for it on hubs exposed to the open internet, or `off`\nto disable the inbox entirely.\n\nEscalation to xNet is a separate, layered choice — three switches, each off\nby default:\n\n1. **Send one report** — from the console, \"Send to xNet\" previews the exact\n   payload and forwards it through the sharing route below. Requires sharing\n   to be configured; without it, the route does not exist.\n2. **Share crash counts** — `XNET_SHARE_CRASH_COUNTS=on` (plus the sharing\n   config below) tees *fingerprint-level* data upstream on each automatic\n   crash: error name, release, surface, grouping hash, and count. Never the\n   message, stack, breadcrumbs, or any identifier.\n3. **Let xNet help debug** — grant xNet's support identity time-boxed,\n   read-only access to your Diagnostics Space from the same settings panel.\n   It expires on its own and can be revoked in one click.\n\n### Diagnostics sharing (opt-in, off by default)\n\nYour hub keeps its own errors to itself. If you'd like xNet to help debug your\nhub, set both `XNET_DIAGNOSTICS_URL` and `XNET_DIAGNOSTICS_SECRET` to enable the\n`POST /diagnostics/report` route, which forwards **scrubbed, content-free** crash\nreports upstream — the sender's DID is hashed (never sent raw) and document\ncontent is never included. Leave them unset (the default) and nothing is\nforwarded; `GET /diagnostics/health` simply reports `sharing: false`.\n\nThe upstream sink is xNet Cloud's first-party `POST /diagnostics` ingest\n(exploration 0315): reports land in a quarantine and are drained into\n`debug-report` nodes in the operator's own xNet workspace, where the workbench\n_is_ the triage console — filterable tables, a `new → acked → fixed → released`\nstatus field, and comments. **xNet does not use a third-party error service such\nas Sentry.** The client keeps a dormant, vendor-neutral Sentry seam (no\n`@sentry/*` SDK is installed and no DSN is minted), so if you self-host a\nSentry-compatible backend you can point that seam at it — [Bugsink][bugsink]\n(single container, SQLite) or [GlitchTip][glitchtip] (MIT, Sentry-SDK\ncompatible) are the proven small-footprint options — but nothing ships enabled.\n\n[bugsink]: https://www.bugsink.com/\n[glitchtip]: https://glitchtip.com/\n\n### CLI Flags\n\n| Flag                | Description                      |\n| ------------------- | -------------------------------- |\n| `--port`            | Listen port                      |\n| `--data`            | Data directory                   |\n| `--no-auth`         | Disable UCAN authentication      |\n| `--storage`         | Storage backend: sqlite, memory  |\n| `--public-url`      | Public hub URL for discovery     |\n| `--max-connections` | Max concurrent WebSocket clients |\n| `--max-blob-size`   | Max backup blob size             |\n| `--awareness-ttl`   | Awareness TTL in ms              |\n| `--discovery-ttl`   | Peer discovery TTL in ms         |\n\n## Connect Your App\n\n### React (Renderer)\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n\n;<XNetProvider\n  config={{\n    hubUrl: 'wss://your-hub.example.com'\n  }}\n>\n  <XNetDevToolsProvider>\n    <App />\n  </XNetDevToolsProvider>\n</XNetProvider>\n```\n\n### Electron (Main)\n\n```ts\nconst manager = new SyncManager({\n  hubUrl: 'wss://your-hub.example.com'\n})\n```\n\n## Operations\n\n### Health & Metrics\n\n| Endpoint       | Purpose                                |\n| -------------- | -------------------------------------- |\n| `GET /health`  | JSON status, uptime, platform metadata |\n| `GET /metrics` | Prometheus metrics                     |\n\n### Core Endpoints\n\n| Endpoint                    | Purpose                       |\n| --------------------------- | ----------------------------- |\n| `PUT /backup/:docId`        | Upload encrypted backup       |\n| `GET /backup/:docId`        | Download encrypted backup     |\n| `GET /backup`               | List backups for your DID     |\n| `PUT /files/:cid`           | Upload content-addressed file |\n| `GET /files/:cid`           | Download file                 |\n| `POST /schemas`             | Publish schema                |\n| `GET /schemas/resolve/:iri` | Resolve schema                |\n| `POST /dids/register`       | Register peer discovery       |\n| `GET /dids/:did`            | Resolve peer                  |\n\n### Backups\n\nThe Hub stores encrypted blobs. Your app encrypts before upload.\n\n| Endpoint             | Purpose                   |\n| -------------------- | ------------------------- |\n| `PUT /backup/:docId` | Upload encrypted backup   |\n| `GET /backup/:docId` | Download encrypted backup |\n| `GET /backup`        | List backups for your DID |\n\n### Query + Search\n\nQueries run locally first, with Hub results filling in the gaps:\n\n```ts\nconst results = await queryClient.search('budget', {\n  federate: true,\n  limit: 20\n})\n```\n\n## Migration\n\nMoving between platforms is straightforward:\n\n1. Stop the old Hub (`SIGTERM` flushes SQLite)\n2. Copy the data directory (`/data` or your `HUB_DATA_DIR`)\n3. Start the new Hub with the same data dir\n4. Update your app's `hubUrl`\n\nRailway → VPS/Fly.io is just a volume export + upload. Fly.io → Railway is the same process in reverse.\n\n## Further Reading\n\n- [Your Own Server](/docs/guides/server/) — run xNet on your own backend with your own auth instead of a Hub\n- [Sync Guide](/docs/guides/sync/)\n- [Sync Architecture](/docs/concepts/sync-architecture/)\n- [Electron Setup](/docs/guides/electron/)","src/content/docs/docs/guides/hub.mdx","f072cc58a1cc3c4c","docs/guides/identity",{id:366,data:368,body:374,filePath:375,digest:376,deferredRender:16},{title:369,description:370,editUrl:16,head:371,template:18,sidebar:372,pagefind:16,draft:21},"Identity & Keys","Generating DID:key pairs, UCAN tokens, and managing user identity.",[],{order:78,hidden:21,attrs:373},{},":::note[You will learn]\n\n- How to generate Ed25519 key pairs and DID:key identifiers\n- The HybridKeyBundle (classical + post-quantum keys)\n- The PQ Key Registry: associating ML-DSA keys with DIDs\n- How to use `useSecurity()` to control signature level\n- How to create and verify UCAN authorization tokens\n- Key recovery via seed phrase and multi-device access\n- How identity flows through the stack (provider → hooks → sync)\n  :::\n\n## DID:key identifiers\n\nEvery xNet user has a **Decentralized Identifier** (DID) derived from their Ed25519 public key. The format follows the W3C DID:key method:\n\n```\ndid:key:z6Mk...\n```\n\nThe public key is embedded directly in the DID, making it **self-certifying** — you can extract the public key and verify signatures without any external resolver or blockchain.\n\n### How it's constructed\n\n1. Take the 32-byte Ed25519 public key\n2. Prepend the multicodec prefix `0xed01` (Ed25519 public key)\n3. Encode with base58btc (multibase prefix `z`)\n4. Prefix with `did:key:`\n\n### Generate an identity\n\n```ts\nimport { generateIdentity, isValidDID } from '@xnetjs/identity'\n\nconst { identity, privateKey } = generateIdentity()\n// identity.did = \"did:key:z6Mk...\"\n// identity.publicKey = Uint8Array (32 bytes)\n// identity.created = Date.now()\n\nisValidDID(identity.did) // true\n```\n\n### Parse a DID\n\n```ts\nimport { parseDID } from '@xnetjs/identity'\n\nconst publicKey = parseDID('did:key:z6Mk...')\n// Returns the 32-byte Ed25519 public key\n```\n\n## Key bundles\n\nEvery xNet identity uses a **HybridKeyBundle** — classical keys (Ed25519 + X25519) bundled with post-quantum keys (ML-DSA-65) to protect against both current and future quantum attacks.\n\n| Key             | Algorithm | Size (bytes) | Purpose                                |\n| --------------- | --------- | ------------ | -------------------------------------- |\n| `signingKey`    | Ed25519   | 32           | Sign changes, Yjs updates, UCAN tokens |\n| `encryptionKey` | X25519    | 32           | Classical key exchange                 |\n| `pqSigningKey`  | ML-DSA-65 | 4,032        | Post-quantum signatures (Level 1/2)    |\n| `pqPublicKey`   | ML-DSA-65 | 1,952        | PQ verification key (cached)           |\n\nThe DID is derived from the Ed25519 public key only — the DID format is unchanged and stays compact.\n\n```ts\nimport { generateHybridKeyBundle, deriveHybridKeyBundle } from '@xnetjs/identity'\n\n// Random generation — includes PQ keys by default\nconst bundle = generateHybridKeyBundle()\n// bundle.signingKey    — Ed25519 private key (32 bytes)\n// bundle.encryptionKey — X25519 private key (32 bytes)\n// bundle.pqSigningKey  — ML-DSA-65 private key (4,032 bytes)\n// bundle.pqPublicKey   — ML-DSA-65 public key (1,952 bytes)\n// bundle.identity      — { did, publicKey, created }\n\n// Deterministic from a seed (same seed = same identity on every device)\nconst bundle2 = deriveHybridKeyBundle(masterSeed)\n```\n\n### Storage\n\nKey bundles are serialized, encrypted with XChaCha20-Poly1305, and stored via `PasskeyStorage`. In production, the encryption key is derived from WebAuthn/passkey credentials.\n\n```ts\nimport { BrowserPasskeyStorage } from '@xnetjs/identity'\n\nconst storage = new BrowserPasskeyStorage()\nconst storedKey = await storage.store(bundle, credentialId)\nconst recovered = await storage.retrieve(storedKey, credentialId)\n```\n\n### Resumable sessions\n\nUnlocking with a passkey on every page load would mean a biometric prompt per\nreload. Instead, after a successful `create()`/`unlock()` the key bundle is\nre-encrypted (AES-GCM) under a freshly generated **non-extractable** WebCrypto\nkey and stored in IndexedDB, bound to the identity's DID. On boot,\n`identityManager.resume()` restores the session silently — no prompt.\n\n- Sessions expire after **7 days**; expiry forces a fresh passkey unlock.\n- Expired, tampered, or DID-mismatched session records are deleted and fall\n  back to a normal unlock.\n- The wrapping key's bytes cannot be exported by script, so an exfiltrated\n  IndexedDB dump is undecryptable off-device. Raw private keys are never\n  stored in plaintext.\n\n### Logging out\n\n`identityManager.lock()` clears the session and cached keys but keeps the\nidentity — the next visit shows the unlock screen. In the app this is\n**Settings → Account → Log out**. `clear()` additionally removes the identity\nitself.\n\n### X25519 from Ed25519\n\nThe Ed25519 signing key can be birationally converted to an X25519 encryption key, so a single DID:key embeds both capabilities. xNet uses this conversion throughout the authorization system — the hub and other users can derive your X25519 public key directly from your DID, with no additional key exchange ceremony:\n\n```ts\nimport { edwardsToMontgomeryPub } from '@noble/curves/ed25519'\n\n// Derive the X25519 public key from an Ed25519 public key\nconst x25519Pub = edwardsToMontgomeryPub(ed25519PublicKey)\n```\n\n## PQ Key Registry\n\nThe DID:key format stays Ed25519-based (compact, human-readable). To support Level 1/2 verification, the **PQ Key Registry** associates each DID with its ML-DSA public key via a `PQKeyAttestation` — a self-signed proof binding the two keys together.\n\n```ts\nimport { MemoryPQKeyRegistry, createPQKeyAttestation } from '@xnetjs/identity'\n\n// Create an attestation binding your DID to your PQ public key\nconst attestation = await createPQKeyAttestation({\n  did: bundle.identity.did,\n  pqPublicKey: bundle.pqPublicKey,\n  signingKey: bundle.signingKey, // Ed25519 signs the attestation\n  pqSigningKey: bundle.pqSigningKey // ML-DSA also signs for cross-attestation\n})\n\n// Store in registry\nconst registry = new MemoryPQKeyRegistry()\nawait registry.store(attestation)\n\n// Look up during verification\nconst pqPub = await registry.lookup(someUserDid)\n```\n\nThe hub maintains a public PQ Key Registry for all registered users. When another user encrypts data for you, they look up your ML-DSA public key here to wrap the content key at Level 1/2.\n\n## Security level in React\n\nUse `XNetProvider` to set the default signing level for your app, and `useSecurity()` to inspect or override it per-operation:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\n\n// Configure default security level\n;<XNetProvider\n  config={{\n    authorDID: identity.did,\n    signingKey: bundle.signingKey,\n    pqSigningKey: bundle.pqSigningKey,\n    security: {\n      level: 1, // 0=Fast, 1=Hybrid(default), 2=PQ-Only\n      minVerificationLevel: 1, // reject signatures below this level\n      verificationPolicy: 'strict' // both Ed25519 AND ML-DSA must verify\n    }\n  }}\n>\n  <App />\n</XNetProvider>\n```\n\n```ts\nimport { useSecurity } from '@xnetjs/react'\n\nfunction HighSecurityAction() {\n  const { level, setLevel, canSignAtLevel } = useSecurity()\n\n  return (\n    <button\n      onClick={() => setLevel(2)}       // elevate to PQ-only for this action\n      disabled={!canSignAtLevel(2)}     // false if PQ keys not available\n    >\n      Sign with maximum security\n    </button>\n  )\n}\n```\n\n`useSecurity()` also exposes stats visible in the DevTools Security panel: current level, signature counts by level, and verification cache hit rate.\n\n## Key recovery\n\n### Seed phrase\n\nYour identity can be derived deterministically from a BIP-39 seed phrase. Back up the seed phrase and you can always restore your identity — and regain access to all your encrypted data — on any device:\n\n```ts\nimport { deriveSeedPhrase, recoverFromSeedPhrase } from '@xnetjs/identity'\n\n// Generate a new identity with a recoverable seed\nconst { mnemonic, bundle } = deriveSeedPhrase()\n// mnemonic: \"correct horse battery staple ...\"\n\n// Recover on a new device — produces the same DID and key pair\nconst recoveredBundle = recoverFromSeedPhrase(mnemonic)\n```\n\nThe seed phrase generates the Ed25519 signing key, and the X25519 encryption key is derived from it via birational conversion — not independently. This ensures the DID, signing key, and encryption key are always consistent.\n\n### Social recovery\n\nAs a fallback when the seed phrase is unavailable, xNet supports Shamir's Secret Sharing. Split the seed across trusted contacts (e.g., 3-of-5 threshold) so any quorum can reconstruct your identity:\n\n```ts\nimport { splitSeed, reconstructSeed } from '@xnetjs/identity'\n\nconst shares = splitSeed(mnemonic, { threshold: 3, total: 5 })\n// Distribute shares to trusted contacts\n\nconst recovered = reconstructSeed(anyThreeShares) // any 3 of 5 work\n```\n\n### Encrypted hub backup\n\nWith opt-in hub backup, your key bundle is stored encrypted on a hub, unlocked by a passphrase or WebAuthn credential. The hub never sees the plaintext key:\n\n```ts\nimport { HubKeyBackup } from '@xnetjs/identity'\n\nconst backup = new HubKeyBackup(hubUrl)\nawait backup.store(bundle, { passphrase: 'my-secret-passphrase' })\nconst restored = await backup.retrieve({ passphrase: 'my-secret-passphrase' })\n```\n\n## Multi-device access\n\nWhen you sign in on a second device:\n\n1. The new device generates a device-specific key pair\n2. It derives the same primary key from your seed phrase\n3. Your primary key wraps content keys for each device\n\nAll devices share the same DID — collaborators don't need to know which device you're on.\n\n## Cryptographic primitives\n\nThe `@xnetjs/crypto` package provides all the low-level operations:\n\n### Hashing (BLAKE3)\n\n```ts\nimport { hash, hashHex } from '@xnetjs/crypto'\n\nconst digest = hash(data) // Uint8Array\nconst hex = hashHex(data) // hex string\nconst b64 = hashBase64(data) // base64url string\nconst sha = hash(data, 'sha256') // SHA-256 fallback\n```\n\n### Signing (Ed25519)\n\n```ts\nimport { generateSigningKeyPair, sign, verify } from '@xnetjs/crypto'\n\nconst { publicKey, privateKey } = generateSigningKeyPair()\nconst signature = sign(message, privateKey)\nconst valid = verify(message, signature, publicKey) // boolean\n```\n\n### Encryption (XChaCha20-Poly1305)\n\n```ts\nimport { generateKey, encrypt, decrypt } from '@xnetjs/crypto'\n\nconst key = generateKey() // 32 bytes\nconst encrypted = encrypt(plaintext, key) // { nonce, ciphertext }\nconst decrypted = decrypt(encrypted, key) // Uint8Array\n```\n\n### Key exchange (X25519 + HKDF)\n\n```ts\nimport { generateKeyPair, deriveSharedSecret } from '@xnetjs/crypto'\n\nconst alice = generateKeyPair()\nconst bob = generateKeyPair()\nconst shared = deriveSharedSecret(alice.privateKey, bob.publicKey)\n// Both sides derive the same 32-byte shared secret\n```\n\n## UCAN tokens\n\nUCANs (User Controlled Authorization Networks) are self-signed capability tokens for decentralized authorization. They replace traditional API keys or OAuth tokens. UCAN tokens are signed with the hybrid signature at whatever level the signer's `SecurityContext` specifies.\n\n### Structure\n\n```ts\ninterface UCANToken {\n  iss: string // Issuer DID\n  aud: string // Audience DID\n  exp: number // Expiration (Unix seconds)\n  att: UCANCapability[] // Capabilities granted\n  prf: string[] // Proof chain (parent tokens)\n  sig: Uint8Array // Ed25519 signature\n}\n\ninterface UCANCapability {\n  with: string // Resource URI: 'xnet://doc/123' or '*'\n  can: string // Action: 'read', 'write', or '*'\n}\n```\n\n### Create a token\n\n```ts\nimport { createUCAN } from '@xnetjs/identity'\n\nconst token = createUCAN({\n  issuer: alice.did,\n  issuerKey: alice.privateKey,\n  audience: bob.did,\n  capabilities: [\n    { with: 'xnet://doc/123', can: 'write' },\n    { with: 'xnet://doc/*', can: 'read' }\n  ],\n  expiration: Date.now() / 1000 + 3600, // 1 hour (default)\n  proofs: [] // Parent tokens for delegation\n})\n```\n\n### Verify a token\n\n```ts\nimport { verifyUCAN, hasCapability } from '@xnetjs/identity'\n\nconst result = verifyUCAN(token)\nif (result.valid) {\n  const canWrite = hasCapability(result.payload, 'xnet://doc/123', 'write')\n}\n```\n\nVerification extracts the issuer's public key from their DID (no external resolver), checks expiration, and verifies the Ed25519 signature.\n\n### Delegation chains\n\n```mermaid\nflowchart LR\n  A[\"Alice\\n(document owner)\"] -->|\"grants write\\n(signs UCAN)\"| B[\"Bob\"]\n  B -->|\"delegates read\\n(cites Alice's UCAN as proof)\"| C[\"Carol\"]\n  C -->|\"verifies chain\"| D[\"Alice → Bob → Carol\"]\n```\n\nUCANs support transitive delegation via the `prf` (proofs) field:\n\n```ts\n// Alice grants Bob write access\nconst aliceToBob = createUCAN({\n  issuer: alice.did,\n  issuerKey: alice.privateKey,\n  audience: bob.did,\n  capabilities: [{ with: 'xnet://doc/123', can: 'write' }]\n})\n\n// Bob delegates read access to Carol, citing Alice's grant as proof\nconst bobToCarol = createUCAN({\n  issuer: bob.did,\n  issuerKey: bob.privateKey,\n  audience: carol.did,\n  capabilities: [{ with: 'xnet://doc/123', can: 'read' }],\n  proofs: [aliceToBob]\n})\n```\n\n## Integration with React\n\nIdentity is provided to the app through `XNetProvider`:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n;<XNetProvider\n  config={{\n    authorDID: identity.did,\n    signingKey: privateKey,\n    identity: identity\n    // ...\n  }}\n>\n  <XNetDevToolsProvider>\n    <App />\n  </XNetDevToolsProvider>\n</XNetProvider>\n```\n\nThe `useIdentity` hook exposes identity state to components:\n\n```ts\nimport { useIdentity } from '@xnetjs/react'\n\nfunction Profile() {\n  const { identity, isAuthenticated, did } = useIdentity()\n\n  if (!isAuthenticated) return <LoginScreen />\n  return <p>Signed in as {did}</p>\n}\n```\n\n## Related\n\n- [Authorization](/docs/guides/authorization/) — Roles, grants, and encryption-first access control\n- [Cryptography](/docs/concepts/cryptography/) — Ed25519, X25519, and the encrypted envelope model\n\n## How identity flows through the stack\n\n```mermaid\nflowchart TD\n  A[\"XNetProvider\\n(authorDID + signingKey)\"] --> B[\"NodeStore\"]\n  A --> C[\"SyncManager\"]\n  B --> D[\"mutate.create() / update()\"]\n  D --> E[\"Ed25519 sign Change‹T›\"]\n  C --> F[\"BSM\\n(Background Sync Manager)\"]\n  F --> G[\"signYjsUpdate()\\nSignedYjsEnvelope\"]\n  F --> H[\"ClientID attestation\\n(clientId → DID binding)\"]\n  G --> I[\"Broadcast to peers\"]\n  I --> J[\"Remote peer\\nverify all signatures\"]\n```\n\n1. `XNetProvider` creates a `NodeStore` with `authorDID` and `signingKey`\n2. Every `mutate.create()` / `mutate.update()` call signs the change with Ed25519\n3. `SyncManager` receives the signing credentials and passes them to the BSM\n4. Yjs updates are signed as `SignedYjsEnvelope` before broadcast\n5. ClientID attestations bind the Yjs clientID to the DID\n6. Remote peers verify all signatures before applying changes","src/content/docs/docs/guides/identity.mdx","0c8d4da6fff1cc9e","docs/guides/notifications",{id:377,data:379,body:385,filePath:386,digest:387,deferredRender:16},{title:380,description:381,editUrl:16,head:382,template:18,sidebar:383,pagefind:16,draft:21},"Notifications & Inbox","The local-first notification engine — rules, read state, badges, and triage.",[],{hidden:21,attrs:384},{},":::note[You will learn]\n\n- How notifications are derived locally from synced changes\n- The rule priority order and its edge semantics\n- How read state works (watermarks + mention acks)\n- Badges, mutes, do-not-disturb, and inbox triage\n  :::\n\n## Overview\n\nThere is no notification server. Because every change in the workspace syncs\nto your device anyway, notifications are **derived locally**: a notifier runs\none evaluation per applied change and decides whether it deserves your\nattention. Your read state is itself a private, user-owned node\n(`InboxState`), so the inbox follows you across devices without anyone else\nseeing what you've read.\n\n## The rules\n\nRules run in priority order — the highest matching reason wins:\n\n```\nmention > dm > assigned > reply > comment > room-mention > keyword\n```\n\nThree details keep this trustworthy:\n\n- **Edge semantics** — assignment notifies on the *transition* into being\n  assigned. A re-sync or replay of the same change never re-notifies.\n- **Own-change suppression** — your own edits never notify you.\n- **Tombstone suppression** — deleted content doesn't resurrect a\n  notification.\n\n## Read state: watermarks + mention acks\n\nRead state is the Zulip-style hybrid:\n\n- a **per-channel watermark** (\"read up to here\") advances as you view a\n  channel, clearing activity in bulk;\n- **explicit mention acks** track each mention individually, so a mention\n  can't be accidentally swept away by scrolling past it.\n\nOn top of that, inbox items can be triaged: **done**, **saved**, or\n**snoozed**.\n\n## Badges and alerting\n\nBadging is two-tier so the urgent never drowns in the ambient:\n\n- a **number** counts things aimed at you — mentions and DMs\n- a **dot** means there's other activity — replies, comments, room chatter\n\nChannels can be **muted**, and a mention **overrides the mute** (you can\nsilence a busy channel without becoming unreachable). **Do-not-disturb\nwindows** suppress alerting overnight; items still accumulate in the inbox.\n\n## The Inbox\n\nThe Notifications tray (bottom panel) is the triage surface: reason-chip\nfilters (mentions / DMs / assigned / replies…), done/snooze actions, and deep\nlinks that jump straight to the message, task, or comment in its own tab. The\nstatus-bar bell carries the two-tier badge.\n\n## Delivery to other surfaces\n\nBecause derivation is local, anything that syncs can notify. Push delivery to\nclosed apps (Web Push, Electron, mobile) rides the hub and is in progress —\nsee the [roadmap](/#roadmap).\n\n## Further reading\n\n- [Chat, Presence & Calls](/docs/guides/chat-and-calls/) — where mentions and\n  DMs come from\n- [Tasks](/docs/guides/tasks/) — assignment notifications\n- [The Workbench](/docs/guides/workbench/) — the tray and status bar","src/content/docs/docs/guides/notifications.mdx","349ae0d37f85d260","docs/guides/offline",{id:388,data:390,body:396,filePath:397,digest:398,deferredRender:16},{title:391,description:392,editUrl:16,head:393,template:18,sidebar:394,pagefind:16,draft:21},"Offline Patterns","Building apps that work without network connectivity.",[],{order:90,hidden:21,attrs:395},{},":::note[You will learn]\n\n- Why xNet apps work offline by default\n- How the offline queue captures changes\n- How changes merge when connectivity returns\n- Patterns for building resilient offline UIs\n  :::\n\n## Local-first by default\n\nxNet apps don't fetch data from a server — they read from a local database (SQLite, OPFS-backed in modern browsers). This means:\n\n- **Queries are instant** — no loading spinners for cached data\n- **Mutations are immediate** — writes go to local storage first\n- **The app works offline** — no network required for core functionality\n- **Sync is eventual** — changes propagate to peers when a connection is available\n\nYou don't need to add special offline handling. The architecture is offline-first from the ground up.\n\n## How offline sync works\n\n### Normal operation (connected)\n\n```\nUser edits → Local Y.Doc update → Broadcast via WebSocket → Peers apply\n                                → Persist to SQLite\n```\n\n### Offline operation\n\n```\nUser edits → Local Y.Doc update → OfflineQueue (persisted)\n                                → Persist to SQLite\n```\n\n### Reconnection\n\n```\nWebSocket connects → OfflineQueue drains → Broadcast queued updates\n                   → Exchange state vectors → Merge remote changes\n```\n\nThe `OfflineQueue` holds up to 1000 entries, persisted to SQLite immediately for crash resilience. On reconnect, entries are drained in order. If a broadcast fails, the entry stays at the front of the queue for retry.\n\n## Patterns\n\n### Optimistic UI\n\nSince mutations write to local storage first, the UI updates immediately. No optimistic update logic is needed — the data is already local:\n\n```tsx\nfunction TaskList() {\n  const { data: tasks } = useQuery(TaskSchema)\n  const mutate = useMutate()\n\n  const addTask = () => {\n    // This writes locally and returns immediately\n    mutate.create(TaskSchema, { title: 'New task', status: 'todo' })\n    // useQuery re-renders with the new task — no loading state\n  }\n\n  return (\n    <div>\n      <button onClick={addTask}>Add Task</button>\n      {tasks.map((t) => (\n        <TaskRow key={t.id} task={t} />\n      ))}\n    </div>\n  )\n}\n```\n\n### Connection status indicator\n\n```tsx\nimport { useSyncManager } from '@xnetjs/react'\n\nfunction NetworkBadge() {\n  const sync = useSyncManager()\n\n  return (\n    <span>\n      {sync.status === 'connected' ? 'Online' : 'Offline'}\n      {sync.queueSize > 0 && ` (${sync.queueSize} pending)`}\n    </span>\n  )\n}\n```\n\n### Background sync for important nodes\n\nTrack nodes so they sync even when no component has them open:\n\n```tsx\nconst sync = useSyncManager()\n\n// Pin a node — it syncs in the background and never expires from the registry\nsync.track(nodeId, schemaId)\n```\n\nTracked nodes stay in the sync registry for 7 days by default. Pinned nodes never expire.\n\n### Handling merge results\n\nWhen offline changes merge with remote changes, both Yjs (rich text) and the NodeStore (properties) resolve conflicts automatically:\n\n- **Rich text** — Yjs CRDT merges character-by-character. Both users' edits appear.\n- **Properties** — Field-level LWW. The change with the higher Lamport timestamp wins. If two users edit different fields on the same node, both changes are preserved.\n\nThere are no merge conflict dialogs. The system is designed so that all peers converge to the same state deterministically.\n\n### Offline-aware forms\n\nFor forms that create multiple related nodes, use `mutate([...])` to execute a batched write:\n\n```tsx\nconst { mutate } = useMutate()\n\nconst createProjectWithTasks = async () => {\n  const result = await mutate([\n    { type: 'create', schema: ProjectSchema, id: 'project-acme', data: { name: 'Acme' } },\n    { type: 'create', schema: TaskSchema, data: { title: 'Setup', project: 'project-acme' } },\n    { type: 'create', schema: TaskSchema, data: { title: 'Launch', project: 'project-acme' } }\n  ])\n\n  // All three writes run through one mutate call.\n  // The known project ID keeps references stable while offline and after sync.\n}\n```\n\n## Storage\n\nxNet uses SQLite through the `@xnetjs/storage` adapter. Data is organized per-node:\n\n- **Y.Doc state** — Full Yjs document state, BLAKE3-hashed for integrity\n- **Node properties** — Structured data from the NodeStore\n- **Offline queue** — Pending updates waiting to sync\n- **Registry** — Tracked node set with last-synced timestamps\n- **Blobs** — File attachments stored locally\n\nThe storage layer handles serialization, compression, and integrity checks. You don't interact with SQLite directly.\n\n## Durable storage\n\nIn the browser, xNet's SQLite database lives in the Origin Private File System, which starts out as **best-effort** storage: the browser may evict it under pressure. xNet asks the browser to upgrade the origin to **persistent** via `navigator.storage.persist()`, but each browser decides that request differently:\n\n| Browser         | Prompt? | When it grants                                                                                                     | Eviction while best-effort                            |\n| --------------- | ------- | ------------------------------------------------------------------------------------------------------------------ | ----------------------------------------------------- |\n| Chrome / Edge   | No      | Silently, once the site is installed, has notification permission, is regularly used, or is a top bookmark — re-evaluated on every request | Only under disk pressure (least-recently-used origins) |\n| Safari          | No      | Only when xNet runs as an installed web app (Add to Dock / Add to Home Screen)                                       | Site data is deleted after 7 days of Safari use without visiting the site |\n| Firefox desktop | Yes     | When you click **Allow** in its permission prompt                                                                    | Only under disk pressure                               |\n\nWhat xNet does about it:\n\n- On Chromium and WebKit browsers the request is silent and never penalized, so xNet re-requests durable storage on every startup. Regular use typically flips Chrome to granted within days; enabling desktop alerts in the Notifications panel or installing the app grants it immediately.\n- On Safari in a browser tab, durable storage cannot be granted and even a granted request would not stop the 7-day cleanup — installing xNet from the Share menu is the only full protection. Visiting at least weekly resets the cleanup timer.\n- On Firefox, xNet only asks when you click **Enable durable storage**, so the prompt appears from a deliberate action.\n\nDurable storage protects against automatic eviction only. Clearing site data in the browser always removes local data — hub sync and exports are the real safety net for important work.\n\n## Limits\n\n| Resource           | Limit                               |\n| ------------------ | ----------------------------------- |\n| Offline queue      | 1000 entries (FIFO, oldest dropped) |\n| Y.Doc size         | 50 MB per document                  |\n| Warm document pool | 50 documents in memory              |\n| Registry TTL       | 7 days (configurable)               |\n\nIf the offline queue fills up during an extended offline period, the oldest entries are dropped. The Y.Doc state in SQLite is still preserved — only the incremental updates that haven't been broadcast are lost. On reconnect, a full state-vector exchange with peers will reconcile any gaps.","src/content/docs/docs/guides/offline.mdx","9023176ce65488e5","docs/guides/plugins",{id:399,data:401,body:407,filePath:408,digest:409,deferredRender:16},{title:402,description:403,editUrl:16,head:404,template:18,sidebar:405,pagefind:16,draft:21},"Plugin Development","Building plugins for xNet's 4-layer extensibility system.",[],{order:55,hidden:21,attrs:406},{},"import { Tabs, TabItem, Steps, FileTree } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- The four plugin layers and when to use each one\n- How to define, register, and distribute an extension\n- All eleven contribution types with working examples\n- The middleware system for intercepting data operations\n- The script sandbox for safe user-authored expressions\n- Platform compatibility across Electron, Web, and Mobile\n  :::\n\n## The four layers\n\nxNet's plugin system is organized into four layers of increasing complexity:\n\n| Layer | Name             | Description                                                         | Platform                          |\n| ----- | ---------------- | ------------------------------------------------------------------- | --------------------------------- |\n| 1     | **Scripts**      | Sandboxed expressions. Safe for AI-generated code.                  | All                               |\n| 2     | **Extensions**   | Developer-built packages with views, commands, editor integrations. | All (some features Electron-only) |\n| 3     | **Services**     | Background processes managed by a process supervisor.               | Electron only                     |\n| 4     | **Integrations** | HTTP API, MCP server, webhooks for external tools.                  | Electron only                     |\n\nMost plugin development happens at Layer 2. Layers 3 and 4 are for advanced use cases that need OS-level access.\n\n## Quick start: your first extension\n\n<Steps>\n\n1. **Define the manifest**\n\n   Every extension starts with an `XNetExtension` manifest. Use `defineExtension()` for validation:\n\n   ```ts\n   import { defineExtension } from '@xnetjs/plugins'\n\n   export const MyPlugin = defineExtension({\n     id: 'com.example.my-plugin', // reverse-domain format\n     name: 'My Plugin',\n     version: '1.0.0',\n     description: 'Adds a custom view and slash command.',\n     platforms: ['electron', 'web'],\n\n     contributes: {\n       // Static contributions declared here\n     },\n\n     activate(ctx) {\n       // Dynamic contributions registered here\n     },\n\n     deactivate() {\n       // Cleanup (optional — subscriptions auto-dispose)\n     }\n   })\n   ```\n\n2. **Register it**\n\n   In your app setup, install the plugin with the registry:\n\n   ```ts\n   import { usePluginRegistry } from '@xnetjs/react'\n   import { MyPlugin } from './plugins/my-plugin'\n\n   function App() {\n     const registry = usePluginRegistry()\n\n     useEffect(() => {\n       registry.install(MyPlugin)\n     }, [])\n   }\n   ```\n\n3. **Consume contributions in your UI**\n\n   ```tsx\n   import { useViews, useCommands } from '@xnetjs/react'\n\n   function Sidebar() {\n     const views = useViews()\n     const commands = useCommands()\n     // Render plugin-contributed views and commands\n   }\n   ```\n\n</Steps>\n\n## Manifest reference\n\nThe `XNetExtension` interface:\n\n```ts\ninterface XNetExtension {\n  id: string // Reverse-domain: 'com.example.my-plugin'\n  name: string\n  version: string // Semver: '1.0.0'\n  description?: string\n  author?: string\n  xnetVersion?: string // Minimum compatible xNet version\n  platforms?: Platform[] // 'web' | 'electron' | 'mobile' (default: all)\n  permissions?: PluginPermissions\n  contributes?: PluginContributions // Static contributions\n  activate?(ctx: ExtensionContext): void | Promise<void>\n  deactivate?(): void | Promise<void>\n}\n```\n\n**Validation rules** enforced by `defineExtension()`:\n\n- `id` must match `/^[a-z][a-z0-9]*(\\.[a-z][a-z0-9-]*)+$/i` (reverse-domain)\n- `version` must be valid semver\n- `platforms` values must be `'web'`, `'electron'`, or `'mobile'`\n- `activate` and `deactivate` must be functions if present\n\n## Lifecycle\n\n```\ninstall → activate → contribute → deactivate → uninstall\n```\n\n1. **Install** — Manifest is validated, platform compatibility checked, plugin persisted as a node in the store (syncs to peers). Status: `'installed'`. Activation happens immediately.\n\n2. **Activate** — An `ExtensionContext` is created. Static contributions from `contributes` are registered. Then `activate(ctx)` is called if defined — this is where you register dynamic contributions, subscribe to data changes, or add middleware.\n\n3. **Contribute** — All `ctx.register*()` calls return `Disposable` objects tracked in `ctx.subscriptions`. Contributions are visible to React hooks immediately.\n\n4. **Deactivate** — `deactivate()` is called, then all subscriptions are disposed. Contributions are unregistered, middleware removed, store subscriptions cancelled.\n\n5. **Uninstall** — Plugin node deleted from the store.\n\n:::tip\nYou rarely need a `deactivate()` function. All resources registered through `ExtensionContext` are automatically cleaned up when the plugin is deactivated.\n:::\n\n## ExtensionContext\n\nThe context object passed to `activate()` provides the full plugin API:\n\n```ts\ninterface ExtensionContext {\n  readonly pluginId: string\n  readonly platform: Platform\n  readonly store: NodeStore\n  readonly storage: ExtensionStorage // Key-value storage scoped to this plugin\n  readonly capabilities: PlatformCapabilities\n  readonly subscriptions: Disposable[]\n\n  // Data access\n  query(schema: SchemaIRI, filter?: QueryFilter): Promise<NodeState[]>\n  subscribe(schema: SchemaIRI | null, callback): Disposable\n\n  // Registration (all return Disposable)\n  registerSchema(schema): Disposable\n  registerView(view: ViewContribution): Disposable\n  registerCommand(command: CommandContribution): Disposable\n  registerSlashCommand(cmd: SlashCommandContribution): Disposable\n  registerEditorExtension(ext: EditorContribution): Disposable\n  registerSidebarItem(item: SidebarContribution): Disposable\n  registerPropertyHandler(type, handler): Disposable\n  registerBlockType(block: BlockContribution): Disposable\n  addMiddleware(middleware: NodeStoreMiddleware): Disposable\n}\n```\n\n## Contribution types\n\nxNet supports eleven contribution types. Each can be declared statically in `contributes` or registered dynamically in `activate()`.\n\n### Views\n\nCustom UI panels for displaying node data:\n\n```ts\ninterface ViewContribution {\n  type: string // Unique view type identifier\n  name: string\n  icon?: string | ComponentType\n  component: ComponentType<ViewProps> // React component\n  supportedSchemas?: string[] // Restrict to specific schemas\n}\n\ninterface ViewProps {\n  nodeId: string\n  schemaId: string\n}\n```\n\n```tsx\nconst KanbanView: ViewContribution = {\n  type: 'kanban',\n  name: 'Kanban Board',\n  icon: 'columns',\n  supportedSchemas: ['xnet://app/Task'],\n  component: ({ nodeId, schemaId }) => {\n    const { data } = useQuery(schemaId)\n    return <KanbanBoard tasks={data} />\n  }\n}\n```\n\n### Commands\n\nActions triggered by keyboard shortcuts or the command palette:\n\n```ts\ninterface CommandContribution {\n  id: string\n  name: string\n  description?: string\n  keybinding?: string // e.g., 'Mod-Shift-P' (Mod = Cmd on Mac, Ctrl elsewhere)\n  keywords?: string[] // For command palette search\n  icon?: string\n  execute: () => void | Promise<void>\n  when?: () => boolean // Show/enable condition\n}\n```\n\n```ts\nctx.registerCommand({\n  id: 'my-plugin.export-csv',\n  name: 'Export as CSV',\n  keybinding: 'Mod-Shift-E',\n  keywords: ['export', 'csv', 'download'],\n  execute: async () => {\n    const nodes = await ctx.query('xnet://app/Task')\n    downloadCSV(nodes)\n  }\n})\n```\n\n### Slash commands\n\nIn-editor commands triggered by typing `/`:\n\n```ts\ninterface SlashCommandContribution {\n  id: string\n  name: string\n  description?: string\n  aliases?: string[] // Alternative trigger words\n  icon?: string\n  execute: (props: SlashCommandContext) => void\n}\n\ninterface SlashCommandContext {\n  editor: unknown // TipTap Editor instance\n  range: { from: number; to: number }\n}\n```\n\n### Editor extensions\n\nTipTap editor extensions (nodes, marks, plugins):\n\n```ts\ninterface EditorContribution {\n  id: string\n  extension: Extension // TipTap Extension/Node/Mark\n  priority?: number // Default: 100. Lower runs first.\n  toolbar?: ToolbarContribution\n}\n\ninterface ToolbarContribution {\n  icon: string | ComponentType\n  title: string\n  group?: 'format' | 'insert' | 'block' | 'custom'\n  isActive?: (editor) => boolean\n  action: (editor) => void\n  shortcut?: string\n}\n```\n\n### Sidebar items\n\nAdd items to the application sidebar:\n\n```ts\ninterface SidebarContribution {\n  id: string\n  name: string\n  icon: string | ComponentType\n  position?: 'top' | 'bottom' | 'section'\n  section?: string\n  priority?: number\n  badge?: () => string | number | null\n  action: (() => void) | string // Function or route string\n  panel?: ComponentType // Expandable panel content\n}\n```\n\nIn the workbench shell, a `SidebarContribution` becomes a rail item; a\ncontribution with a `panel` component becomes a left-panel view. See\n[The Workbench](/docs/guides/workbench/) for the container model.\n\n### Status bar items\n\nAdd items to the workbench status bar — workspace scope on the left,\nview scope on the right:\n\n```ts\ninterface StatusBarContribution {\n  id: string\n  alignment: 'left' | 'right'\n  priority?: number\n  item: ComponentType // Rendered in the 24px mono status bar\n}\n```\n\n### Dashboard widgets\n\nRegister widgets users can add to dashboards (and drop onto canvases) with a\n`WidgetContribution`. The trust tier is host-assigned — a plugin can never\nself-declare one. See [Dashboards & Widgets](/docs/guides/dashboards/) for the\nwidget contract.\n\n### Property handlers\n\nCustom renderers for property types in table cells and editors:\n\n```ts\ninterface PropertyHandlerContribution {\n  type: string // Property type identifier\n  handler: {\n    Cell: ComponentType<{ value; config? }> // Read-only display\n    Editor: ComponentType<{ value; onChange; config? }> // Edit mode\n    parse?: (input: string) => unknown\n    format?: (value: unknown) => string\n    validate?: (value: unknown) => boolean\n  }\n}\n```\n\n### Block types\n\nCustom block-level elements inside the editor:\n\n```ts\ninterface BlockContribution {\n  type: string\n  name: string\n  component: ComponentType<{\n    node: unknown\n    updateAttributes: (attrs: Record<string, unknown>) => void\n  }>\n}\n```\n\n### Settings panels\n\nAdd sections to the application settings UI:\n\n```ts\ninterface SettingContribution {\n  id: string\n  title: string\n  description?: string\n  icon?: string\n  section?: 'general' | 'appearance' | 'plugins' | 'data' | 'network'\n  component: ComponentType<{\n    storage: ExtensionStorage\n  }>\n}\n```\n\n### Schema contributions\n\nRegister new schemas from a plugin:\n\n```ts\ninterface SchemaContribution {\n  schema: unknown // A defineSchema() result\n}\n```\n\n## React hooks\n\nUse these hooks to consume plugin contributions in your components:\n\n| Hook                        | Returns                            | Description                                        |\n| --------------------------- | ---------------------------------- | -------------------------------------------------- |\n| `usePlugins()`              | `RegisteredPlugin[]`               | All registered plugins with status                 |\n| `useViews()`                | `ViewContribution[]`               | All view contributions                             |\n| `useCommands()`             | `CommandContribution[]`            | All command contributions                          |\n| `useSlashCommands()`        | `SlashCommandContribution[]`       | All slash commands                                 |\n| `useSidebarItems()`         | `SidebarContribution[]`            | All sidebar items                                  |\n| `useEditorExtensions()`     | `EditorContribution[]`             | All editor extensions (throws if no plugin system) |\n| `useEditorExtensionsSafe()` | `EditorContribution[]`             | Same, returns `[]` if no plugin system             |\n| `useContributions(type)`    | `Contribution[]`                   | Generic — pass `'views'`, `'commands'`, etc.       |\n| `useView(type)`             | `ViewContribution \\| undefined`    | Find a specific view by type                       |\n| `useCommand(id)`            | `CommandContribution \\| undefined` | Find a specific command by ID                      |\n| `usePluginRegistry()`       | `PluginRegistry`                   | Direct registry access (throws if missing)         |\n\nAll hooks are reactive — they re-render when contributions change.\n\n## Middleware\n\nMiddleware lets you intercept NodeStore operations. This is useful for validation, audit logging, computed fields, or cross-plugin data transformation.\n\n```ts\ninterface NodeStoreMiddleware {\n  id: string\n  priority?: number // Lower runs first. Default: 100.\n  beforeChange?(change: PendingChange, next: () => Promise<unknown>): Promise<unknown>\n  afterChange?(event: NodeChangeEvent): void\n}\n```\n\n### Example: audit log middleware\n\n```ts\nctx.addMiddleware({\n  id: 'my-plugin.audit-log',\n  priority: 50, // Run early\n\n  async beforeChange(change, next) {\n    // Pass through — let the operation proceed\n    const result = await next()\n    return result\n  },\n\n  afterChange({ change, node, isRemote }) {\n    if (!isRemote) {\n      console.log(`[audit] ${change.type} on ${change.nodeId}`)\n    }\n  }\n})\n```\n\n### Middleware capabilities\n\n- **Pass through**: Call `next()` to continue the chain\n- **Modify**: Mutate the `change` object before calling `next()`\n- **Reject**: Throw an error to abort the operation\n- **Short-circuit**: Return a value without calling `next()`\n\nThe `MiddlewareChain` executes `beforeChange` hooks in priority order (lowest first). After the store operation completes, `afterChange` hooks run for all middleware — one failing hook does not prevent others.\n\n## Layer 1: Scripts\n\nScripts are sandboxed expressions for safe, user-authored (or AI-generated) logic. They run in a restricted JavaScript subset with no access to the DOM, network, or Node.js APIs.\n\n### Script node\n\nScripts are stored as nodes with schema `xnet://xnet.dev/Script`:\n\n```ts\ninterface ScriptNode {\n  name: string\n  description?: string\n  code: string // The script body\n  triggerType: 'manual' | 'onChange' | 'onView' | 'scheduled'\n  triggerProperty?: string // For onChange: which property triggers re-run\n  inputSchema?: string // SchemaIRI to filter triggers\n  outputType: 'value' | 'mutation' | 'decoration' | 'void'\n  enabled: boolean\n  lastError?: string\n  lastRun?: number\n}\n```\n\n### Script context\n\nScripts receive a frozen context with helper libraries:\n\n```ts\ninterface ScriptContext {\n  node: Readonly<FlatNode> // Current node\n  nodes: (schemaIRI?) => ReadonlyArray<FlatNode> // Query siblings\n  now: () => number // Current timestamp\n  format: { date; number; currency; relativeTime; bytes }\n  math: { sum; avg; min; max; round; clamp; abs; floor; ceil }\n  text: { slugify; truncate; capitalize; titleCase; contains; template; trim; lower; upper }\n  array: { first; last; sortBy; groupBy; unique; count; compact }\n}\n```\n\n### Example script\n\n```js\n// Compute a \"progress\" value from subtask completion\nconst tasks = nodes('xnet://app/Task')\nconst done = array.count(tasks, (t) => t.status === 'done')\nconst total = tasks.length\ntotal > 0 ? math.round((done / total) * 100) : 0\n```\n\n### AST validation\n\nBefore execution, scripts are parsed with `acorn` and validated against a strict allowlist. Blocked patterns include:\n\n- 60+ forbidden globals (`window`, `document`, `fetch`, `eval`, `require`, `process`, `setTimeout`, etc.)\n- Forbidden property access (`__proto__`, `constructor`, `prototype`)\n- Import/export statements and dynamic `import()`\n- `async`/`await`, `new Function()`, `with` statements\n\n### Sandbox execution\n\n```ts\nimport { ScriptSandbox, createScriptContext } from '@xnetjs/plugins'\n\nconst sandbox = new ScriptSandbox({ timeoutMs: 1000 })\nconst context = createScriptContext(node, queryFn)\nconst result = await sandbox.execute(code, context)\n```\n\nThe sandbox wraps code in a `new Function()` with all dangerous globals shadowed to `undefined`. Output is sanitized — functions, symbols, circular references, and non-plain objects are stripped.\n\n### AI script generation\n\nxNet includes an AI script generator that produces validated scripts:\n\n```ts\nimport { generateScript, createAIProvider } from '@xnetjs/plugins'\n\nconst provider = createAIProvider({\n  type: 'anthropic',   // or 'openai', 'ollama'\n  options: { apiKey: '...' }\n})\n\nconst result = await generateScript(provider, {\n  intent: 'Calculate total price from quantity and unit price',\n  schema: { name: 'LineItem', schemaIRI: '...', properties: [...] },\n  outputType: 'value'\n})\n\nif (result.validated) {\n  // result.code is safe to execute in the sandbox\n}\n```\n\nThe generator builds a structured prompt with schema context and helper documentation, then validates the output through the AST validator. It retries up to 2 times if validation fails.\n\n## Layer 3: Services\n\nServices are background processes managed by `ProcessManager` in the Electron main process. Think of them as supervised daemons.\n\n```ts\ninterface ServiceDefinition {\n  id: string\n  name: string\n  process: {\n    command: string // e.g., 'python', 'node'\n    args?: string[]\n    cwd?: string\n    env?: Record<string, string>\n  }\n  lifecycle: {\n    restart: 'always' | 'on-failure' | 'never'\n    maxRestarts?: number\n    restartDelayMs?: number\n    healthCheck?: {\n      type: 'http' | 'tcp' | 'stdout'\n      url?: string\n      port?: number\n      intervalMs?: number\n    }\n  }\n  communication: {\n    protocol: 'stdio' | 'http' | 'websocket' | 'ipc'\n    port?: number\n  }\n}\n```\n\nFrom the renderer, use the `ServiceClient`:\n\n```ts\nimport { createServiceClient } from '@xnetjs/plugins'\n\nconst services = createServiceClient()\nawait services.start(myServiceDef)\n\nconst status = await services.status('my-service')\n// { state: 'running', pid: 12345, uptime: 60000, ... }\n\nconst result = await services.call('my-service', 'POST', '/analyze', { data })\n```\n\nThe service client communicates with the main process via IPC. It is only available in Electron.\n\n## Layer 4: Integrations\n\n### Local HTTP API\n\nA REST API on `localhost:31415` for external tools:\n\n```\nGET    /api/v1/nodes?schema=&limit=&offset=\nPOST   /api/v1/nodes          { schema, properties }\nGET    /api/v1/nodes/:id\nPATCH  /api/v1/nodes/:id\nDELETE /api/v1/nodes/:id\nPOST   /api/v1/query          { schema, limit?, offset? }\nGET    /api/v1/events?since=   Polling endpoint\nGET    /api/v1/schemas\n```\n\nOptional Bearer token authentication. CORS enabled.\n\n### MCP server\n\nExposes xNet data to AI agents via the Model Context Protocol:\n\n| Tool           | Description            |\n| -------------- | ---------------------- |\n| `xnet_query`   | Query nodes by schema  |\n| `xnet_get`     | Get a node by ID       |\n| `xnet_create`  | Create a node          |\n| `xnet_update`  | Update node properties |\n| `xnet_delete`  | Delete a node          |\n| `xnet_schemas` | List all schemas       |\n\nThe MCP server reads from stdin and writes JSON-RPC 2.0 responses to stdout.\n\n:::tip\nMCP is the fallback surface for agents. The primary agent interface is the\nfiles-first workspace checkout plus the `xnet` CLI — dramatically cheaper in\ntokens. See [Agent Interfaces](/docs/guides/agent-interfaces/).\n:::\n\n### Webhooks\n\nPush notifications on store changes:\n\n```ts\nimport { createWebhookEmitter } from '@xnetjs/plugins'\n\nconst emitter = createWebhookEmitter(store)\nemitter.register({\n  id: 'notify-slack',\n  url: 'https://hooks.slack.com/...',\n  events: ['created', 'updated'],\n  schema: 'xnet://app/Task',\n  secret: 'hmac-secret',\n  retries: 3\n})\nemitter.start()\n```\n\nPayloads are signed with HMAC-SHA256 (`x-xnet-signature-256` header). Failed deliveries retry with exponential backoff.\n\n## Worked example: Mermaid plugin\n\nHere is the complete source for the built-in Mermaid diagram plugin:\n\n```ts\nimport type { XNetExtension } from '@xnetjs/plugins'\nimport { MermaidExtension } from '@xnetjs/editor/extensions'\n\nexport const MermaidPlugin: XNetExtension = {\n  id: 'fyi.xnet.mermaid',\n  name: 'Mermaid Diagrams',\n  version: '1.0.0',\n  description: 'Add flowcharts, sequence diagrams, and more using Mermaid syntax.',\n  author: 'xNet',\n  platforms: ['electron', 'web'],\n\n  contributes: {\n    editorExtensions: [\n      {\n        id: 'mermaid',\n        extension: MermaidExtension,\n        priority: 100\n      }\n    ],\n    slashCommands: [\n      {\n        id: 'mermaid',\n        name: 'Mermaid Diagram',\n        description: 'Insert a Mermaid diagram',\n        aliases: ['diagram', 'flowchart', 'sequence', 'chart'],\n        icon: 'git-branch',\n        execute: ({ editor, range }) => {\n          ;(editor as any).chain().focus().deleteRange(range).setMermaid().run()\n        }\n      }\n    ]\n  }\n}\n```\n\nKey takeaways:\n\n- **No `activate`/`deactivate`** — simple plugins only need `contributes`\n- **Two contributions** — an editor extension and a slash command that work together\n- **Platform restriction** — excluded from mobile where the editor isn't available\n- **Bundled plugins** are installed from `BUNDLED_PLUGINS` in the app entry point and rehydrated on restart using `registry.rehydrate()` to restore live function references after deserialization\n\n## Permissions\n\nPlugins can declare the permissions they need:\n\n```ts\npermissions: {\n  schemas: {\n    read: ['xnet://app/Task', 'xnet://app/Project'],\n    write: ['xnet://app/Task'],\n    create: ['xnet://app/Task']\n  },\n  capabilities: {\n    network: ['https://api.example.com'],   // or true for all\n    storage: 'local',                        // or 'shared'\n    clipboard: true,\n    notifications: true,\n    processes: true                           // Electron only\n  }\n}\n```\n\n## Platform compatibility\n\n| Feature              | Electron | Web | Mobile |\n| -------------------- | -------- | --- | ------ |\n| Views                | Yes      | Yes | Yes    |\n| Commands             | Yes      | Yes | Yes    |\n| Slash commands       | Yes      | Yes | No     |\n| Editor extensions    | Yes      | Yes | No     |\n| Sidebar items        | Yes      | Yes | Yes    |\n| Property handlers    | Yes      | Yes | Yes    |\n| Block types          | Yes      | Yes | No     |\n| Settings panels      | Yes      | Yes | Yes    |\n| Scripts (sandbox)    | Yes      | Yes | Yes    |\n| Services (processes) | Yes      | No  | No     |\n| Local API            | Yes      | No  | No     |\n| MCP server           | Yes      | No  | No     |\n| Webhooks             | Yes      | Yes | Yes    |\n\nIf a plugin specifies `platforms` and the current platform isn't included, installation is rejected. Use `ctx.capabilities` to check feature availability at runtime.\n\n## Ecosystem APIs: capabilities, marketplace, testing\n\nThe `@xnetjs/plugins` ecosystem layer turns a [`FeatureModule`](#the-four-layers) manifest into something installable, trustworthy, and testable. Every export below is available from `@xnetjs/plugins`.\n\n### Declared capabilities are enforced\n\nA `FeatureModule` declares a `capabilities` grant. At install, the registry hands the plugin a `NodeStore` wrapped by a guard, so a write outside the grant throws a `CapabilityError` — the declaration is a runtime gate, not a label.\n\n```ts\nimport { defineFeatureModule } from '@xnetjs/plugins'\n\nexport const KanbanModule = defineFeatureModule({\n  id: 'com.acme.kanban',\n  name: 'Kanban Board',\n  version: '1.0.0',\n  capabilities: {\n    schemaWrite: ['xnet://xnet.fyi/Task@*'], // may write any Task version…\n    network: ['api.acme.com'] //               …and reach only this host\n  }\n})\n// Inside activate(ctx): ctx.store.create({ schemaId: 'xnet://xnet.fyi/Secret@1.0.0' })\n// → throws CapabilityError — Secret is outside the grant.\n```\n\nPatterns: exact (`…/Task@1.0.0`), version-wildcard (`…/Task@*`), authority-wildcard (`…/fyi/*`), or `*` (all — rendered as a danger in the consent dialog). Reads default open; declare `schemaRead` to restrict them.\n\n### Provenance, trust tier, and install consent\n\nA plugin's trust tier follows its **provenance** (where it came from), never anything it declares about itself. Pass `provenance` to `install`; the registry derives the tier and prompts for consent when needed.\n\n```ts\nimport { evaluateInstallConsent } from '@xnetjs/plugins'\n\nawait registry.install(manifest, {\n  provenance: 'marketplace', // → marketplace tier (iframe sandbox)\n  hostVersion: '0.7.0', //       gates on manifest.xnetVersion\n  onConsent: async (decision) => {\n    // decision.lines describes each requested capability (danger-flagged)\n    return confirm(decision.lines.map((l) => l.text).join('\\n'))\n  }\n})\n```\n\n`deriveTrustTier`/`requiresCapabilityReprompt` map provenance to tier and consent: `builtin`→first-party, `authored`/`ai-generated`/`imported`/`synced`→user, `marketplace`→marketplace. Synced and marketplace installs always re-prompt — sync is not consent.\n\n### Version compatibility and dependencies\n\nDeclare a host requirement with `xnetVersion` (a semver range) and other plugins with `dependencies`. Install gates on both.\n\n```ts\ndefineFeatureModule({\n  id: 'com.acme.app',\n  name: 'App',\n  version: '1.0.0',\n  xnetVersion: '>=0.6.0', // satisfiesRange / isHostCompatible\n  dependencies: { 'com.acme.core': '^1.2.0' } // resolveInstallOrder / findMissingDependencies\n})\n```\n\n### Marketplace index and supply-chain provenance\n\nThe marketplace is a GitHub-hosted `registry.json` of `MarketplaceEntry`s. `MarketplaceClient` fetches once and searches in memory; `verifyProvenance` checks a Sigstore-style attestation and **fails closed** (no verifier configured ⇒ \"unverified\", never a false green).\n\n```ts\nimport { MarketplaceClient, verifyProvenance } from '@xnetjs/plugins'\n\nconst market = new MarketplaceClient({ indexUrl: REGISTRY_URL })\nconst results = await market.search('tasks', { sort: 'installs', category: 'productivity' })\nconst { verified, reason } = await verifyProvenance({ artifactDigest, provenance })\n```\n\n### Testing a plugin\n\n`createTestPluginHarness` wires an in-memory store into a real `PluginRegistry`, so you can install a manifest and assert on its contributions without the app.\n\n```ts\nimport { createTestPluginHarness } from '@xnetjs/plugins'\n\nconst harness = createTestPluginHarness()\nawait harness.install(KanbanModule)\nexpect(harness.registry.get('com.acme.kanban')?.status).toBe('active')\nexpect(harness.registry.getContributions().slashCommands.getAll()).toHaveLength(1)\n```\n\n### Scaffolding a new plugin\n\n`xnet plugin scaffold` writes a ready-to-edit project (manifest, harness test, `package.json`, README) from one of three templates — `client`, `two-sided`, or `ai-script`:\n\n```bash\nxnet plugin scaffold com.acme.kanban --name \"Kanban Board\" --template client\n# → com.acme.kanban/{package.json,tsconfig.json,src/index.ts,src/index.test.ts,README.md}\n```\n\nThe pure core, `scaffoldPlugin(spec)`, returns the project as a path→content map, so tooling can generate plugins without touching disk:\n\n```ts\nimport { scaffoldPlugin } from '@xnetjs/plugins'\n\nconst { files } = scaffoldPlugin({ id: 'com.acme.kanban', name: 'Kanban', template: 'client' })\n// files['src/index.ts'] is a defineFeatureModule(...) ; files['src/index.test.ts'] uses the harness\n```\n\n### Authoring a plugin with AI\n\nThe AI generators in `@xnetjs/plugins/ai` turn natural language into an AST-validated script. `scriptToPluginManifest` wraps a **validated** generated script into an installable plugin stamped with `ai-generated` provenance (so the install path sandboxes it at the `user` tier and still routes its capability requests through consent). It refuses unvalidated code — \"the AI made it\" never bypasses the gate.\n\n```ts\nimport { scriptToPluginManifest } from '@xnetjs/plugins'\n\nconst { manifest, provenance } = scriptToPluginManifest({\n  id: 'com.me.counter',\n  script: generated, // { code, suggestedName, validated, explanation } from the AI generator\n  run: (code) => runInSandbox(code) // how the command executes the script\n})\nawait registry.install(manifest, { provenance }) // provenance === 'ai-generated'\n```\n\n### Reaching the network safely\n\nA plugin that declares `network` hosts is handed a `guardedFetch` instead of the ambient `fetch`. Every request is checked against the allowlist before it leaves; an undeclared host rejects with `CapabilityError`, and a plugin with no `network` grant gets no egress at all.\n\n```ts\nimport { guardedFetch } from '@xnetjs/plugins'\n\nconst fetch = guardedFetch({ network: ['api.acme.com'] }, 'com.acme.kanban')\nawait fetch('https://api.acme.com/cards') // ok\nawait fetch('https://evil.example.com') // rejects: CapabilityError\n```\n\n## Publishing to the marketplace\n\nYour plugin's code stays in **your own repo** — getting listed on the\n[plugins marketplace](/plugins) is a one-line pull request, not a code dump into\nthe monorepo.\n\n<Steps>\n\n1. **Ship a Release.** Build your plugin into a single `plugin.js` and attach it,\n   with `manifest.json`, to a GitHub Release. (A copyable template with a release\n   workflow lives in\n   [`examples/xnet-plugin-template`](https://github.com/crs48/xNet/tree/main/examples/xnet-plugin-template).)\n\n2. **Add one entry** to [`registry/community.json`](https://github.com/crs48/xNet/tree/main/registry):\n\n   ```jsonc\n   [{ \"repo\": \"you/xnet-plugin-kanban\", \"category\": \"views\" }]\n   ```\n\n3. **Open a PR.** CI validates the submission; after merge, a daily job enriches\n   your entry from the GitHub API and points the install link at your Release's\n   `manifest.json`. Updates you ship afterward are picked up automatically.\n\n</Steps>\n\nThe app installs community plugins in a sandbox scoped to their trust tier,\nafter showing the user the capabilities the plugin requests and verifying its\nprovenance. See [`registry/README.md`](https://github.com/crs48/xNet/tree/main/registry)\nfor the full flow.","src/content/docs/docs/guides/plugins.mdx","5bdaae6a37a75dbf","docs/guides/quiet-shell",{id:410,data:412,body:418,filePath:419,digest:420,deferredRender:16},{title:413,description:414,editUrl:16,head:415,template:18,sidebar:416,pagefind:16,draft:21},"The Quiet Shell & the Desk","A blank-sheet workspace posture: the surface owns the screen, chrome is summoned from the edges.",[],{hidden:21,attrs:417},{},":::note[You will learn]\n\n- What the quiet chrome posture is and how to switch into it\n- The disclosure ladder: corners, edges, chords, and Esc\n- The Desk — your bounded home canvas — and how pinning works\n- The SurfaceDock, and how it maps to the pinned shell's tray\n  :::\n\n## Overview\n\nThe quiet shell inverts the calm shell's composition: at rest the screen is\njust your work — a document, a database, or the Desk canvas — and the chrome\nis *summoned*, never pinned. Glyph clusters sit dimmed in the corners; the\nnavigator and the contextual canvas slide in from the edges; the dock expands\nfrom the bottom-right the way devtools always has. Nothing is removed — every\ndrawer is reachable three ways: pointer (hover an edge, or swipe on a phone),\nkeyboard chord, or the ⌘K palette.\n\nSwitch postures any time with **⌘K → \"View: Quiet chrome\"** (and back with\n\"View: Pinned chrome\"). The setting is per-device and changes nothing about\nyour data or routes.\n\n## The disclosure ladder\n\n| Level | What you see                | How you got here                             |\n| ----- | --------------------------- | -------------------------------------------- |\n| L0    | Bare surface, dimmed glyphs | Rest state                                   |\n| L1    | Glyphs lit                  | Pointer near an edge, or a touch             |\n| L2    | One overlay open            | Edge hover-dwell, swipe, ⌘B / ⌘\\ / ⌘J / ⌘K |\n| L3    | Pinned chrome               | \"View: Pinned chrome\" or the workbench grid  |\n\n**Esc always walks down one rung.** Dismissing an overlay returns you to the\nbare surface; it never dead-ends.\n\n| Surface   | Pointer / touch          | Chord | Palette             |\n| --------- | ------------------------ | ----- | ------------------- |\n| Navigator | left edge hover / swipe  | ⌘B    | Toggle left panel   |\n| Context   | right edge hover / swipe | ⌘\\    | Toggle right panel  |\n| Dock      | corner launcher / FAB    | ⌘J    | `Dock: <panel>`     |\n| Palette   | corner search glyph      | ⌘K    | —                   |\n\n## The Desk\n\nThe Desk is a personal home canvas with a deterministic, identity-derived id —\nit is created the first time you visit it, and the same identity gets the same\nDesk on every device. It is **bounded but growable**: panning clamps near your\ncontent (you can't strand yourself in empty space), and the board grows as\ncards land outside it. **Fit to content** (Ctrl/Cmd 1) is the home anchor.\n\nBuild your workspace by pinning:\n\n- **Drag** anything from the navigator onto the Desk.\n- **Pin to Desk** from a document via ⌘K, or the desk icon that appears when\n  you hover a navigator row. Pins queue up and land the next time the Desk is\n  on screen — you don't have to be looking at it.\n- **Go to Desk** (`g k`) from anywhere.\n\nPinned cards are live views of the real nodes — edit the source and the card\nfollows. On a phone the Desk renders as an ordered list (reading order of the\nboard), which is also how screen readers traverse it.\n\n## The SurfaceDock\n\nThe bottom-right launcher is the devtools grammar for everyone: a single\nglyph that expands into the *hero* panels (Shelf, Capture, Notifications) with\nthe rest behind **More** and the palette. It reuses the pinned shell's bottom\ntray state, so ⌘J toggles the same panels in either posture. Plugins add\npanels through the `surfaceDock` contribution point in `@xnetjs/plugins`.\n\n## Rollout\n\nQuiet chrome ships opt-in. New identities boot straight to the Desk under\nquiet chrome once the staged-rollout flag flips; existing workspaces keep\nwhatever posture they chose.","src/content/docs/docs/guides/quiet-shell.mdx","341689637e269a0e","docs/guides/server",{id:421,data:423,body:429,filePath:430,digest:431,deferredRender:16},{title:424,description:425,editUrl:16,head:426,template:18,sidebar:427,pagefind:16,draft:21},"Your Own Server","Run xNet on your own backend with your own auth using @xnetjs/server — keep the React hooks, bring your own database and identity.",[],{order:305,hidden:21,attrs:428},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- When to use a managed Hub vs. your own server\n- How `@xnetjs/server` maps **your** auth onto xNet's data layer\n- The three hooks: `authenticate`, `authorizeRead`, `authorizeWrite`\n- The trust spectrum: `server`, `custodial`, `signed`\n- How to wire it to the React hooks with no client changes\n  :::\n\n## Two paths to a backend\n\nxNet React works against two kinds of backend, and **the React hooks\n(`useQuery` / `useMutate` / `useNode`) are identical either way**:\n\n| Path                 | What you run                         | Identity & auth                    |\n| -------------------- | ------------------------------------ | ---------------------------------- |\n| **Managed Hub**      | Nothing — point at a Hub URL         | xNet identity (DIDs), works out of the box |\n| **Your own server**  | `@xnetjs/server` in your Node backend | **Your** auth (session/JWT/Clerk/…) |\n\nIf you want the decentralized, user-owned defaults, use a [Hub](/docs/guides/hub/).\nIf you want a centralized app on your own infrastructure, gated by your existing\nauth and stored in your own database, use `@xnetjs/server`.\n\n## What `@xnetjs/server` is\n\nA small, framework-agnostic engine you mount in your Node backend (Express,\nHono, Fastify, a Next.js route handler). It owns a server-side node store over a\npluggable storage adapter and exposes:\n\n- **`server.query(request)`** — the server side of the remote-query protocol: a\n  structured-query executor that authenticates, scopes the read, runs it, and\n  returns results.\n- **`server.mutate(token, input)`** — backend-authoritative writes: authenticate,\n  validate, then apply.\n- **`server.createRemoteQueryClient(getToken)`** — an in-process client that\n  drops into `XNetProvider`'s `remoteNodeQueryClient`, so React reads route to\n  your server unchanged.\n\n## Install\n\n<Tabs syncKey=\"pkg\">\n<TabItem label=\"pnpm\">\n\n```bash\npnpm add @xnetjs/server\n```\n\n</TabItem>\n<TabItem label=\"npm\">\n\n```bash\nnpm install @xnetjs/server\n```\n\n</TabItem>\n<TabItem label=\"yarn\">\n\n```bash\nyarn add @xnetjs/server\n```\n\n</TabItem>\n</Tabs>\n\n## Three hooks map your auth onto the data layer\n\nYou wire your existing auth through three callbacks. No UCAN, no `did:key`\nrequired from your users.\n\n```ts\nimport { createXNetServer } from '@xnetjs/server'\n\nconst xnet = await createXNetServer({\n  trust: 'custodial',\n\n  // 1. Exchange a token/cookie for your own principal. Return null to reject.\n  authenticate: async (token) => {\n    const session = await verifyMySession(token)\n    return session ? { subject: session.userId, tenant: session.orgId } : null\n  },\n\n  // 2. Scope what a subject can read (row-level security).\n  authorizeRead: (ctx, query) => query.and({ tenant: ctx.tenant }),\n\n  // 3. Validate writes in your own terms. For update/delete, authorize against\n  //    the STORED node (`write.existing`), not the client-supplied data.\n  authorizeWrite: (ctx, write) => {\n    const tenant =\n      write.op === 'create' ? write.payload.properties.tenant : write.existing?.properties.tenant\n    return tenant === ctx.tenant ? { ok: true } : { ok: false, reason: 'wrong tenant' }\n  }\n})\n```\n\n`authenticate` returns a `ServerAuthContext` — `{ subject, ...claims }` — where\n`subject` is your own user id (or a `did:key` in `signed` mode). Extra claims\n(roles, orgs, tenant) ride along for the authorize hooks.\n\n`authorizeRead` receives a narrowable query; `query.and({ … })` ANDs equality\nfilters into the read (the canonical \"only this tenant's rows\" move).\n\n`authorizeWrite` receives a normalized `PendingWrite`. For `update`/`delete` it\nincludes `existing` — the **stored** node snapshot — so ownership checks and\nschema allow-lists can't be bypassed by a by-id write. Return\n`{ ok: false, reason }` to deny; the client receives a typed rejection.\n\n## The trust spectrum\n\nHow an end-user's identity maps onto xNet's signed-change model:\n\n| Mode          | Who signs                       | `authorDID` is              | Best for                              |\n| ------------- | ------------------------------- | --------------------------- | ------------------------------------- |\n| `server`      | the server (one identity)       | the server                  | centralized apps, maximum simplicity  |\n| `custodial`   | the server, per-user derived key | a stable per-user DID       | mainstream apps wanting per-user attribution, no key UX |\n| `signed`      | the client                      | the client's DID (bound to the authenticated subject) | tamper-evident, user-owned data |\n\nIn `signed` mode the server verifies the client's signature **and** that the\nchange's author matches the authenticated subject — a forged author is rejected\n(`IDENTITY_MISMATCH`), and a tampered change is rejected (`SIGNATURE_INVALID`).\n\n## Wire it to React — no hook changes\n\nReads route through the existing `remoteNodeQueryClient` seam:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\n\nconst remoteNodeQueryClient = xnet.createRemoteQueryClient(getToken)\n\nexport function App() {\n  return (\n    <XNetProvider config={{ remoteNodeQueryClient }}>\n      <Todos />\n    </XNetProvider>\n  )\n}\n\nfunction Todos() {\n  // Exactly the same hooks as a managed-Hub app:\n  const { data: todos } = useQuery(TodoSchema, { where: { done: false } })\n  const { create, update } = useMutate()\n  // …\n}\n```\n\n## Mounting in your server\n\n`createXNetServer` is transport-agnostic — call `query`/`mutate` from any HTTP\nor WebSocket handler. A minimal Express sketch:\n\n```ts\nimport express from 'express'\n\nconst app = express()\napp.use(express.json())\n\n// Reads\napp.post('/xnet/query', async (req, res) => {\n  res.json(await xnet.query(req.body))\n})\n\n// Writes\napp.post('/xnet/mutate', async (req, res) => {\n  const token = req.headers.authorization?.replace('Bearer ', '')\n  res.json(await xnet.mutate(token, req.body))\n})\n```\n\n## Storage\n\nBy default `@xnetjs/server` keeps an in-memory store (great for tests). Pass any\n`NodeStorageAdapter` via the `storage` option to persist — for example a SQLite\nadapter — so your data lives in your own database.\n\n## Status\n\nThe engine — structured-query executor, backend-authoritative mutations, the\nauth hooks, and the trust spectrum — is shipped and tested. Networked\ntransports (a built-in WebSocket relay, framework adapters, a Postgres adapter,\nlive streaming), and the full offline write client are tracked as follow-ups in\nexploration `0223`.\n\n## See also\n\n- [React Hooks overview](/docs/hooks/overview/)\n- [Hub Setup](/docs/guides/hub/) — the managed path\n- [Authorization](/docs/guides/authorization/) — xNet's built-in model (opt-in)","src/content/docs/docs/guides/server.mdx","f052b4b9038f27da","docs/guides/sync",{id:432,data:434,body:440,filePath:441,digest:442,deferredRender:16},{title:435,description:436,editUrl:16,head:437,template:18,sidebar:438,pagefind:16,draft:21},"Sync Guide","How P2P sync works and how to configure it.",[],{order:20,hidden:21,attrs:439},{},":::note[You will learn]\n\n- How xNet's dual-CRDT sync model works\n- The signaling server and WebSocket transport\n- How Yjs updates are signed, rate-limited, and verified\n- The SyncManager lifecycle and configuration\n- How to debug sync issues\n  :::\n\n## The dual-CRDT model\n\nxNet uses two complementary sync strategies, each optimized for a different data shape:\n\n| Data type                    | Mechanism                     | Conflict resolution                            |\n| ---------------------------- | ----------------------------- | ---------------------------------------------- |\n| Rich text (editor content)   | Yjs CRDT                      | Character-level merge — no conflicts by design |\n| Structured data (properties) | NodeStore with Lamport clocks | Field-level Last-Writer-Wins (LWW)             |\n\nBoth strategies sync over the same multiplexed WebSocket connection.\n\n### Yjs for rich text\n\nEach node with editor content gets a `Y.Doc`. Yjs handles character-level CRDT merging internally — two users typing in the same paragraph at the same time will see their edits merge without conflict. The sync protocol exchanges state vectors and diffs:\n\n1. Peer A sends sync-step1 (its state vector)\n2. Peer B responds with sync-step2 (the diff A is missing), plus its own sync-step1\n3. After the initial exchange, incremental updates flow as `sync-update` messages\n\n### NodeStore for structured data\n\nProperty changes (title, status, assignee, etc.) go through the `Change<T>` pipeline:\n\n```ts\ninterface Change<T> {\n  id: string\n  type: string\n  payload: T\n  hash: ContentId // cid:blake3:... content-addressed\n  parentHash: ContentId | null // Hash chain linkage\n  authorDID: DID\n  signature: Uint8Array // Ed25519 over hash\n  lamport: LamportTimestamp // Causal ordering\n}\n```\n\nEach change is signed with Ed25519, content-addressed with BLAKE3, and linked into a hash chain. Conflicts are resolved by comparing Lamport timestamps — higher time wins, with DID string as a deterministic tie-breaker.\n\n### MetaBridge: the one-way bridge\n\nThe `MetaBridge` keeps the Y.Doc's metadata map in sync with NodeStore properties, but the data flow is intentionally **one-directional**:\n\n```\nNodeStore → MetaBridge → Y.Doc meta map (write)\nY.Doc meta → Editor UI (read-only display)\nEditor UI → mutate() → NodeStore (signed writes)\n```\n\nThis prevents malicious Yjs updates from poisoning structured data. Property changes always go through `mutate()` → signed Change pipeline, never through the Yjs document directly.\n\n## Yjs security\n\nEvery Yjs update transmitted over the network is wrapped in a `SignedYjsEnvelope`:\n\n```ts\ninterface SignedYjsEnvelope {\n  update: Uint8Array // Raw Yjs update bytes\n  authorDID: string // did:key:...\n  signature: Uint8Array // Ed25519 over BLAKE3(update)\n  timestamp: number\n  clientId: number // Yjs clientID bound to this DID\n}\n```\n\n### Signing and verification flow\n\n```mermaid\nflowchart LR\n  subgraph Signing\n    A[\"Yjs update bytes\"] --> B[\"BLAKE3 hash\"]\n    B --> C[\"Ed25519 sign\\n(private key)\"]\n    C --> D[\"SignedYjsEnvelope\\n+ DID, clientId, ts\"]\n  end\n\n  subgraph Verification\n    E[\"Receive envelope\"] --> F[\"Parse DID →\\npublic key\"]\n    E --> G[\"BLAKE3 hash\\nupdate bytes\"]\n    F --> H[\"Ed25519 verify\\nsig vs hash\"]\n    G --> H\n    H -->|valid| I[\"Apply update\"]\n    H -->|invalid| J[\"Reject + penalize\"]\n  end\n\n  D -.->|network| E\n```\n\n**Signing:** BLAKE3 hash the raw Yjs update bytes → Ed25519 sign the hash with the author's private key → attach envelope metadata (DID, clientId, timestamp).\n\n**Verification:** Parse the author's DID to extract their Ed25519 public key (self-certifying — no resolver needed) → BLAKE3 hash the update bytes → verify the Ed25519 signature against the hash.\n\n### Rate limiting\n\nThe `YjsRateLimiter` enforces per-peer limits:\n\n| Limit              | Value           |\n| ------------------ | --------------- |\n| Max update size    | 1 MB            |\n| Updates per second | 30 (+ 10 burst) |\n| Updates per minute | 600             |\n| Max document size  | 50 MB           |\n| Sync chunk size    | 256 KB          |\n\nLarge initial syncs are automatically chunked into 256 KB pieces and reassembled on the receiving end.\n\n### Peer scoring\n\nThe `YjsPeerScorer` tracks peer behavior. Peers start at score 100:\n\n| Violation           | Penalty                  |\n| ------------------- | ------------------------ |\n| Invalid signature   | -30 (auto-block after 3) |\n| Unsigned update     | -20                      |\n| Unattested clientId | -15                      |\n| Oversized update    | -10                      |\n| Rate exceeded       | -5                       |\n\nScore thresholds: **warn** at 50, **throttle** at 30, **block** at 10. Peers recover +1 per tick if they have no violations for 60 seconds.\n\n### ClientID attestation\n\nYjs assigns random integer clientIDs with no identity binding. xNet fixes this with signed attestations:\n\n```ts\ninterface ClientIdAttestation {\n  clientId: number\n  did: string\n  signature: Uint8Array // Ed25519 over BLAKE3(\"clientid-bind:{clientId}:{did}:{room}:{expiresAt}\")\n  expiresAt: number\n  room: string\n}\n```\n\nA `ClientIdMap` maintains bidirectional `clientId ↔ DID` mappings. When an envelope arrives, `validateClientIdOwnership` checks that the envelope's clientID matches the attested DID.\n\n### Update batching\n\nThe `YjsBatcher` collects individual Yjs updates (around 5/second from keystrokes) and flushes them in batches every 2 seconds (or at most 50 updates per batch). This reduces signature operations from ~5/sec to ~0.5/sec. Batches flush early on paragraph breaks.\n\n### Hash-at-rest integrity\n\nPersisted Yjs state is BLAKE3-hashed before writing to storage. On load, the hash is re-verified to detect storage-level corruption before it propagates to peers. After 100 incremental updates or 1 hour, the document is compacted (re-encoded from scratch).\n\n## SyncManager\n\nThe `SyncManager` is the top-level orchestrator that wires everything together.\n\n### Configuration\n\n```ts\ninterface SyncManagerConfig {\n  nodeStore: NodeStore\n  storage: NodeStorageAdapter\n  signalingUrl: string // WebSocket URL, e.g., 'wss://hub.xnet.dev'\n  poolSize?: number // Default: 50 warm documents\n  trackTTL?: number // Default: 7 days\n  authorDID?: string\n  blobStore?: BlobStoreForSync\n}\n```\n\n### Lifecycle\n\n```\nstart → connected → drainOfflineQueue → sync\n                                          ↕\n                              disconnected → enqueueLocally\n                                          ↕\nstop → flushDirtyDocs → pruneRegistry → save\n```\n\n1. **`start()`** — Load registry and offline queue from storage, connect WebSocket, join rooms for all tracked nodes, start blob sync.\n2. **On connected** — Drain offline queue (broadcast queued updates), re-send sync-step1 for all pooled documents.\n3. **`acquire(nodeId)`** — Load Y.Doc from pool or storage, set up broadcast listener, join room, send sync-step1. Used by `useNode`.\n4. **`release(nodeId)`** — Decrement refcount. Doc stays warm in the pool and continues syncing in the background.\n5. **`track(nodeId, schemaId)`** — Add to the persistent registry for background sync. Tracked nodes are synced even when no component has them open.\n6. **`stop()`** — Leave all rooms, disconnect, flush dirty docs to storage, prune expired registry entries, save state.\n\n### NodePool\n\nThe pool manages Y.Doc instances in three states:\n\n- **Active** (refCount > 0) — Currently used by a component. Never evicted.\n- **Warm** (refCount = 0) — Released but kept in memory for quick re-acquisition. Evicted via LRU when pool is full.\n- **Cold** — Evicted to storage. Loaded on next `acquire()`.\n\nDirty documents are persisted on a debounced 2-second timer.\n\n### Registry\n\nThe persistent tracked-node set that survives app restarts:\n\n```ts\ninterface TrackedNode {\n  nodeId: string\n  schemaId: string\n  lastOpened: number\n  lastSynced: number\n  pinned: boolean // Pinned nodes never expire\n}\n```\n\nTracked nodes with no activity for `trackTTL` (default 7 days) are pruned on shutdown, unless pinned.\n\n### OfflineQueue\n\nWhen the WebSocket is disconnected, local Y.Doc updates are enqueued:\n\n```ts\ninterface OfflineQueue {\n  enqueue(nodeId: string, update: Uint8Array): Promise<void>\n  drain(handler): Promise<number>\n  readonly size: number\n}\n```\n\n- Max 1000 entries (FIFO — oldest dropped if full)\n- Persisted immediately on enqueue for crash resilience\n- Drained in order on reconnect; stops on first error (entry stays at front for retry)\n\n## Transport\n\n### ConnectionManager\n\nA single multiplexed WebSocket connection handles all documents (O(1) connections, not O(N) per doc):\n\n- Room-based pub/sub: `subscribe(topics)`, `publish(topic, data)`\n- Auto-reconnect with configurable delay and max attempts\n- On reconnect: automatically re-subscribes to all rooms\n\n### WebSocketSyncProvider\n\nA per-document provider that implements the Yjs sync protocol over the shared connection:\n\n1. On connect — subscribe to room, broadcast sync-step1 (state vector)\n2. On sync-step1 from peer — respond with sync-step2 (diff)\n3. On sync-step2 — apply update, mark synced\n4. On sync-update — apply incremental update\n5. Awareness updates (cursor position, user name) flow alongside document updates\n\n## Lamport clocks\n\nxNet uses Lamport clocks for causal ordering of structured data changes:\n\n```ts\ninterface LamportTimestamp {\n  time: number\n  author: DID\n}\n```\n\n- `tick(clock)` — increment time by 1, return `[newClock, timestamp]`\n- `receive(clock, receivedTime)` — set time to `max(ours, received)` (no increment)\n- `compareLamportTimestamps(a, b)` — compare by time first, then DID string as tie-breaker\n- `serializeTimestamp()` — zero-padded 16-digit time + DID for lexicographic sorting\n- All functions are pure — they return new objects, never mutate\n\n### Hash chains\n\nChanges link to their parent via `parentHash`, forming a directed acyclic graph:\n\n- `validateChain()` — verify all hashes are correct\n- `detectFork()` — find where two changes share a parent\n- `topologicalSort()` — deterministic replay order (parents before children)\n- `getForks()` — returns detailed fork info with branches sorted by Lamport\n\nForks are valid — they represent concurrent edits, not errors. Field-level LWW resolves them deterministically.\n\n## Debugging\n\nEnable debug logging in the browser console:\n\n```js\nlocalStorage.setItem('xnet:sync:debug', 'true')\n```\n\nThe DevTools sync panel shows:\n\n- Connection status and peer count\n- Document pool state (active, warm, cold)\n- Registry entries with last-synced timestamps\n- Offline queue size\n- Per-peer scoring data\n\nUse `pnpm dev:both` in the Electron app to run two instances for testing sync behavior locally.","src/content/docs/docs/guides/sync.mdx","0da46ba6f7491cce","docs/guides/tasks",{id:443,data:445,body:451,filePath:452,digest:453,deferredRender:16},{title:446,description:447,editUrl:16,head:448,template:18,sidebar:449,pagefind:16,draft:21},"Tasks","Task surfaces, inline editing, quick-add with mentions, and the field-authority model.",[],{hidden:21,attrs:450},{},":::note[You will learn]\n\n- Where tasks live in the app and how the surfaces connect\n- Inline editing and quick-add with `@mention`\n- Deep links (`/tasks?task=`, `/tasks?project=`)\n- Why some task fields are read-only outside their hosting page\n  :::\n\n## Overview\n\nTasks are first-class nodes (`TaskSchema`) with status, priority, assignees,\ndue dates, and project membership. They show up — and are **editable in\nplace** — on every surface that renders them: the Tasks view, the sidebar\nmini-dashboard, page checklists, kanban boards, and the right context panel.\n\n## Surfaces\n\n### The Tasks view (`/tasks`)\n\nThe main surface: list and board layouts with keyboard verbs —\n`j`/`k` to move, `x` to complete, `s` for status, `p` for priority, `Enter` to\nedit. Clicking a row expands an editor beneath it; board cards open a peek\noverlay; the right context panel hosts the same live editor for the focused\ntask.\n\nDeep links are first-class:\n\n- `/tasks?task=<id>` opens that task's editor directly.\n- `/tasks?project=<id>` scopes the surface to a project (with a clearable\n  chip); quick-added tasks join that project.\n\n### The sidebar Tasks panel\n\nA personal mini-dashboard in the left panel:\n\n- **Pinned** — tasks you pinned, surfaced first\n- **In progress** — your tasks in a started status\n- **Assigned to me** — priority-ordered (urgent → low, then nearest due date),\n  paginated\n- **Projects** — projects you follow, with open-task counts; click one to\n  scope the Tasks view to it\n\nRows are draggable onto canvases and deep-link into the Tasks view.\n\n### Everywhere else\n\nTask checklists inside pages, task widgets on dashboards, and task rows in\ndatabase views all expand the same shared editor — title with\n**@mention-to-assign**, status/priority pickers, a due-date popover\n(Today / Tomorrow / Next week / pick a date / clear), an assignee picker, and\na pin toggle.\n\n## Quick-add\n\nEvery task surface has a quick-add input. Type `@` while entering the title to\nassign as you type — pending assignees render as removable chips before the\ntask is created.\n\n## Field authority: pages own their checklists\n\nA task can be **hosted by a page** (created from a checklist item in a\ndocument). The hosting page is the source of truth for the fields it renders\ninline:\n\n| Field                          | Owner                                  |\n| ------------------------------ | -------------------------------------- |\n| Title, assignees, due date     | The hosting page (document content)    |\n| Status, priority, completion, pins | The task node — editable everywhere |\n\nOn the page itself, edits to doc-owned fields **write through the live\ndocument** (mention nodes, due chips) and the page then reconciles the task\nnode. On other surfaces (e.g. `/tasks`), doc-owned fields of hosted tasks\nrender read-only with an *Open page* affordance — a node-side write would be\nsilently overwritten by the page's next snapshot, so the app doesn't offer\none.\n\nTasks created outside a page (quick-add, Tasks view, widgets) have no hosting\npage and every field is editable everywhere.\n\n## Querying tasks in your own code\n\nTasks are ordinary nodes — the same hooks apply:\n\n```tsx\nimport { useQuery, useMutate } from '@xnetjs/react'\n\nconst { data: myTasks } = useQuery(TaskSchema, {\n  filter: { assignees: { contains: me }, status: { not: 'done' } },\n  sort: [{ field: 'priority' }, { field: 'dueDate' }]\n})\n\nconst { update } = useMutate()\nawait update(TaskSchema, taskId, { status: 'in-progress' })\n```\n\n## Further reading\n\n- [The Workbench](/docs/guides/workbench/) — where the task surfaces live\n- [Dashboards](/docs/guides/dashboards/) — task-list and metric widgets\n- [Quickstart](/docs/quickstart/) — build your own task schema from scratch","src/content/docs/docs/guides/tasks.mdx","6007dd48a9cb74aa","docs/guides/testing",{id:454,data:456,body:462,filePath:463,digest:464,deferredRender:16},{title:457,description:458,editUrl:16,head:459,template:18,sidebar:460,pagefind:16,draft:21},"Testing","Testing xNet apps with Vitest.",[],{order:136,hidden:21,attrs:461},{},":::note[You will learn]\n\n- How to run the xNet test suite\n- How to write tests for schemas, stores, and sync\n- Common patterns for mocking crypto and storage\n- How to test multi-peer sync scenarios\n  :::\n\n## Running tests\n\n```bash\n# All tests (~4,700 tests across all packages)\npnpm test\n\n# Single package\npnpm --filter @xnetjs/sync test\npnpm --filter @xnetjs/data test\npnpm --filter @xnetjs/canvas test\n\n# Single file\npnpm --filter @xnetjs/sync vitest run src/clock.test.ts\n\n# Pattern match\npnpm --filter @xnetjs/data vitest run -t \"NodeStore\"\n\n# Watch mode\npnpm --filter @xnetjs/sync test:watch\n```\n\nAll tests use Vitest with the standard `describe` / `it` / `expect` structure.\n\n## Test structure\n\nFollow the Arrange-Act-Assert pattern:\n\n```ts\nimport { describe, it, expect } from 'vitest'\n\ndescribe('ModuleName', () => {\n  describe('functionName', () => {\n    it('should do expected behavior', () => {\n      // Arrange\n      const input = createTestData()\n\n      // Act\n      const result = functionName(input)\n\n      // Assert\n      expect(result).toBe(expected)\n    })\n  })\n})\n```\n\n## Testing schemas\n\n```ts\nimport { describe, it, expect } from 'vitest'\nimport { defineSchema, text, number, checkbox } from '@xnetjs/data'\n\ndescribe('TaskSchema', () => {\n  const TaskSchema = defineSchema({\n    name: 'Task',\n    namespace: 'xnet://example/',\n    properties: {\n      title: text(),\n      priority: number({ default: 0 }),\n      done: checkbox({ default: false })\n    }\n  })\n\n  it('should have the correct schema ID', () => {\n    expect(TaskSchema._schemaId).toContain('xnet://example/Task@')\n  })\n\n  it('should define expected properties', () => {\n    expect(TaskSchema._properties.title).toBeDefined()\n    expect(TaskSchema._properties.priority).toBeDefined()\n    expect(TaskSchema._properties.done).toBeDefined()\n  })\n})\n```\n\n## Testing crypto and signing\n\nGenerate keys in tests using `@xnetjs/crypto` and `@xnetjs/identity`:\n\n```ts\nimport { generateSigningKeyPair, sign, verify, hash } from '@xnetjs/crypto'\nimport { generateIdentity } from '@xnetjs/identity'\n\ndescribe('Signing', () => {\n  it('should sign and verify a message', () => {\n    const { publicKey, privateKey } = generateSigningKeyPair()\n    const message = new TextEncoder().encode('hello')\n\n    const signature = sign(message, privateKey)\n    expect(verify(message, signature, publicKey)).toBe(true)\n  })\n\n  it('should reject tampered messages', () => {\n    const { publicKey, privateKey } = generateSigningKeyPair()\n    const message = new TextEncoder().encode('hello')\n    const tampered = new TextEncoder().encode('world')\n\n    const signature = sign(message, privateKey)\n    expect(verify(tampered, signature, publicKey)).toBe(false)\n  })\n})\n```\n\n## Testing Lamport clocks\n\n```ts\nimport { createLamportClock, tick, receive, compareLamportTimestamps } from '@xnetjs/sync'\n\ndescribe('LamportClock', () => {\n  it('should increment on tick', () => {\n    const clock = createLamportClock('did:key:alice')\n    const [newClock, timestamp] = tick(clock)\n\n    expect(newClock.time).toBe(1)\n    expect(timestamp.time).toBe(1)\n    expect(timestamp.author).toBe('did:key:alice')\n  })\n\n  it('should fast-forward on receive', () => {\n    const clock = createLamportClock('did:key:alice')\n    const updated = receive(clock, 10)\n\n    expect(updated.time).toBe(10)\n  })\n\n  it('should break ties by DID', () => {\n    const a = { time: 5, author: 'did:key:alice' }\n    const b = { time: 5, author: 'did:key:bob' }\n\n    // Deterministic: string comparison on DID\n    expect(compareLamportTimestamps(a, b)).not.toBe(0)\n  })\n})\n```\n\n## Testing Change\\<T\\> and hash chains\n\n```ts\nimport { signChange, verifyChange, verifyChangeHash } from '@xnetjs/sync'\nimport { generateSigningKeyPair } from '@xnetjs/crypto'\nimport { generateIdentity } from '@xnetjs/identity'\n\ndescribe('Change', () => {\n  it('should sign and verify a change', () => {\n    const { identity, privateKey } = generateIdentity()\n    const { publicKey } = generateSigningKeyPair()\n\n    const unsigned = {\n      id: 'change-1',\n      type: 'create-task',\n      payload: { title: 'Test' },\n      parentHash: null,\n      authorDID: identity.did,\n      wallTime: Date.now(),\n      lamport: { time: 1, author: identity.did }\n    }\n\n    const signed = signChange(unsigned, privateKey)\n    expect(signed.hash).toMatch(/^cid:blake3:/)\n    expect(signed.signature).toBeInstanceOf(Uint8Array)\n  })\n})\n```\n\n## Testing Yjs security\n\n```ts\nimport { signYjsUpdate, verifyYjsEnvelope } from '@xnetjs/sync'\nimport { generateIdentity } from '@xnetjs/identity'\n\ndescribe('YjsEnvelope', () => {\n  it('should round-trip sign and verify', async () => {\n    const { identity, privateKey } = generateIdentity()\n    const update = new Uint8Array([1, 2, 3, 4])\n\n    const envelope = signYjsUpdate(update, identity.did, privateKey, 12345)\n    const result = await verifyYjsEnvelope(envelope)\n\n    expect(result.valid).toBe(true)\n  })\n\n  it('should reject tampered updates', async () => {\n    const { identity, privateKey } = generateIdentity()\n    const update = new Uint8Array([1, 2, 3, 4])\n\n    const envelope = signYjsUpdate(update, identity.did, privateKey, 12345)\n    envelope.update = new Uint8Array([5, 6, 7, 8]) // Tamper\n\n    const result = await verifyYjsEnvelope(envelope)\n    expect(result.valid).toBe(false)\n  })\n})\n```\n\n## Testing sync scenarios\n\nFor multi-peer sync tests, create separate clock instances and simulate message exchange:\n\n```ts\nimport { createLamportClock, tick, receive } from '@xnetjs/sync'\n\ndescribe('Two-peer sync', () => {\n  it('should converge after message exchange', () => {\n    let alice = createLamportClock('did:key:alice')\n    let bob = createLamportClock('did:key:bob')\n\n    // Alice makes two changes\n    let ts1\n    ;[alice, ts1] = tick(alice)\n    let ts2\n    ;[alice, ts2] = tick(alice)\n\n    // Bob receives Alice's second change\n    bob = receive(bob, ts2.time)\n\n    // Bob's next tick is higher than Alice's\n    let ts3\n    ;[bob, ts3] = tick(bob)\n    expect(ts3.time).toBe(3)\n  })\n})\n```\n\n## Testing plugins\n\n```ts\nimport { describe, it, expect, vi } from 'vitest'\nimport { PluginRegistry } from '@xnetjs/plugins'\n\ndescribe('PluginRegistry', () => {\n  it('should install and activate a plugin', async () => {\n    const activate = vi.fn()\n    const registry = new PluginRegistry(mockStore, 'electron')\n\n    await registry.install({\n      id: 'com.test.plugin',\n      name: 'Test Plugin',\n      version: '1.0.0',\n      activate\n    })\n\n    expect(activate).toHaveBeenCalled()\n    const plugins = registry.getAll()\n    expect(plugins[0].status).toBe('active')\n  })\n})\n```\n\n## Testing middleware\n\n```ts\nimport { MiddlewareChain } from '@xnetjs/plugins'\n\ndescribe('MiddlewareChain', () => {\n  it('should execute in priority order', async () => {\n    const chain = new MiddlewareChain()\n    const order: number[] = []\n\n    chain.add({\n      id: 'second',\n      priority: 200,\n      async beforeChange(change, next) {\n        order.push(2)\n        return next()\n      }\n    })\n\n    chain.add({\n      id: 'first',\n      priority: 100,\n      async beforeChange(change, next) {\n        order.push(1)\n        return next()\n      }\n    })\n\n    await chain.executeBefore(mockChange, async () => {\n      order.push(3)\n    })\n    expect(order).toEqual([1, 2, 3])\n  })\n})\n```\n\n## Common patterns\n\n### Suppressing console noise\n\n```ts\nvi.spyOn(console, 'error').mockImplementation(() => {})\nvi.spyOn(console, 'warn').mockImplementation(() => {})\n```\n\n### Immutability assertions\n\n```ts\nit('should not mutate the original clock', () => {\n  const original = createLamportClock('did:key:alice')\n  const originalTime = original.time\n\n  tick(original) // Returns new object\n\n  expect(original.time).toBe(originalTime) // Original unchanged\n})\n```\n\n### Test DIDs\n\nUse typed DID strings in tests:\n\n```ts\nconst testDID = 'did:key:z6MkTest123' as DID\n```\n\nOr generate real ones:\n\n```ts\nconst { identity } = generateIdentity()\nconst did = identity.did // Real did:key:z6Mk...\n```","src/content/docs/docs/guides/testing.mdx","c857fe2828b5d875","docs/guides/versioning",{id:465,data:467,body:473,filePath:474,digest:475,deferredRender:16},{title:468,description:469,editUrl:16,head:470,template:18,sidebar:471,pagefind:16,draft:21},"Version Compatibility","How to evolve schemas safely and maintain compatibility across versions.",[],{order:317,hidden:21,attrs:472},{},":::note[You will learn]\n\n- How protocol versioning and schema versioning work\n- How to create migrations with lenses\n- How version negotiation keeps peers compatible\n- How to use CLI tools for schema management\n- How to diagnose and repair data issues\n  :::\n\n## Overview\n\nxNet uses a **translate-on-read** approach to version compatibility:\n\n```mermaid\nflowchart LR\n  subgraph Storage\n    V1[\"v1 data\"]\n    V2[\"v2 data\"]\n    V3[\"v3 data\"]\n  end\n\n  subgraph \"Read Path\"\n    L1[\"Lens v1→v2\"]\n    L2[\"Lens v2→v3\"]\n  end\n\n  subgraph App\n    Current[\"Current Schema (v3)\"]\n  end\n\n  V1 --> L1 --> L2 --> Current\n  V2 --> L2\n  V3 --> Current\n```\n\n1. Data is stored in its original format\n2. Migrations are applied when reading, not when writing\n3. Old clients can still read new data (graceful degradation)\n4. No batch migrations required\n\nThis means you can ship schema changes incrementally without breaking existing clients.\n\n## Protocol versioning\n\nThe sync protocol is versioned separately from schemas. Every `Change<T>` includes a `protocolVersion`:\n\n```ts\ninterface Change<T> {\n  id: string\n  type: string\n  payload: T\n  protocolVersion: number // Currently: 1\n  hash: ContentId\n  parentHash: ContentId | null\n  authorDID: DID\n  signature: Uint8Array\n  lamport: LamportTimestamp\n}\n```\n\n### Version compatibility\n\n| Your Version | Peer Version | Behavior                                           |\n| ------------ | ------------ | -------------------------------------------------- |\n| v1           | v1           | Full compatibility                                 |\n| v1           | v0 (legacy)  | Full backward compatibility                        |\n| v1           | v2+          | Partial — unknown fields preserved, warning logged |\n\n### Feature negotiation\n\nWhen peers connect, they negotiate a common feature set:\n\n```mermaid\nsequenceDiagram\n  participant A as Client A (v1.2)\n  participant B as Client B (v1.0)\n\n  A->>B: Hello {features: [yjs, change_v2, compression]}\n  B->>A: Hello {features: [yjs, change_v1]}\n  Note over A,B: Negotiate intersection\n  A->>B: Using {features: [yjs, change_v1]}\n  Note over A,B: A downgrades to v1 format\n```\n\n```ts\n// Handshake exchange\n{\n  clientVersion: '1.2.0',\n  protocolVersion: 1,\n  features: ['yjs_sync', 'change_v2', 'signatures', 'compression']\n}\n```\n\nThe negotiator finds the intersection of features both peers support. If a required feature is missing, the connection is downgraded or rejected.\n\n## Schema versioning\n\nEvery schema should have a semantic version:\n\n```ts\nimport { defineSchema } from '@xnetjs/data'\n\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  version: '2.0.0', // Major.Minor.Patch\n  properties: {\n    title: { type: 'text' },\n    status: { type: 'select', options: ['todo', 'doing', 'done'] },\n    priority: { type: 'select', options: ['low', 'medium', 'high'] }\n  }\n})\n```\n\n### Version bump rules\n\n| Change Type                     | Version Bump | Example           |\n| ------------------------------- | ------------ | ----------------- |\n| Add optional field              | Minor        | `1.0.0` → `1.1.0` |\n| Add required field with default | Minor        | `1.0.0` → `1.1.0` |\n| Remove field                    | Major        | `1.0.0` → `2.0.0` |\n| Rename field                    | Major        | `1.0.0` → `2.0.0` |\n| Change field type               | Major        | `1.0.0` → `2.0.0` |\n| Fix bug in migration            | Patch        | `1.0.1` → `1.0.2` |\n\n### Schema change classification\n\nEvery schema change falls into one of three risk categories:\n\n```mermaid\nflowchart TB\n    subgraph \"SAFE - Ship Anytime\"\n        SAFE1[\"Add optional properties\"]\n        SAFE2[\"Add new schemas\"]\n        SAFE3[\"Add new change types\"]\n        SAFE4[\"Add new select options\"]\n        SAFE5[\"Make required → optional\"]\n    end\n\n    subgraph \"CAUTION - Plan Ahead\"\n        CAUTION1[\"Add required properties\"]\n        CAUTION2[\"Remove properties\"]\n        CAUTION3[\"Make optional → required\"]\n        CAUTION4[\"Change property defaults\"]\n    end\n\n    subgraph \"BREAKING - Requires Migration\"\n        DANGER1[\"Change property type\"]\n        DANGER2[\"Rename properties\"]\n        DANGER3[\"Change schema namespace\"]\n        DANGER4[\"Remove select options\"]\n    end\n\n    style SAFE1 fill:#c8e6c9\n    style SAFE2 fill:#c8e6c9\n    style SAFE3 fill:#c8e6c9\n    style SAFE4 fill:#c8e6c9\n    style SAFE5 fill:#c8e6c9\n    style CAUTION1 fill:#fff3e0\n    style CAUTION2 fill:#fff3e0\n    style CAUTION3 fill:#fff3e0\n    style CAUTION4 fill:#fff3e0\n    style DANGER1 fill:#ffcdd2\n    style DANGER2 fill:#ffcdd2\n    style DANGER3 fill:#ffcdd2\n    style DANGER4 fill:#ffcdd2\n```\n\n#### Classification matrix\n\n| Change Type            | Forward Safe | Backward Safe | Auto-Migrate | Manual Action    |\n| ---------------------- | ------------ | ------------- | ------------ | ---------------- |\n| Add optional property  | Yes          | Yes           | N/A          | None             |\n| Add required property  | No           | Yes           | Yes          | Define default   |\n| Remove property        | Yes          | No            | Yes          | None             |\n| Change property type   | No           | No            | Maybe        | Define transform |\n| Rename property        | No           | No            | Yes          | Define mapping   |\n| Add select option      | Yes          | Yes           | N/A          | None             |\n| Remove select option   | No           | No            | Maybe        | Define fallback  |\n| Make optional→required | No           | Yes           | Yes          | Define default   |\n| Make required→optional | Yes          | Yes           | N/A          | None             |\n\n**Legend:**\n\n- **Forward Safe**: Old clients can read data created by new clients\n- **Backward Safe**: New clients can read data created by old clients\n- **Auto-Migrate**: The system can generate migration code automatically\n\n#### Migration wizard\n\nUse the **Migrate** panel in DevTools to:\n\n1. **Analyze** - Scan your store for schema changes\n2. **Review** - See changes grouped by risk level\n3. **Generate** - Auto-generate lens code for migrations\n4. **Test** - Validate migrations on sample data\n5. **Apply** - Apply migrations to your store\n\n```mermaid\nflowchart TB\n    START[\"Schema Change Detected\"]\n    ANALYZE[\"Analyze Changes\"]\n    CLASSIFY[\"Classify Risk\"]\n\n    START --> ANALYZE\n    ANALYZE --> CLASSIFY\n\n    CLASSIFY -->|\"Safe\"| AUTO[\"Auto-apply\"]\n    CLASSIFY -->|\"Caution\"| REVIEW[\"Review & Confirm\"]\n    CLASSIFY -->|\"Breaking\"| WIZARD[\"Migration Wizard\"]\n\n    WIZARD --> LENS[\"Generate Lens Code\"]\n    LENS --> TEST[\"Test Migration\"]\n    TEST -->|\"Pass\"| APPLY[\"Apply to Store\"]\n    TEST -->|\"Fail\"| EDIT[\"Edit Lens\"]\n    EDIT --> TEST\n\n    AUTO --> DONE[\"Done\"]\n    REVIEW --> APPLY\n    APPLY --> DONE\n\n    style AUTO fill:#c8e6c9\n    style REVIEW fill:#fff3e0\n    style WIZARD fill:#ffcdd2\n```\n\n## Migrations with lenses\n\nLenses transform data between schema versions. They're bidirectional — you can upgrade and downgrade.\n\n```mermaid\nflowchart LR\n  subgraph \"Lens\"\n    UP[\"up()\"]\n    DOWN[\"down()\"]\n  end\n\n  V1[\"v1.0.0\"] -->|upgrade| UP --> V2[\"v2.0.0\"]\n  V2 -->|downgrade| DOWN --> V1\n```\n\n### Creating a lens\n\n```ts\nimport { createLens, type SchemaLens } from '@xnetjs/data'\n\nconst taskV1ToV2: SchemaLens = createLens({\n  from: '1.0.0',\n  to: '2.0.0',\n\n  // Transform v1 → v2\n  up(node) {\n    return {\n      ...node,\n      priority: node.priority ?? 'medium' // Add default\n    }\n  },\n\n  // Transform v2 → v1\n  down(node) {\n    const { priority, ...rest } = node\n    return rest // Remove new field\n  }\n})\n```\n\n### Registering lenses\n\n```ts\nimport { LensRegistry } from '@xnetjs/data'\n\nconst registry = new LensRegistry()\n\n// Register all lenses for a schema\nregistry.register('Task', taskV1ToV2)\nregistry.register('Task', taskV2ToV3)\n\n// The registry automatically chains lenses\n// v1 → v2 → v3 happens automatically\n```\n\n```mermaid\nflowchart LR\n  V1[\"v1.0.0\"] --> L1[\"Lens 1\"] --> V2[\"v2.0.0\"] --> L2[\"Lens 2\"] --> V3[\"v3.0.0\"]\n\n  style V1 fill:#fee\n  style V2 fill:#ffe\n  style V3 fill:#efe\n```\n\nThe registry finds the shortest path between any two versions and chains the lenses automatically.\n\n### Reading with migration\n\n```ts\nimport { NodeStore } from '@xnetjs/data'\n\nconst store = new NodeStore({ lensRegistry: registry })\n\n// Read with automatic migration\nconst task = await store.getWithMigration(taskId, {\n  targetVersion: '3.0.0'\n})\n// Data is transformed to v3 format\n\n// Original data unchanged in storage\nconst original = await store.get(taskId)\n// Still in its original version\n```\n\n## Common migration patterns\n\n### Adding a field\n\n```ts\nconst addPriority = createLens({\n  from: '1.0.0',\n  to: '1.1.0',\n  up: (node) => ({\n    ...node,\n    priority: 'medium' // Sensible default\n  }),\n  down: (node) => {\n    const { priority, ...rest } = node\n    return rest\n  }\n})\n```\n\n### Renaming a field\n\n```ts\nconst renameDueDate = createLens({\n  from: '1.0.0',\n  to: '2.0.0',\n  up: (node) => {\n    const { due_date, ...rest } = node\n    return { ...rest, dueDate: due_date }\n  },\n  down: (node) => {\n    const { dueDate, ...rest } = node\n    return { ...rest, due_date: dueDate }\n  }\n})\n```\n\n### Splitting a field\n\n```ts\nconst splitName = createLens({\n  from: '1.0.0',\n  to: '2.0.0',\n  up: (node) => {\n    const [firstName, ...rest] = (node.name || '').split(' ')\n    return {\n      ...node,\n      firstName,\n      lastName: rest.join(' ')\n    }\n  },\n  down: (node) => ({\n    ...node,\n    name: `${node.firstName} ${node.lastName}`.trim()\n  })\n})\n```\n\n## React integration\n\n### useQuery with migrations\n\n```tsx\nimport { useQuery } from '@xnetjs/react'\n\nfunction TaskList() {\n  const { data: tasks } = useQuery({\n    type: 'Task',\n    targetVersion: '3.0.0' // Migrate to this version\n  })\n\n  // All tasks are v3 format, regardless of storage version\n  return tasks.map((task) => <TaskCard key={task.id} task={task} />)\n}\n```\n\n## CLI tools\n\n### Extract schemas\n\n```bash\n# Extract current schema to JSON\nxnet schema extract --output schemas/\n\n# Creates schemas/Task.v2.0.0.json\n```\n\n### Compare schemas\n\n```bash\n# Compare two versions\nxnet schema diff Task 1.0.0 2.0.0\n\n# Output:\n# + priority: select (added)\n# ~ status: text → select (type changed)\n```\n\n### Validate migrations\n\n```bash\n# Check that lenses are registered for all version pairs\nxnet migrate validate\n\n# Output:\n# ✓ Task: 1.0.0 → 2.0.0 (lens registered)\n# ✓ Task: 2.0.0 → 3.0.0 (lens registered)\n# ✗ Contact: 1.0.0 → 2.0.0 (no lens!)\n```\n\n### Diagnose issues\n\n```bash\n# Full diagnostic\nxnet doctor\n\n# Output:\n# Checking nodes...\n#   ✓ 1,234 nodes checked\n#   ✓ All hashes valid\n#   ⚠ 3 nodes have unknown schema types\n#\n# Summary:\n#   Errors: 0\n#   Warnings: 3\n#   Status: HEALTHY (with warnings)\n```\n\n### Repair data\n\n```bash\n# Preview what would be fixed\nxnet repair --dry-run\n\n# Apply fixes\nxnet repair\n```\n\n### Export and import\n\n```bash\n# Export all data to JSON\nxnet export --output backup.json\n\n# Import with migration\nxnet import backup.json --migrate-to-current\n```\n\n## Graceful degradation\n\nWhen encountering unknown data, xNet preserves it rather than discarding it:\n\n```mermaid\nflowchart TD\n  subgraph \"New Client (v2)\"\n    N1[\"Create node with\\nnew 'priority' field\"]\n  end\n\n  subgraph \"Old Client (v1)\"\n    O1[\"Receive node\"]\n    O2[\"Unknown field\\n'priority'\"]\n    O3[\"Store as-is\\n(preserve field)\"]\n    O4[\"Edit 'title'\"]\n    O5[\"Save node\\n(priority intact)\"]\n  end\n\n  N1 --> O1 --> O2 --> O3 --> O4 --> O5\n```\n\n### Unknown schema type\n\n```ts\n// Node with unknown schema type\nconst node = {\n  '@type': 'xnet://example.com/FutureType',\n  title: 'Something new',\n  unknownField: { complex: 'data' }\n}\n\n// Old client behavior:\n// - Stores node as-is\n// - Can display raw data\n// - Preserves unknown fields on save\n```\n\n### Unknown property type\n\n```ts\n// Property with future type\nconst property = {\n  name: 'location',\n  type: 'geo-polygon',  // Unknown type\n  value: { points: [...] }\n}\n\n// Old client behavior:\n// - Preserves value\n// - Displays as JSON in UI\n// - Round-trips correctly\n```\n\n## Deprecation policy\n\nFeatures follow a deprecation lifecycle:\n\n```mermaid\nflowchart LR\n  A[\"Active\"] --> D[\"Deprecated\\n(warning)\"]\n  D --> X[\"Discouraged\\n(error)\"]\n  X --> R[\"Removed\"]\n\n  D -.- |\"6+ months\"| X\n  X -.- |\"3+ months\"| R\n```\n\n| Stage       | Behavior               | Duration     |\n| ----------- | ---------------------- | ------------ |\n| Active      | Works normally         | Indefinite   |\n| Deprecated  | Works, warning logged  | Min 6 months |\n| Discouraged | Works, error logged    | Min 3 months |\n| Removed     | Feature does not exist | Permanent    |\n\nCheck for deprecations programmatically:\n\n```ts\nimport { checkDeprecations } from '@xnetjs/sync'\n\nconst warnings = checkDeprecations({\n  protocolVersion: 0,\n  features: ['change_v1']\n})\n\nwarnings.forEach((w) => {\n  console.warn(`${w.feature}: ${w.message}`)\n  console.warn(`  Deadline: ${w.deadline}`)\n})\n```\n\n## DevTools panel\n\nThe Version DevTools panel shows:\n\n- Current protocol version\n- Connected peer versions\n- Feature negotiation results\n- Deprecation warnings\n- Schema version distribution\n\nEnable it in the DevTools:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n\nfunction App() {\n  return (\n    <XNetProvider config={{ authorDID, signingKey }}>\n      <XNetDevToolsProvider>\n        <YourApp />\n      </XNetDevToolsProvider>\n    </XNetProvider>\n  )\n}\n```\n\n## Best practices\n\n1. **Always provide defaults** when adding fields:\n\n   ```ts\n   up: (node) => ({ ...node, priority: node.priority ?? 'medium' })\n   ```\n\n2. **Test both directions** — migrations should round-trip:\n\n   ```ts\n   const roundTripped = lens.down(lens.up(original))\n   expect(roundTripped.title).toBe(original.title)\n   ```\n\n3. **Keep lenses simple** — one concern per lens, chain for complex migrations\n\n4. **Version bumps are cheap** — don't be afraid to bump minor versions for additive changes\n\n5. **Run `xnet doctor`** in CI to catch issues early\n\n## Further reading\n\n- [Sync Guide](/docs/guides/sync/) — How sync works\n- [Schemas Overview](/docs/schemas/overview/) — Defining schemas\n- [DevTools](/docs/guides/devtools/) — Debugging tools","src/content/docs/docs/guides/versioning.mdx","25e01b809c6c59f9","docs/guides/workbench",{id:476,data:478,body:484,filePath:485,digest:486,deferredRender:16},{title:479,description:480,editUrl:16,head:481,template:18,sidebar:482,pagefind:16,draft:21},"The Workbench","The fixed-region, keyboard-first shell that hosts every xNet surface.",[],{hidden:21,attrs:483},{},":::note[You will learn]\n\n- The workbench regions and what lives in each\n- How tabs work (preview tabs, pinning, splits, deep links)\n- The command palette and core keyboard map\n- How plugins contribute to the shell\n  :::\n\n## Overview\n\nThe web app's shell is a fixed-region workbench in the VS Code mold: predictable\nnamed regions, everything opens as a tab, one command palette, one drag model.\nThe chrome is monochrome by design — hue is reserved for your data (status dots,\ncharts), so the interface recedes and the work reads first.\n\n## Regions\n\n| Region       | What lives there                                                                    |\n| ------------ | ----------------------------------------------------------------------------------- |\n| Rail (left)  | Search, Explorer, Tasks, Data, Chats, plugin items; identity and settings below     |\n| Left Panel   | One view at a time: Explorer, Tasks, Data, Chats, or a plugin view                  |\n| Editor Area  | Tabbed documents — pages, databases, canvases, dashboards, channels, saved views    |\n| Right Panel  | Contextual sections published by the active tab (properties, comments, backlinks…)  |\n| Bottom Panel | Tray: Shelf, quick capture, Notifications, sync activity, and a query console       |\n| Status Bar   | Left = workspace scope (sync, presence), right = view scope (save state, theme)     |\n\nLayout, open tabs, pins, recents, and zen-mode snapshots persist locally and\nsurvive reloads bit-for-bit.\n\n## Tabs\n\nEverything opens as a tab, and **the router stays authoritative**: navigating\nopens-or-activates the matching tab, so deep links, back/forward, and old\nbookmarks keep working.\n\n- **Preview tabs** — a single click from the Explorer or palette opens an\n  italic _preview_ tab that is replaced by the next preview. Editing the\n  content or double-clicking promotes it to a real tab.\n- **Pinning** — pinned tabs stay put and survive \"close others\".\n- **Splits** — one optional second editor group: drag a tab to the editor edge\n  or press `⌘⇧\\`.\n- **Performance** — background tabs are unmounted entirely; they hold no live\n  document subscriptions.\n\n## Command palette\n\n`⌘K` (or `⌘P`) opens quick-open: recents first, then full-text page matches and\nevery node type. Type `>` to switch to command mode — every command in the\nregistry is listed with its keyboard chord. Escape restores focus to where you\nwere.\n\n## Keyboard map\n\n| Chord          | Action                                                |\n| -------------- | ----------------------------------------------------- |\n| `⌘K` / `⌘P`    | Palette / quick-open (`>` = command mode)             |\n| `⌘B`, `⌘\\`, `⌘J` | Toggle left / right / bottom panel                  |\n| `⌘.`           | Zen mode (Esc Esc exits; layout restored bit-for-bit) |\n| `⌘T` / `⌘W`    | New page / close tab                                  |\n| `⌃Tab` / `⌃⇧Tab` | Cycle tabs                                          |\n| `⌘1` / `⌘2`    | Focus editor group                                    |\n| `⌘⇧\\`          | Split editor                                          |\n| `F6` / `⇧F6`   | Cycle focus through shell regions                     |\n\n## Drag model\n\nEvery draggable entity — explorer rows, tabs, task rows, database row chips,\ncanvas selections — carries the same node payload. Drops create **references,\nnever copies**:\n\n- onto the editor → a wikilink chip at the drop point\n- onto a relation cell → a link\n- onto a canvas → a source-backed card\n- onto the tab bar → a tab\n- onto an editor edge → a split\n- onto the Shelf (bottom tray) → a held reference for later\n\n## Theme\n\nThe token system is a single APCA-contrast-tuned monochrome ramp per mode\n(`surface-0/1/2`, `ink-1/2/3`, `hairline`, `accent-ink`). Chrome sits on dimmer\nsurfaces than the work; the editor area is the only brightest-surface region. A\n`true-black` variant collapses dark surfaces to `#000` for OLED displays —\ntoggle it from the status bar theme control.\n\n## Extending the shell\n\nPlugins contribute _items_ into fixed containers; they cannot invent new chrome:\n\n- **Rail items / left-panel views** — `SidebarContribution` (a `panel`\n  component becomes a left-panel view)\n- **Status bar items** — `StatusBarContribution` (workspace scope or view scope)\n- **Palette commands** — `CommandContribution`, chords included\n- **Context sections** — views publish sections to the Right Panel\n- **Dashboard widgets** — `WidgetContribution` (see the\n  [Dashboards guide](/docs/guides/dashboards/))\n\nSee the [Plugins guide](/docs/guides/plugins/) for the contribution API.\n\n## Further reading\n\n- [Tasks](/docs/guides/tasks/) — the task surfaces hosted by the shell\n- [Dashboards](/docs/guides/dashboards/) — widget boards as tabs\n- [Chat & Calls](/docs/guides/chat-and-calls/) — channels as tabs, calls in a dock","src/content/docs/docs/guides/workbench.mdx","72636ad5938a621b","docs/hooks/overview",{id:487,data:489,body:495,filePath:496,digest:497,deferredRender:16},{title:490,description:491,editUrl:16,head:492,template:18,sidebar:493,pagefind:16,draft:21},"Hooks Overview","How xNet's React hooks connect and which to use when.",[],{order:43,hidden:21,attrs:494},{},"import { Card, CardGrid, LinkCard } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- Which hook to use for which task\n- How the hooks relate to each other\n- The flow of data through the system\n  :::\n\n## The three core hooks\n\n| Hook                                  | When to use it                                   | Returns                                            |\n| ------------------------------------- | ------------------------------------------------ | -------------------------------------------------- |\n| [`useQuery`](/docs/hooks/usequery/)   | List or find nodes. Read-only.                   | `{ data, loading, error, reload }`                 |\n| [`useMutate`](/docs/hooks/usemutate/) | Create, update, delete nodes.                    | `{ create, update, remove, restore, mutate }`      |\n| [`useNode`](/docs/hooks/usenode/)     | Edit a single node with collaborative rich text. | `{ data, doc, update, syncStatus, presence, ... }` |\n\n### When to use which\n\n- **Listing data** (tables, lists, grids, search results) — `useQuery`\n- **Reading a single node by ID** (detail views, cards) — `useQuery(schema, id)`\n- **Creating or deleting** — `useMutate`\n- **Updating properties** on a detail page — `useMutate().update` or `useNode().update`\n- **Rich text editing** (TipTap, collaborative docs) — `useNode` (gives you a `Y.Doc`)\n- **Showing who's online** (presence, cursors) — `useNode` (gives you `presence` and `awareness`)\n\n### The decision tree\n\n```\nDo you need a Yjs document (rich text, canvas)?\n  ├── Yes → useNode\n  └── No\n        ├── Reading data? → useQuery\n        └── Writing data? → useMutate\n```\n\n`useNode` is the only hook that manages a Yjs document and P2P sync connection. If you don't need collaborative editing, `useQuery` + `useMutate` are simpler and more efficient.\n\n## Supporting hooks\n\n| Hook                                      | Purpose                                    |\n| ----------------------------------------- | ------------------------------------------ |\n| [`useIdentity`](/docs/hooks/useidentity/) | Get the current user's DID and auth status |\n| `useCan` / `useGrants`                    | Permission checks and grant management — see the [Authorization guide](/docs/guides/authorization/) |\n| `useComments`                             | Thread-based comments on any node          |\n| `useHistory`                              | Change history for a node                  |\n| `useUndo`                                 | Undo/redo for node changes                 |\n\n## All hooks require `XNetProvider`\n\nEvery hook reads from a React context provided by `XNetProvider`. If you call a hook outside the provider, it throws:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n\nfunction App() {\n  return (\n    <XNetProvider config={{ authorDID, signingKey }}>\n      <XNetDevToolsProvider>\n        {/* All hooks work inside here */}\n        <TaskList />\n      </XNetDevToolsProvider>\n    </XNetProvider>\n  )\n}\n```\n\n## Data flow\n\n```\nReact Component\n  │\n  ├── useQuery(TaskSchema, filter)\n  │     └── NodeStore.list() → SQLite\n  │           └── subscribes to NodeChangeEvents\n  │\n  ├── useMutate()\n  │     └── NodeStore.create/update/delete()\n  │           ├── validates against schema\n  │           ├── signs change (Ed25519)\n  │           ├── persists to SQLite\n  │           ├── emits NodeChangeEvent → useQuery re-renders\n  │           └── syncs to peers (via SyncManager)\n  │\n  └── useNode(PageSchema, id)\n        ├── NodeStore (structured properties)\n        └── Y.Doc (rich text)\n              ├── WebRTC sync (via SyncManager or WebSocketSyncProvider)\n              ├── debounced persistence to SQLite\n              └── awareness (presence, cursors)\n```\n\n## Next steps\n\n<CardGrid>\n  <LinkCard\n    title=\"useQuery\"\n    description=\"Read data reactively. Filter, sort, paginate.\"\n    href=\"/docs/hooks/usequery/\"\n  />\n  <LinkCard\n    title=\"useMutate\"\n    description=\"Create, update, delete with type safety.\"\n    href=\"/docs/hooks/usemutate/\"\n  />\n  <LinkCard\n    title=\"useNode\"\n    description=\"Collaborative editing with Yjs, presence, and sync.\"\n    href=\"/docs/hooks/usenode/\"\n  />\n  <LinkCard\n    title=\"Your own server\"\n    description=\"Run @xnetjs/server with your own auth instead of a managed Hub.\"\n    href=\"/docs/guides/server/\"\n  />\n</CardGrid>","src/content/docs/docs/hooks/overview.mdx","3675e6527c75f476","docs/hooks/useidentity",{id:498,data:500,body:506,filePath:507,digest:508,deferredRender:16},{title:501,description:502,editUrl:16,head:503,template:18,sidebar:504,pagefind:16,draft:21},"useIdentity","Access the current user's DID and authentication status.",[],{order:113,hidden:21,attrs:505},{},":::note[You will learn]\n\n- How to access the current user's identity\n- The difference between `identity`, `did`, and `isAuthenticated`\n  :::\n\n## Quick example\n\n```tsx\nimport { useIdentity } from '@xnetjs/react'\n\nfunction UserBadge() {\n  const { did, isAuthenticated } = useIdentity()\n\n  if (!isAuthenticated) return <p>Not signed in</p>\n  return <p>Signed in as {did?.slice(0, 20)}...</p>\n}\n```\n\n## Signature\n\n```ts\nfunction useIdentity(): UseIdentityResult\n```\n\nTakes no parameters. Reads from the `XNetProvider` context.\n\n## Return value\n\n| Field             | Type               | Description                                                           |\n| ----------------- | ------------------ | --------------------------------------------------------------------- |\n| `identity`        | `Identity \\| null` | The full Identity object from `XNetProvider` config, or `null`.       |\n| `isAuthenticated` | `boolean`          | `true` if either `identity` or `authorDID` is set.                    |\n| `did`             | `string \\| null`   | The user's DID. Resolved from `identity.did` first, then `authorDID`. |\n\n## Usage patterns\n\n### Pass DID to useNode for presence\n\n```tsx\nconst { did } = useIdentity()\nconst { presence } = useNode(PageSchema, pageId, { did: did ?? undefined })\n```\n\n### Conditional rendering\n\n```tsx\nconst { isAuthenticated } = useIdentity()\n\nif (!isAuthenticated) {\n  return <OnboardingFlow />\n}\nreturn <AppContent />\n```\n\n## Gotchas\n\n:::note[`isAuthenticated` doesn't mean full identity]\n`isAuthenticated` is `true` if either `identity` or `authorDID` was passed to `XNetProvider`. You can be \"authenticated\" with just a DID and no full Identity object — this is common during development.\n:::\n\n:::caution[Throws outside XNetProvider]\nLike all xNet hooks, `useIdentity` throws if called outside `XNetProvider`.\n:::\n\n## Related\n\n- [`useNode`](/docs/hooks/usenode/) — pass `did` for presence awareness\n- [Identity guide](/docs/guides/identity/) — generating and managing key pairs","src/content/docs/docs/hooks/useidentity.mdx","78cadfac5fe2af24","docs/hooks/usemutate",{id:509,data:511,body:520,filePath:521,digest:522,deferredRender:16},{title:512,description:513,editUrl:16,head:514,template:18,sidebar:515,pagefind:16,draft:21},"useMutate","Create, update, delete, and restore nodes with full type safety.",[],{order:20,hidden:21,badge:516,attrs:519},{variant:517,text:518},"success","Core",{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- Every method on the `useMutate` return object\n- How to batch operations in a transaction\n- How to track pending mutations\n- Edge cases around optimistic updates\n  :::\n\n:::tip[What useMutate replaces]\nIn a traditional app, `useMutate` replaces:\n\n- **Prisma / Drizzle** — database writes\n- **REST POST/PUT/DELETE** — API mutations\n- **Redux actions / Zustand mutations** — state updates\n- **Optimistic updates** — the local-first model is inherently optimistic\n\nEvery mutation is validated, signed, persisted, and synced — automatically.\n:::\n\n## Quick example\n\n```tsx\nimport { useMutate } from '@xnetjs/react'\nimport { TaskSchema } from './schema'\n\nfunction AddTaskButton() {\n  const { create, isPending } = useMutate()\n\n  return (\n    <button\n      disabled={isPending}\n      onClick={() =>\n        create(TaskSchema, {\n          title: 'New task',\n          status: 'todo'\n        })\n      }\n    >\n      {isPending ? 'Creating...' : 'Add Task'}\n    </button>\n  )\n}\n```\n\n## Signature\n\n```ts\nfunction useMutate(): UseMutateResult\n```\n\nTakes no parameters. Returns methods for all mutation operations.\n\n## Return value\n\n### Mutation methods\n\n| Method    | Signature                                          | Description                                                                 |\n| --------- | -------------------------------------------------- | --------------------------------------------------------------------------- |\n| `create`  | `(schema, data, id?) => Promise<FlatNode \\| null>` | Create a new node. Returns the created node or `null` if store isn't ready. |\n| `update`  | `(schema, id, data) => Promise<FlatNode \\| null>`  | Update properties. Only changed fields are written.                         |\n| `remove`  | `(id) => Promise<void>`                            | Soft-delete a node. Recoverable via `restore`.                              |\n| `restore` | `(id) => Promise<FlatNode \\| null>`                | Restore a soft-deleted node.                                                |\n| `mutate`  | `(ops[]) => Promise<MutateResult \\| null>`         | Execute a batch of operations through the active data bridge.               |\n\n### Status fields\n\n| Field          | Type      | Description                                    |\n| -------------- | --------- | ---------------------------------------------- |\n| `isPending`    | `boolean` | `true` if any mutation is currently in flight. |\n| `pendingCount` | `number`  | Number of concurrent mutations in flight.      |\n\n## Usage patterns\n\n### Basic CRUD\n\n```tsx\nconst { create, update, remove, restore } = useMutate()\n\n// Create\nconst task = await create(TaskSchema, {\n  title: 'Ship v1',\n  status: 'todo'\n})\n\n// Update (sparse — only changed fields)\nawait update(TaskSchema, task.id, { status: 'doing' })\n\n// Soft-delete\nawait remove(task.id)\n\n// Restore\nawait restore(task.id)\n```\n\n### Custom ID\n\nPass an optional third argument to `create` to specify the node ID:\n\n```tsx\nconst task = await create(TaskSchema, { title: 'Known ID' }, 'my-custom-id')\n// task.id === 'my-custom-id'\n```\n\n### Transactions (batch operations)\n\nUse `mutate()` to execute multiple operations in one call:\n\n```tsx\nconst { mutate } = useMutate()\n\nconst result = await mutate([\n  { type: 'create', schema: TaskSchema, data: { title: 'Task A' } },\n  { type: 'create', schema: TaskSchema, data: { title: 'Task B' } },\n  { type: 'update', id: existingId, data: { status: 'done' } },\n  { type: 'delete', id: oldTaskId }\n])\n```\n\n### MutateResult\n\n```ts\ninterface MutateResult {\n  results: (NodeState | null)[] // One result per operation (null for deletes)\n}\n```\n\n### Form integration\n\n```tsx\nfunction TaskForm({ taskId }: { taskId: string }) {\n  const { data: task } = useQuery(TaskSchema, taskId)\n  const { update } = useMutate()\n  const [title, setTitle] = useState('')\n\n  useEffect(() => {\n    if (task) setTitle(task.title)\n  }, [task])\n\n  const save = () => update(TaskSchema, taskId, { title })\n\n  return (\n    <form\n      onSubmit={(e) => {\n        e.preventDefault()\n        save()\n      }}\n    >\n      <input value={title} onChange={(e) => setTitle(e.target.value)} />\n      <button type=\"submit\">Save</button>\n    </form>\n  )\n}\n```\n\n### Tracking pending state\n\n```tsx\nconst { create, isPending, pendingCount } = useMutate()\n\n// Disable UI during mutations\n<button disabled={isPending}>Save</button>\n\n// Show count for batch operations\n{pendingCount > 0 && <span>{pendingCount} operations pending...</span>}\n```\n\n## Gotchas\n\n:::caution[`null` means the store isn't ready]\nAll mutation methods return `null` if the NodeStore hasn't initialized yet (e.g., `XNetProvider` is still mounting). This is rare but possible if you call a mutation immediately on mount.\n:::\n\n:::tip[Updates are sparse]\n`update()` only writes the fields you pass. Other properties are untouched. This is important for conflict resolution — you're only claiming ownership of the fields you change.\n\n```tsx\n// This only updates `status`, not `title`\nawait update(TaskSchema, id, { status: 'done' })\n```\n\n:::\n\n:::note[Mutations trigger useQuery updates]\nWhen you call `create`, `update`, `remove`, or `restore`, the NodeStore emits a `NodeChangeEvent`. Any `useQuery` hook watching the same schema will automatically re-render with the new data. You don't need to manually invalidate queries.\n:::\n\n## Related\n\n- [`useQuery`](/docs/hooks/usequery/) — read the data you mutate\n- [`useNode`](/docs/hooks/usenode/) — alternative for single-node editing with Yjs\n- [`defineSchema`](/docs/schemas/defineschema/) — define the schemas you write to","src/content/docs/docs/hooks/usemutate.mdx","d9c66da3d4284dff","docs/hooks/patterns",{id:523,data:525,body:531,filePath:532,digest:533,deferredRender:16},{title:526,description:527,editUrl:16,head:528,template:18,sidebar:529,pagefind:16,draft:21},"Hook Patterns","Common patterns, recipes, and best practices for xNet React hooks.",[],{order:90,hidden:21,attrs:530},{},":::note[You will learn]\n\n- Patterns for combining hooks effectively\n- Performance tips and memoization\n- Error handling strategies\n- Testing approaches\n  :::\n\n## List + detail pattern\n\nThe most common pattern: a list view with a detail editor.\n\n```tsx\nfunction App() {\n  const [selectedId, setSelectedId] = useState<string | null>(null)\n\n  return (\n    <div style={{ display: 'flex' }}>\n      <TaskList onSelect={setSelectedId} />\n      {selectedId && <TaskDetail id={selectedId} />}\n    </div>\n  )\n}\n\nfunction TaskList({ onSelect }: { onSelect: (id: string) => void }) {\n  const { data: tasks } = useQuery(TaskSchema, {\n    orderBy: { createdAt: 'desc' }\n  })\n\n  return (\n    <ul>\n      {tasks.map((task) => (\n        <li key={task.id} onClick={() => onSelect(task.id)}>\n          {task.title}\n        </li>\n      ))}\n    </ul>\n  )\n}\n\nfunction TaskDetail({ id }: { id: string }) {\n  const { data, doc, update } = useNode(TaskSchema, id)\n\n  if (!data) return null\n  return (\n    <div>\n      <input value={data.title} onChange={(e) => update({ title: e.target.value })} />\n      {doc && <RichTextEditor doc={doc} />}\n    </div>\n  )\n}\n```\n\n## Create and navigate\n\nCreate a node and immediately navigate to it:\n\n```tsx\nfunction NewPageButton() {\n  const { create } = useMutate()\n  const navigate = useNavigate()\n\n  const handleCreate = async () => {\n    const page = await create(PageSchema, { title: 'Untitled' })\n    if (page) navigate(`/pages/${page.id}`)\n  }\n\n  return <button onClick={handleCreate}>New Page</button>\n}\n```\n\n## Stable filter references\n\nAvoid re-creating filter objects on every render:\n\n```tsx\n// Option 1: Module-level constant\nconst ACTIVE_FILTER = {\n  where: { status: 'active' as const },\n  orderBy: { updatedAt: 'desc' as const }\n} satisfies QueryFilter<typeof ProjectSchema._properties>\n\nfunction ActiveProjects() {\n  const { data } = useQuery(ProjectSchema, ACTIVE_FILTER)\n  // ...\n}\n\n// Option 2: useMemo for dynamic filters\nfunction FilteredTasks({ status }: { status: string }) {\n  const filter = useMemo(() => ({ where: { status } }), [status])\n  const { data } = useQuery(TaskSchema, filter)\n  // ...\n}\n```\n\n## Debounced updates\n\nFor frequently changing values (like text inputs), debounce the update:\n\n```tsx\nfunction TitleInput({ id }: { id: string }) {\n  const { data, update } = useNode(TaskSchema, id)\n  const [local, setLocal] = useState(data?.title ?? '')\n  const timeoutRef = useRef<number>()\n\n  // Sync from remote changes\n  useEffect(() => {\n    if (data?.title !== undefined) setLocal(data.title)\n  }, [data?.title])\n\n  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {\n    const value = e.target.value\n    setLocal(value)\n\n    clearTimeout(timeoutRef.current)\n    timeoutRef.current = window.setTimeout(() => {\n      update({ title: value })\n    }, 300)\n  }\n\n  return <input value={local} onChange={handleChange} />\n}\n```\n\n## Error boundaries\n\nWrap xNet-powered components in error boundaries for resilience:\n\n```tsx\nimport { XNetProvider } from '@xnetjs/react'\nimport { XNetDevToolsProvider } from '@xnetjs/devtools'\n\nfunction App() {\n  return (\n    <XNetProvider config={config}>\n      <XNetDevToolsProvider>\n        <ErrorBoundary fallback={<p>Something went wrong</p>}>\n          <TaskList />\n        </ErrorBoundary>\n      </XNetDevToolsProvider>\n    </XNetProvider>\n  )\n}\n```\n\n## Conditional hooks\n\nWhen you might not have an ID yet:\n\n```tsx\n// useNode accepts null to disable\nfunction MaybeEditor({ id }: { id: string | null }) {\n  const { data } = useNode(PageSchema, id)\n\n  if (!data) return <p>Select a page</p>\n  return <Editor data={data} />\n}\n```\n\n## Sync status indicator\n\nA reusable component showing connection state:\n\n```tsx\nfunction SyncIndicator({ id }: { id: string }) {\n  const { syncStatus, peerCount, syncError } = useNode(PageSchema, id)\n\n  const statusMap = {\n    offline: { color: 'gray', label: 'Offline' },\n    connecting: { color: 'yellow', label: 'Connecting...' },\n    connected: { color: 'green', label: `${peerCount} peer(s)` },\n    error: { color: 'red', label: syncError ?? 'Error' }\n  }\n\n  const { color, label } = statusMap[syncStatus]\n  return <span style={{ color }}>{label}</span>\n}\n```\n\n## Related\n\n- [`useQuery`](/docs/hooks/usequery/) — reading data\n- [`useMutate`](/docs/hooks/usemutate/) — writing data\n- [`useNode`](/docs/hooks/usenode/) — collaborative editing","src/content/docs/docs/hooks/patterns.mdx","228cad0c59bff507","docs/hooks/usequery",{id:534,data:536,body:543,filePath:544,digest:545,deferredRender:16},{title:537,description:538,editUrl:16,head:539,template:18,sidebar:540,pagefind:16,draft:21},"useQuery","Read data reactively with filtering, sorting, and pagination.",[],{order:55,hidden:21,badge:541,attrs:542},{variant:517,text:518},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- The full API signature and all three overloads\n- How to filter, sort, and paginate results\n- How reactive updates work under the hood\n- Common gotchas and edge cases\n  :::\n\n:::tip[What useQuery replaces]\nIn a traditional React app, `useQuery` replaces:\n\n- **React Query / SWR** — reactive data fetching\n- **REST/GraphQL client** — API calls\n- **Database queries** — Prisma/Drizzle on the backend\n- **WebSocket subscriptions** — real-time updates\n\nWith xNet, all of this is one hook. Data is local, so queries are instant.\n:::\n\n## Quick example\n\n```tsx\nimport { useQuery } from '@xnetjs/react'\nimport { TaskSchema } from './schema'\n\nfunction TaskList() {\n  const { data: tasks, loading } = useQuery(TaskSchema, {\n    where: { status: 'todo' },\n    orderBy: { createdAt: 'desc' },\n    limit: 20\n  })\n\n  if (loading) return <p>Loading...</p>\n  return (\n    <ul>\n      {tasks.map((t) => (\n        <li key={t.id}>{t.title}</li>\n      ))}\n    </ul>\n  )\n}\n```\n\n## Signature\n\n`useQuery` has three overloads:\n\n```ts\n// Overload 1: List all nodes of a schema\nfunction useQuery<P>(schema: DefinedSchema<P>): QueryListResult<P>\n\n// Overload 2: Get a single node by ID\nfunction useQuery<P>(schema: DefinedSchema<P>, id: string): QuerySingleResult<P>\n\n// Overload 3: Query with filters\nfunction useQuery<P>(schema: DefinedSchema<P>, filter: QueryFilter<P>): QueryListResult<P>\n```\n\nThe second argument determines the overload: pass a `string` for single-node lookup, an object for filtered queries, or omit it to get all nodes.\n\n## Parameters\n\n| Parameter | Type               | Description                                                                        |\n| --------- | ------------------ | ---------------------------------------------------------------------------------- |\n| `schema`  | `DefinedSchema<P>` | The schema to query. Created with [`defineSchema()`](/docs/schemas/defineschema/). |\n| `id`      | `string`           | _(Overload 2)_ Node ID to fetch.                                                   |\n| `filter`  | `QueryFilter<P>`   | _(Overload 3)_ Filter, sort, and pagination options.                               |\n\n### QueryFilter\n\n| Field            | Type                              | Default | Description                                          |\n| ---------------- | --------------------------------- | ------- | ---------------------------------------------------- |\n| `where`          | `Partial<InferCreateProps<P>>`    | —       | Filter by property values. Strict equality matching. |\n| `includeDeleted` | `boolean`                         | `false` | Include soft-deleted nodes in results.               |\n| `orderBy`        | `Record<string, 'asc' \\| 'desc'>` | —       | Sort by any property, `createdAt`, or `updatedAt`.   |\n| `limit`          | `number`                          | —       | Maximum results to return.                           |\n| `offset`         | `number`                          | —       | Skip N results (for pagination).                     |\n\n## Return value\n\n### List result (overloads 1 and 3)\n\n| Field     | Type            | Description                                                       |\n| --------- | --------------- | ----------------------------------------------------------------- |\n| `data`    | `FlatNode<P>[]` | The query results. Properties are spread to top level.            |\n| `loading` | `boolean`       | `true` during initial load, `false` once data is available.       |\n| `error`   | `Error \\| null` | Any error during query execution.                                 |\n| `reload`  | `() => void`    | Force re-run the subscription. Rarely needed — data auto-updates. |\n\n### Single result (overload 2)\n\n| Field     | Type                  | Description                                  |\n| --------- | --------------------- | -------------------------------------------- |\n| `data`    | `FlatNode<P> \\| null` | The node, or `null` if not found or deleted. |\n| `loading` | `boolean`             | `true` during initial load.                  |\n| `error`   | `Error \\| null`       | Any error during query execution.            |\n| `reload`  | `() => void`          | Force re-run the subscription.               |\n\n### FlatNode\n\nEvery node includes system fields (managed automatically) plus your schema properties:\n\n```ts\ninterface FlatNode<P> {\n  id: string\n  schemaId: string // e.g., 'xnet://my-app/Task'\n  createdAt: number // Auto-set at creation time\n  createdBy: string // DID of creator\n  updatedAt: number // Auto-updated on every change\n  updatedBy: string // DID of last modifier\n  deleted: boolean\n  // ... plus all your schema properties\n}\n```\n\nYou can filter and sort by any of these system fields without defining them in your schema.\n\n## Usage patterns\n\n### List all nodes\n\nThe simplest query — returns every node of a schema:\n\n```tsx\nconst { data: tasks } = useQuery(TaskSchema)\n// tasks: FlatNode<typeof TaskSchema._properties>[]\n```\n\n### Filter and sort\n\n```tsx\nconst { data: activeTasks } = useQuery(TaskSchema, {\n  where: { status: 'doing' },\n  orderBy: { updatedAt: 'desc' },\n  limit: 50\n})\n```\n\n### Single node by ID\n\n```tsx\nconst { data: task } = useQuery(TaskSchema, taskId)\n// task: FlatNode | null\n```\n\n### Conditional query (skip when ID is null)\n\nWhen `id` is null or undefined, use a guard:\n\n```tsx\nfunction TaskDetail({ id }: { id: string | null }) {\n  // Only query when id is available\n  const { data: task } = useQuery(TaskSchema, id ?? '')\n\n  if (!id || !task) return <p>No task selected</p>\n  return <h1>{task.title}</h1>\n}\n```\n\n### Pagination\n\n```tsx\nconst [page, setPage] = useState(0)\nconst PAGE_SIZE = 20\n\nconst { data: tasks } = useQuery(TaskSchema, {\n  orderBy: { createdAt: 'desc' },\n  limit: PAGE_SIZE,\n  offset: page * PAGE_SIZE\n})\n```\n\n## Gotchas\n\n:::caution[Memoize your `where` object]\nThe `where` filter uses `JSON.stringify()` for dependency tracking. If you create a new object on every render, the subscription re-fires unnecessarily. Define the filter outside the component or memoize it:\n\n```tsx\n// Bad — new object every render\nconst { data } = useQuery(TaskSchema, { where: { status: 'todo' } })\n\n// Good — stable reference\nconst filter = useMemo(() => ({ where: { status: 'todo' } }), [])\nconst { data } = useQuery(TaskSchema, filter)\n\n// Also good — defined outside component\nconst TODO_FILTER = { where: { status: 'todo' as const } }\nfunction TaskList() {\n  const { data } = useQuery(TaskSchema, TODO_FILTER)\n}\n```\n\n:::\n\n:::tip[No loading spinners for local data]\nSince data is stored locally, `loading` transitions from `true` to `false` almost instantly. You usually don't need a loading state for local queries — the data is already there.\n:::\n\n:::caution[Filtering is in-memory]\n`where` filtering happens in JavaScript after loading from the store. For large datasets (1000+ nodes), consider using `limit` and `offset` rather than loading everything and filtering client-side.\n:::\n\n:::note[Deleted nodes are excluded by default]\nSingle-node queries return `null` for deleted nodes. List queries exclude deleted nodes unless you pass `includeDeleted: true`.\n:::\n\n## Related\n\n- [`useMutate`](/docs/hooks/usemutate/) — write data that `useQuery` reads\n- [`useNode`](/docs/hooks/usenode/) — when you need a Yjs document for one node\n- [`defineSchema`](/docs/schemas/defineschema/) — define the schemas you query","src/content/docs/docs/hooks/usequery.mdx","e32a6949d880d32f","docs/hooks/usenode",{id:546,data:548,body:555,filePath:556,digest:557,deferredRender:16},{title:549,description:550,editUrl:16,head:551,template:18,sidebar:552,pagefind:16,draft:21},"useNode","Edit a single node with collaborative rich text, P2P sync, and presence.",[],{order:78,hidden:21,badge:553,attrs:554},{variant:517,text:518},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- All options and the full return type (grouped by category)\n- How to bind a Yjs document to TipTap\n- How the dual-write model works (NodeStore + Y.Doc)\n- Sync lifecycle, presence, and error handling\n  :::\n\n:::tip[What useNode replaces]\nIn a traditional app, `useNode` replaces:\n\n- **WebSocket connection** — real-time sync per document\n- **Yjs provider setup** — WebRTC/WebSocket provider, awareness, persistence\n- **Autosave logic** — debounced persistence\n- **Presence system** — who's online, cursor positions\n- **Document loading** — fetch, cache, conflict handling\n\nOne hook. All of it.\n:::\n\n## Quick example\n\n```tsx\nimport { useNode } from '@xnetjs/react'\nimport { useEditor, EditorContent } from '@tiptap/react'\nimport Collaboration from '@tiptap/extension-collaboration'\nimport { PageSchema } from './schema'\n\nfunction PageEditor({ pageId }: { pageId: string }) {\n  const { data, doc, update, syncStatus, presence } = useNode(PageSchema, pageId, {\n    createIfMissing: { title: 'Untitled' },\n    did: currentUserDID\n  })\n\n  const editor = useEditor(\n    {\n      extensions: [\n        // ... your extensions\n        Collaboration.configure({ document: doc })\n      ]\n    },\n    [doc]\n  )\n\n  if (!data) return <p>Loading...</p>\n\n  return (\n    <div>\n      <input value={data.title} onChange={(e) => update({ title: e.target.value })} />\n      <div>{syncStatus === 'connected' ? `${presence.length} collaborator(s)` : syncStatus}</div>\n      <EditorContent editor={editor} />\n    </div>\n  )\n}\n```\n\n## Signature\n\n```ts\nfunction useNode<P extends Record<string, PropertyBuilder>>(\n  schema: DefinedSchema<P>,\n  id: string | null,\n  options?: UseNodeOptions<P>\n): UseNodeResult<P>\n```\n\nPassing `null` for `id` disables the hook — `data` and `doc` will be `null`.\n\n## Parameters\n\n| Parameter | Type                | Description                                                          |\n| --------- | ------------------- | -------------------------------------------------------------------- |\n| `schema`  | `DefinedSchema<P>`  | The schema for this node. Must have `document: 'yjs'` for rich text. |\n| `id`      | `string \\| null`    | The node ID to load. `null` disables the hook.                       |\n| `options` | `UseNodeOptions<P>` | Configuration for sync, persistence, and auto-creation.              |\n\n### UseNodeOptions\n\n| Option             | Type                  | Default                   | Description                                             |\n| ------------------ | --------------------- | ------------------------- | ------------------------------------------------------- |\n| `signalingServers` | `string[]`            | `['ws://localhost:4444']` | WebSocket servers for peer discovery.                   |\n| `disableSync`      | `boolean`             | `false`                   | Disable P2P sync (local-only mode).                     |\n| `persistDebounce`  | `number`              | `1000`                    | Milliseconds to debounce Y.Doc saves to storage.        |\n| `createIfMissing`  | `InferCreateProps<P>` | —                         | Auto-create the node if it doesn't exist.               |\n| `did`              | `string`              | —                         | User's DID for presence awareness (cursors, user list). |\n\n## Return value\n\n### Data\n\n| Field  | Type                  | Description                                                                        |\n| ------ | --------------------- | ---------------------------------------------------------------------------------- |\n| `data` | `FlatNode<P> \\| null` | The node's structured properties (flattened). `null` if loading or not found.      |\n| `doc`  | `Y.Doc \\| null`       | Yjs document for collaborative editing. `null` if schema has no `document: 'yjs'`. |\n\n### Mutations\n\n| Field    | Type                                                     | Description                                                                     |\n| -------- | -------------------------------------------------------- | ------------------------------------------------------------------------------- |\n| `update` | `(props: Partial<InferCreateProps<P>>) => Promise<void>` | Update structured properties. Dual-writes to both NodeStore and Y.Doc meta map. |\n| `remove` | `() => Promise<void>`                                    | Soft-delete this node.                                                          |\n\n### State\n\n| Field         | Type             | Description                                                          |\n| ------------- | ---------------- | -------------------------------------------------------------------- |\n| `loading`     | `boolean`        | `true` during initial load.                                          |\n| `error`       | `Error \\| null`  | Any error during loading, sync, or persistence.                      |\n| `isDirty`     | `boolean`        | `true` if the Y.Doc has unsaved changes (debounce timer is pending). |\n| `lastSavedAt` | `number \\| null` | Timestamp of last successful persistence.                            |\n| `wasCreated`  | `boolean`        | `true` if the node was auto-created via `createIfMissing`.           |\n\n### Sync\n\n| Field        | Type             | Description                                                  |\n| ------------ | ---------------- | ------------------------------------------------------------ |\n| `syncStatus` | `SyncStatus`     | `'offline' \\| 'connecting' \\| 'connected' \\| 'error'`        |\n| `syncError`  | `string \\| null` | Human-readable error message when `syncStatus` is `'error'`. |\n| `peerCount`  | `number`         | Number of currently connected peers editing this document.   |\n\n### Presence\n\n| Field       | Type                | Description                                                                                                           |\n| ----------- | ------------------- | --------------------------------------------------------------------------------------------------------------------- |\n| `presence`  | `PresenceUser[]`    | Other users from live awareness + hub snapshots. Each has `did`, optional `name`, `color`, `lastSeen`, and `isStale`. |\n| `awareness` | `Awareness \\| null` | Yjs Awareness instance. Pass to TipTap's `CollaborationCursor` extension.                                             |\n\n### Actions\n\n| Field    | Type                  | Description                                             |\n| -------- | --------------------- | ------------------------------------------------------- |\n| `save`   | `() => Promise<void>` | Manually flush pending changes (bypass debounce timer). |\n| `reload` | `() => Promise<void>` | Reload node and document from storage.                  |\n\n## Usage patterns\n\n### Structured properties only (no rich text)\n\nIf your schema doesn't have `document: 'yjs'`, `doc` will be `null` and useNode behaves like a single-node version of useQuery + useMutate:\n\n```tsx\nconst { data, update } = useNode(TaskSchema, taskId)\n\n// Update properties\nawait update({ status: 'done', title: 'Shipped!' })\n```\n\n### Rich text with TipTap\n\n```tsx\nimport Collaboration from '@tiptap/extension-collaboration'\nimport CollaborationCursor from '@tiptap/extension-collaboration-cursor'\n\nconst { doc, awareness, presence } = useNode(PageSchema, id, { did })\n\nconst editor = useEditor(\n  {\n    extensions: [\n      StarterKit.configure({ history: false }), // Disable built-in history\n      Collaboration.configure({ document: doc }),\n      CollaborationCursor.configure({\n        provider: awareness,\n        user: { name: 'You', color: '#6366f1' }\n      })\n    ]\n  },\n  [doc]\n)\n```\n\n:::caution[Disable TipTap's built-in history]\nWhen using `Collaboration`, you must disable TipTap's built-in `history` extension. Yjs has its own undo manager. Using both causes conflicts.\n:::\n\n### Presence awareness\n\nPass `did` to enable presence. Users are reported with a deterministic color derived from their DID:\n\n```tsx\nconst { presence, syncStatus } = useNode(PageSchema, id, {\n  did: currentUserDID\n})\n\nreturn (\n  <div>\n    {presence.map((user) => (\n      <span key={user.did} style={{ color: user.color }}>\n        {user.did.slice(8, 16)}...\n      </span>\n    ))}\n    <span>{syncStatus}</span>\n  </div>\n)\n```\n\n### Auto-create with `createIfMissing`\n\nFor \"new document\" flows, pass default properties. If the node doesn't exist, it's created automatically:\n\n```tsx\nconst { data, wasCreated } = useNode(PageSchema, newPageId, {\n  createIfMissing: { title: 'Untitled', content: '' }\n})\n\nif (wasCreated) {\n  // Focus the title input, show onboarding, etc.\n}\n```\n\nIf the node exists but is soft-deleted, `createIfMissing` restores it instead of creating a duplicate.\n\n### Manual save\n\nThe debounced persistence timer (default: 1000ms) means there's a window where changes exist in memory but not on disk. For critical moments, flush manually:\n\n```tsx\nconst { save, isDirty } = useNode(PageSchema, id)\n\nconst handleNavigateAway = async () => {\n  if (isDirty) await save()\n  router.push('/home')\n}\n```\n\n## The dual-write model\n\nThis is the most important thing to understand about `useNode`:\n\nWhen you call `update({ title: 'New Title' })`, it writes to **two places**:\n\n1. **NodeStore** — structured data with Lamport timestamps (for `useQuery` and persistence)\n2. **Y.Doc meta map** — a `Y.Map('meta')` inside the Yjs document (for P2P sync)\n\nWhen a remote peer changes the Y.Doc meta map, a `metaObserver` picks up the change and writes it back to the NodeStore. This bidirectional bridge keeps both stores in sync.\n\n:::danger[Direct Y.Doc edits don't update NodeStore]\nIf you modify the Y.Doc's text content directly (e.g., via TipTap), that content syncs fine through Yjs. But if you modify the Y.Doc's `meta` map directly (bypassing `update()`), the change will NOT be written to the NodeStore unless it comes from a remote peer. Always use the `update()` method for structured properties.\n:::\n\n## Lifecycle\n\n1. **Mount** — NodeStore lookup. If not found and `createIfMissing` is set, create the node.\n2. **Init Y.Doc** — If schema has `document: 'yjs'`, load stored content and initialize the Yjs document.\n3. **Connect** — Acquire a sync connection from `SyncManager` (or create a `WebSocketSyncProvider` as fallback).\n4. **Editing** — User and peer changes flow through Yjs CRDT. Property changes go through the dual-write bridge.\n5. **Persist** — Y.Doc changes are debounced and saved to SQLite as `Y.encodeStateAsUpdate()`.\n6. **Unmount** — Flush all pending changes immediately, release the sync connection.\n\n:::caution[Navigation flush]\nWhen the component unmounts, `useNode` immediately flushes the Y.Doc to storage. If you navigate back to the same node quickly, the new instance waits for the previous flush to complete before loading. This prevents data loss but can cause a brief delay.\n:::\n\n## Gotchas\n\n:::tip[Pass `did` for presence]\nWithout the `did` option, awareness broadcasts are disabled and presence data is usually empty:\n\n```tsx\nconst { did } = useIdentity()\nconst { presence } = useNode(PageSchema, id, { did })\n```\n\n:::\n\n:::caution[Sync timeout on new documents]\nWhen `wasCreated` is true (you're joining a shared document that was created by someone else), a 10-second timeout checks if any sync content was received. If not, `syncStatus` changes to `'error'` with a descriptive message. This helps surface connectivity issues.\n:::\n\n:::tip[Debug logging]\nEnable sync debug logs in the browser console:\n\n```js\nlocalStorage.setItem('xnet:sync:debug', 'true')\n```\n\n:::\n\n## Related\n\n- [`useQuery`](/docs/hooks/usequery/) — for reading multiple nodes (no Yjs)\n- [`useMutate`](/docs/hooks/usemutate/) — for mutations without a Yjs document\n- [`useIdentity`](/docs/hooks/useidentity/) — get the current DID for presence\n- [Collaboration guide](/docs/guides/collaboration/) — full walkthrough of building a collaborative editor","src/content/docs/docs/hooks/usenode.mdx","3b88132645e25731","docs/languages/rust",{id:558,data:560,body:567,filePath:568,digest:569,deferredRender:16},{title:561,description:562,editUrl:16,head:563,template:18,sidebar:564,pagefind:16,draft:21},"Rust — xnet-core","xnet-core is a portable Rust implementation of the xNet interop kernel: did:key identity, the canonical-JSON BLAKE3 change hash, deterministic Ed25519, LWW convergence, and the L2/L3 decision functions — with a C/UniFFI binding surface to back native SDKs.",[],{order:113,label:565,hidden:21,attrs:566},"Rust",{},"import { Aside, LinkCard, Badge } from '@astrojs/starlight/components'\n\n<p>\n  <Badge text=\"Core · beta\" variant=\"note\" />\n  <Badge text=\"regenerates the golden vectors\" variant=\"tip\" />\n</p>\n\n[**xnet-core**](https://github.com/crs48/xNet/tree/main/rust/xnet-core) is a\nportable Rust implementation of the xNet **interop kernel** — the byte-exact core\nof the [protocol](/docs/protocol/overview/): `did:key` identity, the canonical-JSON\nchange hash, Ed25519 sign/verify, per-property LWW convergence, and the pure\nL2/L3 decision functions (version negotiation, authorization expression\nevaluation).\n\nUnlike a full app SDK, `xnet-core` is the **kernel + a binding surface**. It's\nPhase 2 of [exploration 0210](https://github.com/crs48/xNet/blob/main/docs/explorations/0210_%5B_%5D_NATIVE_SWIFT_SDK_AND_PORTABLE_MULTI_LANGUAGE_CORE.md):\none portable core that can back the Swift, Kotlin, and .NET SDKs via UniFFI / a C\nABI, instead of each language re-implementing the kernel.\n\n## Conformance\n\n`cargo test` runs the **shared golden-vector corpus** ([`conformance/vectors/`](/docs/protocol/conformance/))\n— the same vectors the TypeScript reference and the Python/Swift kernels pass:\n\n```text\ntest l0_identity ... ok      # did:key derivation + round-trip\ntest l1_change ... ok        # canonical JSON, BLAKE3 hash, verify, AND re-sign\ntest l1_lww ... ok           # per-property LWW convergence\ntest l2_replication ... ok   # version-handshake negotiation + catch-up filter\ntest l3_authz ... ok         # authorization expression-AST evaluation\n```\n\n<Aside type=\"tip\" title=\"Re-sign, byte-for-byte\">\n  `xnet-core` reproduces a TypeScript-produced signature **exactly** — Ed25519 here is the\n  deterministic RFC-8032 construction on `curve25519-dalek` + `sha2`, so the only crypto\n  dependencies are audited group-math and hash primitives (base58btc and canonical JSON are inline).\n  That makes Rust a candidate for **regenerating** the golden vectors, not just verifying them.\n</Aside>\n\n```bash\ncd rust/xnet-core\ncargo test          # 5 conformance suites + 1 FFI round-trip\n```\n\n## The binding surface\n\n[`src/ffi.rs`](https://github.com/crs48/xNet/blob/main/rust/xnet-core/src/ffi.rs)\nexposes the kernel across a `String` / `Vec<u8>` / `bool` boundary — the shape a\nUniFFI or C-ABI consumer wants — so a native SDK (Swift, Kotlin, .NET) can call\nthe verified kernel instead of porting it. The crate is dependency-light by\ndesign:\n\n```toml\n[dependencies]\ncurve25519-dalek = \"4.1\"   # RFC-8032 Ed25519 (deterministic)\nsha2 = \"0.10\"\nblake3 = \"1\"               # the change-hash digest\nserde_json = \"1\"\n```\n\n## Scope & status\n\n<Aside type=\"caution\" title=\"Kernel, not a full app SDK\">\n  xnet-core is the **L0/L1 + L2/L3 decision core** — identity, change hashing, LWW, and the pure\n  decision functions. It is not (yet) an application SDK with storage, a live-sync transport, or a\n  query engine; those live in the native SDKs it's meant to back. The crate lives **in the\n  repository** (not yet on crates.io).\n</Aside>\n\n<LinkCard\n  title=\"xnet-core source & tests →\"\n  href=\"https://github.com/crs48/xNet/tree/main/rust/xnet-core\"\n  description=\"The kernel (src/lib.rs), the FFI surface (src/ffi.rs), and the conformance tests.\"\n/>\n<LinkCard\n  title=\"Implement xNet in your language →\"\n  href=\"/docs/protocol/implement-in-your-language/\"\n  description=\"The same path xnet-core followed — kernel, vectors, conformance.\"\n/>","src/content/docs/docs/languages/rust.mdx","a3d634b262fd458f","docs/languages/overview",{id:570,data:572,body:579,filePath:580,digest:581,deferredRender:16},{title:573,description:574,editUrl:16,head:575,template:18,sidebar:576,pagefind:16,draft:21},"Languages & SDKs","Build xNet apps in TypeScript, React, Swift, Rust, Vue, Svelte, or any language. One protocol, verified by the same golden vectors — at honest, labeled maturity levels.",[],{order:43,label:577,hidden:21,attrs:578},"Overview & matrix",{},"import { Badge, LinkCard, Aside } from '@astrojs/starlight/components'\n\nxNet is a **protocol** first and an app second. The same signed, hash-chained,\nlast-write-wins data model can be implemented — and **proven byte-for-byte** —\nin more than one language, and the JavaScript runtime binds to more than one UI\nframework. This page is the honest map of what exists today and how mature it is.\n\n<Aside type=\"tip\" title=\"You don't have to trust us — you can check\">\n  Every implementation below passes the **same [golden vectors](/docs/protocol/conformance/)**:\n  identity (`did:key`), the canonical-JSON BLAKE3 change hash, signing, and LWW convergence. That\n  shared corpus is the difference between \"supported\" and \"verifiably interoperable.\"\n</Aside>\n\n## The two axes\n\nThere are two different \"multi-X\" stories, and they mean different things:\n\n- **Languages** implement the [protocol](/docs/protocol/overview/) (identity,\n  change hashing, replication, authorization) and interoperate over the wire.\n- **JavaScript UI frameworks** bind the same JS [runtime](/docs/architecture/package-graph/)\n  (`createXNetClient` + `liveQuery`) into React, Vue, Svelte, or Solid.\n\n## Maturity matrix\n\nWhat the badges mean: <Badge text=\"Reference\" variant=\"tip\" /> the canonical\nimplementation the vectors are generated from · <Badge text=\"Stable SDK\" variant=\"success\" />\nfirst-class and app-ready · <Badge text=\"Beta\" variant=\"note\" /> real and\nconformance-pinned, still evolving · <Badge text=\"On demand\" variant=\"caution\" />\na thin binding published when asked for · <Badge text=\"Reference kernel\" variant=\"default\" />\na verifier / teaching implementation.\n\n### Languages\n\n| Language         | What you get                                                     | Maturity                                            | Where                                                      |\n| ---------------- | ---------------------------------------------------------------- | --------------------------------------------------- | ---------------------------------------------------------- |\n| **TypeScript**   | The full runtime + React SDK, published to npm                   | <Badge text=\"Reference\" variant=\"tip\" />            | [Quickstart](/docs/quickstart/)                            |\n| **Swift**        | Native SDK — schemas, store, query, SwiftUI live binding, SQLite | <Badge text=\"Native SDK · beta\" variant=\"note\" />   | [Swift](/docs/languages/swift/)                            |\n| **Rust**         | Portable interop kernel + C/UniFFI binding surface               | <Badge text=\"Core · beta\" variant=\"note\" />         | [Rust](/docs/languages/rust/)                              |\n| **Python**       | ~100-line reference kernel + vector verifier                     | <Badge text=\"Reference kernel\" variant=\"default\" /> | [Implement it](/docs/protocol/implement-in-your-language/) |\n| **Any language** | Build a conforming impl from the spec + vectors                  | <Badge text=\"DIY\" variant=\"default\" />              | [Implement it](/docs/protocol/implement-in-your-language/) |\n\n### JavaScript UI frameworks\n\n| Framework                   | What you get                                               | Maturity                                               | Where                                  |\n| --------------------------- | ---------------------------------------------------------- | ------------------------------------------------------ | -------------------------------------- |\n| **React**                   | Hooks **and** components — the toolkit the app itself uses | <Badge text=\"Stable SDK\" variant=\"success\" />          | [React hooks](/docs/hooks/overview/)   |\n| **Vue**                     | `useQuery` / `useMutate` data binding (no components)      | <Badge text=\"Adapter · on demand\" variant=\"caution\" /> | [Frameworks](/docs/guides/frameworks/) |\n| **Svelte**                  | `liveQuery` is already a Svelte store                      | <Badge text=\"Adapter · on demand\" variant=\"caution\" /> | [Frameworks](/docs/guides/frameworks/) |\n| **Solid**                   | `createQuery` via `from()`                                 | <Badge text=\"Adapter · on demand\" variant=\"caution\" /> | [Frameworks](/docs/guides/frameworks/) |\n| **Vanilla / Lit / Angular** | Subscribe to `liveQuery` directly                          | <Badge text=\"Pattern\" variant=\"default\" />             | [Frameworks](/docs/guides/frameworks/) |\n\n<Aside type=\"note\" title=\"Honest scope\">\n  Only **React** ships UI components; the component kit is React by design (see the [framework\n  support policy](/docs/guides/frameworks/)). The Swift and Rust packages live **in the repo**\n  (SwiftPM / Cargo), not on a public registry yet — the per-language pages show how to depend on\n  them today.\n</Aside>\n\n## Pick your path\n\n<LinkCard\n  title=\"JavaScript frameworks →\"\n  href=\"/docs/guides/frameworks/\"\n  description=\"React, Vue, Svelte, Solid, or vanilla — bind the runtime in ~40 lines.\"\n/>\n<LinkCard\n  title=\"Swift — XNetKit →\"\n  href=\"/docs/languages/swift/\"\n  description=\"Define schemas in Swift and bind queries into a SwiftUI re-render loop.\"\n/>\n<LinkCard\n  title=\"Rust — xnet-core →\"\n  href=\"/docs/languages/rust/\"\n  description=\"The portable interop kernel that backs native SDKs, with C/UniFFI bindings.\"\n/>\n<LinkCard\n  title=\"Implement it in any language →\"\n  href=\"/docs/protocol/implement-in-your-language/\"\n  description=\"The kernel, the golden vectors, and how to claim conformance.\"\n/>","src/content/docs/docs/languages/overview.mdx","deae8b72864e4b2f","docs/languages/swift",{id:582,data:584,body:591,filePath:592,digest:593,deferredRender:16},{title:585,description:586,editUrl:16,head:587,template:18,sidebar:588,pagefind:16,draft:21},"Swift — XNetKit","XNetKit is a native Swift SDK for xNet: define schemas in Swift, query a local-first store, bind results into a SwiftUI re-render loop, and sync live with an xNet hub — no JavaScript, no React.",[],{order:78,label:589,hidden:21,attrs:590},"Swift",{},"import { Aside, LinkCard, Badge, Steps } from '@astrojs/starlight/components'\n\n<p>\n  <Badge text=\"Native SDK · beta\" variant=\"note\" />\n  <Badge text=\"passes the golden vectors\" variant=\"tip\" />\n</p>\n\n[**XNetKit**](https://github.com/crs48/xNet/tree/main/swift/XNetKit) is a native\nSwift SDK for xNet's local-first graph database. Define schemas in Swift, write\nand query the database in Swift, and bind results into a SwiftUI re-rendering\nloop — no JavaScript, no React. It's built directly on the conformance-pinned\n[protocol kernel](/docs/protocol/overview/), so it interoperates with the\nTypeScript reference **byte-for-byte** where it matters: identity, canonical\nchange hashes, and LWW convergence.\n\n## Quick look\n\n```swift\nimport XNetKit\n\n// Identity — an Ed25519 did:key (would live in the Keychain in a real app).\nlet me = Identity()\n\n// Define a schema in Swift (the analogue of TS `defineSchema`).\nlet Task = Schema(name: \"Task\", namespace: \"xnet://xnet.fyi/\",\n                  authorization: .spaceCascade(relation: \"space\")) {\n    text(\"title\", required: true, maxLength: 200)\n    select(\"status\", options: [\"todo\", \"doing\", \"done\"], default: \"todo\")\n    relation(\"space\", target: \"xnet://xnet.fyi/Space@1.0.0\")\n    money(\"bounty\", currency: \"USD\")\n}\nTask.id   // \"xnet://xnet.fyi/Task@1.0.0\"\n\n// A local store owned by `me`. Every write signs a Change and folds it via LWW.\n// Pass a SQLiteChangeLog to persist — state replays from it on next launch.\nlet store = NodeStore(identity: me, persistence: SQLiteChangeLog(path: dbPath))\nlet task = store.create(Task, [\"title\": \"Ship the Swift SDK\", \"status\": \"todo\"])\nstore.update(task.id, [\"status\": \"doing\"])\n\n// Query the database in Swift.\nlet todo = store.query(Query(Task, where: .equals(\"status\", \"todo\")).ordered(by: \"title\"))\n```\n\n## The native re-render loop (SwiftUI)\n\n`LiveQueryModel` is an `@Observable` analogue of React's `useQuery`: a SwiftUI\nview reads `model.rows` and re-renders automatically whenever the result\nchanges — no hooks, no manual subscriptions.\n\n```swift\nimport SwiftUI\nimport XNetKit\n\nstruct TaskListView: View {\n    @State private var model: LiveQueryModel\n\n    init(store: NodeStore, schema: Schema) {\n        _model = State(initialValue: LiveQueryModel(\n            store, Query(schema, where: .equals(\"status\", \"todo\")).ordered(by: \"title\")))\n    }\n\n    var body: some View {\n        List(model.rows) { node in\n            Text(node[\"title\"]?.stringValue ?? \"\")\n        }\n    }\n}\n```\n\nHeadless, the same reactivity is the framework-agnostic `LiveQuery` —\n`subscribe(_:)` fires immediately and on every change, a 1:1 port of\n[`packages/runtime/src/live-query.ts`](https://github.com/crs48/xNet/blob/main/packages/runtime/src/live-query.ts).\n\n## Live sync with an xNet hub\n\n`HubConnection` speaks the L2 [replication wire protocol](/docs/protocol/replication/)\nover a WebSocket — and it's proven against the **real TypeScript hub**. The\n`xnet-sync-demo` target has a Swift client sign a change, publish it to the hub\n(which verifies the hash + Ed25519 signature), a second Swift client catch up and\nmaterialize the node, then receive a **live relayed update** the moment the\nwriter publishes — a true cross-language, real-time round-trip.\n\n```swift\nlet conn = HubConnection(url: URL(string: \"wss://hub.xnet.app\")!, did: identity.did)\ntry await conn.connect()\nstore.onLocalChange = { change in Task { try await conn.publish(change, room: docId) } }\nconn.onRemoteChange = { change in store.apply(change) } // verifies hash + signature\ntry await conn.subscribe(room: docId)\nconn.startStreaming()\n```\n\n## Install\n\nXNetKit is a SwiftPM package that lives **in the repository** (not yet on a\npublic index). Platforms: macOS 14, iOS 17, visionOS 1.\n\n<Steps>\n\n1. Add it as a local or git package dependency in your `Package.swift`:\n\n   ```swift\n   dependencies: [\n     .package(url: \"https://github.com/crs48/xNet.git\", branch: \"main\")\n     // then reference the \"XNetKit\" product from swift/XNetKit\n   ]\n   ```\n\n2. Build and run the bundled demos:\n\n   ```bash\n   cd swift/XNetKit\n   swift run xnet-demo     # schema → signed writes → query → reactive loop\n   swift test              # 18 tests incl. golden vectors, wire codec, persistence\n   ```\n\n</Steps>\n\n## Scope & status\n\n<Aside type=\"caution\" title=\"What this slice does and doesn't cover\">\n  XNetKit covers identity, schemas, signed-change + LWW store, query, the SwiftUI live binding,\n  SQLite persistence, and **live node-change hub sync**. The collaborative **Yjs rich-text document\n  body** is the remaining piece — it travels the wire as opaque bytes, so a Swift node can relay and\n  store it, but in-Swift CRDT editing is future work. See [exploration\n  0210](https://github.com/crs48/xNet/blob/main/docs/explorations/0210_%5B_%5D_NATIVE_SWIFT_SDK_AND_PORTABLE_MULTI_LANGUAGE_CORE.md).\n</Aside>\n\n<LinkCard\n  title=\"XNetKit source & tests →\"\n  href=\"https://github.com/crs48/xNet/tree/main/swift/XNetKit\"\n  description=\"The full package: Sources, Tests, and the xnet-demo / xnet-sync-demo executables.\"\n/>\n<LinkCard\n  title=\"Conformance vectors →\"\n  href=\"/docs/protocol/conformance/\"\n  description=\"The golden corpus XNetKit reproduces byte-for-byte.\"\n/>","src/content/docs/docs/languages/swift.mdx","0cdcd9705f880a7a","docs/protocol/authorization",{id:594,data:596,body:602,filePath:603,digest:604,deferredRender:16},{title:597,description:598,editUrl:16,head:599,template:18,sidebar:600,pagefind:16,draft:21},"Authorization (L3)","Access control as data: schema rules, role resolvers, the expression AST, grants, and UCAN — enforced at the sync boundary.",[],{order:113,label:233,hidden:21,attrs:601},{},"In XNet, authorization is **data, not application logic**: rules are declared on\nschemas and delegated through grant nodes and UCAN tokens, and enforced at the\nsync boundary. Because two implementations that disagree on policy make different\nread/write decisions on the same graph, the decision *semantics* are normative.\nNormative text:\n[`04-authorization.md`](https://github.com/crs48/xNet/blob/main/docs/specs/protocol/04-authorization.md).\n\n## Actions and decisions\n\n```\naction ∈ { read, create, update, write, delete, share, admin }\ncan(subject: DID, action, nodeId) → { allowed, reasons }\n```\n\n`create` and `update` are **refinements of `write`**: `create` governs bringing\na node into existence, `update` governs mutating one that exists. A schema may\ndeclare either; when absent, each falls back to the schema's `write`\nexpression (and a legacy `write` check follows the `update` rule), so schemas\nthat only declare `write` behave exactly as before. Create checks evaluate\nagainst the *draft* node built from the payload — container relations in the\npayload (e.g. `space`, `channel`) resolve membership roles, which is how\ncreation into a shared container is gated. A grant carrying `write` satisfies\nboth refinements; a granular grant covers only itself.\n\n```ts\nactions: {\n  read:   allow('owner', 'spaceMember'),\n  create: allow('spaceMember'),          // members may add…\n  update: allow('owner', 'spaceAdmin'),  // …only the author (or admins) may edit\n  write:  allow('owner', 'spaceMember'), // fallback for engines without the split\n  delete: allow('owner', 'spaceAdmin'),\n  share:  allow('owner', 'spaceAdmin')\n}\n```\n\n## Schema authorization\n\nA schema may carry an `authorization` block defining **roles** (how a subject\nearns a role on a node) and **actions** (which roles may perform each action):\n\n```ts\ninterface AuthorizationDefinition {\n  roles:   Record<string, RoleResolver>\n  actions: Record<AuthAction, AuthExpression>\n  publicProps?: string[]\n  fieldRules?: Record<string, { allow: AuthExpression; deny?: AuthExpression }>\n}\n```\n\n## Role resolvers\n\n| Kind | Subject earns the role when… |\n|---|---|\n| **creator** | `subject == node.createdBy` |\n| **property** | it appears in a named `person`/`relation` property (e.g. `editors`) |\n| **relation** | it holds a role on a *related* node (inheritance) |\n| **membership** | a membership edge (e.g. `SpaceMembership`) links it to a container with a role ≥ `minRole`, cascading to nested containers |\n\nResolution walks relations/memberships with a bounded depth and must terminate.\n\n## The expression AST\n\n```\nexpr ::= allow(role…) | deny(role…) | roleRef(name)\n       | and(expr…) | or(expr…) | not(expr) | PUBLIC | AUTHENTICATED\n```\n\n**Deny wins:** if any matching `deny` is true, the action is denied regardless of\nany `allow`. Evaluation is total and deterministic.\n\n## Encryption as access control\n\nFor private nodes, **the ability to decrypt is the read‑control mechanism**:\ncontent keys are wrapped per recipient (X25519 + XChaCha20). A subject not in the\nrecipient set can't read encrypted properties even if it receives the bytes.\n`publicProps` and the four universal node fields stay readable for indexing and\nattribution.\n\n## Grants and UCAN\n\n- **Grant nodes** — ordinary XNet nodes recording `{ issuer, grantee, resource,\n  actions, expiresAt, revokedAt }`. Active iff not revoked and not expired.\n- **UCAN tokens** — capability tokens (JWT/EdDSA) with a proof chain. Each\n  capability must be an attenuation of its proof; child expiry ≤ parent; chains\n  acyclic.\n\n## Deterministic pipeline\n\n```mermaid\nflowchart TB\n  Q[\"can(subject, action, node)\"] --> ND{node-level deny?}\n  ND -->|yes| DENY\n  ND -->|no| RR[\"resolve roles (depth-bounded)\"]\n  RR --> SE[\"evaluate schema expression (deny-wins)\"]\n  SE -->|allowed| ALLOW\n  SE -->|no| GR{active grant / UCAN?}\n  GR -->|yes| ALLOW\n  GR -->|no| PUB{PUBLIC / publicProps?}\n  PUB -->|yes| ALLOW\n  PUB -->|no| DENY\n```\n\nCaching and indexing are private; the *decisions* must match the\ndecision‑trace [conformance vectors](/docs/protocol/conformance/).\n\nNext: [Implement it in your language →](/docs/protocol/implement-in-your-language/)","src/content/docs/docs/protocol/authorization.mdx","14d9554f9b8a7e7f","docs/protocol/conformance",{id:605,data:607,body:613,filePath:614,digest:615,deferredRender:16},{title:608,description:609,editUrl:16,head:610,template:18,sidebar:611,pagefind:16,draft:21},"Conformance","The language-agnostic golden-vector corpus that proves independent XNet implementations interoperate.",[],{order:148,label:608,hidden:21,attrs:612},{},"import { Aside } from '@astrojs/starlight/components'\n\nA specification without a conformance suite drifts — independent implementations\ndiverge silently. (ActivityPub shipped a W3C Recommendation with no test suite\nfor ~5 years; the fediverse is still paying for it.) XNet ships a\n**language‑agnostic golden‑vector corpus alongside the spec, from day one**, and\nre‑verifies it in CI.\n\nThe corpus lives at\n[`conformance/`](https://github.com/crs48/xNet/tree/main/conformance).\n\n## What conformance means\n\nYou claim conformance to a layer by **reproducing that layer's vectors\nbyte‑for‑byte**. The vectors are plain JSON `{ description, input, expected }` —\nany language can load them.\n\n| Suite | Layer | Proves |\n|---|---|---|\n| `vectors/identity/` | L0 | seed → `did:key` + public key |\n| `vectors/change/` | L1 | unsigned change → canonical bytes → BLAKE3 hash → Ed25519 signature |\n| `vectors/lww/` | L1 | change sequence → converged state (order‑independent) |\n| `vectors/replication/` | L2 | version handshake, catch‑up filtering, signed Yjs envelope |\n| `vectors/authz/` | L3 | authorization expression (AST) evaluation |\n| `vectors/authz-actions/` | L3 | action‑expression resolution (`create`/`update` → `write` fallback) |\n\n`xnet/1.0`'s first corpus covers the **interop kernel** (L0 + L1). Full L3\ndecision‑trace suites are tracked as\n[XPPs](https://github.com/crs48/xNet/tree/main/docs/specs/protocol/xpp).\n\n## Example vector\n\n```jsonc\n{\n  \"description\": \"First change for a Page node, fixed author seed\",\n  \"input\": { \"authorSeedHex\": \"aaaa…\", \"unsignedChange\": { /* … */ } },\n  \"expected\": {\n    \"authorDID\": \"did:key:z6Mkv1o2…\",\n    \"canonicalJson\": \"{\\\"authorDID\\\":\\\"did:key:z6Mkv1o2…\\\",…}\",\n    \"hash\": \"cid:blake3:76fdfa20…\",\n    \"signatureBase64\": \"UcVsz+sh…==\"\n  }\n}\n```\n\n## The drift guard\n\n<Aside type=\"tip\">\n  The reference implementation re‑derives every vector from its own code and\n  asserts equality in CI. A change to canonicalization, hashing, or DID\n  derivation that isn't reflected in the corpus **fails the build** — the spec's\n  central claim is executable, not aspirational.\n</Aside>\n\n```bash\n# verify (CI drift guard)\npnpm exec vitest run --project runtime packages/runtime/src/conformance.test.ts\n\n# the second-language proof\npip install pynacl blake3 base58\npython conformance/reference/python/verify_vectors.py\n```\n\n## The conformance matrix\n\nFollowing [Willow](https://willowprotocol.org/)'s lightweight model, conforming\nimplementations are tracked per layer:\n\n| Implementation | Language | L0 identity | L1 change | L1 lww | L2 | L3 |\n|---|---|:--:|:--:|:--:|:--:|:--:|\n| `xNet` (reference) | TypeScript | ✅ | ✅ | ✅ | reference | reference |\n| `reference/python` | Python | ✅ | ✅ | — | — | — |\n| _add yours_ | | | | | | |\n\nTo add your implementation, reproduce the vectors and open a PR against\n[`conformance/README.md`](https://github.com/crs48/xNet/blob/main/conformance/README.md).","src/content/docs/docs/protocol/conformance.mdx","b6655f011fd29cc6","docs/protocol/data-model",{id:616,data:618,body:624,filePath:625,digest:626,deferredRender:16},{title:619,description:620,editUrl:16,head:621,template:18,sidebar:622,pagefind:16,draft:21},"Data Model (L1)","The Node, the signed Change, the byte-exact canonicalization, and Last-Write-Wins — the interop kernel of XNet.",[],{order:20,label:98,hidden:21,attrs:623},{},"import { Aside } from '@astrojs/starlight/components'\n\nThis is the heart of the protocol. Get it right and your implementation can\nparticipate in the node graph. The normative text is\n[`02-data-model.md`](https://github.com/crs48/xNet/blob/main/docs/specs/protocol/02-data-model.md).\n\n## The Node\n\nEvery node, in every implementation, has exactly four universal fields; all\nothers are schema‑defined:\n\n```ts\ninterface Node {\n  id: string            // opaque, collision-resistant (nanoid in the reference impl)\n  schemaId: SchemaIRI   // \"xnet://authority/Name@version\"\n  createdAt: number     // Unix ms, set on first change\n  createdBy: DID         // did:key of the creator — immutable\n  [key: string]: unknown // schema-defined properties\n}\n```\n\n`createdBy` is the root of a node's provenance and never changes. Nodes are\n**soft‑deleted** (tombstoned), never hard‑deleted.\n\n## Schema references\n\n```\nSchemaIRI = \"xnet://\" authority \"/\" Name ( \"@\" semver )?\n```\n\nThe `authority` names who governs the schema — `xnet.fyi` for built‑ins, a domain\nfor organizations, or a DID for personal schemas. Nodes are self‑describing via\n`schemaId`, so relays and stores can process them without resolving the schema.\nSchemas are JSON‑Schema‑shaped — **not** JSON‑LD/RDF (a deliberate choice; full\nJSON‑LD is the reason ActivityPub implementations diverge).\n\n## The Change\n\nA node is never mutated in place. Its state is the fold of an append‑only log of\nsigned **Change** records:\n\n```ts\ninterface Change {\n  protocolVersion: 3\n  id: string\n  type: 'node-change'\n  payload: { nodeId, schemaId?, properties, deleted? }  // sparse\n  hash: string                  // \"cid:blake3:<hex>\"\n  parentHash: string | null     // the causal hash chain\n  authorDID: DID\n  signature: Uint8Array         // Ed25519 over UTF-8(hash)\n  wallTime: number\n  lamport: number               // ordering / LWW\n}\n```\n\nThe **first** change for a node carries `schemaId`; later changes carry only the\nproperties that changed.\n\n## The byte‑exact contract\n\n<Aside type=\"caution\" title=\"This is the #1 interop rule\">\n  Two implementations that disagree on these bytes cannot verify each other's\n  signatures. The reference impl hashes with **BLAKE3** (not SHA‑256) and signs\n  the **UTF‑8 bytes of the hash string** `cid:blake3:<hex>` — not the raw digest.\n</Aside>\n\n1. Take the unsigned change (all fields except `hash`/`signature`).\n2. **Canonical JSON:** sort object keys lexicographically and recursively, no\n   whitespace, arrays in order, `undefined` omitted, UTF‑8 bytes.\n3. **Hash:** `\"cid:blake3:\" + hex(BLAKE3(bytes))`.\n4. **Sign:** `Ed25519(UTF8(hash_string), key)`.\n\n```js\nconst sorted = sortKeysRecursively(unsigned)        // recursive key sort\nconst bytes  = utf8(JSON.stringify(sorted))          // compact\nconst hash   = \"cid:blake3:\" + hex(blake3(bytes))\nconst sig    = ed25519.sign(utf8(hash), signingKey)  // sign the STRING bytes\n```\n\nThis exact transform is pinned by the\n[golden vectors](/docs/protocol/conformance/), so any implementation can check\nitself byte‑for‑byte.\n\n## Conflict resolution: Lamport + LWW\n\nMaterialized state keeps a `{ lamport, wallTime }` timestamp **per property**.\nWhen two changes touch the same property:\n\n1. higher **`lamport`** wins;\n2. tie → higher `wallTime`;\n3. tie → higher `authorDID` (lexicographic) — a deterministic final tiebreak so\n   all peers converge identically.\n\nBecause LWW is per‑property, concurrent edits to *different* properties of the\nsame node both survive.\n\n## The document codec (where Yjs lives — and why it's opaque)\n\nA schema may declare a collaborative body with `document: 'yjs'`. Such nodes\ncarry a `documentContent` blob identified by a `documentCodec` discriminator\n(`yjs-v1`, `automerge-2`, `none`). Implementations **must transport and persist**\nthe blob faithfully, but **interpreting it is optional** — a peer that can't parse\n`yjs-v1` still fully participates in the graph. This is the seam that makes XNet\nportable without porting a CRDT byte format across languages.\n\nNext: [Replication (L2) →](/docs/protocol/replication/)","src/content/docs/docs/protocol/data-model.mdx","d6b9f85cd26ae52e","docs/protocol/implement-in-your-language",{id:627,data:629,body:636,filePath:637,digest:638,deferredRender:16},{title:630,description:631,editUrl:16,head:632,template:18,sidebar:633,pagefind:16,draft:21},"Implement XNet in Your Language","A step-by-step path to a second XNet implementation: the interop kernel, the golden vectors, and how to claim conformance.",[],{order:90,label:634,hidden:21,attrs:635},"Implement it",{},"import { Steps, Aside, LinkCard } from '@astrojs/starlight/components'\n\nYou don't need to port the whole `xNet` codebase to build a compatible\nimplementation. You need the **interop kernel** (L0 + L1) — and the\n[golden vectors](/docs/protocol/conformance/) tell you exactly when you've got it\nright.\n\n<Aside type=\"tip\">\n  The proof this is real: a ~100‑line Python kernel reproduces the same DIDs and\n  verifies — and re‑signs byte‑for‑byte — changes signed by the TypeScript\n  reference implementation. The full kernel is at\n  [`conformance/reference/python`](https://github.com/crs48/xNet/tree/main/conformance/reference/python).\n</Aside>\n\n## The path\n\n<Steps>\n\n1. **Identity — `did:key` over Ed25519.** Generate an Ed25519 key, prefix the\n   public key with multicodec `0xed 0x01`, base58btc‑encode, prepend\n   `did:key:z`. Check against `conformance/vectors/identity/`.\n\n2. **Canonicalize a change.** Sort keys lexicographically and recursively,\n   serialize to compact UTF‑8 JSON. Check against the `canonicalJson` field in\n   `conformance/vectors/change/`.\n\n3. **Hash & sign.** `\"cid:blake3:\" + hex(BLAKE3(bytes))`, then Ed25519‑sign the\n   **UTF‑8 bytes of that hash string**. Reproduce `hash` and `signatureBase64`.\n\n4. **Last‑Write‑Wins.** Fold a change sequence with per‑property\n   `{lamport, wallTime, authorDID}` resolution (higher wins, author breaks ties).\n   Check against `conformance/vectors/lww/`.\n\n5. **(Optional) Replication & authorization.** Implement the\n   [wire messages](/docs/protocol/replication/) and\n   [policy evaluation](/docs/protocol/authorization/) to join live rooms.\n\n</Steps>\n\n## The kernel, in ~30 lines\n\nThis is the entire L0 + L1 verify path in Python — proof that the spec, not the\nTypeScript source, is enough to interoperate:\n\n```python\nimport base64, json, base58\nfrom blake3 import blake3\nfrom nacl.signing import SigningKey, VerifyKey\n\nED25519_MULTICODEC = b\"\\xed\\x01\"\n\ndef did_from_public_key(pub: bytes) -> str:                       # L0 §1\n    return \"did:key:z\" + base58.b58encode(ED25519_MULTICODEC + pub).decode()\n\ndef canonical_json(value) -> bytes:                               # L1 §6\n    return json.dumps(value, sort_keys=True, separators=(\",\", \":\"),\n                      ensure_ascii=False).encode(\"utf-8\")\n\ndef change_hash(unsigned: dict) -> str:                           # L1 §6\n    to_hash = {k: v for k, v in unsigned.items() if k != \"protocolVersion\"} \\\n        if unsigned.get(\"protocolVersion\", 0) in (0, None) else unsigned\n    return \"cid:blake3:\" + blake3(canonical_json(to_hash)).hexdigest()\n\ndef verify_change(unsigned: dict, sig: bytes, pub: bytes) -> bool:\n    try:\n        VerifyKey(pub).verify(change_hash(unsigned).encode(), sig); return True\n    except Exception:\n        return False\n```\n\n## Run the proof\n\n```bash\ngit clone https://github.com/crs48/xNet && cd xNet\npip install pynacl blake3 base58\npython conformance/reference/python/verify_vectors.py\n# → 18 passed, 0 failed\n```\n\n## Claim conformance\n\nReproduce a layer's [golden vectors](/docs/protocol/conformance/) byte‑for‑byte,\nthen open a PR adding a row to the\n[conformance matrix](https://github.com/crs48/xNet/blob/main/conformance/README.md).\nProposing a change to the protocol itself? File an\n[XPP](https://github.com/crs48/xNet/tree/main/docs/specs/protocol/xpp) — the\nlightweight, \"prove‑it‑before‑you‑spec‑it\" proposal process.\n\n<LinkCard title=\"Conformance corpus & matrix →\" href=\"/docs/protocol/conformance/\" description=\"The golden vectors every implementation must reproduce.\" />","src/content/docs/docs/protocol/implement-in-your-language.mdx","d46a61743d70aa98","docs/protocol/overview",{id:639,data:641,body:648,filePath:649,digest:650,deferredRender:16},{title:642,description:643,editUrl:16,head:644,template:18,sidebar:645,pagefind:16,draft:21},"The XNet Protocol","XNet is an open protocol, not just an app. Anyone can re-implement it in any language, over any database, and interoperate.",[],{order:55,label:646,hidden:21,attrs:647},"Overview",{},"import { Card, CardGrid, LinkCard, Aside } from '@astrojs/starlight/components'\n\nThe `xNet` repository is **one implementation** of XNet. XNet itself is a\n**protocol** — a written interface you can re‑implement in any language, over any\ndatabase, and still interoperate with every other conforming implementation. Like\nMatrix, the AT Protocol, or ActivityPub, the standard is separate from any one\ncodebase.\n\n<Aside type=\"tip\" title=\"The normative spec lives in the repo\">\n  This page is the friendly tour. The **normative source of truth** is\n  [`docs/specs/protocol/`](https://github.com/crs48/xNet/tree/main/docs/specs/protocol) — versioned\n  with the code, backed by a machine‑checked conformance corpus.\n</Aside>\n\n## The boundary in one sentence\n\n> A conforming XNet implementation agrees on the **cryptographic primitives**,\n> the **data model** (especially the byte‑exact canonicalization of a change),\n> the **replication wire format**, and the **authorization semantics** — and\n> treats everything above (query, storage layout, UI, the built‑in app schemas)\n> as private.\n\n## Four normative layers\n\n```mermaid\nflowchart TB\n  L4[\"L4 · Application Profile — NON-NORMATIVE\\nbuilt-in schemas, spaces, query, UI\"]\n  L3[\"L3 · Authorization\\nschema rules, roles, grants, UCAN\"]\n  L2[\"L2 · Replication\\nchange relay, signed Yjs envelope, handshake, transports\"]\n  L1[\"L1 · Data Model\\nNode, SchemaIRI, properties, Change, canonicalization, LWW, document codec\"]\n  L0[\"L0 · Primitives\\ndid:key/Ed25519, XChaCha20, X25519, BLAKE3, UCAN\"]\n  L4 --> L3 --> L2 --> L1 --> L0\n```\n\n<CardGrid>\n  <LinkCard\n    title=\"L0 · Primitives\"\n    href=\"https://github.com/crs48/xNet/blob/main/docs/specs/protocol/01-primitives.md\"\n    description=\"did:key, Ed25519, XChaCha20-Poly1305, X25519, BLAKE3, UCAN — mostly a profile over existing standards.\"\n  />\n  <LinkCard\n    title=\"L1 · Data Model\"\n    href=\"/docs/protocol/data-model/\"\n    description=\"The Node, the signed Change, and the byte-exact canonicalization that makes it all interoperate.\"\n  />\n  <LinkCard\n    title=\"L2 · Replication\"\n    href=\"/docs/protocol/replication/\"\n    description=\"The wire messages, the signed Yjs envelope, and the version handshake.\"\n  />\n  <LinkCard\n    title=\"L3 · Authorization\"\n    href=\"/docs/protocol/authorization/\"\n    description=\"Access control as data: schema rules, role resolvers, grants, and UCAN tokens.\"\n  />\n</CardGrid>\n\n## The interop kernel (the part that makes it XNet)\n\nThe irreducible core is small. An implementation that does **only L0 + L1** can\nalready create, sign, verify, and converge nodes — fully participating in the\ngraph:\n\n1. A **`did:key`** identity from an Ed25519 key.\n2. A **Node** = four universal fields (`id`, `schemaId`, `createdAt`,\n   `createdBy`) plus schema‑defined properties.\n3. A **Change** = a signed, hash‑chained, Lamport‑stamped mutation whose\n   canonical bytes and BLAKE3 hash are specified exactly.\n4. **Last‑Write‑Wins** per‑property conflict resolution on the Lamport clock.\n\n## Yjs is _not_ the protocol\n\nA common misconception: \"XNet is built on Yjs, so I'd have to port a CRDT.\" Not\nso. Yjs is used only for the optional rich‑text **document body** of certain\nnodes, and it travels the wire as **opaque bytes inside a signed envelope**. A\nsecond implementation can relay and store that blob without parsing it, and still\nparticipate fully. The CRDT is a **pluggable document codec**, not the\ninterop kernel. (See [data model](/docs/protocol/data-model/).)\n\n## One umbrella version\n\nPeers negotiate a single named bundle — `xnet/1.0` — exactly as Matrix bundles\nbreaking changes into _room versions_. It expands to the per‑subsystem versions\n(change record, sync envelope, awareness, schema, crypto level). The\nmachine‑readable constant is `XNET_PROTOCOL_VERSION`, exported by `@xnetjs/sdk`.\n\n## Prove it, don't just read it\n\nEvery claim in the spec is backed by a **language‑agnostic golden‑vector\ncorpus** shipped _with_ the spec and re‑checked in CI — so the prose can't drift\nfrom reality. A ~100‑line Python kernel reproduces the same DIDs and verifies\nTypeScript‑signed changes. Want to build your own implementation?\n\n<LinkCard\n  title=\"Implement XNet in your language →\"\n  href=\"/docs/protocol/implement-in-your-language/\"\n  description=\"A step-by-step kernel, the golden vectors, and how to claim conformance.\"\n/>\n\n<LinkCard\n  title=\"Languages & SDKs →\"\n  href=\"/docs/languages/overview/\"\n  description=\"TypeScript, Swift, Rust, Python — and the JS frameworks — at honest, labeled maturity levels.\"\n/>","src/content/docs/docs/protocol/overview.mdx","31ea052fffacac76","docs/protocol/replication",{id:651,data:653,body:660,filePath:661,digest:662,deferredRender:16},{title:654,description:655,editUrl:16,head:656,template:18,sidebar:657,pagefind:16,draft:21},"Replication (L2)","How nodes and document bodies move between peers: wire messages, the signed Yjs envelope, awareness, and the version handshake.",[],{order:78,label:658,hidden:21,attrs:659},"Replication",{},"How nodes and document bodies move between peers. The message *semantics* are\ndefined once and bind to multiple transports. Normative text:\n[`03-replication.md`](https://github.com/crs48/xNet/blob/main/docs/specs/protocol/03-replication.md).\n\n## Two streams per document\n\nA document (room) carries two complementary streams. An implementation must relay\nboth faithfully; it need only *interpret* the first.\n\n```mermaid\nflowchart LR\n  P1[\"Peer A\"] <-->|relay / P2P| Room\n  Room[\"Room = one document (docId)\"] <-->|relay / P2P| P2[\"Peer B\"]\n  Room --- A[\"Structured node sync\\nsigned Change records\"]\n  Room --- B[\"Document body sync\\nsigned Yjs envelope (opaque)\"]\n```\n\n## Structured node sync\n\n```ts\n{ type: \"node-change\", room, change }                    // one new signed change\n{ type: \"node-sync-request\", room, sinceLamport }        // catch-up request\n{ type: \"node-sync-response\", room, changes, highWaterMark } // catch-up batch\n```\n\nA receiver verifies each change's signature, applies idempotently (re‑applying a\nknown `hash` is a no‑op), and orders by `lamport`. `highWaterMark` enables\nresumable catch‑up.\n\n## The signed Yjs envelope\n\nDocument bodies sync with [y‑protocols](https://github.com/yjs/y-protocols)\nsync v1, each update wrapped so the relay can authenticate authorship **without\nparsing the CRDT**:\n\n```jsonc\n{\n  \"v\": 2,\n  \"u\": \"base64(Yjs update bytes)\",   // OPAQUE codec payload\n  \"m\": { \"a\": \"did:key:…\", \"c\": 12345, \"t\": 1718641200000, \"d\": \"<docId>\" },\n  \"s\": { \"ed25519\": \"base64\", \"mlDsa\": null, \"level\": 0 }\n}\n```\n\nThe signature covers `BLAKE3(update || JSON(meta))` and is verified against the\nauthor DID. Relays forward the envelope byte‑preserving; a peer that doesn't\nimplement `yjs-v1` still forwards and stores `u`.\n\n## Awareness\n\nEphemeral presence (cursor, selection, online status) uses y‑protocols\nawareness. It is **not** persisted as node data and is exempt from the hash\nchain; relays should rate‑limit and expire it.\n\n## The version handshake\n\n```mermaid\nsequenceDiagram\n  participant C as Client\n  participant H as Hub\n  H->>C: handshake { xnetProtocol:[\"xnet/1.0\"], minXnetProtocol, hubDid }\n  C->>H: client-handshake { did, xnetProtocol:[\"xnet/1.0\"] }\n  alt no shared umbrella version\n    H-->>C: version-mismatch { suggestion }\n  else compatible\n    C->>H: subscribe { topics:[\"xnet-doc-…\"] }\n    H-->>C: relays node-change / sync-* / awareness\n  end\n```\n\nTwo peers are compatible iff their `xnetProtocol` sets intersect; a peer with no\nacceptable version refuses with a typed `version-mismatch` rather than partially\nsyncing. The token is `XNET_PROTOCOL_VERSION.id` (`\"xnet/1.0\"`) from `@xnetjs/sdk`.\n\n## Transport bindings\n\nThe same logical messages bind to two transports: **WebSocket** (JSON frames,\nbrowser ↔ hub) and **libp2p** (length‑prefixed msgpack over `/xnet/sync/1.0.0`,\nP2P). A relay may bridge between them.\n\nNext: [Authorization (L3) →](/docs/protocol/authorization/)","src/content/docs/docs/protocol/replication.mdx","eeac9f41550ddd28","docs/schemas/extending-schemas",{id:663,data:665,body:671,filePath:672,digest:673,deferredRender:16},{title:666,description:667,editUrl:16,head:668,template:18,sidebar:669,pagefind:16,draft:21},"Extending Schemas","Add custom fields to a shipped schema with overlays, sidecars, or a new schema version.",[],{hidden:21,attrs:670},{},"xNet ships typed schemas like `Task`, `Contact`, and `Page` with a fixed set of\nproperties. When you need to track something they don't model — a `leadScore`\non a contact, a `billableRate` on a task — you have three ways to extend them,\nfrom lightest to heaviest.\n\n## 1. Overlay fields (the everyday path)\n\nAn **overlay** stores custom attributes directly on the node under a reserved,\nnamespaced key: `ext:<authority>/<field>`. The `authority` (a Space id, a DID,\nor a domain) keeps two parties from colliding. Overlay values are ordinary node\nproperties, so they sync and conflict-resolve per-key (LWW) and inherit the\nnode's authorization automatically — no join, no schema fork.\n\nAdd a field with `createExtensionField`:\n\n```ts\nimport { createExtensionField } from '@xnetjs/data'\n\nconst { key } = await createExtensionField(store, {\n  targetSchema: 'xnet://xnet.fyi/Contact@1.0.0',\n  authority: 'acme.com',\n  name: 'leadScore',\n  type: 'number',\n  config: { min: 0, max: 100 }\n})\n// key === 'ext:acme.com/leadScore'\n```\n\nRead and write the value like any other property — the overlay key rides along\non the node:\n\n```ts\nconst { update } = useMutate()\nawait update(ContactSchema, contact.id, { 'ext:acme.com/leadScore': 87 })\n\n// Filtering uses the standard where path (it pushes down like any property):\nconst hot = useQuery(ContactSchema, { where: { 'ext:acme.com/leadScore': 87 } })\n```\n\nThe grid composes the **effective schema** — core columns plus your overlay\ncolumns — via `useEffectiveSchema`. Schema-defined (core) columns are\nstructurally **locked**: you can edit their values but not rename, retype, or\ndelete them. Only overlay columns are restructurable.\n\n```ts\nconst { schema } = useEffectiveSchema('xnet://xnet.fyi/Contact@1.0.0')\n// schema.properties includes 'name' (readonly) … 'ext:acme.com/leadScore'\n```\n\n## 2. Sidecar extensions (when access differs)\n\nAn overlay inherits the target node's authorization. When the attributes need\ntheir **own** owner or access — say, _your_ private notes on a `Contact`\nsomeone else shares with you — use a **sidecar**: a separate node that\nreferences the target and carries its own `authorization` (typically\n`presets.private()`).\n\n```ts\nimport { defineSchema, relation, text, presets, sidecarId } from '@xnetjs/data'\n\nconst ContactNotes = defineSchema({\n  name: 'ContactNotes',\n  namespace: 'xnet://did:key:.../',\n  properties: {\n    target: relation({ target: 'xnet://xnet.fyi/Contact@1.0.0', required: true }),\n    notes: text({})\n  },\n  authorization: presets.private()\n})\n// one sidecar per (authority, target): id = sidecarId(authority, contactId)\n```\n\nThe grid folds a sidecar's attributes into the same `ext:<authority>/<field>`\ncolumn space as overlays via `mergeSidecarsIntoRow`, so both render uniformly.\n\n## 3. A new schema version (custom objects)\n\nWhen you're really creating a new _type_ — not just decorating an existing one\n— define a new schema (optionally `extends` the base) and migrate existing\nnodes with a **lens**. To graduate an overlay into a first-class property, use\n`promoteOverlay`:\n\n```ts\nimport { composeLens, promoteOverlay } from '@xnetjs/data'\n\nconst v1ToV2 = composeLens(\n  'xnet://xnet.fyi/Contact@1.0.0',\n  'xnet://xnet.fyi/Contact@2.0.0',\n  promoteOverlay('acme.com', 'leadScore', 'leadScore')\n)\n// { 'ext:acme.com/leadScore': 87 } → { leadScore: 87 }  (lossless)\n```\n\n## Which one?\n\n| Need                                      | Use                               |\n| ----------------------------------------- | --------------------------------- |\n| A custom field, same record + permissions | **Overlay** (`ext:` key)          |\n| A field with its own owner / access       | **Sidecar** (join node)           |\n| A distinct, fully-typed type              | **New schema** (`extends` + lens) |\n\nOverlay is the default — it's the cheapest to store and query. Reach for a\nsidecar only when access must differ, and a new schema only when you're\nauthoring a genuinely new type.","src/content/docs/docs/schemas/extending-schemas.mdx","fb3e2ccd293ce513","docs/schemas/defineschema",{id:674,data:676,body:683,filePath:684,digest:685,deferredRender:16},{title:677,description:678,editUrl:16,head:679,template:18,sidebar:680,pagefind:16,draft:21},"defineSchema","Create a schema definition with full TypeScript inference.",[],{order:55,hidden:21,badge:681,attrs:682},{variant:517,text:518},{},":::note[You will learn]\n\n- The full `defineSchema()` API\n- All options and what they do\n- What a `DefinedSchema` gives you\n- How validation and coercion work\n  :::\n\n## Quick example\n\n```ts\nimport { defineSchema, text, select, checkbox, relation } from '@xnetjs/data'\n\nexport const TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true, maxLength: 500 }),\n    status: select({\n      options: [\n        { id: 'todo', name: 'To Do', color: '#6366f1' },\n        { id: 'doing', name: 'Doing', color: '#f59e0b' },\n        { id: 'done', name: 'Done', color: '#10b981' }\n      ] as const\n    }),\n    completed: checkbox({ default: false }),\n    project: relation({ target: 'xnet://my-app/Project' })\n  }\n})\n```\n\n:::tip[Automatic fields]\nEvery node automatically gets `id`, `schemaId`, `createdAt`, `updatedAt`, `createdBy`, and `updatedBy`. You don't need to define these in your schema — they're managed by the store and available on every node when you read it.\n:::\n\n## Signature\n\n```ts\nfunction defineSchema<P extends Record<string, PropertyBuilder>>(\n  options: DefineSchemaOptions<P>\n): DefinedSchema<P>\n```\n\n## Options\n\n| Field           | Type                              | Required | Description                                                                              |\n| --------------- | --------------------------------- | -------- | ---------------------------------------------------------------------------------------- |\n| `name`          | `string`                          | Yes      | Schema name (e.g., `'Task'`). Used in the schema IRI.                                    |\n| `namespace`     | `` `xnet://${string}/` ``         | Yes      | Namespace for grouping. Must end with `/`.                                               |\n| `properties`    | `Record<string, PropertyBuilder>` | Yes      | Property definitions using builder functions.                                            |\n| `extends`       | `DefinedSchema`                   | No       | Parent schema to inherit properties from.                                                |\n| `document`      | `'yjs' \\| 'automerge'`            | No       | CRDT document type. Required for [`useNode`](/docs/hooks/usenode/) rich text.            |\n| `authorization` | `AuthorizationBlock`              | No       | Roles, actions, and encryption policy. See [Authorization](/docs/guides/authorization/). |\n\n### Schema IRI\n\nThe schema's unique identifier is `${namespace}${name}`:\n\n```ts\ndefineSchema({ name: 'Task', namespace: 'xnet://my-app/' })\n// Schema IRI: 'xnet://my-app/Task'\n```\n\nEach property also gets an IRI: `${schemaId}#${propertyName}`:\n\n```\nxnet://my-app/Task#title\nxnet://my-app/Task#status\n```\n\n## Return value: DefinedSchema\n\n| Field/Method             | Type                            | Description                                       |\n| ------------------------ | ------------------------------- | ------------------------------------------------- |\n| `schema`                 | `Schema`                        | The JSON-LD compatible schema object.             |\n| `validate(node)`         | `(unknown) => ValidationResult` | Validate a node against this schema.              |\n| `create(props, options)` | `(props, options) => Node`      | Create a new node (used internally).              |\n| `is(node)`               | `(node) => boolean`             | Type guard — check if a node matches this schema. |\n| `_schemaId`              | `string`                        | The computed schema IRI.                          |\n| `_properties`            | `P`                             | Property builders (for type inference).           |\n\n### ValidationResult\n\n```ts\ninterface ValidationResult {\n  valid: boolean\n  errors: ValidationError[] // { path, message, value? }\n}\n```\n\nValidation checks:\n\n- Required system fields (`id`, `schemaId`, `createdAt`, `createdBy`)\n- `schemaId` matches the schema\n- `createdBy` starts with `did:key:`\n- Each property's constraints (required, min/max, pattern, etc.)\n\n## Adding authorization\n\nAdd an `authorization` block to define who can read, write, delete, and share nodes of this schema. The mutation policy can optionally be split into `create` (who may add nodes) and `update` (who may modify existing ones) — each falls back to `write` when not declared:\n\n```ts\nimport { defineSchema, text, person, relation } from '@xnetjs/data'\nimport { allow, role } from '@xnetjs/data/auth'\n\nexport const TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    assignee: person(),\n    project: relation({ target: 'xnet://my-app/Project' as const })\n  },\n  authorization: {\n    roles: {\n      owner: role.creator(),\n      assignee: role.property('assignee'),\n      admin: role.relation('project', 'admin')\n    },\n    actions: {\n      read: allow('owner', 'assignee', 'admin'),\n      write: allow('owner', 'admin'),\n      delete: allow('owner', 'admin'),\n      share: allow('owner', 'admin')\n    },\n    publicProps: ['title'] // these fields are readable without decryption\n  }\n})\n```\n\nNodes are encrypted with a **per-node content key** and only users in the recipient list can decrypt them. The hub stores encrypted envelopes and filters queries by recipient list without ever decrypting content.\n\nSee the [Authorization Guide](/docs/guides/authorization/) for the full model including presets, `useCan`, `useGrants`, delegation, and key recovery.\n\n## Adding rich text support\n\nAdd `document: 'yjs'` to enable collaborative editing via [`useNode`](/docs/hooks/usenode/):\n\n```ts\nexport const PageSchema = defineSchema({\n  name: 'Page',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    icon: text()\n  },\n  document: 'yjs'\n})\n```\n\nWhen `document: 'yjs'` is set, `useNode` creates a `Y.Doc` for the node and manages P2P sync for its content.\n\n## Schema inheritance\n\nUse `extends` to inherit properties from a parent schema:\n\n```ts\nconst BaseSchema = defineSchema({\n  name: 'Base',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    tags: multiSelect({ options: ['draft', 'published'] as const })\n  }\n})\n\nconst ArticleSchema = defineSchema({\n  name: 'Article',\n  namespace: 'xnet://my-app/',\n  extends: BaseSchema,\n  properties: {\n    body: text(),\n    publishedAt: date()\n  }\n})\n// ArticleSchema has: title, tags, body, publishedAt\n```\n\n## Coercion\n\nWhen you create or update a node, property values are **coerced** through the property builder:\n\n- `text()` — calls `String(value)`, trims whitespace\n- `number()` — calls `Number(value)`, applies `Math.round()` if `integer`\n- `select()` — validates against option IDs, tries case-insensitive name matching as fallback\n- `date()` — accepts `number`, `Date`, or ISO string; normalizes to timestamp\n- `email()` — trims and lowercases\n- `url()` — auto-prepends `https://` if no protocol\n\nThis means your data is always normalized regardless of what the user types.\n\n## Dev-time warnings\n\nIn development, `defineSchema` warns if:\n\n- A `text()` property has a name that looks like a reference (e.g., `targetId`, `parentId`), suggesting you use `relation()` instead\n\n## Related\n\n- [Property Types](/docs/schemas/property-types/) — all 15 property builders\n- [Relations](/docs/schemas/relations/) — linking nodes together\n- [Type Inference](/docs/schemas/type-inference/) — how TypeScript types flow\n- [Authorization](/docs/guides/authorization/) — roles, grants, encryption, and key recovery","src/content/docs/docs/schemas/defineschema.mdx","7f3fbdb551bd4d2b","docs/schemas/overview",{id:686,data:688,body:694,filePath:695,digest:696,deferredRender:16},{title:689,description:690,editUrl:16,head:691,template:18,sidebar:692,pagefind:16,draft:21},"Schemas Overview","How schemas define and validate your data in xNet.",[],{order:43,hidden:21,attrs:693},{},"import { LinkCard, CardGrid } from '@astrojs/starlight/components'\n\n:::note[In this article]\n\n- What schemas are and why they matter\n- The relationship between schemas, nodes, and hooks\n- How type inference flows from schema to component\n  :::\n\n## What is a schema?\n\nA schema is a TypeScript definition that describes the shape of your data. Every node in xNet conforms to a schema.\n\n```ts\nimport { defineSchema, text, select, date } from '@xnetjs/data'\n\nexport const TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text({ required: true }),\n    status: select({\n      options: [\n        { id: 'todo', name: 'To Do' },\n        { id: 'done', name: 'Done' }\n      ] as const\n    }),\n    dueDate: date({ includeTime: true })\n  }\n})\n```\n\nThis gives you:\n\n- **Type safety** — `task.status` is `'todo' | 'done'`, not `string`\n- **Validation** — required fields are enforced, values are range-checked\n- **Identity** — the schema has a unique IRI: `xnet://my-app/Task`\n- **Coercion** — values are normalized on creation (trimming, type conversion)\n\n## Schemas are the source of truth\n\nThe type inference flows from schema definition through every hook:\n\n```\ndefineSchema({ properties: { title: text(), ... } })\n  ↓\nuseQuery(TaskSchema)        → { data: { id, title, ... }[] }\nuseMutate().create(TaskSchema, { title: '...' })\nuseNode(TaskSchema, id)     → { data: { id, title, ... } }\n```\n\nYou define types once. Every hook infers from the schema.\n\n## Schema anatomy\n\nEvery schema has:\n\n| Field        | Required | Description                                                   |\n| ------------ | -------- | ------------------------------------------------------------- |\n| `name`       | Yes      | Display name (e.g., `'Task'`, `'Page'`).                      |\n| `namespace`  | Yes      | Must match `` `xnet://${string}/` ``. Groups related schemas. |\n| `properties` | Yes      | Record of property builders (e.g., `text()`, `select()`).     |\n| `extends`    | No       | Parent schema to inherit properties from.                     |\n| `document`   | No       | CRDT document type: `'yjs'` for rich text editing.            |\n\nThe schema IRI is computed as `${namespace}${name}` — e.g., `xnet://my-app/Task`.\n\n## Next steps\n\n<CardGrid>\n  <LinkCard\n    title=\"defineSchema\"\n    description=\"Full reference for creating schemas.\"\n    href=\"/docs/schemas/defineschema/\"\n  />\n  <LinkCard\n    title=\"Property Types\"\n    description=\"All 15 property types with examples.\"\n    href=\"/docs/schemas/property-types/\"\n  />\n  <LinkCard\n    title=\"Relations\"\n    description=\"Link nodes together with references.\"\n    href=\"/docs/schemas/relations/\"\n  />\n  <LinkCard\n    title=\"Type Inference\"\n    description=\"How TypeScript types flow from schemas.\"\n    href=\"/docs/schemas/type-inference/\"\n  />\n</CardGrid>","src/content/docs/docs/schemas/overview.mdx","503cc683d723d0b5","docs/schemas/relations",{id:697,data:699,body:705,filePath:706,digest:707,deferredRender:16},{title:700,description:701,editUrl:16,head:702,template:18,sidebar:703,pagefind:16,draft:21},"Relations","Link nodes together with relation() and person() properties.",[],{hidden:21,attrs:704},{},"Relations are how you connect nodes together in xNet. Instead of embedding nested objects, you store references between nodes using two specialized property types: `relation()` and `person()`.\n\n## relation()\n\nThe `relation()` property stores a reference to another node by its ID. You can think of it like a foreign key in a relational database, except it works across peers in a local-first system. When you need to link a task to a project, or a comment to a post, `relation()` is the right choice.\n\n```ts\nimport { defineSchema, relation, text } from '@xnetjs/data'\n\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text(),\n    project: relation({ target: 'xnet://my-app/Project@1.0.0' }), // single reference\n    blockedBy: relation({ multiple: true }) // multiple references\n  }\n})\n```\n\nRelations support both single and multiple cardinality. Use `relation()` for a single link and `relation({ multiple: true })` for an array of links.\n\n## person()\n\nThe `person()` property links to a user by their DID (Decentralized Identifier) rather than a node ID. This is useful for ownership, assignment, and authorship fields where you need to reference an identity rather than a piece of data.\n\n```ts\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text(),\n    assignee: person(), // single DID reference\n    watchers: person({ multiple: true }) // multiple DID references\n  }\n})\n```\n\n## Related creates in one mutate call\n\nWhen creating multiple related nodes at once, use explicit IDs so later operations can reference earlier creates in the same mutate call:\n\n```ts\nconst { mutate } = useMutate()\n\nawait mutate([\n  {\n    type: 'create',\n    schema: ProjectSchema,\n    id: 'project-acme',\n    data: { name: 'Acme' }\n  },\n  {\n    type: 'create',\n    schema: TaskSchema,\n    data: { title: 'Setup', project: 'project-acme' }\n  }\n])\n```\n\nBecause the project node is created first (with a known ID), the task can safely reference it in the next operation.","src/content/docs/docs/schemas/relations.mdx","6f7602709a29ff2f","docs/schemas/property-types",{id:708,data:710,body:717,filePath:718,digest:719,deferredRender:16},{title:711,description:712,editUrl:16,head:713,template:18,sidebar:714,pagefind:16,draft:21},"Property Types","All 15 property types available in xNet schemas.",[],{order:20,hidden:21,badge:715,attrs:716},{variant:517,text:518},{},"import { Tabs, TabItem } from '@astrojs/starlight/components'\n\n:::note[You will learn]\n\n- Every property type and its options\n- What TypeScript type each property infers to\n- Validation rules and coercion behavior\n  :::\n\nxNet provides 15 property types organized into five categories.\n\n## Basic types\n\n### text\n\nA string property with optional length and pattern constraints.\n\n```ts\nimport { text } from '@xnetjs/data'\n\ntitle: text({ required: true, maxLength: 500 })\ndraft: false\ndescription: text({ placeholder: 'Enter a description...' })\nslug: text({ pattern: /^[a-z0-9-]+$/ })\n```\n\n| Option        | Type      | Default | Description                   |\n| ------------- | --------- | ------- | ----------------------------- |\n| `required`    | `boolean` | `false` | Reject null/undefined values. |\n| `minLength`   | `number`  | —       | Minimum string length.        |\n| `maxLength`   | `number`  | —       | Maximum string length.        |\n| `pattern`     | `RegExp`  | —       | Regex pattern to match.       |\n| `placeholder` | `string`  | —       | UI hint (not enforced).       |\n\n**Infers to:** `string`\n**Coercion:** `String(value)`. Returns `null` for null/undefined.\n\n---\n\n### number\n\nA numeric property with optional range and integer constraints.\n\n```ts\nimport { number } from '@xnetjs/data'\n\npriority: number({ min: 1, max: 5 })\nscore: number({ min: 0, integer: true })\n```\n\n| Option     | Type      | Default | Description               |\n| ---------- | --------- | ------- | ------------------------- |\n| `required` | `boolean` | `false` |                           |\n| `min`      | `number`  | —       | Minimum value.            |\n| `max`      | `number`  | —       | Maximum value.            |\n| `integer`  | `boolean` | `false` | Round to nearest integer. |\n\n**Infers to:** `number`\n**Coercion:** `Number(value)`. If `integer`, applies `Math.round()`. Returns `null` for NaN.\n\n---\n\n### checkbox\n\nA boolean property with an optional default.\n\n```ts\nimport { checkbox } from '@xnetjs/data'\n\ncompleted: checkbox({ default: false })\nisPublic: checkbox({ default: true })\n```\n\n| Option     | Type      | Default | Description                       |\n| ---------- | --------- | ------- | --------------------------------- |\n| `required` | `boolean` | `false` |                                   |\n| `default`  | `boolean` | —       | Default value for null/undefined. |\n\n**Infers to:** `boolean`\n**Coercion:** `'true'`/`1` to `true`, `'false'`/`0` to `false`, else `Boolean(value)`.\n\n---\n\n## Temporal types\n\n### date\n\nA timestamp stored as Unix milliseconds.\n\n```ts\nimport { date } from '@xnetjs/data'\n\ndueDate: date()\nscheduledAt: date({ includeTime: true })\n```\n\n| Option        | Type      | Default | Description                      |\n| ------------- | --------- | ------- | -------------------------------- |\n| `required`    | `boolean` | `false` |                                  |\n| `includeTime` | `boolean` | `false` | UI hint for showing time picker. |\n\n**Infers to:** `number` (Unix timestamp in ms)\n**Coercion:** Accepts `number`, `Date` objects (`.getTime()`), ISO strings (`Date.parse()`). Returns `null` if unparseable.\n**Validation:** Must be between 0 and year 3000 (`32503680000000`).\n\n---\n\n### dateRange\n\nA range with a start and optional end date.\n\n```ts\nimport { dateRange } from '@xnetjs/data'\n\ntimeline: dateRange()\nsprint: dateRange({ includeTime: true })\n```\n\n| Option        | Type      | Default | Description |\n| ------------- | --------- | ------- | ----------- |\n| `required`    | `boolean` | `false` |             |\n| `includeTime` | `boolean` | `false` | UI hint.    |\n\n**Infers to:** `{ start: string; end?: string }` (ISO 8601 strings)\n**Coercion:** Parses `start` and `end` through `new Date()` and converts to ISO strings.\n\n---\n\n## Selection types\n\n### select\n\nA single choice from a predefined list.\n\n```ts\nimport { select } from '@xnetjs/data'\n\nstatus: select({\n  options: [\n    { id: 'todo', name: 'To Do', color: '#6366f1' },\n    { id: 'doing', name: 'Doing', color: '#f59e0b' },\n    { id: 'done', name: 'Done', color: '#10b981' }\n  ] as const,\n  default: 'todo'\n})\n```\n\n| Option     | Type             | Default | Description                                                 |\n| ---------- | ---------------- | ------- | ----------------------------------------------------------- |\n| `options`  | `SelectOption[]` | —       | Available choices. Each has `id`, `name`, optional `color`. |\n| `required` | `boolean`        | `false` |                                                             |\n| `default`  | `string`         | —       | Default option ID.                                          |\n\n**Infers to:** Union of option IDs (e.g., `'todo' | 'doing' | 'done'`). Requires `as const` on the options array.\n**Coercion:** Returns `default` for null/undefined. Tries case-insensitive name matching as fallback.\n\n:::tip[Use `as const` for literal types]\nWithout `as const`, the type is just `string`. With it, you get exact literal types:\n\n```ts\n// Without as const → string\nselect({ options: [{ id: 'todo', name: 'To Do' }] })\n\n// With as const → 'todo'\nselect({ options: [{ id: 'todo', name: 'To Do' }] as const })\n```\n\n:::\n\n---\n\n### multiSelect\n\nMultiple choices from a predefined list.\n\n```ts\nimport { multiSelect } from '@xnetjs/data'\n\ntags: multiSelect({\n  options: [\n    { id: 'bug', name: 'Bug', color: '#ef4444' },\n    { id: 'feature', name: 'Feature', color: '#3b82f6' },\n    { id: 'docs', name: 'Docs', color: '#8b5cf6' }\n  ] as const\n})\n```\n\n| Option     | Type             | Default | Description         |\n| ---------- | ---------------- | ------- | ------------------- |\n| `options`  | `SelectOption[]` | —       | Available choices.  |\n| `required` | `boolean`        | `false` |                     |\n| `default`  | `string[]`       | —       | Default option IDs. |\n\n**Infers to:** Union of option IDs as array (e.g., `('bug' | 'feature' | 'docs')[]`)\n**Coercion:** Returns `default ?? []` for null/undefined. Coerces single string to `[value]`. Filters invalid entries.\n\n---\n\n## Reference types\n\n### relation\n\nA reference to another node by ID.\n\n```ts\nimport { relation } from '@xnetjs/data'\n\nproject: relation({ target: 'xnet://my-app/Project' })\nchildren: relation({ multiple: true })\n```\n\n| Option     | Type        | Default | Description                                |\n| ---------- | ----------- | ------- | ------------------------------------------ |\n| `target`   | `SchemaIRI` | —       | Constrain to a specific schema (optional). |\n| `required` | `boolean`   | `false` |                                            |\n| `multiple` | `boolean`   | `false` | Allow array of references.                 |\n\n**Infers to:** `string` (single) or `string[]` (multiple)\n**Coercion:** Returns `null`/`[]` for null/undefined. Filters empty strings.\n\nSee [Relations](/docs/schemas/relations/) for patterns and temp ID resolution in transactions.\n\n---\n\n### person\n\nA reference to a user by DID.\n\n```ts\nimport { person } from '@xnetjs/data'\n\nassignee: person()\ncollaborators: person({ multiple: true })\n```\n\n| Option     | Type      | Default | Description          |\n| ---------- | --------- | ------- | -------------------- |\n| `required` | `boolean` | `false` |                      |\n| `multiple` | `boolean` | `false` | Allow array of DIDs. |\n\n**Infers to:** `string` (DID) or `string[]` (multiple DIDs)\n**Validation:** Must match DID pattern: `/^did:[a-z]+:[a-zA-Z0-9._:-]+$/`\n**Coercion:** Returns `null`/`[]` for null/undefined. Filters invalid DIDs.\n\n---\n\n## Rich types\n\n### url\n\nA validated URL string.\n\n```ts\nimport { url } from '@xnetjs/data'\n\nwebsite: url()\nrepository: url({ placeholder: 'https://github.com/...' })\n```\n\n| Option        | Type      | Default | Description |\n| ------------- | --------- | ------- | ----------- |\n| `required`    | `boolean` | `false` |             |\n| `placeholder` | `string`  | —       | UI hint.    |\n\n**Infers to:** `string`\n**Validation:** Must match `/^https?:\\/\\/.+/i`\n**Coercion:** Trims whitespace. Auto-prepends `https://` if no protocol present.\n\n---\n\n### email\n\nA validated email string.\n\n```ts\nimport { email } from '@xnetjs/data'\n\ncontactEmail: email()\n```\n\n| Option        | Type      | Default | Description |\n| ------------- | --------- | ------- | ----------- |\n| `required`    | `boolean` | `false` |             |\n| `placeholder` | `string`  | —       | UI hint.    |\n\n**Infers to:** `string`\n**Validation:** Must match `/^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/`\n**Coercion:** Trims and lowercases.\n\n---\n\n### phone\n\nA validated phone number string.\n\n```ts\nimport { phone } from '@xnetjs/data'\n\ncontactPhone: phone()\n```\n\n| Option        | Type      | Default | Description |\n| ------------- | --------- | ------- | ----------- |\n| `required`    | `boolean` | `false` |             |\n| `placeholder` | `string`  | —       | UI hint.    |\n\n**Infers to:** `string`\n**Validation:** Must match `/^[+]?[(]?[0-9]{1,4}[)]?[-\\s./0-9]*$/` with at least 7 digits.\n**Coercion:** Trims, collapses whitespace. Preserves formatting.\n\n---\n\n### file\n\nA content-addressed file reference.\n\n```ts\nimport { file } from '@xnetjs/data'\n\navatar: file({ accept: ['image/*'], maxSize: 5 * 1024 * 1024 })\nattachments: file({ multiple: true })\n```\n\n| Option     | Type       | Default | Description                                                  |\n| ---------- | ---------- | ------- | ------------------------------------------------------------ |\n| `required` | `boolean`  | `false` |                                                              |\n| `multiple` | `boolean`  | `false` | Allow array of files.                                        |\n| `accept`   | `string[]` | —       | Allowed MIME types (e.g., `['image/*', 'application/pdf']`). |\n| `maxSize`  | `number`   | —       | Maximum file size in bytes.                                  |\n\n**Infers to:** `FileRef` or `FileRef[]`\n\n```ts\ninterface FileRef {\n  cid: string // Content-addressed ID\n  name: string // Original filename\n  mimeType: string // MIME type\n  size: number // File size in bytes\n}\n```\n\n---\n\n## Auto-populated types\n\n:::note[Usually not needed]\nEvery node automatically gets `createdAt`, `updatedAt`, `createdBy`, and `updatedBy` as system fields — you don't need to define them in your schema. These property builders exist for cases where you want timestamps or authorship to appear as **formal schema properties** (e.g., for generic table UIs that render columns from schema definitions). For most schemas, skip these entirely.\n:::\n\nThese are read-only fields populated automatically by the system.\n\n### created\n\nTimestamp of when the node was created.\n\n```ts\nimport { created } from '@xnetjs/data'\n\ncreatedAt: created()\n```\n\n**Infers to:** `number` (Unix timestamp in ms)\n**Behavior:** Set to `Date.now()` at creation time. Read-only afterward.\n\n---\n\n### updated\n\nTimestamp of the last modification.\n\n```ts\nimport { updated } from '@xnetjs/data'\n\nupdatedAt: updated()\n```\n\n**Infers to:** `number` (Unix timestamp in ms)\n**Behavior:** Set to `Date.now()` on every update. Read-only.\n\n---\n\n### createdBy\n\nDID of the user who created the node.\n\n```ts\nimport { createdBy } from '@xnetjs/data'\n\nauthor: createdBy()\n```\n\n**Infers to:** `string` (DID)\n**Behavior:** Set to the author's DID at creation time. Read-only afterward.\n\n---\n\n## Summary table\n\n| Type          | Infers to              | Validates                 | Notable                |\n| ------------- | ---------------------- | ------------------------- | ---------------------- |\n| `text`        | `string`               | length, pattern           |                        |\n| `number`      | `number`               | min, max, integer         |                        |\n| `checkbox`    | `boolean`              |                           | has `default`          |\n| `date`        | `number`               | 0 to year 3000            | stored as ms timestamp |\n| `dateRange`   | `{ start, end? }`      | valid dates               | ISO 8601 strings       |\n| `select`      | literal union          | option IDs                | use `as const`         |\n| `multiSelect` | literal union[]        | option IDs                | use `as const`         |\n| `relation`    | `string \\| string[]`   | non-empty                 | supports temp IDs      |\n| `person`      | `string \\| string[]`   | DID pattern               | `did:*:*`              |\n| `url`         | `string`               | http(s)                   | auto-prepends https    |\n| `email`       | `string`               | email pattern             | lowercased             |\n| `phone`       | `string`               | phone pattern             | 7+ digits              |\n| `file`        | `FileRef \\| FileRef[]` | cid, name, mimeType, size | content-addressed      |\n| `created`     | `number`               |                           | auto, read-only        |\n| `updated`     | `number`               |                           | auto, read-only        |\n| `createdBy`   | `string` (DID)         |                           | auto, read-only        |\n\n## Related\n\n- [`defineSchema`](/docs/schemas/defineschema/) — using these types in a schema\n- [Relations](/docs/schemas/relations/) — patterns for linking nodes\n- [Type Inference](/docs/schemas/type-inference/) — how types flow to hooks","src/content/docs/docs/schemas/property-types.mdx","dc255a0571df8922","docs/schemas/type-inference",{id:720,data:722,body:728,filePath:729,digest:730,deferredRender:16},{title:723,description:724,editUrl:16,head:725,template:18,sidebar:726,pagefind:16,draft:21},"Type Inference","How TypeScript types flow from schemas to hooks.",[],{hidden:21,attrs:727},{},"One of xNet's key design goals is end-to-end type safety: you define a schema once and TypeScript carries those types all the way through to your React hooks. No manual type annotations, no `as` casts, no runtime surprises.\n\n## How It Works\n\nThe type inference pipeline has three stages:\n\n1. **`defineSchema`** captures the property builder functions you pass in and preserves their types as a generic parameter. Each builder (like `text()`, `number()`, `relation()`) returns a typed descriptor that encodes the property's value type, default, and cardinality.\n\n2. **`InferCreateProps<S>`** maps over the schema's property descriptors to produce the type you pass to `createNode()`. Required properties (no default) become required fields; optional properties (with defaults) become optional fields. This is the \"write\" side of the type.\n\n3. **`FlatNode<S>`** merges the automatic system fields (`id`, `schemaId`, `createdAt`, `updatedAt`, `createdBy`, `updatedBy`) with the inferred property types to produce the \"read\" side. These system fields are managed by the store — you don't define them in your schema. This is what you get back from `useQuery` and `useNode`.\n\n## From Schema to Hook\n\n```ts\n// 1. Define schema — types are captured here\nconst TaskSchema = defineSchema({\n  name: 'Task',\n  namespace: 'xnet://my-app/',\n  properties: {\n    title: text(),\n    done: checkbox({ default: false }),\n    assignee: person()\n  }\n})\n\n// 2. Create — TypeScript knows title is required, done is optional\nconst { create } = useMutate()\ncreate(TaskSchema, { title: 'Ship it' }) // ✅\ncreate(TaskSchema, {}) // ❌ missing title\n\n// 3. Read — TypeScript knows the full shape\nconst { data: tasks } = useQuery(TaskSchema)\ntasks[0].title // string\ntasks[0].done // boolean\ntasks[0].id // string (from base fields)\n```\n\n## Extending the Type System\n\nBecause schemas are plain objects with typed descriptors, you can compose them, create utility types around them, and build higher-level abstractions without losing type information. The property builder pattern ensures that new property types automatically flow through `InferCreateProps` and `FlatNode` without any changes to the inference machinery.\n\nIf you're building a custom property type, implement the `PropertyBuilder` interface and the inference pipeline will pick it up automatically.","src/content/docs/docs/schemas/type-inference.mdx","e9e62a4857181863"];

export { _astro_dataLayerContent as default };
